UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے یہ حدیث بیان کی۔ انہوں نے کہا کہ ہمیں اس کی بابت حنظلہ بن ابی سفیان نے خبر دی۔ انہوں نے عکرمہ بن خالد سے روایت کی انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے روایت کی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اسلام کی بنیاد پانچ چیزوں پر قائم کی گئی ہے۔ اول گواہی دینا کہ اللہ کے سوا کوئی معبود نہیں اور بیشک محمد صلی اللہ علیہ وسلم اللہ کے سچے رسول ہیں اور نماز قائم کرنا اور زکوٰۃ ادا کرنا اور حج کرنا اور رمضان کے روزے رکھنا۔' WHERE id = 9;
UPDATE hadiths SET urdu = 'ہم سے اس حدیث کو ابوالیمان نے بیان کیا، ان کو شعیب نے خبر دی، وہ زہری سے نقل کرتے ہیں، انہیں ابوادریس عائذ اللہ بن عبداللہ نے خبر دی کہ عبادہ بن صامت رضی اللہ عنہ جو بدر کی لڑائی میں شریک تھے اور لیلۃالعقبہ کے ( بارہ ) نقیبوں میں سے تھے۔ فرماتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے اس وقت جب آپ کے گرد صحابہ کی ایک جماعت بیٹھی ہوئی تھی فرمایا کہ مجھ سے بیعت کرو اس بات پر کہ اللہ کے ساتھ کسی کو شریک نہ کرو گے، چوری نہ کرو گے، زنا نہ کرو گے، اپنی اولاد کو قتل نہ کرو گے اور نہ عمداً کسی پر کوئی ناحق بہتان باندھو گے اور کسی بھی اچھی بات میں ( اللہ کی ) نافرمانی نہ کرو گے۔ جو کوئی تم میں ( اس عہد کو ) پورا کرے گا تو اس کا ثواب اللہ کے ذمے ہے اور جو کوئی ان ( بری باتوں ) میں سے کسی کا ارتکاب کرے اور اسے دنیا میں ( اسلامی قانون کے تحت ) سزا دے دی گئی تو یہ سزا اس کے ( گناہوں کے ) لیے بدلا ہو جائے گی اور جو کوئی ان میں سے کسی بات میں مبتلا ہو گیا اور اللہ نے اس کے ( گناہ ) کو چھپا لیا تو پھر اس کا ( معاملہ ) اللہ کے حوالہ ہے، اگر چاہے معاف کرے اور اگر چاہے سزا دیدے۔ ( عبادہ کہتے ہیں کہ ) پھر ہم سب نے ان ( سب باتوں ) پر آپ صلی اللہ علیہ وسلم سے بیعت کر لی۔' WHERE id = 19;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے یزید بن ابی حبیب سے، انہوں نے ابوالخیر سے، انہوں نے عبداللہ بن عمرو رضی اللہ عنہما سے کہ ایک آدمی نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کون سا اسلام بہتر ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو کھانا کھلائے اور ہر شخص کو سلام کرے خواہ اس کو تو جانتا ہو یا نہ جانتا ہو۔' WHERE id = 29;
UPDATE hadiths SET urdu = 'ہم نے ابن سلام نے بیان کیا، انہوں نے کہا کہ ہمیں محمد بن فضیل نے خبر دی، انہوں نے کہا کہ ہم سے یحییٰ بن سعید نے بیان کیا، انہوں نے ابوسلمہ سے روایت کی، وہ ابوہریرہ رضی اللہ عنہ سے نقل کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جس نے رمضان کے روزے ایمان اور خالص نیت کے ساتھ رکھے اس کے پچھلے گناہ بخش دیئے گئے۔' WHERE id = 39;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، وہ کہتے ہیں کہ ہم سے شعبہ نے بیان کیا، انہوں نے زبید بن حارث سے، کہا میں نے ابووائل سے مرجیہ کے بارے میں پوچھا، (وہ کہتے ہیں گناہ سے آدمی فاسق نہیں ہوتا) انہوں نے کہا کہ مجھ سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مسلمان کو گالی دینے سے آدمی فاسق ہو جاتا ہے اور مسلمان سے لڑنا کفر ہے۔' WHERE id = 49;
UPDATE hadiths SET urdu = 'ہم سے ابونعمان نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، انہوں نے زیاد سے، انہوں نے علاقہ سے، کہا میں نے جریر بن عبداللہ سے سنا جس دن مغیرہ بن شعبہ ( حاکم کوفہ ) کا انتقال ہوا تو وہ خطبہ کے لیے کھڑے ہوئے اور اللہ کی تعریف اور خوبی بیان کی اور کہا تم کو اکیلے اللہ کا ڈر رکھنا چاہیے اس کا کوئی شریک نہیں اور تحمل اور اطمینان سے رہنا چاہیے اس وقت تک کہ کوئی دوسرا حاکم تمہارے اوپر آئے اور وہ ابھی آنے والا ہے۔ پھر فرمایا کہ اپنے مرنے والے حاکم کے لیے دعائے مغفرت کرو کیونکہ وہ ( مغیرہ ) بھی معافی کو پسند کرتا تھا پھر کہا کہ اس کے بعد تم کو معلوم ہونا چاہیے کہ میں ایک دفعہ نبی کریم صلی اللہ علیہ وسلم کے پاس آیا اور میں نے عرض کیا کہ میں آپ سے اسلام پر بیعت کرتا ہوں آپ صلی اللہ علیہ وسلم نے مجھ سے ہر مسلمان کی خیر خواہی کے لیے شرط کی، پس میں نے اس شرط پر آپ سے بیعت کر لی ( پس ) اس مسجد کے رب کی قسم کہ میں تمہارا خیرخواہ ہوں پھر استغفار کیا اور منبر سے اتر آئے۔' WHERE id = 59;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہیں سفیان نے اعمش سے خبر دی، وہ ابووائل سے روایت کرتے ہیں، وہ عبداللہ بن مسعود رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے ہمیں نصیحت فرمانے کے لیے کچھ دن مقرر کر دیئے تھے اس ڈر سے کہ کہیں ہم کبیدہ خاطر نہ ہو جائیں۔' WHERE id = 69;
UPDATE hadiths SET urdu = 'ہم سے ابوالقاسم خالد بن خلی قاضی حمص نے بیان کیا، ان سے محمد بن حرب نے، اوزاعی کہتے ہیں کہ ہمیں زہری نے عبیداللہ ابن عبداللہ بن عتبہ بن مسعود سے خبر دی، وہ عبداللہ بن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ وہ اور حر بن قیس بن حصن فزاری موسیٰ علیہ السلام کے ساتھی کے بارے میں جھگڑے۔ ( اس دوران میں ) ان کے پاس سے ابی بن کعب گزرے، تو ابن عباس رضی اللہ عنہما نے انہیں بلا لیا اور کہا کہ میں اور میرے ( یہ ) ساتھی موسیٰ علیہ السلام کے ساتھی کے بارے میں بحث کر رہے ہیں جس سے ملنے کی موسیٰ علیہ السلام نے ( اللہ سے ) دعا کی تھی۔ کیا آپ نے رسول اللہ صلی اللہ علیہ وسلم کو کچھ ان کا ذکر فرماتے ہوئے سنا ہے؟ ابی نے کہا کہ ہاں! میں نے رسول اللہ صلی اللہ علیہ وسلم کو ان کا حال بیان فرماتے ہوئے سنا ہے۔ آپ فرما رہے تھے کہ ایک بار موسیٰ علیہ السلام بنی اسرائیل کی ایک جماعت میں تھے کہ اتنے میں ایک شخص آیا اور کہنے لگا کیا آپ جانتے ہیں کہ دنیا میں آپ سے بھی بڑھ کر کوئی عالم موجود ہے۔ موسیٰ علیہ السلام نے فرمایا کہ نہیں۔ تب اللہ تعالیٰ نے موسیٰ علیہ السلام پر وحی نازل کی کہ ہاں ہمارا بندہ خضر ( علم میں تم سے بڑھ کر ) ہے۔ تو موسیٰ علیہ السلام نے ان سے ملنے کی راہ دریافت کی، اس وقت اللہ تعالیٰ نے ( ان سے ملاقات کے لیے ) مچھلی کو نشانی قرار دیا اور ان سے کہہ دیا کہ جب تم مچھلی کو نہ پاؤ تو لوٹ جانا، تب تم خضر علیہ السلام سے ملاقات کر لو گے۔ موسیٰ علیہ السلام دریا میں مچھلی کے نشان کا انتظار کرتے رہے۔ تب ان کے خادم نے ان سے کہا۔ کیا آپ نے دیکھا تھا کہ جب ہم پتھر کے پاس تھے، تو میں ( وہاں ) مچھلی بھول گیا۔ اور مجھے شیطان ہی نے غافل کر دیا۔ موسیٰ علیہ السلام نے کہا کہ ہم اسی ( مقام ) کے تو متلاشی تھے، تب وہ اپنے ( قدموں کے ) نشانوں پر باتیں کرتے ہوئے واپس لوٹے۔ ( وہاں ) خضر علیہ السلام کو انہوں نے پایا۔ پھر ان کا قصہ وہی ہے جو اللہ تعالیٰ نے اپنی کتاب میں بیان فرمایا ہے۔' WHERE id = 79;
UPDATE hadiths SET urdu = 'ہم سے ابوالحسن محمد بن مقاتل نے بیان کیا، انہیں عبداللہ نے خبر دی، انہیں عمر بن سعید بن ابی حسین نے خبر دی، ان سے عبداللہ بن ابی ملیکہ نے عقبہ ابن الحارث کے واسطے سے نقل کیا کہ عقبہ نے ابواہاب بن عزیز کی لڑکی سے نکاح کیا تو ان کے پاس ایک عورت آئی اور کہنے لگی کہ میں نے عقبہ کو اور جس سے اس کا نکاح ہوا ہے، اس کو دودھ پلایا ہے۔ نہ تو نے کبھی مجھے بتایا ہے۔ ( یہ سن کر ) عقبہ نے کہا، مجھے نہیں معلوم کہ تو نے مجھے دودھ پلایا ہے اور نہ تو نے کبھی مجھے بتایا ہے۔ تب عقبہ سوار ہو کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں مدینہ منورہ حاضر ہوئے اور آپ سے اس کے متعلق دریافت کیا، تو آپ صلی اللہ علیہ وسلم نے فرمایا، کس طرح ( تم اس لڑکی سے رشتہ رکھو گے ) حالانکہ ( اس کے متعلق یہ ) کہا گیا تب عقبہ بن حارث نے اس لڑکی کو چھوڑ دیا اور اس نے دوسرا خاوند کر لیا۔' WHERE id = 89;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، ان سے شعبہ نے ایوب کے واسطے سے بیان کیا، انہوں نے عطاء بن ابی رباح سے سنا، انہوں نے ابن عباس رضی اللہ عنہما سے سنا کہ میں رسول اللہ صلی اللہ علیہ وسلم پر گواہی دیتا ہوں، یا عطاء نے کہا کہ میں ابن عباس پر گواہی دیتا ہوں کہ نبی کریم صلی اللہ علیہ وسلم ( ایک مرتبہ عید کے موقع پر مردوں کی صفوں میں سے ) نکلے اور آپ صلی اللہ علیہ وسلم کے ساتھ بلال رضی اللہ عنہ تھے۔ آپ کو خیال ہوا کہ عورتوں کو ( خطبہ اچھی طرح ) نہیں سنائی دیا۔ تو آپ صلی اللہ علیہ وسلم نے انہیں علیحدہ نصیحت فرمائی اور صدقے کا حکم دیا ( یہ وعظ سن کر ) کوئی عورت بالی ( اور کوئی عورت ) انگوٹھی ڈالنے لگی اور بلال رضی اللہ عنہ اپنے کپڑے کے دامن میں ( یہ چیزیں ) لینے لگے۔ اس حدیث کو اسماعیل بن علیہ نے ایوب سے روایت کیا، انہوں نے عطاء سے کہ ابن عباس رضی اللہ عنہما نے یوں کہا کہ میں نبی کریم صلی اللہ علیہ وسلم پر گواہی دیتا ہوں ( اس میں شک نہیں ہے ) ۔ امام بخاری رحمہ اللہ کی غرض یہ ہے کہ اگلا باب عام لوگوں سے متعلق تھا اور یہ حاکم اور امام سے متعلق ہے کہ وہ بھی عورتوں کو وعظ سنائے۔' WHERE id = 99;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، ان سے عبدالوارث نے عبدالعزیز کے واسطے سے نقل کیا کہ انس رضی اللہ عنہ فرماتے تھے کہ مجھے بہت سی حدیثیں بیان کرنے سے یہ بات روکتی ہے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص مجھ پر جان بوجھ کر جھوٹ باندھے تو وہ اپنا ٹھکانا جہنم میں بنا لے۔' WHERE id = 109;
UPDATE hadiths SET urdu = 'عبدالعزیز بن عبداللہ نے ہم سے بیان کیا، ان سے مالک نے ابن شہاب کے واسطے سے نقل کیا، انہوں نے اعرج سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، وہ کہتے ہیں کہ لوگ کہتے ہیں کہ ابوہریرہ رضی اللہ عنہ بہت حدیثیں بیان کرتے ہیں اور ( میں کہتا ہوں ) کہ قرآن میں دو آیتیں نہ ہوتیں تو میں کوئی حدیث بیان نہ کرتا۔ پھر یہ آیت پڑھی، ( جس کا ترجمہ یہ ہے ) کہ جو لوگ اللہ کی نازل کی ہوئی دلیلوں اور آیتوں کو چھپاتے ہیں ( آخر آیت ) «رحيم‏» تک۔ ( واقعہ یہ ہے کہ ) ہمارے مہاجرین بھائی تو بازار کی خرید و فروخت میں لگے رہتے تھے اور انصار بھائی اپنی جائیدادوں میں مشغول رہتے اور ابوہریرہ، رسول اللہ صلی اللہ علیہ وسلم کے ساتھ جی بھر کر رہتا ( تاکہ آپ کی رفاقت میں شکم پری سے بھی بےفکری رہے ) اور ( ان مجلسوں میں ) حاضر رہتا جن ( مجلسوں ) میں دوسرے حاضر نہ ہوتے اور وہ ( باتیں ) محفوظ رکھتا جو دوسرے محفوظ نہیں رکھ سکتے تھے۔' WHERE id = 119;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم نے بیان کیا، کہا ہم سے معاذ بن ہشام نے بیان کیا، اس نے کہا کہ میرے باپ نے قتادہ کے واسطے سے نقل کیا، وہ انس بن مالک سے روایت کرتے ہیں کہ ( ایک مرتبہ ) معاذ بن جبل رسول اللہ صلی اللہ علیہ وسلم کے پیچھے سواری پر سوار تھے، آپ صلی اللہ علیہ وسلم نے فرمایا، اے معاذ! میں نے عرض کیا، حاضر ہوں یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے ( دوبارہ ) فرمایا، اے معاذ! میں نے عرض کیا، حاضر ہوں اے اللہ کے رسول! آپ صلی اللہ علیہ وسلم نے ( سہ بارہ ) فرمایا، اے معاذ! میں نے عرض کیا، حاضر ہوں، اے اللہ کے رسول، تین بار ایسا ہوا۔ ( اس کے بعد ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص سچے دل سے اس بات کی گواہی دے کہ اللہ کے سوا کوئی معبود نہیں ہے اور محمد صلی اللہ علیہ وسلم اللہ کے سچے رسول ہیں، اللہ تعالیٰ اس کو ( دوزخ کی ) آگ پر حرام کر دیتا ہے۔ میں نے کہا یا رسول اللہ! کیا اس بات سے لوگوں کو باخبر نہ کر دوں تاکہ وہ خوش ہو جائیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا ( اگر تم یہ خبر سناؤ گے ) تو لوگ اس پر بھروسہ کر بیٹھیں گے ( اور عمل چھوڑ دیں گے ) معاذ رضی اللہ عنہ نے انتقال کے وقت یہ حدیث اس خیال سے بیان فرما دی کہ کہیں حدیث رسول چھپانے کے گناہ پر ان سے آخرت میں مواخذہ نہ ہو۔' WHERE id = 129;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان نے عمرو کے واسطے سے نقل کیا، انہیں کریب نے ابن عباس رضی اللہ عنہما سے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم سوئے یہاں تک کہ آپ صلی اللہ علیہ وسلم خراٹے لینے لگے۔ پھر آپ صلی اللہ علیہ وسلم نے نماز پڑھی اور کبھی ( راوی نے یوں ) کہا کہ آپ صلی اللہ علیہ وسلم لیٹ گئے۔ پھر خراٹے لینے لگے۔ پھر آپ صلی اللہ علیہ وسلم کھڑے ہوئے اس کے بعد نماز پڑھی۔ پھر سفیان نے ہم سے دوسری مرتبہ یہی حدیث بیان کی عمرو سے، انہوں نے کریب سے، انہوں نے ابن عباس رضی اللہ عنہما سے نقل کیا کہ وہ کہتے تھے کہ ( ایک مرتبہ ) میں نے اپنی خالہ ( ام المؤمنین ) میمونہ رضی اللہ عنہا کے گھر رات گزاری، تو ( میں نے دیکھا کہ ) رسول اللہ صلی اللہ علیہ وسلم رات کو اٹھے۔ جب تھوڑی رات باقی رہ گئی۔ تو آپ صلی اللہ علیہ وسلم نے اٹھ کر ایک لٹکے ہوئے مشکیزے سے ہلکا سا وضو کیا۔ عمرو اس کا ہلکا پن اور معمولی ہونا بیان کرتے تھے اور آپ کھڑے ہو کر نماز پڑھنے لگے، تو میں نے بھی اسی طرح وضو کیا۔ جس طرح آپ صلی اللہ علیہ وسلم نے کیا تھا۔ پھر آ کر آپ کے بائیں طرف کھڑا ہو گیا اور کبھی سفیان نے «عن يساره» کی بجائے «عن شماله» کا لفظ کہا ( مطلب دونوں کا ایک ہی ہے ) پھر آپ صلی اللہ علیہ وسلم نے مجھے پھیر لیا اور اپنی داہنی جانب کر لیا۔ پھر نماز پڑھی جس قدر اللہ کو منظور تھا۔ پھر آپ لیٹ گئے اور سو گئے۔ حتیٰ کہ خراٹوں کی آواز آنے لگی۔ پھر آپ کی خدمت میں مؤذن حاضر ہوا اور اس نے آپ کو نماز کی اطلاع دی۔ آپ صلی اللہ علیہ وسلم اس کے ساتھ نماز کے لیے تشریف لے گئے۔ پھر آپ نے نماز پڑھی اور وضو نہیں کیا۔ ( سفیان کہتے ہیں کہ ) ہم نے عمرو سے کہا، کچھ لوگ کہتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم کی آنکھیں سوتی تھیں، دل نہیں سوتا تھا۔ عمرو نے کہا میں نے عبید بن عمیر سے سنا، وہ کہتے تھے کہ انبیاء علیہم السلام کے خواب بھی وحی ہوتے ہیں۔ پھر ( قرآن کی یہ ) آیت پڑھی۔ ”میں خواب میں دیکھتا ہوں کہ میں تجھے ذبح کر رہا ہوں۔“' WHERE id = 139;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا کہ ہم سے انس بن عیاض نے عبیداللہ بن عمر کے واسطے سے بیان کیا، وہ محمد بن یحییٰ بن حبان سے نقل کرتے ہیں، وہ واسع بن حبان سے، وہ عبداللہ بن عمر رضی اللہ عنہما سے روایت کرتے ہیں کہ ( ایک دن میں اپنی بہن اور رسول اللہ صلی اللہ علیہ وسلم کی اہلیہ محترمہ ) حفصہ رضی اللہ عنہا کے مکان کی چھت پر اپنی کسی ضرورت سے چڑھا، تو مجھے رسول اللہ صلی اللہ علیہ وسلم قضاء حاجت کرتے وقت قبلہ کی طرف پشت اور شام کی طرف منہ کئے ہوئے نظر آئے۔' WHERE id = 149;
UPDATE hadiths SET urdu = 'ہم سے حسین بن عیسیٰ نے بیان کیا، انہوں نے کہا ہم سے یونس بن محمد نے بیان کیا، انہوں نے کہا ہم سے فلیح بن سلیمان نے عبداللہ بن ابی بکر بن محمد بن عمرو بن حزم کے واسطے سے بیان کیا، وہ عباد بن تمیم سے نقل کرتے ہیں، وہ عبداللہ بن زید رضی اللہ عنہ کے واسطے سے بیان کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم نے وضو میں اعضاء کو دو دو بار دھویا۔' WHERE id = 159;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، ان سے شعبہ نے بیان کیا، انہیں اشعث بن سلیم نے خبر دی، ان کے باپ نے مسروق سے سنا، وہ ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا سے روایت کرتے ہیں کہ وہ فرماتی ہیں کہ رسول اللہ صلی اللہ علیہ وسلم جوتا پہننے، کنگھی کرنے، وضو کرنے اور اپنے ہر کام میں داہنی طرف سے کام کی ابتداء کرنے کو پسند فرمایا کرتے تھے۔' WHERE id = 169;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے جریر نے اعمش کے واسطے سے بیان کیا، وہ منذر سے، وہ ابویعلیٰ ثوری سے، وہ محمد ابن الحنفیہ سے نقل کرتے ہیں کہ علی رضی اللہ عنہ نے فرمایا کہ میں ایسا آدمی تھا جس کو سیلان مذی کی شکایت تھی، مگر رسول اللہ صلی اللہ علیہ وسلم سے دریافت کرتے ہوئے مجھے شرم آئی۔ تو میں نے ابن الاسود کو حکم دیا، انہوں نے آپ صلی اللہ علیہ وسلم سے پوچھا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس میں وضو کرنا فرض ہے۔ اس روایت کو شعبہ نے بھی اعمش سے روایت کیا۔' WHERE id = 179;
UPDATE hadiths SET urdu = '(اور ایک دوسری حدیث میں) ابوموسیٰ اشعری رضی اللہ عنہ کہتے ہیں کہ نبی اکرم صلی اللہ علیہ وسلم نے ایک پیالہ منگوایا۔ جس میں پانی تھا۔ اس سے آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ دھوئے اور اسی پیالہ میں منہ دھویا اور اس میں کلی فرمائی، پھر فرمایا، تو تم لوگ اس کو پی لو اور اپنے چہروں اور سینوں پر ڈال لو۔' WHERE id = 189;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے زہری سے خبر دی، کہا مجھے عبیداللہ بن عبداللہ بن عتبہ نے خبر دی تحقیق عائشہ رضی اللہ عنہا نے فرمایا کہ جب رسول اللہ صلی اللہ علیہ وسلم بیمار ہوئے اور آپ صلی اللہ علیہ وسلم کی بیماری زیادہ ہو گئی تو آپ صلی اللہ علیہ وسلم نے اپنی ( دوسری ) بیویوں سے اس بات کی اجازت لے لی کہ آپ کی تیمارداری میرے ہی گھر کی جائے۔ انہوں نے آپ کو اجازت دے دی، ( ایک روز ) رسول اللہ صلی اللہ علیہ وسلم دو آدمیوں کے درمیان ( سہارا لے کر ) گھر سے نکلے۔ آپ کے پاؤں ( کمزوری کی وجہ سے ) زمین پر گھسٹتے جاتے تھے، عباس رضی اللہ عنہ اور ایک آدمی کے درمیان ( آپ باہر ) نکلے تھے۔ عبیداللہ ( راوی حدیث ) کہتے ہیں کہ میں نے یہ حدیث عبداللہ بن عباس رضی اللہ عنہما کو سنائی، تو وہ بولے، تم جانتے ہو دوسرا آدمی کون تھا، میں نے عرض کیا کہ نہیں۔ کہنے لگے وہ علی رضی اللہ عنہ تھے۔ پھر عائشہ رضی اللہ عنہا بیان فرماتی تھیں کہ جب نبی کریم صلی اللہ علیہ وسلم اپنے گھر میں داخل ہوئے اور آپ صلی اللہ علیہ وسلم کا مرض بڑھ گیا۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا میرے اوپر ایسی سات مشکوں کا پانی ڈالو، جن کے سربند نہ کھولے گئے ہوں۔ تاکہ میں ( سکون کے بعد ) لوگوں کو کچھ وصیت کروں۔ ( چنانچہ ) آپ کو حفصہ رسول اللہ صلی اللہ علیہ وسلم کی ( دوسری ) بیوی کے لگن میں ( جو تانبے کا تھا ) بیٹھا دیا گیا اور ہم نے آپ پر ان مشکوں سے پانی بہانا شروع کیا۔ جب آپ ہم کو اشارہ فرمانے لگے کہ بس اب تم نے اپنا کام پورا کر دیا تو اس کے بعد آپ لوگوں کے پاس باہر تشریف لے گئے۔' WHERE id = 199;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہمیں لیث نے عقیل سے خبر دی، وہ ابن شہاب سے روایت کرتے ہیں، انہیں جعفر بن عمرو بن امیہ نے اپنے باپ عمرو سے خبر دی کہ انھوں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ آپ صلی اللہ علیہ وسلم بکری کے شانہ سے کاٹ کاٹ کر کھا رہے تھے، پھر آپ صلی اللہ علیہ وسلم نماز کے لیے بلائے گئے تو آپ صلی اللہ علیہ وسلم نے چھری ڈال دی اور نماز پڑھی، نیا وضو نہیں کیا۔' WHERE id = 209;
UPDATE hadiths SET urdu = 'ہم سے محمد بن المثنی نے بیان کیا، انہوں نے کہا ہم سے محمد بن حازم نے بیان کیا، انہوں نے کہا ہم سے اعمش نے مجاہد کے واسطے سے روایت کیا، وہ طاؤس سے، وہ عبداللہ بن عباس رضی اللہ عنہما سے روایت کرتے ہیں کہ ( ایک مرتبہ ) رسول اللہ صلی اللہ علیہ وسلم دو قبروں پر گزرے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان دونوں قبر والوں کو عذاب دیا جا رہا ہے اور کسی بڑے گناہ پر نہیں۔ ایک تو ان میں سے پیشاب سے احتیاط نہیں کرتا تھا اور دوسرا چغل خوری کیا کرتا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے ایک ہری ٹہنی لے کر بیچ سے اس کے دو ٹکڑے کئے اور ہر ایک قبر پر ایک ٹکڑا گاڑ دیا۔ لوگوں نے پوچھا کہ یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے ( ایسا ) کیوں کیا؟ آپ صلی اللہ علیہ وسلم نے فرمایا، شاید جب تک یہ ٹہنیاں خشک نہ ہوں ان پر عذاب میں کچھ تخفیف رہے۔ ابن المثنی نے کہا کہ اس حدیث کو ہم سے وکیع نے بیان کیا، ان سے اعمش نے، انہوں نے مجاہد سے اسی طرح سنا۔' WHERE id = 219;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا مجھ سے ابومعاویہ نے، کہا ہم سے ہشام بن عروہ نے اپنے باپ (عروہ) کے واسطے سے، وہ عائشہ رضی اللہ عنہا سے نقل کرتے ہیں، وہ فرماتی ہیں کہ ابوحبیش کی بیٹی فاطمہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور اس نے کہا کہ میں ایک ایسی عورت ہوں جسے استحاضہ کی بیماری ہے۔ اس لیے میں پاک نہیں رہتی تو کیا میں نماز چھوڑ دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں، یہ ایک رگ ( کا خون ) ہے حیض نہیں ہے۔ تو جب تجھے حیض آئے تو نماز چھوڑ دے اور جب یہ دن گزر جائیں تو اپنے ( بدن اور کپڑے ) سے خون کو دھو ڈال پھر نماز پڑھ۔ ہشام کہتے ہیں کہ میرے باپ عروہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے یہ ( بھی ) فرمایا کہ پھر ہر نماز کے لیے وضو کر یہاں تک کہ وہی ( حیض کا ) وقت پھر آ جائے۔' WHERE id = 229;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا مجھے ابوالزناد نے خبر دی کہ ان سے عبدالرحمٰن بن ہرمزالاعرج نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرماتے تھے کہ ہم ( لوگ ) دنیا میں پچھلے زمانے میں آئے ہیں ( مگر آخرت میں ) سب سے آگے ہیں۔' WHERE id = 239;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں مالک نے ہشام سے خبر دی، وہ اپنے والد سے، وہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا سے روایت کرتے ہیں کہ نبی کریم صلی اللہ علیہ وسلم جب غسل فرماتے تو آپ صلی اللہ علیہ وسلم پہلے اپنے دونوں ہاتھ دھوتے پھر اسی طرح وضو کرتے جیسا نماز کے لیے آپ صلی اللہ علیہ وسلم وضو کیا کرتے تھے۔ پھر پانی میں اپنی انگلیاں داخل فرماتے اور ان سے بالوں کی جڑوں کا خلال کرتے۔ پھر اپنے ہاتھوں سے تین چلو سر پر ڈالتے پھر تمام بدن پر پانی بہا لیتے۔' WHERE id = 249;
UPDATE hadiths SET urdu = 'محمد بن مثنیٰ نے ہم سے بیان کیا، کہا کہ ہم سے ابوعاصم (ضحاک بن مخلد) نے بیان کیا، وہ حنظلہ بن ابی سفیان سے، وہ قاسم بن محمد سے، وہ عائشہ رضی اللہ عنہا سے۔ آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم جب غسل جنابت کرنا چاہتے تو حلاب کی طرح ایک چیز منگاتے۔ پھر ( پانی کا چلو ) اپنے ہاتھ میں لیتے اور سر کے داہنے حصے سے غسل کی ابتداء کرتے۔ پھر بائیں حصہ کا غسل کرتے۔ پھر اپنے دونوں ہاتھوں کو سر کے بیچ میں لگاتے تھے۔' WHERE id = 259;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا۔ انہوں نے کہا ہم سے معاذ بن ہشام نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے قتادہ کے واسطہ سے، کہا ہم سے انس بن مالک نے کہ نبی کریم صلی اللہ علیہ وسلم دن اور رات کے ایک ہی وقت میں اپنی تمام ازواج مطہرات کے پاس گئے اور یہ گیارہ تھیں۔ ( نو منکوحہ اور دو لونڈیاں ) راوی نے کہا، میں نے انس سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم اس کی طاقت رکھتے تھے۔ تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہم آپس میں کہا کرتے تھے کہ آپ صلی اللہ علیہ وسلم کو تیس مردوں کے برابر طاقت دی گئی ہے اور سعید نے کہا قتادہ کے واسطہ سے کہ ہم کہتے تھے کہ انس نے ان سے نو ازواج کا ذکر کیا۔' WHERE id = 269;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے روایت کی۔ انہوں نے امام مالک سے، انہوں نے عمر بن عبیداللہ کے مولیٰ ابونضر سے کہ ام ہانی بنت ابی طالب کے مولیٰ ابومرہ نے انہیں بتایا کہ انہوں نے ام ہانی بنت ابی طالب کو یہ کہتے سنا کہ میں فتح مکہ کے دن رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی تو میں نے دیکھا کہ آپ غسل فرما رہے ہیں اور فاطمہ رضی اللہ عنہا نے پردہ کر رکھا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے پوچھا یہ کون ہیں۔ میں نے عرض کی کہ میں ام ہانی ہوں۔' WHERE id = 280;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے خبر دی انہوں نے عبداللہ بن دینار سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہا سے، انہوں نے کہا عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کی کہ رات میں انہیں غسل کی ضرورت ہو جایا کرتی ہے تو رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ وضو کر لیا کر اور شرمگاہ کو دھو کر سو جا۔' WHERE id = 290;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان محمد بن فضل نے بیان کیا، انہوں نے کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، انہوں نے کہا ہم سے ابواسحاق شیبانی نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن شداد نے بیان کیا، انہوں نے کہا میں نے میمونہ سے سنا، انہوں نے کہا کہ جب نبی کریم صلی اللہ علیہ وسلم اپنی بیویوں میں سے کسی سے مباشرت کرنا چاہتے اور وہ حائضہ ہوتی، تو آپ صلی اللہ علیہ وسلم کے حکم سے، وہ پہلے ازار باندھ لیتیں۔ اور سفیان نے شیبانی سے اس کو روایت کیا ہے۔' WHERE id = 301;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا ہم سے حماد بن زید نے ایوب سختیانی سے، انہوں نے حفصہ سے، وہ ام عطیہ سے، آپ نے فرمایا کہ ہمیں کسی میت پر تین دن سے زیادہ سوگ کرنے سے منع کیا جاتا تھا۔ لیکن شوہر کی موت پر چار مہینے دس دن کے سوگ کا حکم تھا۔ ان دنوں میں ہم نہ سرمہ لگاتیں نہ خوشبو اور عصب ( یمن کی بنی ہوئی ایک چادر جو رنگین بھی ہوتی تھی ) کے علاوہ کوئی رنگین کپڑا ہم استعمال نہیں کرتی تھیں اور ہمیں ( عدت کے دنوں میں ) حیض کے غسل کے بعد کست اظفار استعمال کرنے کی اجازت تھی اور ہمیں جنازہ کے پیچھے چلنے سے منع کیا جاتا تھا۔ اس حدیث کو ہشام بن حسان نے حفصہ سے، انہوں نے ام عطیہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا ہے۔' WHERE id = 311;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، کہا ہم سے ہشام دستوائی نے یحییٰ بن ابی کثیر سے، وہ ابوسلمہ سے، وہ زینب بنت ابی سلمہ سے، وہ ام سلمہ سے، انہوں نے بتلایا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک چادر میں لیٹی ہوئی تھی کہ مجھے حیض آ گیا، میں چپکے سے چلی گئی اور حیض کے کپڑے بدل لیے، آپ نے پوچھا کیا تجھ کو حیض آ گیا ہے۔ میں نے کہا، جی ہاں! پھر مجھے آپ نے بلا لیا اور میں آپ کے ساتھ چادر میں لیٹ گئی۔' WHERE id = 321;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سنان عوفی نے بیان کیا، انہوں نے کہا ہم سے ہشیم نے بیان کیا (دوسری سند) کہا اور مجھ سے سعید بن نضر نے بیان کیا، انہوں نے کہا ہمیں خبر دی ہشیم نے، انہوں نے کہا ہمیں خبر دی سیار نے، انہوں نے کہا ہم سے یزید الفقیر نے بیان کیا، انہوں نے کہا ہمیں جابر بن عبداللہ نے نبی کریم صلی اللہ علیہ وسلم نے فرمایا مجھے پانچ چیزیں ایسی دی گئی ہیں جو مجھ سے پہلے کسی کو نہیں دی گئی تھیں۔ ایک مہینہ کی مسافت سے رعب کے ذریعہ میری مدد کی گئی ہے اور تمام زمین میرے لیے سجدہ گاہ اور پاکی کے لائق بنائی گئی۔ پس میری امت کا جو انسان نماز کے وقت کو ( جہاں بھی ) پالے اسے وہاں ہی نماز ادا کر لینی چاہیے۔ اور میرے لیے غنیمت کا مال حلال کیا گیا ہے۔ مجھ سے پہلے یہ کسی کے لیے بھی حلال نہ تھا۔ اور مجھے شفاعت عطا کی گئی۔ اور تمام انبیاء اپنی اپنی قوم کے لیے مبعوث ہوتے تھے لیکن میں تمام انسانوں کے لیے عام طور پر نبی بنا کر بھیجا گیا ہوں۔' WHERE id = 332;
UPDATE hadiths SET urdu = 'ہم سے بشر بن خالد نے بیان کیا، کہا مجھ کو محمد نے خبر دی جو غندر کے نام سے مشہور ہیں، شعبہ کے واسطہ سے، وہ سلیمان سے نقل کرتے ہیں اور وہ ابووائل سے کہ ابوموسیٰ نے عبداللہ بن مسعود سے کہا کہ اگر ( غسل کی حاجت ہو اور ) پانی نہ ملے تو کیا نماز نہ پڑھی جائے۔ عبداللہ نے فرمایا، ہاں! اگر مجھے ایک مہینہ تک بھی پانی نہ ملے تو میں نماز نہ پڑھوں گا۔ اگر اس میں لوگوں کو اجازت دے دی جائے تو سردی معلوم کر کے بھی لوگ تیمم سے نماز پڑھ لیں گے۔ ابوموسیٰ کہتے ہیں کہ میں نے کہا کہ پھر عمر رضی اللہ عنہ کے سامنے عمار رضی اللہ عنہ کے قول کا کیا جواب ہو گا۔ بولے کہ مجھے تو نہیں معلوم ہے کہ عمر رضی اللہ عنہ عمار رضی اللہ عنہ کی بات سے مطمئن ہو گئے تھے۔' WHERE id = 342;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، انہوں نے کہا کہ ہم سے ہشام نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے والد نے عمر بن ابی سلمہ سے نقل کر کے بیان کیا کہ انھوں نے نبی کریم صلی اللہ علیہ وسلم کو ام سلمہ کے گھر میں ایک کپڑے میں نماز پڑھتے دیکھا، کپڑے کے دونوں کناروں کو آپ نے دونوں کاندھوں پر ڈال رکھا تھا۔' WHERE id = 352;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا کہ کہا ہم سے حماد بن زید نے ایوب کے واسطہ سے، انہوں نے محمد سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، آپ نے فرمایا کہ ایک شخص نبی کریم صلی اللہ علیہ وسلم کے سامنے کھڑا ہوا اور اس نے صرف ایک کپڑا پہن کر نماز پڑھنے کے بارے میں سوال کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم سب ہی لوگوں کے پاس دو کپڑے ہو سکتے ہیں؟ پھر ( یہی مسئلہ ) عمر رضی اللہ عنہ سے ایک شخص نے پوچھا تو انہوں نے کہا جب اللہ تعالیٰ نے تمہیں فراغت دی ہے تو تم بھی فراغت کے ساتھ رہو۔ آدمی کو چاہیے کہ نماز میں اپنے کپڑے اکٹھا کر لے، کوئی آدمی تہبند اور چادر میں نماز پڑھے، کوئی تہبند اور قمیص، کوئی تہبند اور قباء میں، کوئی پاجامہ اور چادر میں، کوئی پاجامہ اور قمیص میں، کوئی پاجامہ اور قباء میں، کوئی جانگیا اور قباء میں، کوئی جانگیا اور قمیص میں نماز پڑھے۔ ابوہریرہ رضی اللہ عنہ نے کہا کہ مجھے یاد آتا ہے کہ آپ نے یہ بھی کہا کہ کوئی جانگیا اور چادر میں نماز پڑھے۔' WHERE id = 362;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے یزید بن حبیب سے بیان کیا، انہوں نے ابوالخیر مرثد سے، انہوں نے عقبہ بن عامر سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کو ایک ریشم کی قباء تحفہ میں دی گئی۔ اسے آپ صلی اللہ علیہ وسلم نے پہنا اور نماز پڑھی لیکن آپ صلی اللہ علیہ وسلم جب نماز سے فارغ ہوئے تو بڑی تیزی کے ساتھ اسے اتار دیا۔ گویا آپ صلی اللہ علیہ وسلم اسے پہن کر ناگواری محسوس کر رہے تھے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا یہ پرہیزگاروں کے لائق نہیں ہے۔' WHERE id = 372;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید ہشام بن عبدالملک نے بیان کیا، انہوں نے کہا ہم سے بشر بن مفضل نے بیان کیا، انہوں نے کہا مجھے غالب قطان نے بکر بن عبداللہ کے واسطے سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز پڑھتے تھے۔ پھر سخت گرمی کی وجہ سے کوئی کوئی ہم میں سے اپنے کپڑے کا کنارہ سجدے کی جگہ رکھ لیتا۔' WHERE id = 382;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا سیف ابن ابی سلیمان سے، انہوں نے کہا میں نے مجاہد سے سنا، انہوں نے کہا کہ ابن عمر رضی اللہ عنہما کی خدمت میں ایک آدمی آیا اور کہنے لگا، اے لو یہ رسول اللہ صلی اللہ علیہ وسلم آن پہنچے اور آپ کعبہ کے اندر داخل ہو گئے۔ ابن عمر رضی اللہ عنہما نے کہا کہ میں جب آیا تو نبی کریم صلی اللہ علیہ وسلم کعبہ سے نکل چکے تھے، میں نے دیکھا کہ بلال دونوں دروازوں کے سامنے کھڑے ہیں۔ میں نے بلال سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم نے کعبہ کے اندر نماز پڑھی ہے؟ انہوں نے کہا کہ ہاں! دو رکعت ان دو ستونوں کے درمیان پڑھی تھیں، جو کعبہ میں داخل ہوتے وقت بائیں طرف واقع ہیں۔ پھر جب باہر تشریف لائے تو کعبہ کے سامنے دو رکعت نماز ادا فرمائی۔' WHERE id = 393;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہمیں امام مالک نے ہشام بن عروہ کے واسطہ سے، انہوں نے اپنے والد سے، انہوں نے عائشہ ام المؤمنین رضی اللہ عنہا سے کہ رسول اللہ صلی اللہ علیہ وسلم نے قبلہ کی دیوار پر رینٹ یا تھوک یا بلغم دیکھا تو اسے آپ صلی اللہ علیہ وسلم نے کھرچ ڈالا۔' WHERE id = 404;
UPDATE hadiths SET urdu = 'ابراہیم بن طہمان نے کہا، عبدالعزیز بن صہیب سے، انہوں نے انس رضی اللہ عنہ سے روایت کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس بحرین سے رقم آئی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے مسجد میں ڈال دو اور یہ رقم اس تمام رقم سے زیادہ تھی جو اب تک آپ صلی اللہ علیہ وسلم کی خدمت میں آ چکی تھی۔ پھر آپ صلی اللہ علیہ وسلم نماز کے لیے تشریف لائے اور اس کی طرف کوئی توجہ نہیں فرمائی، جب آپ صلی اللہ علیہ وسلم نماز پوری کر چکے تو آ کر مال ( رقم ) کے پاس بیٹھ گئے اور اسے تقسیم کرنا شروع فرما دیا۔ اس وقت جسے بھی آپ صلی اللہ علیہ وسلم دیکھتے اسے عطا فرما دیتے۔ اتنے میں عباس رضی اللہ عنہ حاضر ہوئے اور بولے کہ یا رسول اللہ! مجھے بھی عطا کیجیئے کیونکہ میں نے ( غزوہ بدر میں ) اپنا بھی فدیہ دیا تھا اور عقیل کا بھی ( اس لیے میں زیر بار ہوں ) رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ لے لیجیئے۔ انہوں نے اپنے کپڑے میں روپیہ بھر لیا اور اسے اٹھانے کی کوشش کی لیکن ( وزن کی زیادتی کی وجہ سے ) وہ نہ اٹھا سکے اور کہنے لگے یا رسول اللہ! کسی کو فرمائیے کہ وہ اٹھانے میں میری مدد کرے۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں ( یہ نہیں ہو سکتا ) انہوں نے کہا کہ پھر آپ ہی اٹھوا دیجیئے۔ آپ صلی اللہ علیہ وسلم نے اس پر بھی انکار کیا، تب عباس رضی اللہ عنہ نے اس میں سے تھوڑا سا گرا دیا اور باقی کو اٹھانے کی کوشش کی، ( لیکن اب بھی نہ اٹھا سکے ) پھر فرمایا کہ یا رسول اللہ! کسی کو میری مدد کرنے کا حکم دیجیئے۔ آپ صلی اللہ علیہ وسلم نے انکار فرمایا تو انہوں نے کہا کہ پھر آپ ہی اٹھوا دیجیئے۔ لیکن آپ صلی اللہ علیہ وسلم نے اس سے بھی انکار کیا، تب انہوں نے اس میں سے تھوڑا سا روپیہ گرا دیا اور اسے اٹھا کر اپنے کاندھے پر رکھ لیا اور چلنے لگے، رسول اللہ صلی اللہ علیہ وسلم کو ان کی اس حرص پر اتنا تعجب ہوا کہ آپ صلی اللہ علیہ وسلم اس وقت تک ان کی طرف دیکھتے رہے جب تک وہ ہماری نظروں سے غائب نہیں ہو گئے اور آپ صلی اللہ علیہ وسلم بھی وہاں سے اس وقت تک نہ اٹھے جب تک کہ ایک چونی بھی باقی رہی۔' WHERE id = 416;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، انہوں نے امام مالک کے واسطہ سے بیان کیا، انہوں نے زید بن اسلم سے، انہوں نے عطاء بن یسار سے، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے، انہوں نے فرمایا کہ سورج گہن ہوا تو نبی کریم صلی اللہ علیہ وسلم نے نماز پڑھی اور فرمایا کہ مجھے ( آج ) دوزخ دکھائی گئی، اس سے زیادہ بھیانک منظر میں نے کبھی نہیں دیکھا۔' WHERE id = 426;
UPDATE hadiths SET urdu = 'ہم سے خلاد بن یحییٰ نے بیان کیا، کہا ہم سے مسعر نے، کہا ہم سے محارب بن دثار نے جابر بن عبداللہ کے واسطہ سے، وہ کہتے ہیں کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ آپ صلی اللہ علیہ وسلم اس وقت مسجد میں تشریف فرما تھے۔ مسعر نے کہا میرا خیال ہے کہ محارب نے چاشت کا وقت بتایا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ( پہلے ) دو رکعت نماز پڑھ اور میرا نبی کریم صلی اللہ علیہ وسلم پر کچھ قرض تھا۔ جسے آپ صلی اللہ علیہ وسلم نے ادا کیا اور زیادہ ہی دیا۔' WHERE id = 437;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکم بن نافع نے بیان کیا کہ ہمیں شعیب بن ابی حمزہ نے زہری کے واسطے سے کہا کہ مجھے ابوسلمہ (اسماعیل یا عبداللہ) ابن عبدالرحمٰن بن عوف نے، انہوں نے حسان بن ثابت انصاری رضی اللہ عنہ سے سنا، وہ ابوہریرہ رضی اللہ عنہ کو اس بات پر گواہ بنا رہے تھے کہ میں تمہیں اللہ کا واسطہ دیتا ہوں کہ کیا تم نے رسول اللہ صلی اللہ علیہ وسلم کو یہ کہتے ہوئے نہیں سنا تھا کہ اے حسان! اللہ کے رسول صلی اللہ علیہ وسلم کی طرف سے ( مشرکوں کو اشعار میں ) جواب دو اور اے اللہ! حسان کی روح القدس کے ذریعہ مدد کر۔ ابوہریرہ رضی اللہ عنہ نے فرمایا، ہاں ( میں گواہ ہوں۔ بیشک میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ سنا ہے ) ۔' WHERE id = 447;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنی نے بیان کیا انہوں نے کہا ہم سے معاذ بن ہشام نے بیان کیا، انہوں نے کہا مجھ سے میرے والد نے قتادہ کے واسطہ سے بیان کیا، کہا ہم سے انس رضی اللہ عنہ نے بیان کیا کہ دو شخص نبی کریم صلی اللہ علیہ وسلم کے پاس سے نکلے، ایک عباد بن بشر اور دوسرے صاحب میرے خیال کے مطابق اسید بن حضیر تھے۔ رات تاریک تھی اور دونوں اصحاب کے پاس روشن چراغ کی طرح کوئی چیز تھی جس سے ان کے آگے آگے روشنی پھیل رہی تھی پس جب وہ دونوں اصحاب ایک دوسرے سے جدا ہوئے تو ہر ایک کے ساتھ ایک ایک چراغ رہ گیا جو گھر تک ساتھ رہا۔' WHERE id = 458;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک کے واسطہ سے، انہوں نے ابن شہاب زہری سے، انہوں نے عباد بن تمیم سے، انہوں نے اپنے چچا (عبداللہ بن زید بن عاصم مازنی رضی اللہ عنہ) سے کہ انھوں نے رسول اللہ صلی اللہ علیہ وسلم کو چت لیٹے ہوئے دیکھا۔ آپ صلی اللہ علیہ وسلم اپنا ایک پاؤں دوسرے پر رکھے ہوئے تھے۔ ابن شہاب زہری سے مروی ہے، وہ سعید بن مسیب سے روایت کرتے ہیں کہ عمر اور عثمان رضی اللہ عنہما بھی اسی طرح لیٹتے تھے۔' WHERE id = 468;
UPDATE hadiths SET urdu = 'اور عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم راستے کے دائیں طرف مقابل میں ایک گھنے درخت کے نیچے وسیع اور نرم علاقہ میں قیام فرماتے جو قریہ رویثہ کے قریب ہے۔ پھر آپ اس ٹیلہ سے جو رویثہ کے راستے سے تقریباً دو میل کے فاصلے پر ہے چلتے تھے۔ اب اس درخت کا اوپر کا حصہ ٹوٹ گیا ہے۔ اور درمیان میں سے دوہرا ہو کر جڑ پر کھڑا ہے۔ اس کی جڑ میں ریت کے بہت سے ٹیلے ہیں۔' WHERE id = 479;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا کہ ہم سے یزید بن ابی عبید نے، انہوں نے سلمہ بن اکوع رضی اللہ عنہ سے بیان کیا، انہوں نے فرمایا کہ مسجد کی دیوار اور منبر کے درمیان بکری کے گزر سکنے کے فاصلے کے برابر جگہ تھی۔' WHERE id = 489;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی بصریٰ نے بیان کیا، کہا کہ ہم سے معتمر بن سلیمان نے بیان کیا عبیداللہ بن عمر سے، وہ نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم اپنی سواری کو سامنے عرض میں کر لیتے اور اس کی طرف منہ کر کے نماز پڑھتے تھے، عبیداللہ بن عمر نے نافع سے پوچھا کہ جب سواری اچھلنے کودنے لگتی تو اس وقت آپ کیا کیا کرتے تھے؟ نافع نے کہا کہ آپ اس وقت کجاوے کو اپنے سامنے کر لیتے اور اس کے آخری حصے کی ( جس پر سوار ٹیک لگاتا ہے ایک کھڑی سی لکڑی کی ) طرف منہ کر کے نماز پڑھتے اور عبداللہ بن عمر رضی اللہ عنہما بھی اسی طرح کیا کرتے تھے۔' WHERE id = 499;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن زرارہ نے بیان کیا، کہا کہ ہم سے ہشیم نے شیبانی کے واسطے سے بیان کیا، انہوں نے عبداللہ بن شداد بن ہاد سے، کہا مجھے میری خالہ میمونہ بنت الحارث رضی اللہ عنہا نے خبر دی کہ میرا بستر نبی کریم صلی اللہ علیہ وسلم کے مصلے کے برابر میں ہوتا تھا۔ اور بعض دفعہ آپ صلی اللہ علیہ وسلم کا کپڑا ( نماز پڑھتے میں ) میرے اوپر آ جاتا اور میں اپنے بستر پر ہی ہوتی تھی۔' WHERE id = 509;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے مہدی بن میمون نے غیلان بن جریر کے واسطہ سے، انہوں نے انس رضی اللہ عنہ سے، آپ نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے عہد کی کوئی بات اس زمانہ میں نہیں پاتا۔ لوگوں نے کہا، نماز تو ہے۔ فرمایا اس کے اندر بھی تم نے کر رکھا ہے جو کر رکھا ہے۔' WHERE id = 520;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا عمرو بن دینار سے۔ انہوں نے جابر بن زید سے، انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ میں رہ کر سات رکعات ( ایک ساتھ ) اور آٹھ رکعات ( ایک ساتھ ) پڑھیں۔ ظہر اور عصر ( کی آٹھ رکعات ) اور مغرب اور عشاء ( کی سات رکعات ) ایوب سختیانی نے جابر بن زید سے پوچھا شاید برسات کا موسم رہا ہو۔ جابر بن زید نے جواب دیا کہ غالباً ایسا ہی ہو گا۔' WHERE id = 532;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے ہشام بن عبداللہ دستوائی نے بیان کیا، کہا ہمیں یحییٰ بن ابی کثیر نے ابوقلابہ عبداللہ بن زید سے خبر دی۔ انہوں نے ابوالملیح سے، کہا ہم بریدہ رضی اللہ عنہ کے ساتھ ایک سفر جنگ میں تھے۔ ابر و بارش کا دن تھا۔ آپ نے فرمایا کہ عصر کی نماز جلدی پڑھ لو۔ کیونکہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے عصر کی نماز چھوڑ دی، اس کا نیک عمل ضائع ہو گیا۔' WHERE id = 542;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، جو عبداللہ بن عمرو ہیں، کہا ہم سے عبدالوارث بن سعید نے حسین بن ذکوان سے بیان کیا، کہا ہم سے عبداللہ بن بریدہ نے، کہا مجھ سے عبداللہ مزنی رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ایسا نہ ہو کہ ”مغرب“ کی نماز کے نام کے لیے اعراب ( یعنی دیہاتی لوگوں ) کا محاورہ تمہاری زبانوں پر چڑھ جائے۔ عبداللہ بن مغفل رضی اللہ عنہ نے کہا یا خود نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بدوی مغرب کو عشاء کہتے تھے۔' WHERE id = 552;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عاصم نے یہ حدیث بیان کی، کہا ہم سے ہمام نے یہ حدیث بیان کی قتادہ سے، انہوں نے انس رضی اللہ عنہ سے کہ یزید بن ثابت رضی اللہ عنہ نے ان سے بیان کیا کہ ان لوگوں نے ( ایک مرتبہ ) نبی کریم صلی اللہ علیہ وسلم کے ساتھ سحری کھائی، پھر نماز کے لیے کھڑے ہو گئے۔ میں نے دریافت کیا کہ ان دونوں کے درمیان کس قدر فاصلہ رہا ہو گا۔ فرمایا کہ جتنا پچاس یا ساٹھ آیت پڑھنے میں صرف ہوتا ہے اتنا فاصلہ تھا۔' WHERE id = 563;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابان نے بیان کیا، کہا کہ ہم سے غندر محمد بن جعفر نے بیان کیا، کہا کہ ہم سے شعبہ نے حدیث بیان کی ابوالتیاح یزید بن حمید سے، کہا کہ میں نے حمران بن ابان سے سنا، وہ معاویہ بن ابی سفیان رضی اللہ عنہما سے یہ حدیث بیان کرتے تھے کہ انھوں نے فرمایا کہ تم لوگ تو ایک ایسی نماز پڑھتے ہو کہ ہم رسول اللہ صلی اللہ علیہ وسلم کی صحبت میں رہے لیکن ہم نے کبھی آپ صلی اللہ علیہ وسلم کو وہ نماز پڑھتے نہیں دیکھا۔ بلکہ آپ صلی اللہ علیہ وسلم نے تو اس سے منع فرمایا تھا۔ معاویہ رضی اللہ عنہ کی مراد عصر کے بعد دو رکعتوں سے تھی ( جسے آپ کے زمانہ میں بعض لوگ پڑھتے تھے ) ۔' WHERE id = 574;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین اور موسیٰ بن اسماعیل نے بیان کیا، ان دونوں نے کہا کہ ہم سے ہمام بن یحییٰ نے قتادہ سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ آپ صلی اللہ علیہ وسلم نے فرمایا اگر کوئی نماز پڑھنا بھول جائے تو جب بھی یاد آ جائے اس کو پڑھ لے۔ اس قضاء کے سوا اور کوئی کفارہ اس کی وجہ سے نہیں ہوتا۔ اور ( اللہ تعالیٰ نے فرمایا کہ ) نماز میرے یاد آنے پر قائم کر۔ موسیٰ نے کہا کہ ہم سے ہمام نے حدیث بیان کی کہ میں نے قتادہ رضی اللہ عنہ سے سنا وہ یوں پڑھتے تھے نماز پڑھ میری یاد کے لیے۔ حبان بن ہلال نے کہا، ہم سے ہمام نے بیان کیا، کہا ہم سے قتادہ نے، کہا ہم سے انس رضی اللہ عنہ نے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے، پھر ایسی ہی حدیث بیان کی۔' WHERE id = 584;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ بن مدینی نے بیان کیا، کہا کہ ہم سے اسماعیل بن ابراہیم بن علیہ نے بیان کیا، کہا ہم سے خالد حذاء نے ابوقلابہ سے بیان کیا، انہوں نے انس رضی اللہ عنہ سے کہ بلال رضی اللہ عنہ کو حکم دیا گیا کہ اذان کے کلمات دو دو دفعہ کہیں اور تکبیر میں یہی کلمات ایک ایک دفعہ۔ اسماعیل نے بتایا کہ میں نے ایوب سختیانی سے اس حدیث کا ذکر کیا تو انہوں نے کہا مگر لفظ «قد قامت الصلوة» دو ہی دفعہ کہا جائے گا۔' WHERE id = 594;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا امام مالک سے، انہوں نے ابن شہاب سے، انہوں نے سالم بن عبداللہ بن عمر رضی اللہ عنہما سے، انہوں نے اپنے والد عبداللہ بن عمر سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ بلال تو رات رہے اذان دیتے ہیں۔ اس لیے تم لوگ کھاتے پیتے رہو۔ یہاں تک کہ ابن ام مکتوم اذان دیں۔ راوی نے کہا کہ وہ نابینا تھے اور اس وقت تک اذان نہیں دیتے تھے جب تک ان سے کہا نہ جاتا کہ صبح ہو گئی۔ صبح ہو گئی۔' WHERE id = 604;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا کہ ہم سے شعبہ نے مہاجر ابوالحسن سے بیان کیا، انہوں نے زید بن وہب سے، انہوں نے ابوذرغفاری رضی اللہ عنہ سے، انہوں نے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے۔ مؤذن نے اذان دینی چاہی تو آپ صلی اللہ علیہ وسلم نے فرمایا ٹھنڈا ہونے دے۔ پھر مؤذن نے اذان دینی چاہی تو آپ صلی اللہ علیہ وسلم نے پھر یہی فرمایا کہ ٹھنڈا ہونے دے۔ یہاں تک کہ سایہ ٹیلوں کے برابر ہو گیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ گرمی کی شدت دوزخ کی بھاپ سے پیدا ہوتی ہے۔' WHERE id = 615;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا کہ ہم سے ابراہیم بن سعد نے بیان کیا، وہ صالح بن کیسان سے، وہ ابن شہاب سے، وہ ابوسلمہ بن عبدالرحمٰن سے، وہ ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم ( ایک دن حجرے سے ) باہر تشریف لائے، اقامت کہی جا چکی تھی اور صفیں برابر کی جا چکی تھیں۔ آپ صلی اللہ علیہ وسلم جب مصلے پر کھڑے ہوئے تو ہم انتظار کر رہے تھے کہ اب آپ صلی اللہ علیہ وسلم تکبیر کہتے ہیں۔ لیکن آپ صلی اللہ علیہ وسلم واپس تشریف لے گئے اور فرمایا کہ اپنی اپنی جگہ پر ٹھہرے رہو۔ ہم اسی حالت میں ٹھہرے رہے یہاں تک کہ آپ صلی اللہ علیہ وسلم دوبارہ تشریف لائے، تو سر مبارک سے پانی ٹپک رہا تھا۔ آپ صلی اللہ علیہ وسلم نے غسل کیا تھا۔' WHERE id = 625;
UPDATE hadiths SET urdu = 'شعیب نے فرمایا کہ مجھ سے نافع نے ابن عمر رضی اللہ عنہما کے واسطہ سے اس طرح حدیث بیان کی کہ جماعت کی نماز اکیلے کی نماز سے ستائیس درجہ زیادہ فضیلت رکھتی ہے۔' WHERE id = 635;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے یزید بن ہارون واسطی نے بیان کیا، کہا کہ ہمیں محمد بن مطرف نے زید بن اسلم سے خبر دی، انہوں نے عطاء بن یسار سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص مسجد میں صبح شام بار بار حاضری دیتا ہے۔ اللہ تعالیٰ جنت میں اس کی مہمانی کا سامان کرے گا۔ وہ صبح شام جب بھی مسجد میں جائے۔' WHERE id = 645;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا، انہوں نے عقیل سے، انہوں نے ابن شہاب سے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جب شام کا کھانا حاضر کیا جائے تو مغرب کی نماز سے پہلے کھانا کھا لو اور کھانے میں بے مزہ بھی نہ ہونا چاہئے اور اپنا کھانا چھوڑ کر نماز میں جلدی مت کرو۔' WHERE id = 655;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے عبداللہ بن وہب نے بیان کیا، کہا کہ مجھ سے یونس بن یزید ایلی نے ابن شہاب سے بیان کیا، انہوں نے حمزہ بن عبداللہ سے، انہوں نے اپنے باپ عبداللہ بن عمر رضی اللہ عنہما سے خبر دی کہ جب رسول اللہ صلی اللہ علیہ وسلم کی بیماری شدت اختیار کر گئی اور آپ صلی اللہ علیہ وسلم سے نماز کے لیے کہا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابوبکر سے کہو کہ وہ نماز پڑھائیں۔ عائشہ رضی اللہ عنہا نے عرض کیا کہ ابوبکر کچے دل کے آدمی ہیں۔ جب وہ قرآن مجید پڑھتے ہیں تو بہت رونے لگتے ہیں۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان ہی سے کہو کہ نماز پڑھائیں۔ دوبارہ انہوں نے پھر وہی عذر دہرایا۔ آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ ان سے نماز پڑھانے کے لیے کہو۔ تم تو بالکل صواحب یوسف کی طرح ہو۔ اس حدیث کی متابعت محمد بن ولید زبیدی اور زہری کے بھتیجے اور اسحاق بن یحییٰ کلبی نے زہری سے کی ہے اور عقیل اور معمر نے زہری سے، انہوں نے حمزہ بن عبداللہ بن عمر سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 665;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر حزامی نے بیان کیا، انہوں نے کہا کہ ہم سے انس بن عیاض نے بیان کیا انہوں نے عبیداللہ عمری سے، انہوں نے نافع سے انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ جب پہلے مہاجرین رسول اللہ صلی اللہ علیہ وسلم کی ہجرت سے بھی پہلے قباء کے مقام عصبہ میں پہنچے تو ان کی امامت ابوحذیفہ کے غلام سالم رضی اللہ عنہ کیا کرتے تھے۔ آپ کو قرآن مجید سب سے زیادہ یاد تھا۔' WHERE id = 676;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا کہ ہم سے زہیر بن معاویہ نے بیان کیا، کہا کہ ہم سے اسماعیل بن ابی خالد نے بیان کیا، کہا کہ میں نے قیس بن ابی حازم سے سنا، کہا کہ مجھے ابومسعود انصاری نے خبر دی کہ ایک شخص نے کہا کہ یا رسول اللہ! قسم اللہ کی میں صبح کی نماز میں فلاں کی وجہ سے دیر میں جاتا ہوں، کیونکہ وہ نماز کو بہت لمبا کر دیتے ہیں، میں نے رسول اللہ صلی اللہ علیہ وسلم کو نصیحت کے وقت اس دن سے زیادہ ( کبھی بھی ) غضب ناک نہیں دیکھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سے کچھ لوگ یہ چاہتے ہیں کہ ( عوام کو عبادت سے یا دین سے ) نفرت دلا دیں، خبردار تم میں لوگوں کو جو شخص بھی نماز پڑھائے تو ہلکی پڑھائے۔ کیونکہ نمازیوں میں کمزور، بوڑھے اور ضرورت والے سب ہی قسم کے لوگ ہوتے ہیں۔' WHERE id = 686;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے عبداللہ بن داؤد نے بیان کیا، کہا کہ ہم سے اعمش نے ابراہیم نخعی سے بیان کیا، انہوں نے اسود سے، انہوں نے عائشہ رضی اللہ عنہا سے کہ آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم کے مرض الوفات میں بلال رضی اللہ عنہ نماز کی اطلاع دینے کے لیے حاضر خدمت ہوئے۔ آپ نے فرمایا کہ ابوبکر سے نماز پڑھانے کے لیے کہو۔ میں نے عرض کیا کہ ابوبکر کچے دل کے آدمی ہیں اگر آپ کی جگہ کھڑے ہوں گے تو رو دیں گے اور قرآت نہ کر سکیں گے۔ آپ نے فرمایا کہ ابوبکر سے کہو وہ نماز پڑھائیں۔ میں نے وہی عذر پھر دہرایا۔ پھر آپ نے تیسری یا چوتھی مرتبہ فرمایا کہ تم لوگ تو بالکل صواحب یوسف کی طرح ہو۔ ابوبکر سے کہو کہ وہ نماز پڑھائیں۔ خیر ابوبکر رضی اللہ عنہ نے نماز شروع کرا دی۔ پھر نبی کریم صلی اللہ علیہ وسلم ( اپنا مزاج ذرا ہلکا پا کر ) دو آدمیوں کا سہارا لیے ہوئے باہر تشریف لائے۔ گویا میری نظروں کے سامنے وہ منظر ہے کہ آپ کے قدم زمین پر نشان کر رہے تھے۔ ابوبکر آپ کو دیکھ کر پیچھے ہٹنے لگے۔ لیکن آپ نے اشارہ سے انہیں نماز پڑھانے کے لیے کہا۔ ابوبکر پیچھے ہٹ گئے اور نبی کریم صلی اللہ علیہ وسلم ان کے بازو میں بیٹھے۔ ابوبکر رضی اللہ عنہ لوگوں کو نبی کریم صلی اللہ علیہ وسلم کی تکبیر سنا رہے تھے۔ عبداللہ بن داؤد کے ساتھ اس حدیث کو محاضر نے بھی اعمش سے روایت کیا ہے۔' WHERE id = 696;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد نے بیان کیا، انہوں نے کہا کہ ہم سے فضل بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے سعید بن عبید طائی نے بیان کیا بشیر بن یسار انصاری سے، انہوں نے انس بن مالک رضی اللہ عنہ سے کہ جب وہ ( بصرہ سے ) مدینہ آئے، تو آپ سے پوچھا گیا کہ نبی کریم صلی اللہ علیہ وسلم کے عہد مبارک اور ہمارے اس دور میں آپ نے کیا فرق پایا۔ فرمایا کہ اور تو کوئی بات نہیں صرف لوگ صفیں برابر نہیں کرتے۔ اور عقبہ بن عبید نے بشیر بن یسار سے یوں روایت کیا کہ انس رضی اللہ عنہ ہمارے پاس مدینہ تشریف لائے۔ پھر یہی حدیث بیان کی۔' WHERE id = 707;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے خبر دی، انہوں نے کہا کہ ابوالزناد نے مجھ سے بیان کیا اعرج کے واسطہ سے، انہوں نے ابوہریرہ رضی اللہ عنہ سے انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، امام اس لیے ہے کہ اس کی پیروی کی جائے، اس لیے جب وہ تکبیر کہے تو تم بھی تکبیر کہو۔ جب وہ رکوع کرے تو تم بھی رکوع کرو اور جب وہ «سمع الله لمن حمده‏» کہے تو تم «ربنا ولك الحمد» اور جب وہ سجدہ کرے تو تم بھی سجدہ کرو اور جب وہ بیٹھ کر نماز پڑھے تو تم سب بھی بیٹھ کر نماز پڑھو۔' WHERE id = 717;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد بن زیاد نے بیان کیا، انہوں نے کہا کہ ہم سے عمارہ بن قعقاع نے بیان کیا، انہوں نے کہا کہ ہم سے ابوزرعہ نے بیان کیا، انہوں نے کہا کہ ہم سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، انہوں نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم تکبیر تحریمہ اور قرآت کے درمیان تھوڑی دیر چپ رہتے تھے۔ ابوزرعہ نے کہا میں سمجھتا ہوں ابوہریرہ رضی اللہ عنہ نے یوں کہا یا رسول اللہ! آپ پر میرے ماں باپ فدا ہوں۔ آپ اس تکبیر اور قرآت کے درمیان کی خاموشی کے بیچ میں کیا پڑھتے ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں پڑھتا ہوں «اللهم باعد بيني وبين خطاياى كما باعدت بين المشرق والمغرب،‏‏‏‏ ‏‏‏‏ اللهم نقني من الخطايا كما ينقى الثوب الأبيض من الدنس،‏‏‏‏ ‏‏‏‏ اللهم اغسل خطاياى بالماء والثلج والبرد» اے اللہ! میرے اور میرے گناہوں کے درمیان اتنی دوری کر جتنی مشرق اور مغرب میں ہے۔ اے اللہ! مجھے گناہوں سے اس طرح پاک کر جیسے سفید کپڑا میل سے پاک ہوتا ہے۔ اے اللہ! میرے گناہوں کو پانی، برف اور اولے سے دھو ڈال۔' WHERE id = 727;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث بن سعد نے بیان کیا، انہوں نے عقیل بن خالد سے بیان کیا، انہوں نے ابن شہاب سے، انہوں نے کہا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ ( نبی کریم صلی اللہ علیہ وسلم کے مرض وفات میں ) مسلمان فجر کی نماز پڑھ رہے تھے، اچانک رسول اللہ صلی اللہ علیہ وسلم نے عائشہ رضی اللہ عنہا کے حجرہ سے پردہ ہٹایا۔ آپ صلی اللہ علیہ وسلم نے صحابہ کو دیکھا۔ سب لوگ صفیں باندھے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم ( خوشی سے ) خوب کھل کر مسکرائے اور ابوبکر رضی اللہ عنہ نے ( آپ صلی اللہ علیہ وسلم کو دیکھ کر ) پیچھے ہٹنا چاہا تاکہ صف میں مل جائیں۔ آپ نے سمجھا کہ نبی کریم صلی اللہ علیہ وسلم تشریف لا رہے ہیں۔ صحابہ ( آپ صلی اللہ علیہ وسلم کو دیکھ کر خوشی سے اس قدر بےقرار ہوئے کہ گویا ) نماز ہی چھوڑ دیں گے۔ لیکن نبی کریم صلی اللہ علیہ وسلم نے اشارہ کیا کہ اپنی نماز پوری کر لو اور پردہ ڈال لیا۔ اسی دن چاشت کو آپ صلی اللہ علیہ وسلم نے وفات پائی۔' WHERE id = 737;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے بیان کیا، انہوں نے عبدالملک ابن جریج سے، انہوں نے ابن ابی ملیکہ (زہیر بن عبداللہ) سے، انہوں نے عروہ بن زبیر سے، انہوں نے مروان بن حکم سے، اس نے کہا زید بن ثابت نے مجھے ٹوکا کہ تمہیں کیا ہو گیا ہے کہ تم مغرب میں چھوٹی چھوٹی سورتیں پڑھتے ہو۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو دو لمبی سورتوں میں سے ایک سورت پڑھتے ہوئے سنا۔' WHERE id = 747;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے اسماعیل بن علیہ نے بیان کیا، کہا کہ ہم سے ایوب سختیانی نے عکرمہ سے بیان کیا، انہوں نے ابن عباس رضی اللہ عنہما سے، آپ نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم کو جن نمازوں میں بلند آواز سے قرآن مجید پڑھنے کا حکم ہوا تھا۔ آپ صلی اللہ علیہ وسلم نے ان میں بلند آواز سے پڑھا اور جن میں آہستہ سے پڑھنے کا حکم ہوا تھا ان میں آپ صلی اللہ علیہ وسلم نے آہستہ سے پڑھا اور تیرا رب بھولنے والا نہیں اور رسول اللہ صلی اللہ علیہ وسلم کی زندگی تمہارے لیے بہترین نمونہ ہے۔' WHERE id = 757;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن شاہین واسطی نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن عبداللہ طحان نے سعید بن ایاس جریری سے بیان کیا، انہوں نے ابوالعلاء یزید بن عبداللہ سے، انہوں نے مطرف بن عبداللہ سے، انہوں نے عمران بن حصین سے کہ انہوں نے علی رضی اللہ عنہ کے ساتھ بصرہ میں ایک مرتبہ نماز پڑھی۔ پھر کہا کہ ہمیں انہوں نے وہ نماز یاد دلا دی جو کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ پڑھا کرتے تھے۔ پھر کہا کہ علی رضی اللہ عنہ جب سر اٹھاتے اور جب سر جھکاتے اس وقت تکبیر کہتے۔' WHERE id = 768;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، انہوں نے کہا کہ ہم سے شعبہ نے بیان کیا، انہوں نے کہا منصور بن معتمر نے بیان کیا، انہوں نے ابوالضحیٰ مسلم بن صبیح سے، انہوں نے مسروق سے، انہوں نے عائشہ رضی اللہ عنہا سے، انہوں نے فرمایا کہ نبی کریم صلی اللہ علیہ وسلم رکوع اور سجدہ میں «سبحانك اللهم ربنا وبحمدك،‏‏‏‏ اللهم اغفر لي» پڑھا کرتے تھے۔' WHERE id = 778;
UPDATE hadiths SET urdu = 'ابوبکر اور ابوسلمہ دونوں نے کہا کہ ابوہریرہ رضی اللہ عنہ نے بتلایا کہ رسول اللہ صلی اللہ علیہ وسلم جب سر مبارک ( رکوع سے ) اٹھاتے تو «سمع الله لمن حمده،‏‏‏‏ ربنا ولك الحمد‏» کہہ کر چند لوگوں کے لیے دعائیں کرتے اور نام لے لے کر فرماتے۔ یا اللہ! ولید بن ولید، سلمہ بن ہشام، عیاش بن ابی ربیعہ اور تمام کمزور مسلمانوں کو ( کفار سے ) نجات دے۔ اے اللہ! قبیلہ مضر کے لوگوں کو سختی کے ساتھ کچل دے اور ان پر قحط مسلط کر جیسا کہ یوسف علیہ السلام کے زمانہ میں آیا تھا۔ ان دنوں پورب والے قبیلہ مضر کے لوگ مخالفین میں تھے۔' WHERE id = 788;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا کہ ہمیں سفیان نے ابوحازم سلمہ بن دینار کے واسطے سے خبر دی، انہوں نے سہل بن سعد سے، انہوں نے کہا کہ کچھ لوگ نبی کریم صلی اللہ علیہ وسلم کے ساتھ تہبند چھوٹے ہونے کی وجہ سے انہیں گردنوں سے باندھ کر نماز پڑھتے تھے اور عورتوں سے کہہ دیا گیا تھا کہ جب تک مرد اچھی طرح بیٹھ نہ جائیں تم اپنے سروں کو ( سجدہ سے ) نہ اٹھاؤ۔' WHERE id = 798;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، انہوں نے کہا کہ ہم سے غیلان بن جریر نے بیان کیا، انہوں نے مطرف بن عبداللہ سے، انہوں نے کہا کہ میں نے اور عمران بن حصین رضی اللہ عنہما نے علی بن ابی طالب رضی اللہ عنہ کی اقتداء میں نماز پڑھی۔ آپ نے جب سجدہ کیا، سجدہ سے سر اٹھایا دو رکعتوں کے بعد کھڑے ہوئے تو ہر مرتبہ تکبیر کہی۔ جب آپ نے سلام پھیر دیا تو عمران بن حصین نے میرا ہاتھ پکڑ کر کہا کہ انہوں نے واقعی ہمیں محمد صلی اللہ علیہ وسلم کی طرح نماز پڑھائی ہے یا یہ کہا کہ مجھے انہوں نے محمد صلی اللہ علیہ وسلم کی نماز یاد دلا دی۔' WHERE id = 809;
UPDATE hadiths SET urdu = 'ہم سے حبان بن موسیٰ نے بیان کیا، کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، کہا کہ ہمیں معمر بن راشد نے زہری سے خبر دی، انہیں محمود بن ربیع انصاری نے انہیں عتبان بن مالک رضی اللہ عنہ نے آپ نے فرمایا کہ ہم نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نماز پڑھی۔ پھر جب آپ صلی اللہ علیہ وسلم نے سلام پھیرا تو ہم نے بھی سلام پھیرا۔' WHERE id = 820;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبید نے بیان کیا، کہا کہ ہم سے عیسیٰ بن یونس نے عمر بن سعید سے یہ حدیث بیان کی، انہوں نے کہا کہ مجھے ابن ابی ملیکہ نے خبر دی ان سے عقبہ بن حارث رضی اللہ عنہ نے فرمایا کہ میں نے مدینہ میں نبی کریم صلی اللہ علیہ وسلم کی اقتداء میں ایک مرتبہ عصر کی نماز پڑھی۔ سلام پھیرنے کے بعد آپ صلی اللہ علیہ وسلم جلدی سے اٹھ کھڑے ہوئے اور صفوں کو چیرتے ہوئے آپ صلی اللہ علیہ وسلم اپنی کسی بیوی کے حجرہ میں گئے۔ لوگ آپ صلی اللہ علیہ وسلم کی اس تیزی کی وجہ سے گھبرا گئے۔ پھر جب آپ صلی اللہ علیہ وسلم باہر تشریف لائے اور جلدی کی وجہ سے لوگوں کے تعجب کو محسوس فرمایا تو فرمایا کہ ہمارے پاس ایک سونے کا ڈلا ( تقسیم کرنے سے ) بچ گیا تھا مجھے اس میں دل لگا رہنا برا معلوم ہوا، میں نے اس کے بانٹ دینے کا حکم دے دیا۔' WHERE id = 831;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعنبی نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے ابن شہاب زہری نے بیان کیا، ان سے عبیداللہ بن عبداللہ بن عتبہ نے بیان کیا، ان سے عبداللہ بن عباس رضی اللہ عنہما نے، آپ نے فرمایا کہ میں ایک گدھی پر سوار ہو کر آیا۔ ابھی میں جوانی کے قریب تھا ( لیکن بالغ نہ تھا ) اور نبی کریم صلی اللہ علیہ وسلم منیٰ میں لوگوں کو نماز پڑھا رہے تھے۔ آپ صلی اللہ علیہ وسلم کے سامنے دیوار وغیرہ ( آڑ ) نہ تھی۔ میں صف کے ایک حصے کے آگے سے گزر کر اترا۔ گدھی چرنے کے لیے چھوڑ دی اور خود صف میں شامل ہو گیا۔ کسی نے مجھ پر اعتراض نہیں کیا ( حالانکہ میں نابالغ تھا ) ۔' WHERE id = 841;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا کہ ہم سے سعید بن منصور نے بیان کیا، کہا کہ ہم سے فلیح بن سلیمان نے عبدالرحمٰن بن قاسم سے بیان کیا، ان سے اس کے باپ (قاسم بن محمد بن ابی بکر) نے ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم صبح کی نماز منہ اندھیرے پڑھتے تھے۔ مسلمانوں کی عورتیں جب ( نماز پڑھ کر ) واپس ہوتیں تو اندھیرے کی وجہ سے ان کی پہچان نہ ہوتی یا وہ ایک دوسری کو نہ پہچان سکتیں۔' WHERE id = 852;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے ابن ابی ذئب نے سعید مقبری سے بیان کیا، کہا کہ مجھے میرے باپ ابوسعید مقبری نے عبداللہ بن ودیعہ سے خبر دی، ان سے سلمان فارسی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جو شخص جمعہ کے دن غسل کرے اور خوب اچھی طرح سے پاکی حاصل کرے اور تیل استعمال کرے یا گھر میں جو خوشبو میسر ہو استعمال کرے پھر نماز جمعہ کے لیے نکلے اور مسجد میں پہنچ کر دو آدمیوں کے درمیان نہ گھسے، پھر جتنی ہو سکے نفل نماز پڑھے اور جب امام خطبہ شروع کرے تو خاموش سنتا رہے تو اس کے اس جمعہ سے لے کر دوسرے جمعہ تک سارے گناہ معاف کر دیئے جاتے ہیں۔' WHERE id = 863;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد مروزی نے بیان کیا، کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، کہا کہ ہمیں یونس بن یزید نے زہری سے خبر دی، انہیں سالم بن عبداللہ نے ابن عمر سے خبر دی، انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو یہ کہتے ہوئے سنا کہ تم میں سے ہر شخص نگہبان ہے اور لیث نے اس میں یہ زیادتی کی کہ یونس نے بیان کیا کہ رزیق بن حکیم نے ابن شہاب کو لکھا، ان دنوں میں بھی وادی القریٰ میں ابن شہاب کے پاس ہی تھا کہ کیا میں جمعہ پڑھا سکتا ہوں۔ رزیق ( ایلہ کے اطراف میں ) ایک زمین کاشت کروا رہے تھے۔ وہاں حبشہ وغیرہ کے کچھ لوگ موجود تھے۔ اس زمانہ میں رزیق ایلہ میں ( عمر بن عبدالعزیز کی طرف سے ) حاکم تھے۔ ابن شہاب رحمہ اللہ نے انہیں لکھوایا، میں وہیں سن رہا تھا کہ رزیق جمعہ پڑھائیں۔ ابن شہاب رزیق کو یہ خبر دے رہے تھے کہ سالم نے ان سے حدیث بیان کی کہ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا۔ آپ نے فرمایا کہ تم میں سے ہر ایک نگراں ہے اور اس کے ماتحتوں کے متعلق اس سے سوال ہو گا۔ امام نگراں ہے اور اس سے سوال اس کی رعایا کے بارے میں ہو گا۔ انسان اپنے گھر کا نگراں ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ عورت اپنے شوہر کے گھر کی نگراں ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ خادم اپنے آقا کے مال کا نگراں ہے اور اس سے اس کی رعیت کے بارے میں سوال ہو گا۔ ابن عمر رضی اللہ عنہما نے فرمایا کہ میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے یہ بھی فرمایا کہ انسان اپنے باپ کے مال کا نگراں ہے اور اس کی رعیت کے بارے میں اس سے سوال ہو گا اور تم میں سے ہر شخص نگراں ہے اور سب سے اس کی رعیت کے بارے میں سوال ہو گا۔' WHERE id = 873;
UPDATE hadiths SET urdu = 'ہم سے سریج بن نعمان نے بیان کیا، انہوں نے کہا کہ ہم سے فلیح بن سلیمان نے بیان کیا، ان سے عثمان بن عبدالرحمٰن بن عثمان تیمی نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم جمعہ کی نماز اس وقت پڑھتے جب سورج ڈھل جاتا۔' WHERE id = 883;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں ابوبکر بن عثمان بن سہل بن حنیف نے خبر دی، انہیں ابوامامہ بن سہل بن حنیف نے، انہوں نے کہا میں نے معاویہ بن ابی سفیان رضی اللہ عنہما کو دیکھا آپ منبر پر بیٹھے، مؤذن نے اذان دی «الله أكبر الله أكبر‏» معاویہ رضی اللہ عنہ نے جواب دیا «الله أكبر الله أكبر‏» مؤذن نے کہا «أشهد أن لا إله إلا الله‏» معاویہ نے جواب دیا «وأنا‏» اور میں بھی توحید کی گواہی دیتا ہوں مؤذن نے کہا «أشهد أن محمدا رسول الله‏» معاویہ نے جواب دیا «وأنا‏» اور میں بھی محمد صلی اللہ علیہ وسلم کی رسالت کی گواہی دیتا ہوں جب مؤذن اذان کہہ چکا تو آپ نے کہا حاضرین! میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا اسی جگہ یعنی منبر پر آپ بیٹھے تھے مؤذن نے اذان دی تو آپ یہی فرما رہے تھے جو تم نے مجھ کو کہتے سنا۔' WHERE id = 893;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث نے عقیل سے بیان کیا، ان سے ابن شہاب نے، انہوں نے کہا کہ مجھے عروہ نے خبر دی کہ عائشہ رضی اللہ عنہا نے انہیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے رات کے وقت اٹھ کر مسجد میں نماز پڑھی اور چند صحابہ بھی آپ صلی اللہ علیہ وسلم کی اقتداء میں نماز پڑھنے کھڑے ہو گئے۔ صبح کو ان صحابہ ( رضوان اللہ علیہم اجمعین ) نے دوسرے لوگوں سے اس کا ذکر کیا چنانچہ ( دوسرے دن ) اس سے بھی زیادہ جمع ہو گئے اور آپ صلی اللہ علیہ وسلم کے پیچھے نماز پڑھی۔ دوسری صبح کو اس کا چرچا اور زیادہ ہوا پھر کیا تھا تیسری رات بڑی تعداد میں لوگ جمع ہو گئے اور جب رسول اللہ صلی اللہ علیہ وسلم اٹھے تو صحابہ رضی اللہ عنہم نے آپ صلی اللہ علیہ وسلم کے پیچھے نماز شروع کر دی۔ چوتھی رات جو آئی تو مسجد میں نمازیوں کی کثرت سے تل رکھنے کی بھی جگہ نہیں تھی۔ لیکن آج رات نبی کریم صلی اللہ علیہ وسلم نے یہ نماز نہ پڑھائی اور فجر کی نماز کے بعد لوگوں سے فرمایا، پہلے آپ نے کلمہ شہادت پڑھا پھر فرمایا۔ «امابعد» ! مجھے تمہاری اس حاضری سے کوئی ڈر نہیں لیکن میں اس بات سے ڈرا کہ کہیں یہ نماز تم پر فرض نہ کر دی جائے، پھر تم سے یہ ادا نہ ہو سکے۔ اس روایت کی متابعت یونس نے کی ہے۔' WHERE id = 903;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا کہ ہم سے لیث بن سعد نے عقیل سے بیان کیا، ان سے ابن شہاب نے، انہوں نے کہا کہ مجھے سعید بن مسیب نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جب امام جمعہ کا خطبہ دے رہا ہو اور تو اپنے پاس بیٹھے ہوئے آدمی سے کہے کہ ”چپ رہ“ تو تو نے خود ایک لغو حرکت کی۔' WHERE id = 913;
UPDATE hadiths SET urdu = 'ہم سے حیوہ بن شریح نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن حرب نے زبیدی سے بیان کیا، ان سے زہری نے، ان سے عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کھڑے ہوئے اور دوسرے لوگ بھی آپ صلی اللہ علیہ وسلم کی اقتداء میں کھڑے ہوئے۔ نبی کریم صلی اللہ علیہ وسلم نے تکبیر کہی تو لوگوں نے بھی تکبیر کہی۔ آپ صلی اللہ علیہ وسلم نے رکوع کیا تو لوگوں نے آپ صلی اللہ علیہ وسلم کے ساتھ رکوع اور سجدہ کر لیا تھا وہ کھڑے کھڑے اپنے بھائیوں کی نگرانی کرتے رہے۔ اور دوسرا گروہ آیا۔ ( جو اب تک حفاظت کے لیے دشمن کے مقابلہ میں کھڑا رہا بعد میں ) اس نے بھی رکوع اور سجدے کئے۔ سب لوگ نماز میں تھے لیکن لوگ ایک دوسرے کی حفاظت کر رہے تھے۔' WHERE id = 923;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا کہ ہم سے محمد بن جعفر نے بیان کیا، انہوں نے کہا کہ مجھے زید بن اسلم نے خبر دی، انہیں عیاض بن عبداللہ بن ابی سرح نے، انہیں ابو سعید خدری رضی اللہ عنہ نے، آپ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم عیدالفطر اور عید الاضحی کے دن ( مدینہ کے باہر ) عیدگاہ تشریف لے جاتے تو سب سے پہلے آپ صلی اللہ علیہ وسلم نماز پڑھاتے، نماز سے فارغ ہو کر آپ صلی اللہ علیہ وسلم لوگوں کے سامنے کھڑے ہوتے۔ تمام لوگ اپنی صفوں میں بیٹھے رہتے، آپ صلی اللہ علیہ وسلم انہیں وعظ و نصیحت فرماتے، اچھی باتوں کا حکم دیتے۔ اگر جہاد کے لیے کہیں لشکر بھیجنے کا ارادہ ہوتا تو اس کو الگ کرتے۔ کسی اور بات کا حکم دینا ہوتا تو وہ حکم دیتے۔ اس کے بعد شہر کو واپس تشریف لاتے۔ ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ لوگ برابر اسی سنت پر قائم رہے لیکن معاویہ کے زمانہ میں مروان جو مدینہ کا حاکم تھا پھر میں اس کے ساتھ عیدالفطر یا عید الاضحی کی نماز کے لیے نکلا ہم جب عیدگاہ پہنچے تو وہاں میں نے کثیر بن صلت کا بنا ہوا ایک منبر دیکھا۔ جاتے ہی مروان نے چاہا کہ اس پر نماز سے پہلے ( خطبہ دینے کے لیے ) چڑھے اس لیے میں نے ان کا دامن پکڑ کر کھینچا اور لیکن وہ جھٹک کر اوپر چڑھ گیا اور نماز سے پہلے خطبہ دیا۔ میں نے اس سے کہا کہ واللہ تم نے ( نبی کریم صلی اللہ علیہ وسلم کی سنت کو ) بدل دیا۔ مروان نے کہا کہ اے ابوسعید! اب وہ زمانہ گزر گیا جس کو تم جانتے ہو۔ ابوسعید نے کہا کہ بخدا میں جس زمانہ کو جانتا ہوں اس زمانہ سے بہتر ہے جو میں نہیں جانتا۔ مروان نے کہا کہ ہمارے دور میں لوگ نماز کے بعد نہیں بیٹھتے، اس لیے میں نے نماز سے پہلے خطبہ کو کر دیا۔' WHERE id = 934;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے امام مالک بن انس نے بیان کیا، کہا کہ مجھ سے محمد بن ابی بکر ثقفی نے بیان کیا، کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے تلبیہ کے متعلق دریافت کیا کہ آپ لوگ نبی کریم صلی اللہ علیہ وسلم کے عہد میں اسے کس طرح کہتے تھے۔ اس وقت ہم منیٰ سے عرفات کی طرف جا رہے تھے، انہوں نے فرمایا کہ تلبیہ کہنے والے تلبیہ کہتے اور تکبیر کہنے والے تکبیر۔ اس پر کوئی اعتراض نہ کرتا۔' WHERE id = 945;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالوارث نے بیان کیا، انہوں نے کہا کہ ہم سے ایوب سختیانی نے حفصہ بن سیرین کے واسطے سے بیان کیا، انہوں نے کہا کہ ہم اپنی لڑکیوں کو عیدگاہ جانے سے منع کرتے تھے۔ پھر ایک خاتون باہر سے آئی اور قصر بنو خلف میں انہوں نے قیام کیا میں ان سے ملنے کے لیے حاضر ہوئی تو انہوں نے بیان کیا کہ ان کی بہن کے شوہر نبی کریم صلی اللہ علیہ وسلم کے ساتھ بارہ لڑائیوں میں شریک رہے اور خود ان کی بہن اپنے شوہر کے ساتھ چھ لڑائیوں میں شریک ہوئی تھیں، ان کا بیان تھا کہ ہم مریضوں کی خدمت کیا کرتے تھے اور زخمیوں کی مرہم پٹی کرتے تھے۔ انہوں نے پوچھا کہ یا رسول اللہ! کیا ہم میں سے اگر کسی کے پاس چادر نہ ہو اور اس وجہ سے وہ عید کے دن ( عیدگاہ ) نہ جا سکے تو کوئی حرج ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی سہیلی اپنی چادر کا ایک حصہ اسے اڑھا دے اور پھر وہ خیر اور مسلمانوں کی دعا میں شریک ہوں۔ حفصہ رضی اللہ عنہا نے بیان کیا کہ پھر جب ام عطیہ رضی اللہ عنہا یہاں تشریف لائیں تو میں ان کی خدمت میں بھی حاضر ہوئی اور دریافت کیا کہ آپ نے فلاں فلاں بات سنی ہے۔ انہوں نے فرمایا کہ ہاں میرے باپ آپ پر فدا ہوں۔ ام عطیہ رضی اللہ عنہا جب بھی نبی کریم صلی اللہ علیہ وسلم کا ذکر کرتیں تو یہ ضرور کہتیں کہ میرے باپ آپ پر فدا ہوں، ہاں تو انہوں نے بتلایا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جوان پردہ والی یا جوان اور پردہ والی باہر نکلیں۔ شبہ ایوب کو تھا۔ البتہ حائضہ عورتیں عیدگاہ سے علیحدہ ہو کر بیٹھیں انہیں خیر اور مسلمانوں کی دعا میں ضرور شریک ہونا چاہیے۔ حفصہ نے کہا کہ میں نے ام عطیہ رضی اللہ عنہا سے دریافت کیا کہ حائضہ عورتیں بھی؟ انہوں نے فرمایا کیا حائضہ عورتیں عرفات نہیں جاتیں اور کیا وہ فلاں فلاں جگہوں میں شریک نہیں ہوتیں ( پھر اجتماع عید ہی کی شرکت میں کون سی قباحت ہے ) ۔' WHERE id = 955;
UPDATE hadiths SET urdu = 'اور اسی سند کے ساتھ نافع سے روایت ہے کہ عبداللہ بن عمر رضی اللہ عنہما وتر کی جب تین رکعتیں پڑھتے تو دو رکعت پڑھ کر سلام پھیرتے یہاں تک کہ ضرورت سے بات بھی کرتے۔' WHERE id = 965;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے ان سے محمد بن سیرین نے، انہوں نے کہا کہ انس بن مالک رضی اللہ عنہ سے پوچھا گیا کہ نبی کریم صلی اللہ علیہ وسلم نے صبح کی نماز میں قنوت پڑھا ہے؟ آپ نے فرمایا کہ ہاں پھر پوچھا گیا کہ کیا رکوع سے پہلے؟ تو آپ نے فرمایا کہ رکوع کے بعد تھوڑے دنوں تک۔' WHERE id = 975;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مرحوم بیکندی نے بیان کیا، انہوں نے کہا کہ ہم سے ابوضمرہ انس بن عیاض نے بیان کیا، انہوں نے کہا کہ ہم سے شریک بن عبداللہ بن ابی نمر نے بیان کیا کہ انہوں نے انس بن مالک رضی اللہ عنہ سے سنا آپ نے ایک شخص ( کعب بن مرہ یا ابوسفیان ) کا ذکر کیا جو منبر کے سامنے والے دروازے سے جمعہ کے دن مسجد نبوی میں آیا۔ رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے خطبہ دے رہے تھے، اس نے بھی کھڑے کھڑے رسول اللہ صلی اللہ علیہ وسلم سے کہا یا رسول اللہ! ( بارش نہ ہونے سے ) جانور مر گئے اور راستے بند ہو گئے آپ اللہ تعالیٰ سے بارش کی دعا فرمائیے انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے یہ کہتے ہی ہاتھ اٹھا دیئے آپ صلی اللہ علیہ وسلم نے دعا کی «اللهم اسقنا،‏‏‏‏ ‏‏‏‏اللهم اسقنا،‏‏‏‏ اللهم اسقنا» کہ اے اللہ! ہمیں سیراب کر۔ اے اللہ! ہمیں سیراب کر۔ اے اللہ! ہمیں سیراب کر۔ انس رضی اللہ عنہ نے کہا بخدا کہیں دور دور تک آسمان پر بادل کا کوئی ٹکڑا نظر نہیں آتا تھا اور نہ کوئی اور چیز ( ہوا وغیرہ جس سے معلوم ہو کہ بارش آئے گی ) اور ہمارے اور سلع پہاڑ کے درمیان کوئی مکان بھی نہ تھا ( کہ ہم بادل ہونے کے باوجود نہ دیکھ سکتے ہوں ) پہاڑ کے پیچھے سے ڈھال کے برابر بادل نمودار ہوا اور بیچ آسمان تک پہنچ کر چاروں طرف پھیل گیا اور بارش شروع ہو گئی، اللہ کی قسم! ہم نے سورج ایک ہفتہ تک نہیں دیکھا۔ پھر ایک شخص دوسرے جمعہ کو اسی دروازے سے آیا۔ رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے خطبہ دے رہے تھے، اس شخص نے پھر آپ صلی اللہ علیہ وسلم کو کھڑے کھڑے ہی مخاطب کیا کہ یا رسول اللہ! ( بارش کی کثرت سے ) مال و منال پر تباہی آ گئی اور راستے بند ہو گئے۔ اللہ تعالیٰ سے دعا کیجئے کہ بارش روک دے۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے ہاتھ اٹھائے اور دعا کی «اللهم حوالينا ولا علينا،‏‏‏‏ ‏‏‏‏ اللهم على الآكام والجبال والآجام والظراب والأودية ومنابت الشجر» کہ یا اللہ اب ہمارے اردگرد بارش برسا ہم سے اسے روک دے۔ ٹیلوں، پہاڑوں، پہاڑیوں، وادیوں اور باغوں کو سیراب کر۔ انہوں نے کہا کہ اس دعا سے بارش ختم ہو گئی اور ہم نکلے تو دھوپ نکل چکی تھی۔ شریک نے کہا کہ میں نے انس رضی اللہ عنہ سے پوچھا کہ یہ وہی پہلا شخص تھا تو انہوں نے فرمایا کہ مجھے معلوم نہیں۔' WHERE id = 986;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان حکیم بن نافع نے بیان کیا، انہوں نے کہا کہ ہمیں شعیب نے خبر دی، انہیں زہری نے، انہوں نے کہا کہ مجھ سے عباد بن تمیم نے بیان کیا کہ ان کے چچا عبداللہ بن زید نے جو صحابی تھے، انہیں خبر دی کہ نبی کریم صلی اللہ علیہ وسلم لوگوں کو ساتھ لے کر استسقاء کے لیے نکلے اور آپ کھڑے ہوئے اور کھڑے ہی کھڑے اللہ تعالیٰ سے دعا کی، پھر قبلہ کی طرف منہ کر کے اپنی چادر پلٹی چنانچہ بارش خوب ہوئی۔' WHERE id = 996;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں امام اوزاعی نے خبر دی، کہا کہ ہم سے اسحاق بن عبداللہ بن ابی طلحہ انصاری نے بیان کیا، انہوں نے کہا مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں لوگوں پر ایک دفعہ قحط پڑا۔ انہی دنوں آپ صلی اللہ علیہ وسلم جمعہ کے دن منبر پر خطبہ دے رہے تھے کہ ایک دیہاتی نے کھڑے ہو کر کہا یا رسول اللہ! جانور مر گئے اور بال بچے فاقے پر فاقے کرر ہے ہیں، اللہ تعالیٰ سے دعا کیجئے کہ پانی برسائے۔ انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے یہ سن کر دعا کے لیے دونوں ہاتھ اٹھا دیئے۔ آسمان پر دور دور تک ابر کا پتہ تک نہیں تھا۔ لیکن ( آپ صلی اللہ علیہ وسلم کی دعا سے ) پہاڑوں کے برابر بادل گرجتے ہوئے آ گئے ابھی نبی کریم صلی اللہ علیہ وسلم منبر سے اترے بھی نہیں تھے کہ میں نے دیکھا کہ بارش کا پانی آپ صلی اللہ علیہ وسلم کی داڑھی سے بہہ رہا ہے۔ انس نے کہا کہ اس روز بارش دن بھر ہوتی رہی۔ دوسرے دن تیسرے دن، بھی اور برابر اسی طرح ہوتی رہی۔ اس طرح دوسرا جمعہ آ گیا۔ پھر یہی بدوی یا کوئی دوسرا شخص کھڑا ہوا اور کہا کہ یا رسول اللہ صلی اللہ علیہ وسلم ! ( کثرت باراں سے ) عمارتیں گر گئیں اور جانور ڈوب گئے، ہمارے لیے اللہ تعالیٰ سے دعا کیجئے۔ چنانچہ رسول اللہ صلی اللہ علیہ وسلم نے پھر دونوں ہاتھ اٹھائے اور دعا کی «اللهم حوالينا ولا علينا» کہ اے اللہ! ہمارے اطراف میں برسا اور ہم پر نہ برسا۔ انس نے کہا کہ نبی کریم صلی اللہ علیہ وسلم اپنے ہاتھوں سے آسمان کی جس طرف بھی اشارہ کر دیتے ابر ادھر سے پھٹ جاتا، اب مدینہ حوض کی طرح بن چکا تھا اور اسی کے بعد وادی قناۃ کا نالہ ایک مہینہ تک بہتا رہا۔ انس نے بیان کیا کہ اس کے بعد مدینہ کے اردگرد سے جو بھی آیا اس نے خوب سیرابی کی خبر لائی۔' WHERE id = 1006;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا کہ ہم سے ہاشم بن قاسم نے بیان کیا، انہوں نے کہا کہ ہم سے شیبان ابومعاویہ نے بیان کیا، ان سے زیاد بن علاقہ نے بیان کیا، ان سے مغیرہ بن شعبہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں سورج گرہن اس دن لگا جس دن ( آپ صلی اللہ علیہ وسلم کے صاحبزادے ) ابراہیم رضی اللہ عنہ کا انتقال ہوا بعض لوگ کہنے لگے کہ گرہن ابراہیم رضی اللہ عنہ کی وفات کی وجہ سے لگا ہے۔ اس لیے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ گرہن کسی کی موت و حیات سے نہیں لگتا۔ البتہ تم جب اسے دیکھو تو نماز پڑھا کرو اور دعا کیا کرو۔' WHERE id = 1016;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ قطان نے اسماعیل بن ابی خالد سے بیان کیا، کہا کہ مجھ سے قیس نے بیان کیا، ان سے ابومسعود عقبہ بن عامر انصاری صحابی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا سورج اور چاند میں گرہن کسی کی موت کی وجہ سے نہیں لگتا البتہ یہ دونوں اللہ تعالیٰ کی نشانیاں ہیں، اس لیے جب تم گرہن دیکھو تو نماز پڑھو۔' WHERE id = 1028;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب اور ابوالنعمان بن فضل نے بیان کیا، ان دونوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے فرمایا کہ سورۃ ص کا سجدہ کچھ تاکیدی سجدوں میں سے نہیں ہے اور میں نے نبی کریم صلی اللہ علیہ وسلم کو سجدہ کرتے ہوئے دیکھا۔' WHERE id = 1039;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، ان سے یحییٰ بن سعیدقطان نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے، اور ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کسی ایسی سورۃ کی تلاوت کرتے جس میں سجدہ ہوتا پھر آپ صلی اللہ علیہ وسلم سجدہ کرتے اور ہم بھی آپ صلی اللہ علیہ وسلم کے ساتھ سجدہ کرتے یہاں تک کہ ہم میں کسی کو اپنی پیشانی رکھنے کی جگہ نہ ملتی۔ ( معلوم ہوا کہ ایسی حالت میں سجدہ نہ کیا جائے تو کوئی حرج نہیں ہے ) «والله أعلم» ۔' WHERE id = 1049;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ ہم سے سفیان نے، محمد بن منکدر اور ابراہیم بن میسرہ سے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ مدینہ منورہ میں ظہر کی چار رکعت پڑھی اور ذوالحلیفہ میں عصر کی دو رکعت پڑھی۔' WHERE id = 1059;
UPDATE hadiths SET urdu = 'ہم سے احمد بن سعید نے بیان کیا، کہا کہ ہم سے حبان بن ہلال نے بیان کیا، کہا کہ ہم سے ہمام بن یحییٰ نے بیان کیا، کہا کہ ہم سے انس بن سیرین نے بیان کیا، انہوں نے کہا کہ انس رضی اللہ عنہ شام سے جب ( حجاج کی خلیفہ سے شکایت کر کے ) واپس ہوئے تو ہم ان سے عین التمر میں ملے۔ میں نے دیکھا کہ آپ گدھے پر سوار ہو کر نماز پڑھ رہے تھے اور آپ کا منہ قبلہ سے بائیں طرف تھا۔ اس پر میں نے کہا کہ میں نے آپ کو قبلہ کے سوا دوسری طرف منہ کر کے نماز پڑھتے ہوئے دیکھا ہے۔ انہوں نے جواب دیا کہ اگر میں رسول اللہ صلی اللہ علیہ وسلم کو ایسا کرتے نہ دیکھتا تو میں بھی نہ کرتا۔ اس روایت کو ابراہیم ابن طہمان نے بھی حجاج سے، انہوں نے انس بن سیرین سے، انہوں نے انس بن مالک رضی اللہ عنہ سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے بیان کیا ہے۔' WHERE id = 1069;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالصمد بن عبدالوارث نے بیان کیا۔ انہوں نے کہا ہم سے حرب بن شداد نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ بن ابی کثیر نے بیان کیا، انہوں نے کہا کہ مجھ سے حفص بن عبیداللہ بن انس نے بیان کیا کہ انس رضی اللہ عنہ نے ان سے یہ بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ان دو نمازوں یعنی مغرب اور عشاء کو سفر میں ایک ساتھ ملا کر پڑھا کرتے تھے۔' WHERE id = 1079;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ ہم سے سلیمان بن ابی مسلم نے بیان کیا، ان سے طاؤس نے اور انہوں نے ابن عباس رضی اللہ عنہما سے سنا کہ رسول اللہ صلی اللہ علیہ وسلم جب رات میں تہجد کے لیے کھڑے ہوتے تو یہ دعا پڑھتے۔ «اللهم لك الحمد أنت قيم السموات والأرض ومن فيهن ولك الحمد،‏‏‏‏ ‏‏‏‏ لك ملك السموات والأرض ومن فيهن،‏‏‏‏ ‏‏‏‏ ولك الحمد أنت نور السموات والأرض،‏‏‏‏ ‏‏‏‏ ولك الحمد أنت الحق،‏‏‏‏ ‏‏‏‏ ووعدك الحق،‏‏‏‏ ‏‏‏‏ ولقاؤك حق،‏‏‏‏ ‏‏‏‏ وقولك حق،‏‏‏‏ ‏‏‏‏ والجنة حق،‏‏‏‏ ‏‏‏‏ والنار حق،‏‏‏‏ ‏‏‏‏ والنبيون حق،‏‏‏‏ ‏‏‏‏ ومحمد صلى الله عليه وسلم حق،‏‏‏‏ ‏‏‏‏ والساعة حق،‏‏‏‏ ‏‏‏‏ اللهم لك أسلمت،‏‏‏‏ ‏‏‏‏ وبك آمنت وعليك توكلت،‏‏‏‏ ‏‏‏‏ وإليك أنبت،‏‏‏‏ ‏‏‏‏ وبك خاصمت،‏‏‏‏ ‏‏‏‏ وإليك حاكمت،‏‏‏‏ ‏‏‏‏ فاغفر لي ما قدمت وما أخرت،‏‏‏‏ ‏‏‏‏ وما أسررت وما أعلنت،‏‏‏‏ ‏‏‏‏ أنت المقدم وأنت المؤخر،‏‏‏‏ ‏‏‏‏لا إله إلا أنت، لا إله غيرك» ( ترجمہ ) ”اے میرے اللہ! ہر طرح کی تعریف تیرے ہی لیے زیبا ہے، تو آسمان اور زمین اور ان میں رہنے والی تمام مخلوق کا سنبھالنے والا ہے اور حمد تمام کی تمام بس تیرے ہی لیے مناسب ہے آسمان اور زمین اور ان کی تمام مخلوقات پر حکومت صرف تیرے ہی لیے ہے اور تعریف تیرے ہی لیے ہے، تو آسمان اور زمین کا نور ہے اور تعریف تیرے ہی لیے زیبا ہے، تو سچا ہے، تیرا وعدہ سچا، تیری ملاقات سچی، تیرا فرمان سچا ہے، جنت سچ ہے، دوزخ سچ ہے، انبیاء سچے ہیں۔ محمد صلی اللہ علیہ وسلم سچے ہیں اور قیامت کا ہونا سچ ہے۔ اے میرے اللہ! میں تیرا ہی فرماں بردار ہوں اور تجھی پر ایمان رکھتا ہوں، تجھی پر بھروسہ ہے، تیری ہی طرف رجوع کرتا ہوں، تیرے ہی عطا کئے ہوئے دلائل کے ذریعہ بحث کرتا ہوں اور تجھی کو حکم بناتا ہوں۔ پس جو خطائیں مجھ سے پہلے ہوئیں اور جو بعد میں ہوں گی ان سب کی مغفرت فرما، خواہ وہ ظاہر ہوئی ہوں یا پوشیدہ۔ آگے کرنے والا اور پیچھے رکھنے والا تو ہی ہے۔ معبود صرف تو ہی ہے۔ یا ( یہ کہا کہ ) تیرے سوا کوئی معبود نہیں“۔ ابوسفیان نے بیان کیا کہ عبدالکریم ابوامیہ نے اس دعا میں یہ زیادتی کی ہے ( «لا حول ولا قوة إلا بالله» ) سفیان نے بیان کیا کہ سلیمان بن مسلم نے طاؤس سے یہ حدیث سنی تھی، انہوں نے عبداللہ بن عباس رضی اللہ عنہما سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 1089;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا کہ مجھے میرے باپ عثمان بن جبلہ نے شعبہ سے خبر دی، انہیں اشعث نے۔ اشعث نے کہا کہ میں نے اپنے باپ (سلیم بن اسود) سے سنا اور میرے باپ نے مسروق سے سنا، انہوں نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم کو کون سا عمل زیادہ پسند تھا؟ آپ نے جواب دیا کہ جس پر ہمیشگی کی جائے ( خواہ وہ کوئی بھی نیک کام ہو ) میں نے دریافت کیا کہ آپ ( رات میں نماز کے لیے ) کب کھڑے ہوتے تھے؟ آپ نے فرمایا کہ جب مرغ کی آواز سنتے۔ ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہمیں ابوالاحوص سلام بن سلیم نے خبر دی، ان سے اشعث نے بیان کیا کہ مرغ کی آواز سنتے ہی آپ کھڑے ہو جاتے اور نماز پڑھتے۔' WHERE id = 1100;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا کہ ہمیں امام مالک رحمہ اللہ نے خبر دی، انہیں ابوالزناد نے، انہیں اعرج نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اکرم صلی اللہ علیہ وسلم نے فرمایا کہ شیطان آدمی کے سر کے پیچھے رات میں سوتے وقت تین گرہیں لگا دیتا ہے اور ہر گرہ پر یہ افسوں پھونک دیتا ہے کہ سو جا ابھی رات بہت باقی ہے پھر اگر کوئی بیدار ہو کر اللہ کی یاد کرنے لگا تو ایک گرہ کھل جاتی ہے پھر جب وضو کرتا ہے تو دوسری گرہ کھل جاتی ہے۔ پھر اگر نماز ( فرض یا نفل ) پڑھے تو تیسری گرہ بھی کھل جاتی ہے۔ اس طرح صبح کے وقت آدمی چاق و چوبند خوش مزاج رہتا ہے۔ ورنہ سست اور بدباطن رہتا ہے۔' WHERE id = 1111;
UPDATE hadiths SET urdu = 'ہم سے عباس بن حسین نے بیان کیا، کہا کہ ہم سے مبشر بن اسماعیل حلبی نے، اوزاعی سے بیان کیا (دوسری سند) اور مجھ سے محمد بن مقاتل ابوالحسن نے بیان کیا، کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہیں امام اوزاعی نے خبر دی کہا کہ مجھ سے یحییٰ بن ابی کثیر نے بیان کیا، کہا کہ مجھ سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا، کہا کہ مجھ سے عبداللہ بن عمرو بن عاص رضی اللہ عنہما نے بیان کیا، کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اے عبداللہ! فلاں کی طرح نہ ہو جانا وہ رات میں عبادت کیا کرتا تھا پھر چھوڑ دی۔ اور ہشام بن عمار نے کہا کہ ہم سے عبدالحمید بن ابوالعشرین نے بیان کیا، ان سے امام اوزاعی نے بیان کیا، کہا کہ مجھ سے یحییٰ نے بیان کیا، ان سے عمرو بن حکم بن ثوبان نے بیان کیا، کہا کہ مجھ سے ابوسلمہ بن عبدالرحمٰن نے، اسی طرح پھر یہی حدیث بیان کی، ابن ابی العشرین کی طرح عمرو بن ابی سلمہ نے بھی اس کو امام اوزاعی سے روایت کیا۔' WHERE id = 1121;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، ان سے عبداللہ بن سعید نے، ان سے عامر بن عبداللہ بن زبیر نے بیان کیا، انہوں نے عمرو بن سلیم زرقی سے، انہوں نے ابوقتادہ بن ربعی انصاری صحابی رضی اللہ عنہ سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جب کوئی تم میں سے مسجد میں آئے تو نہ بیٹھے جب تک دو رکعت ( تحیۃ المسجد کی ) نہ پڑھ لے۔' WHERE id = 1134;
UPDATE hadiths SET urdu = 'ہم سے علی بن جعد نے بیان کیا کہ ہم کو شعبہ نے خبر دی، ان سے انس بن سیرین نے بیان کیا کہ میں نے انس بن مالک انصاری رضی اللہ عنہ سے سنا کہ انصار میں سے ایک شخص ( عتبان بن مالک ) نے جو بہت موٹے آدمی تھے، رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ میں آپ صلی اللہ علیہ وسلم کے ساتھ نماز پڑھنے کی طاقت نہیں رکھتا ( مجھ کو گھر پر نماز پڑھنے کی اجازت دیجئیے تو ) انہوں نے اپنے گھر نبی کریم صلی اللہ علیہ وسلم کے لیے کھانا پکوایا اور آپ صلی اللہ علیہ وسلم کو اپنے گھر بلایا اور ایک چٹائی کے کنارے کو آپ صلی اللہ علیہ وسلم کے لیے پانی سے صاف کیا، آپ صلی اللہ علیہ وسلم نے اس پر دو رکعت نماز پڑھی۔ اور فلاں بن فلاں بن جارود نے انس رضی اللہ عنہ سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم چاشت کی نماز پڑھا کرتے تھے؟ تو آپ نے فرمایا کہ میں نے اس روز کے سوا آپ صلی اللہ علیہ وسلم کو کبھی یہ نماز پڑھتے نہیں دیکھا۔' WHERE id = 1145;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید قطان نے بیان کیا، اور ان سے عبیداللہ عمری نے بیان کیا کہ مجھ سے نافع نے ابن عمر رضی اللہ عنہما سے بیان کیاکہ نبی کریم صلی اللہ علیہ وسلم قباء آتے کبھی پیدل اور کبھی سواری پر۔ ابن نمیر نے اس میں یہ زیادتی کی ہے کہ ہم سے عبیداللہ بن عمیر نے بیان کیا اور ان سے نافع نے کہ پھر آپ صلی اللہ علیہ وسلم اس میں دو رکعت نماز پڑھتے تھے۔' WHERE id = 1157;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بلخی نے بیان کیا، کہا کہ ہم کو وکیع نے خبر دی، انہیں سفیان ثوری نے، انہیں ابوحازم سلمہ بن دینار نے اور انہیں سہل بن سعد رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، سبحان اللہ کہنا مردوں کے لیے ہے اور عورتوں کے لیے تالی بجانا۔' WHERE id = 1168;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے غندر نے بیان کیا، ان سے شعبہ نے، انہوں نے کہا کہ میں نے قتادہ سے سنا، وہ انس بن مالک رضی اللہ عنہ سے روایت کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جب تم میں سے کوئی نماز میں ہو تو وہ اپنے رب سے سرگوشی کرتا ہے، اس لیے اس کو سامنے نہ تھوکنا چاہیے اور نہ دائیں طرف البتہ بائیں طرف اپنے قدم کے نیچے تھوک لے۔' WHERE id = 1178;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ یوسف تینسی نے بیان کیا، کہا کہ ہم کو امام مالک بن انس نے خبر دی، انہیں ابن شہاب نے، انہیں عبدالرحمٰن اعرج نے اور ان سے عبداللہ بن بحینہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کسی ( چار رکعت ) نماز کی دو رکعت پڑھانے کے بعد ( قعدہ تشہد کے بغیر ) کھڑے ہو گئے، پہلا قعدہ نہیں کیا۔ اس لیے لوگ بھی آپ صلی اللہ علیہ وسلم کے ساتھ کھڑے ہو گئے۔ جب آپ صلی اللہ علیہ وسلم نماز پوری کر چکے تو ہم سلام پھیرنے کا انتظار کرنے لگے۔ لیکن آپ صلی اللہ علیہ وسلم نے سلام سے پہلے بیٹھے بیٹھے «الله اكبر» کہا اور سلام ہی سے پہلے دو سجدے بیٹھے بیٹھے کیے پھر سلام پھیرا۔' WHERE id = 1188;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا کہ ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے ابوحازم سلمہ بن دینار نے، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کو خبر پہنچی کہ بنی عمرو بن عوف کے لوگوں میں باہم کوئی جھگڑا پیدا ہو گیا ہے تو آپ صلی اللہ علیہ وسلم چند صحابہ رضوان اللہ علیہم اجمعین کے ساتھ ملاپ کرانے کے لیے وہاں تشریف لے گئے۔ رسول اللہ صلی اللہ علیہ وسلم ابھی مشغول ہی تھے کہ نماز کا وقت ہو گیا۔ اس لیے بلال رضی اللہ عنہ نے ابوبکر رضی اللہ عنہ سے کہا کہ رسول اللہ صلی اللہ علیہ وسلم ابھی تک تشریف نہیں لائے۔ ادھر نماز کا وقت ہو گیا ہے۔ کیا آپ لوگوں کی امامت کریں گے؟ انہوں نے کہا کہ ہاں اگر تم چاہو۔ چنانچہ بلال رضی اللہ عنہ نے تکبیر کہی اور ابوبکر رضی اللہ عنہ نے آگے بڑھ کر تکبیر ( تحریمہ ) کہی۔ اتنے میں رسول اللہ صلی اللہ علیہ وسلم بھی صفوں سے گزرتے ہوئے پہلی صف میں آ کر کھڑے ہو گئے۔ لوگوں نے ( ابوبکر رضی اللہ عنہ کو آگاہ کرنے کے لیے ) ہاتھ پر ہاتھ بجانے شروع کر دیئے لیکن ابوبکر رضی اللہ عنہ نماز میں کسی طرف دھیان نہیں دیا کرتے تھے۔ جب لوگوں نے بہت تالیاں بجائیں تو آپ متوجہ ہوئے اور کیا دیکھتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم کھڑے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے اشارہ سے انہیں نماز پڑھاتے رہنے کے لیے کہا، اس پر ابوبکر رضی اللہ عنہ نے ہاتھ اٹھا کر اللہ تعالیٰ کا شکر ادا کیا اور الٹے پاؤں پیچھے کی طرف آ کر صف میں کھڑے ہو گئے پھر رسول اللہ صلی اللہ علیہ وسلم نے آگے بڑھ کر نماز پڑھائی۔ نماز کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا۔ لوگو! نماز میں ایک امر پیش آیا تو تم لوگ ہاتھ پر ہاتھ کیوں مارنے لگے تھے، یہ دستک دینا تو صرف عورتوں کے لیے ہے۔ جس کو نماز میں کوئی حادثہ پیش آئے تو «سبحان الله» کہے کیونکہ جب بھی کوئی «سبحان الله» سنے گا وہ ادھر خیال کرے گا اور اے ابوبکر! میرے اشارے کے باوجود تم لوگوں کو نماز کیوں نہیں پڑھاتے رہے؟ ابوبکر رضی اللہ عنہ نے عرض کیا کہ بھلا ابوقحافہ کے بیٹے کی کیا مجال تھی کہ رسول اللہ صلی اللہ علیہ وسلم کے آگے نماز پڑھائے۔' WHERE id = 1199;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالوارث نے بیان کیا، ان سے ایوب نے، ان سے حمید بن بلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ زید نے جھنڈا سنبھالا لیکن وہ شہید ہو گئے۔ پھر جعفر نے سنبھالا اور وہ بھی شہید ہو گئے۔ پھر عبداللہ بن رواحہ نے سنبھالا اور وہ بھی شہید ہو گئے۔ اس وقت رسول اللہ صلی اللہ علیہ وسلم کی آنکھوں میں آنسو بہ رہے تھے۔ ( آپ صلی اللہ علیہ وسلم نے فرمایا ) اور پھر خالد بن ولید نے خود اپنے طور پر جھنڈا اٹھا لیا اور ان کو فتح حاصل ہوئی۔' WHERE id = 1210;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا، کہا کہ ہم سے عبداللہ بن وہب نے بیان کیا انہیں ابن جریج نے خبر دی، ان سے ایوب نے بیان کیا کہ میں نے حفصہ بنت سیرین سے سنا، انہوں نے کہا کہ ام عطیہ رضی اللہ عنہا نے ہم سے بیان کیا کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی کے بالوں کو تین لٹوں میں تقسیم کر دیا تھا۔ پہلے بال کھولے گئے پھر انہیں دھو کر ان کی تین چٹیاں کر دی گئیں۔' WHERE id = 1222;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، ان سے ابن عیینہ نے بیان کیا، ان سے عمرو نے، انہوں نے جابر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو عبداللہ بن ابی کو دفن کیا جا رہا تھا۔ آپ صلی اللہ علیہ وسلم نے اسے قبر سے نکلوایا اور اپنا لعاب دہن اس کے منہ میں ڈالا اور اپنی قمیص پہنائی۔' WHERE id = 1232;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سفیان ثوری نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ایوب بن موسیٰ نے بیان کیا ‘ انہوں نے کہا کہ مجھے حمید بن نافع نے زینب بنت ابی سلمہ سے خبر دی کہ ابوسفیان رضی اللہ عنہ کی وفات کی خبر جب شام سے آئی تو ام حبیبہ رضی اللہ عنہا ( ابوسفیان رضی اللہ عنہ کی صاحبزادی اور ام المؤمنین ) نے تیسرے دن ”صفرہ“ ( خوشبو ) منگوا کر اپنے دونوں رخساروں اور بازوؤں پر ملا اور فرمایا کہ اگر میں نے نبی کریم صلی اللہ علیہ وسلم سے یہ نہ سنا ہوتا کہ کوئی بھی عورت جو اللہ اور آخرت کے دن پر ایمان رکھتی ہو اس کے لیے جائز نہیں ہے کہ وہ شوہر کے سوا کسی کا سوگ تین دن سے زیادہ منائے اور شوہر کا سوگ چار مہینے دس دن کرے۔ تو مجھے اس وقت اس خوشبو کے استعمال کی ضرورت نہیں تھی۔' WHERE id = 1242;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ انہیں امام مالک نے خبر دی۔ انہیں ابن شہاب نے ‘ انہیں عامر بن سعد بن ابی وقاص نے اور انہیں ان کے والد سعد بن ابی وقاص رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم حجتہ الوداع کے سال ( 10 ھ میں ) میری عیادت کے لیے تشریف لائے۔ میں سخت بیمار تھا۔ میں نے کہا کہ میرا مرض شدت اختیار کر چکا ہے میرے پاس مال و اسباب بہت ہے اور میری صرف ایک لڑکی ہے جو وارث ہو گی تو کیا میں اپنے دو تہائی مال کو خیرات کر دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے کہا آدھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا نہیں۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک تہائی کر دو اور یہ بھی بڑی خیرات ہے یا بہت خیرات ہے اگر تو اپنے وارثوں کو اپنے پیچھے مالدار چھوڑ جائے تو یہ اس سے بہتر ہو گا کہ محتاجی میں انہیں اس طرح چھوڑ کر جائے کہ وہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں۔ یہ یاد رکھو کہ جو خرچ بھی تم اللہ کی رضا کی نیت سے کرو گے تو اس پر بھی تمہیں ثواب ملے گا۔ حتیٰ کہ اس لقمہ پر بھی جو تم اپنی بیوی کے منہ میں رکھو۔ پھر میں نے پوچھا کہ یا رسول اللہ! میرے ساتھی تو مجھے چھوڑ کر ( حجتہ الوداع کر کے ) مکہ سے جا رہے ہیں اور میں ان سے پیچھے رہ رہا ہوں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہاں رہ کر بھی اگر تم کوئی نیک عمل کرو گے تو اس سے تمہارے درجے بلند ہوں گے اور شاید ابھی تم زندہ رہو گے اور بہت سے لوگوں کو ( مسلمانوں کو ) تم سے فائدہ پہنچے گا اور بہتوں کو ( کفار و مرتدین کو ) نقصان۔ ( پھر آپ صلی اللہ علیہ وسلم نے دعا فرمائی ) اے اللہ! میرے ساتھیوں کو ہجرت پر استقلال عطا فرما اور ان کے قدم پیچھے کی طرف نہ لوٹا۔ لیکن مصیبت زدہ سعد بن خولہ تھے اور رسول اللہ صلی اللہ علیہ وسلم نے ان کے مکہ میں وفات پا جانے کی وجہ سے اظہار غم کیا تھا۔' WHERE id = 1254;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن حوشب نے بیان کیا ‘ کہا ہم سے عبوالوہاب ثقفی نے ‘ ان سے یحییٰ بن سعید انصاری نے، کہا کہ مجھے عمرہ بنت عبدالرحمٰن انصاری نے خبر دی، انہوں نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، آپ نے فرمایا کہ جب زید بن حارثہ ‘ جعفر بن ابی طالب اور عبداللہ بن رواحہ رضی اللہ عنہم کی شہادت کی خبر آئی تو نبی کریم صلی اللہ علیہ وسلم اس طرح بیٹھے کہ غم کے آثار آپ صلی اللہ علیہ وسلم کے چہرے پر نمایاں تھے میں دروازے کے ایک سوراخ سے آپ صلی اللہ علیہ وسلم کو دیکھ رہی تھی۔ اتنے میں ایک صاحب آئے اور کہا کہ یا رسول اللہ! جعفر کے گھر کی عورتیں نوحہ اور ماتم کر رہی ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے روکنے کے لیے کہا۔ وہ صاحب گئے لیکن پھر واپس آ گئے اور کہا کہ وہ نہیں مانتیں۔ آپ صلی اللہ علیہ وسلم نے دوبارہ روکنے کے لیے بھیجا۔ وہ گئے اور پھر واپس چلے آئے۔ کہا کہ بخدا وہ تو مجھ پر غالب آ گئی ہیں یا یہ کہا کہ ہم پر غالب آ گئی ہیں۔ شک محمد بن حوشب کو تھا۔ ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میرا یقین یہ ہے کہ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ان کے منہ میں مٹی جھونک دے۔ اس پر میری زبان سے نکلا کہ اللہ تیری ناک خاک آلودہ کرے تو نہ تو وہ کام کر سکا جس کا نبی کریم صلی اللہ علیہ وسلم نے حکم دیا تھا اور نہ آپ صلی اللہ علیہ وسلم کو تکلیف دینا چھوڑتا ہے۔' WHERE id = 1264;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ انہوں نے کہا کہ ہم سے ابوعوانہ وضاح یشکری نے بیان کیا ‘ ان سے قتادہ نے بیان کیا ‘ ان سے عطاء نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ جب رسول اللہ صلی اللہ علیہ وسلم نے نجاشی کی نماز جنازہ پڑھی تو میں دوسری یا تیسری صف میں تھا۔' WHERE id = 1275;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا ‘ ان سے شیبان نے ‘ ان سے ہلال وزان نے ‘ ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے مرض وفات میں فرمایا کہ یہود اور نصاریٰ پر اللہ کی لعنت ہو کہ انہوں نے اپنے انبیاء کی قبروں کو مساجد بنا لیا۔ عائشہ رضی اللہ عنہا نے کہا کہ اگر ایسا ڈر نہ ہوتا تو آپ صلی اللہ علیہ وسلم کی قبر کھلی رہتی ( اور حجرہ میں نہ ہوتی ) کیونکہ مجھے ڈر اس کا ہے کہ کہیں آپ صلی اللہ علیہ وسلم کی قبر بھی مسجد نہ بنا لی جائے۔' WHERE id = 1286;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا ‘ کہا کہ ہم سے جریر نے بیان کیا ‘ ان سے شیبانی نے ‘ ان سے شعبی نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک ایسے شخص کی نماز جنازہ پڑھی جن کا انتقال رات کے وقت ہوا ( اور اسے رات ہی میں دفن کر دیا گیا تھا ) آپ صلی اللہ علیہ وسلم اور آپ کے اصحاب کھڑے ہوئے اور آپ صلی اللہ علیہ وسلم نے ان کے متعلق پوچھا تھا کہ یہ کن کی قبر ہے۔ لوگوں نے بتایا کہ فلاں کی ہے جسے کل رات ہی دفن کیا گیا ہے۔ پھر سب نے ( دوسرے روز ) نماز جنازہ پڑھی۔' WHERE id = 1296;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا ‘ کہا کہ ہم سے سعید بن عامر نے بیان کیا ‘ ان سے شعبہ نے ‘ ان سے ابن ابی نجیح نے ‘ ان سے عطاء بن ابی رباح اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ میرے باپ کے ساتھ ایک ہی قبر میں ایک اور صحابی ( جابر رضی اللہ عنہ کے چچا ) دفن تھے۔ لیکن میرا دل اس پر راضی نہیں ہو رہا تھا۔ اس لیے میں نے ان کی لاش نکال کر دوسری قبر میں دفن کر دی۔' WHERE id = 1307;
UPDATE hadiths SET urdu = 'ہم سے ابولیمان نے بیان کیا ‘ کہا کہ ہمیں شعیب نے خبر دی ‘ کہا کہ ہم کو ابوالزناد نے خبر دی ‘ ان سے اعرج نے ‘ ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص خود اپنا گلا گھونٹ کر جان دے ڈالتا ہے وہ جہنم میں بھی اپنا گلا گھونٹتا رہے گا اور جو برچھے یا تیر سے اپنے تئیں ( آپ کو ) مارے وہ دوزخ میں بھی اس طرح اپنے ( آپ کو ) تئیں مارتا رہے گا۔' WHERE id = 1318;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا ‘ کہا کہ ہم سے یحییٰ بن سعید قطان نے، کہا ہم سے شعبہ نے، کہا کہ مجھ سے عون بن ابی حجیفہ نے بیان کیا، ان سے ان کے والد ابوحجیفہ نے، ان سے براء بن عازب نے اور ان سے ابوایوب انصاری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مدینہ سے باہر تشریف لے گئے، سورج غروب ہو چکا تھا، اس وقت آپ صلی اللہ علیہ وسلم کو ایک آواز سنائی دی۔ ( یہودیوں پر عذاب قبر کی ) پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہودی پر اس کی قبر میں عذاب ہو رہا ہے۔ اور نضر بن شمیل نے بیان کیا کہ ہمیں شعبہ نے خبر دی، ان سے عون نے بیان کیا، انہوں نے اپنے باپ ابوحجیفہ سے سنا، انہوں نے براء سے سنا، انہوں نے ابوایوب انصاری رضی اللہ عنہ سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 1328;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ ان سے ابن ابی ذئب نے ‘ ان سے زہری نے ‘ ان سے ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہر بچہ کی پیدائش فطرت پر ہوتی ہے پھر اس کے ماں باپ اسے یہودی یا نصرانی یا مجوسی بنا دیتے ہیں بالکل اس طرح جیسے جانور کے بچے صحیح سالم ہوتے ہیں۔ کیا تم نے ( پیدائشی طور پر ) کوئی ان کے جسم کا حصہ کٹا ہوا دیکھا ہے۔' WHERE id = 1338;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم ضحاک بن مخلد نے بیان کیا ‘ ان سے زکریا بن اسحاق نے بیان کیا ‘ ان سے یحییٰ بن عبداللہ بن صیفی نے بیان کیا، ان سے ابومعبد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے جب معاذ رضی اللہ عنہ کو یمن ( کا حاکم بنا کر ) بھیجا تو فرمایا کہ تم انہیں اس کلمہ کی گواہی کی دعوت دینا کہ اللہ کے سوا کوئی معبود نہیں اور یہ کہ میں اللہ کا رسول ہوں۔ اگر وہ لوگ یہ بات مان لیں تو پھر انہیں بتانا کہ اللہ تعالیٰ نے ان پر روزانہ پانچ وقت کی نمازیں فرض کی ہیں۔ اگر وہ لوگ یہ بات بھی مان لیں تو پھر انہیں بتانا کہ اللہ تعالیٰ نے ان کے مال پر کچھ صدقہ فرض کیا ہے جو ان کے مالدار لوگوں سے لے کر انہیں کے محتاجوں میں لوٹا دیا جائے گا۔' WHERE id = 1350;
UPDATE hadiths SET urdu = 'ہم سے علی بن ابی ہاشم نے بیان کیا ‘ انہوں نے ہشیم سے سنا ‘ کہا کہ ہمیں حصین نے خبر دی ‘ انہیں زید بن وہب نے کہا کہ میں مقام ربذہ سے گزر رہا تھا کہ ابوذر رضی اللہ عنہ دکھائی دیئے۔ میں نے پوچھا کہ آپ یہاں کیوں آ گئے ہیں؟ انہوں نے جواب دیا کہ میں شام میں تھا تو معاویہ رضی اللہ عنہ سے میرا اختلاف ( قرآن کی آیت ) ”جو لوگ سونا اور چاندی جمع کرتے ہیں اور انہیں اللہ کی راہ میں خرچ نہیں کرتے“ کے متعلق ہو گیا۔ معاویہ رضی اللہ عنہ کا کہنا یہ تھا کہ یہ آیت اہل کتاب کے بارے میں نازل ہوئی ہے اور میں یہ کہتا تھا کہ اہل کتاب کے ساتھ ہمارے متعلق بھی یہ نازل ہوئی ہے۔ اس اختلاف کے نتیجہ میں میرے اور ان کے درمیان کچھ تلخی پیدا ہو گئی۔ چنانچہ انہوں نے عثمان رضی اللہ عنہ ( جو ان دنوں خلیفۃ المسلمین تھے ) کے یہاں میری شکایت لکھی۔ عثمان رضی اللہ عنہ نے مجھے لکھا کہ میں مدینہ چلا آؤں۔ چنانچہ میں چلا آیا۔ ( وہاں جب پہنچا ) تو لوگوں کا میرے یہاں اس طرح ہجوم ہونے لگا جیسے انہوں نے مجھے پہلے دیکھا ہی نہ ہو۔ پھر جب میں نے لوگوں کے اس طرح اپنی طرف آنے کے متعلق عثمان رضی اللہ عنہ سے کہا تو انہوں نے فرمایا کہ اگر مناسب سمجھو تو یہاں کا قیام چھوڑ کر مدینہ سے قریب ہی کہیں اور جگہ الگ قیام اختیار کر لو۔ یہی بات ہے جو مجھے یہاں ( ربذہ ) تک لے آئی ہے۔ اگر وہ میرے اوپر ایک حبشی کو بھی امیر مقرر کر دیں تو میں اس کی بھی سنوں گا اور اطاعت کروں گا۔' WHERE id = 1360;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا ‘ کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی ‘ کہا کہ ہمیں معمر نے زہری سے خبر دی ‘ انہوں نے کہا کہ مجھ سے عبداللہ بن ابی بکر بن حزم نے بیان کیا ‘ ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ایک عورت اپنی دو بچیوں کو لیے مانگتی ہوئی آئی۔ میرے پاس ایک کھجور کے سوا اس وقت اور کچھ نہ تھا میں نے وہی دے دی۔ وہ ایک کھجور اس نے اپنی دونوں بچیوں میں تقسیم کر دی اور خود نہیں کھائی۔ پھر وہ اٹھی اور چلی گئی۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو میں نے آپ صلی اللہ علیہ وسلم سے اس کا حال بیان کیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے ان بچیوں کی وجہ سے خود کو معمولی سی بھی تکلیف میں ڈالا تو بچیاں اس کے لیے دوزخ سے بچاؤ کے لیے آڑ بن جائیں گی۔' WHERE id = 1371;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نبیل نے عمر بن سعید سے بیان کیا ‘ ان سے ابن ابی ملیکہ نے کہ عقبہ بن حارث رضی اللہ عنہ نے ان سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے عصر کی نماز ادا کی پھر جلدی سے آپ صلی اللہ علیہ وسلم گھر میں تشریف لے گئے۔ تھوڑی دیر بعد باہر تشریف لے آئے۔ اس پر میں نے پوچھا یا کسی اور نے پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں گھر کے اندر صدقہ کے سونے کا ایک ٹکڑا چھوڑ آیا تھا مجھے یہ بات پسند نہیں آئی کہ اسے تقسیم کئے بغیر رات گزاروں پس میں نے اس کو بانٹ دیا۔' WHERE id = 1382;
UPDATE hadiths SET urdu = '(دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے عمر بن حفص نے بیان کیا ‘ کہا کہ مجھ سے میرے باپ حفص بن غیاث نے بیان کیا ‘ کہا کہ ہم سے اعمش نے بیان کیا ‘ ان سے ابووائل شقیق نے ‘ ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا جب بیوی اپنے شوہر کے مال میں سے کسی کو کھلائے اور اس کا ارادہ گھر کو بگاڑنے کا بھی نہ ہو تو اسے اس کا ثواب ملتا ہے اور شوہر کو بھی ویسا ہی ثواب ملتا ہے اور خزانچی کو بھی ویسا ہی ثواب ملتا ہے۔ شوہر کو کمانے کی وجہ سے ثواب ملتا ہے اور عورت کو خرچ کرنے کی وجہ سے۔' WHERE id = 1392;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ انصاری نے بیان کیا ‘ کہا کہ مجھ سے میرے والد نے بیان کیا ‘ کہا کہ مجھ سے ثمامہ نے بیان کیا ‘ اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے انہیں وہی چیز لکھی تھی جسے رسول اللہ صلی اللہ علیہ وسلم نے ضروری قرار دیا تھا۔ یہ کہ زکوٰۃ ( کی زیادتی ) کے خوف سے جدا جدا مال کو یکجا اور یکجا مال کو جدا جدا نہ کیا جائے۔' WHERE id = 1402;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا ‘ انہوں نے کہا کہ ہمیں محمد بن جعفر نے خبر دی ‘ انہوں نے کہا کہ مجھے زید بن اسلم نے خبر دی ‘ انہیں عیاض بن عبداللہ نے ‘ اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا ‘ کہ رسول اللہ صلی اللہ علیہ وسلم عید الاضحی یا عیدالفطر میں عیدگاہ تشریف لے گئے۔ پھر ( نماز کے بعد ) لوگوں کو وعظ فرمایا اور صدقہ کا حکم دیا۔ فرمایا: لوگو! صدقہ دو۔ پھر آپ صلی اللہ علیہ وسلم عورتوں کی طرف گئے اور ان سے بھی یہی فرمایا کہ عورتو! صدقہ دو کہ میں نے جہنم میں بکثرت تم ہی کو دیکھا ہے۔ عورتوں نے پوچھا کہ یا رسول اللہ! ایسا کیوں ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ‘ اس لیے کہ تم لعن وطعن زیادہ کرتی ہو اور اپنے شوہر کی ناشکری کرتی ہو۔ میں نے تم سے زیادہ عقل اور دین کے اعتبار سے ناقص ایسی کوئی مخلوق نہیں دیکھی جو کار آزمودہ مرد کی عقل کو بھی اپنی مٹھی میں لے لیتی ہو۔ ہاں اے عورتو! پھر آپ صلی اللہ علیہ وسلم واپس گھر پہنچے تو ابن مسعود رضی اللہ عنہ کی بیوی زینب رضی اللہ عنہا آئیں اور اجازت چاہی۔ آپ صلی اللہ علیہ وسلم سے کہا گیا کہ یہ زینب آئی ہیں۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کون سی زینب ( کیونکہ زینب نام کی بہت سی عورتیں تھیں ) کہا گیا کہ ابن مسعود رضی اللہ عنہ کی بیوی۔ آپ صلی اللہ علیہ وسلم نے فرمایا۔ اچھا انہیں اجازت دے دو ‘ چنانچہ اجازت دے دی گئی۔ انہوں نے آ کر عرض کیا کہ یا رسول اللہ! آج آپ نے صدقہ کا حکم دیا تھا۔ اور میرے پاس بھی کچھ زیور ہے جسے میں صدقہ کرنا چاہتی تھی۔ لیکن ( میرے خاوند ) ابن مسعود رضی اللہ عنہ یہ خیال کرتے ہیں کہ وہ اور ان کے لڑکے اس کے ان ( مسکینوں ) سے زیادہ مستحق ہیں جن پر میں صدقہ کروں گی۔ رسول اللہ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ ابن مسعود رضی اللہ عنہ نے صحیح کہا۔ تمہارے شوہر اور تمہارے لڑکے اس صدقہ کے ان سے زیادہ مستحق ہیں جنہیں تم صدقہ کے طور پر دو گی۔ ( معلوم ہوا کہ اقارب اگر محتاج ہوں تو صدقہ کے اولین مستحق وہی ہیں ) ۔' WHERE id = 1413;
UPDATE hadiths SET urdu = 'ہم سے عبد ان نے بیان کیا ‘ کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی ‘ کہا کہ ہمیں یونس نے خبر دی ‘ انہیں زہری نے ‘ انہیں عروہ بن زبیر اور سعید بن مسیب نے کہ حکیم بن حزام رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے کچھ مانگا۔ آپ صلی اللہ علیہ وسلم نے عطا فرمایا۔ میں نے پھر مانگا اور آپ صلی اللہ علیہ وسلم نے پھر عطا فرمایا۔ میں نے پھر مانگا آپ صلی اللہ علیہ وسلم نے پھر بھی عطا فرمایا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے ارشاد فرمایا۔ اے حکیم! یہ دولت بڑی سرسبز اور بہت ہی شیریں ہے۔ لیکن جو شخص اسے اپنے دل کو سخی رکھ کر لے تو اس کی دولت میں برکت ہوتی ہے۔ اور جو لالچ کے ساتھ لیتا ہے تو اس کی دولت میں کچھ بھی برکت نہیں ہو گی۔ اس کا حال اس شخص جیسا ہو گا جو کھاتا ہے لیکن آسودہ نہیں ہوتا ( یاد رکھو ) اوپر کا ہاتھ نیچے کے ہاتھ سے بہتر ہے۔ حکیم بن حزام رضی اللہ عنہ نے کہا ‘ کہ میں نے عرض کی اس ذات کی قسم! جس نے آپ کو سچائی کے ساتھ مبعوث کیا ہے۔ اب اس کے بعد میں کسی سے کوئی چیز نہیں لوں گا۔ تاآنکہ اس دنیا ہی سے میں جدا ہو جاؤں۔ چنانچہ ابوبکر رضی اللہ عنہ حکیم رضی اللہ عنہ کو ان کا معمول دینے کو بلاتے تو وہ لینے سے انکار کر دیتے۔ پھر عمر رضی اللہ عنہ نے بھی انہیں ان کا حصہ دینا چاہا تو انہوں نے اس کے لینے سے انکار کر دیا۔ اس پر عمر رضی اللہ عنہ نے فرمایا کہ مسلمانو! میں تمہیں حکیم بن حزام کے معاملہ میں گواہ بناتا ہوں کہ میں نے ان کا حق انہیں دینا چاہا لیکن انہوں نے لینے سے انکار کر دیا۔ غرض حکیم بن حزام رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کے بعد اسی طرح کسی سے بھی کوئی چیز لینے سے ہمیشہ انکار ہی کرتے رہے۔ یہاں تک کہ وفات پا گئے۔ عمر رضی اللہ عنہ ”مال فے“ یعنی ملکی آمدنی سے ان کا حصہ ان کو دینا چاہتے تھے مگر انہوں نے وہ بھی نہیں لیا۔' WHERE id = 1423;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا ‘ کہا کہ ہم سے شعبہ نے بیان کیا ‘ کہا کہ مجھے عبداللہ بن دینار نے خبر دی ‘ کہا کہ میں نے ابن عمر رضی اللہ عنہما سے سنا ‘ انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے کھجور کو ( درخت پر ) اس وقت تک بیچنے سے منع فرمایا ہے جب تک اس کی پختگی ظاہر نہ ہو۔ اور ابن عمر رضی اللہ عنہما سے جب پوچھتے کہ اس کی پختگی کیا ہے، وہ کہتے کہ جب یہ معلوم ہو جائے کہ اب یہ پھل آفت سے بچ رہے گا۔' WHERE id = 1435;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا ‘ انہوں نے کہا کہ ہمیں عبداللہ نے خبر دی ‘ انہوں نے کہا کہ ہمیں زکریا ابن اسحاق نے خبر دی ‘ انہیں یحییٰ بن عبداللہ بن صیفی نے ‘ انہیں ابن عباس رضی اللہ عنہما کے غلام ابومعبد نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے معاذ رضی اللہ عنہ کو جب یمن بھیجا ‘ تو ان سے فرمایا کہ تم ایک ایسی قوم کے پاس جا رہے ہو جو اہل کتاب ہیں۔ اس لیے جب تم وہاں پہنچو تو پہلے انہیں دعوت دو کہ وہ اس بات کی گواہی دیں کہ اللہ کے سوا کوئی معبود نہیں اور محمد ( صلی اللہ علیہ وسلم ) اللہ کے سچے رسول ہیں۔ وہ اس بات میں جب تمہاری بات مان لیں تو انہیں بتاؤ کہ اللہ تعالیٰ نے ان پر روزانہ دن رات میں پانچ وقت کی نمازیں فرض کی ہیں۔ جب وہ تمہاری یہ بات بھی مان لیں تو انہیں بتاؤ کہ ان کے لیے اللہ تعالیٰ نے زکوٰۃ دینا ضروری قرار دیا ہے ‘ یہ ان کے مالداروں سے لی جائے گی اور ان کے غریبوں پر خرچ کی جائے گی۔ پھر جب وہ اس میں بھی تمہاری بات مان لیں تو ان کے اچھے مال لینے سے بچو اور مظلوم کی آہ سے ڈرو کہ اس کے اور اللہ تعالیٰ کے درمیان کوئی رکاوٹ نہیں ہوتی۔' WHERE id = 1445;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ انہوں نے کہا کہ ہمیں امام مالک نے خبر دی ‘ ان سے زید بن اسلم نے بیان کیا ‘ ان سے عیاض بن عبداللہ بن سعد بن ابی سرح عامری نے بیان کیا ‘ کہ انہوں نے ابو سعید خدری رضی اللہ عنہ سے سنا۔ آپ فرماتے تھے کہ ہم فطرہ کی زکوٰۃ ایک صاع اناج یا گیہوں یا ایک صاع جَو یا ایک صاع کھجور یا ایک صاع پنیر یا ایک صاع زبیب ( خشک انگور یا انجیر ) نکالا کرتے تھے۔' WHERE id = 1455;
UPDATE hadiths SET urdu = 'اور ابان نے کہا ہم سے مالک بن دینار نے بیان کیا، ان سے قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے ساتھ ان کے بھائی عبدالرحمٰن کو بھیجا اور انہوں نے عائشہ رضی اللہ عنہا کو تنعیم سے عمرہ کرایا اور پالان کی پچھلی لکڑی پر ان کو بٹھا لیا۔ عمر رضی اللہ عنہ نے فرمایا کہ حج کے لیے پالانیں باندھو کیونکہ یہ بھی ایک جہاد ہے۔' WHERE id = 1465;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے عمرو بن دینار نے بیان کیا، ان سے طاؤس نے بیان کیا، اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے مدینہ والوں کے لیے ذوالحلیفہ کو میقات مقرر کیا، شام والوں کے لیے حجفہ، نجد والوں کے لیے قرن المنازل اور یمن والوں کے لیے یلملم۔ یہ میقات ان ملک والوں کے ہیں اور ان لوگوں کے لیے بھی جو ان ملکوں سے گزر کر حرم میں داخل ہوں اور حج یا عمرہ کا ارادہ رکھتے ہوں۔ لیکن جو لوگ میقات کے اندر رہتے ہوں۔ یہاں تک کہ مکہ کے لوگ احرام مکہ ہی سے باندھیں۔' WHERE id = 1475;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، کہا کہ ہم سے ابوعاصم، ضحاک بن مخلد نبیل نے بیان کیا، کہا کہ ہمیں ابن جریج نے خبر دی کہا کہ مجھے عطاء بن ابی رباح نے خبر دی، انہیں صفوان بن یعلیٰ نے، کہا کہ ان کے باپ یعلیٰ بن امیہ نے عمر رضی اللہ عنہ سے کہا کہ کبھی آپ مجھے نبی کریم صلی اللہ علیہ وسلم کو اس حال میں دکھایئے جب آپ صلی اللہ علیہ وسلم پر وحی نازل ہو رہی ہو۔ انہوں نے بیان کیا کہ ایک بار رسول اللہ صلی اللہ علیہ وسلم جعرانہ میں اپنے اصحاب کی ایک جماعت کے ساتھ ٹھہرے ہوئے تھے کہ ایک شخص نے آ کر پوچھا یا رسول اللہ! اس شخص کے متعلق آپ کا کیا حکم ہے جس نے عمرہ کا احرام اس طرح باندھا کہ اس کے کپڑے خوشبو میں بسے ہوئے ہوں۔ نبی کریم صلی اللہ علیہ وسلم اس پر تھوڑی دیر کے لیے چپ ہو گئے۔ پھر آپ صلی اللہ علیہ وسلم پر وحی نازل ہوئی تو عمر رضی اللہ عنہ نے یعلیٰ رضی اللہ عنہ کو اشارہ کیا۔ یعلیٰ آئے تو رسول اللہ صلی اللہ علیہ وسلم پر ایک کپڑا تھا جس کے اندر آپ صلی اللہ علیہ وسلم تشریف رکھتے تھے۔ انہوں نے کپڑے کے اندر اپنا سر کیا تو کیا دیکھتے ہیں کہ روئے مبارک سرخ ہے اور آپ صلی اللہ علیہ وسلم خراٹے لے رہے ہیں۔ پھر یہ حالت ختم ہوئی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ شخص کہاں ہے جس نے عمرہ کے متعلق پوچھا تھا۔ شخص مذکور حاضر کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جو خوشبو لگا رکھی ہے اسے تین مرتبہ دھو لے اور اپنا جبہ اتار دے۔ عمرہ میں بھی اسی طرح کر جس طرح حج میں کرتے ہو۔ میں نے عطاء سے پوچھا کہ کیا نبی کریم صلی اللہ علیہ وسلم کے تین مرتبہ دھونے کے حکم سے پوری طرح صفائی مراد تھی؟ تو انہوں نے کہا کہ ہاں۔' WHERE id = 1485;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے اعمش سے بیان کیا، ان سے عمارہ نے ان سے ابوعطیہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ میں جانتی ہوں کہ کس طرف نبی کریم صلی اللہ علیہ وسلم تلبیہ کہتے تھے۔ آپ صلی اللہ علیہ وسلم تلبیہ یوں کہتے تھے «لبيك اللهم لبيك،‏‏‏‏ لبيك لا شريك لك لبيك،‏‏‏‏ إن الحمد والنعمة لك‏» ( ترجمہ گزر چکا ہے ) اس کی متابعت سفیان ثوری کی طرح ابومعاویہ نے اعمش سے بھی کی ہے۔ اور شعبہ نے کہا کہ مجھ کو سلیمان اعمش نے خبر دی کہ میں نے خیثمہ سے سنا اور انہوں نے ابوعطیہ سے، انہوں نے عائشہ رضی اللہ عنہا سے سنا۔ پھر یہی حدیث بیان کی۔' WHERE id = 1497;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے ابوبکر حنفی نے بیان کیا، کہا کہ ہم سے افلح بن حمید نے بیان کیا، کہا کہ میں نے قاسم بن محمد سے سنا، ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ حج کے مہینوں میں حج کی راتوں میں اور حج کے دنوں میں نکلے۔ پھر سرف میں جا کر اترے۔ آپ نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے صحابہ کو خطاب فرمایا جس کے ساتھ ہدی نہ ہو اور وہ چاہتا ہو کہ اپنے احرام کو صرف عمرہ کا بنا لے تو اسے ایسا کر لینا چاہئے لیکن جس کے ساتھ قربانی ہے وہ ایسا نہ کرے۔ عائشہ رضی اللہ عنہا نے بیان فرمایا کہ نبی کریم صلی اللہ علیہ وسلم کے بعض اصحاب نے اس فرمان پر عمل کیا اور بعض نے نہیں کیا۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اور آپ کے بعض اصحاب جو استطاعت و حوصلہ والے تھے ( کہ وہ احرام کے ممنوعات سے بچ سکتے تھے۔ ) ان کے ساتھ ہدی بھی تھی، اس لیے وہ تنہا عمرہ نہیں کر سکتے تھے ( پس انہوں نے احرام نہیں کھولا ) عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم میرے پاس تشریف لائے تو میں رو رہی تھی۔ آپ صلی اللہ علیہ وسلم نے پوچھا کہ ( اے بھولی بھالی عورت! تو ) رو کیوں رہی ہے؟ میں نے عرض کی کہ میں نے آپ کے اپنے صحابہ سے ارشاد کو سن لیا، اب تو میں عمرہ نہ کر سکوں گی۔ آپ صلی اللہ علیہ وسلم نے پوچھا کیا بات ہے؟ میں نے کہا میں نماز پڑھنے کے قابل نہ رہی ( یعنی حائضہ ہو گئی ) آپ صلی اللہ علیہ وسلم نے فرمایا کوئی حرج نہیں۔ آخر تم بھی تو آدم کی بیٹیوں کی طرح ایک عورت ہو اور اللہ نے تمہارے لیے بھی وہ مقدر کیا ہے جو تمام عورتوں کے لیے کیا ہے۔ اس لیے ( عمرہ چھوڑ کر ) حج کرتی رہ اللہ تعالیٰ تمہیں جلد ہی عمرہ کی توفیق دیدے گا۔ عائشہ رضی اللہ عنہا نے یہ بیان کیا کہ ہم حج کے لیے نکلے۔ جب ہم ( عرفات سے ) منیٰ پہنچے تو میں پاک ہو گئی۔ پھر منٰی سے جب میں نکلی تو بیت اللہ کا طواف الزیارۃ کیا۔ آپ نے بیان کیا کہ آخر میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ جب واپس ہونے لگی تو آپ صلی اللہ علیہ وسلم وادی محصب میں آن کر اترے۔ ہم بھی آپ صلی اللہ علیہ وسلم کے ساتھ ٹھہرے۔ آپ صلی اللہ علیہ وسلم نے عبدالرحمٰن بن ابی بکر کو بلا کر کہا کہ اپنی بہن کو لے کر حرم سے باہر جا اور وہاں سے عمرہ کا احرام باندھ پھر عمرہ سے فارغ ہو کر تم لوگ یہیں واپس آ جاؤ، میں تمہارا انتظار کرتا رہوں گا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ ہم ( نبی کریم صلی اللہ علیہ وسلم کی ہدایت کے مطابق ) چلے اور جب میں اور میرے بھائی طواف سے فارغ ہو لیے تو میں سحری کے وقت آپ صلی اللہ علیہ وسلم کی خدمت میں پہنچی۔ آپ صلی اللہ علیہ وسلم نے پوچھا کہ فارغ ہو لیں؟ میں نے کہا ہاں۔ تب آپ صلی اللہ علیہ وسلم نے اپنے ساتھیوں سے سفر شروع کر دینے کے لیے کہا۔ سفر شروع ہو گیا اور آپ صلی اللہ علیہ وسلم مدینہ منورہ واپس ہو رہے تھے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ جو «لايضيرک» ہے وہ «ضار يضير ضيراا» سے مشتق ہے ضار يضور ضورا» بھی استعمال ہوتا ہے۔ اور جس روایت میں «لايضرک» ہے وہ «ضر يضر ضرا‏» سے نکلا ہے۔' WHERE id = 1507;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، کہا کہ میں نے مجاہد سے سنا، انہوں نے کہا ہم سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا انہوں نے کہا کہ جب ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ آئے تو ہم نے حج کی لبیک پکاری۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے ہمیں حکم دیا ہم نے اسے عمرہ بنا لیا۔' WHERE id = 1517;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا کہ ہم سے حاتم بن اسماعیل نے ہشام سے بیان کیا، ان سے عروہ نے بیان کیاکہ نبی کریم صلی اللہ علیہ وسلم فتح مکہ کے موقع پر مکہ کے بالائی علاقہ کداء کی طرف سے داخل ہوئے تھے۔ لیکن عروہ اکثر کدیٰ کی طرف سے داخل ہوتے تھے کیونکہ یہ راستہ ان کے گھر سے قریب تھا۔' WHERE id = 1527;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، انہوں نے کہا کہ ہم سے ولید بن مسلم نے بیان کیا، انہوں نے کہا کہ ہم سے امام اوزاعی نے بیان کیا، انہوں نے کہا کہ مجھ سے زہری نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ گیارہویں کی صبح کو جب نبی کریم صلی اللہ علیہ وسلم منیٰ میں تھے تو یہ فرمایا تھا کہ کل ہم خیف بنی کنانہ میں قیام کریں گے جہاں قریش نے کفر کی حمایت کی قسم کھائی تھی۔ آپ صلی اللہ علیہ وسلم کی مراد محصب سے تھی کیونکہ یہیں قریش اور کنانہ نے بنو ہاشم اور بنو عبدالمطلب یا ( راوی نے ) بنوالمطلب ( کہا ) کے خلاف حلف اٹھایا تھا کہ جب تک وہ نبی کریم صلی اللہ علیہ وسلم کو ان کے حوالہ نہ کر دیں، ان کے یہاں شادی بیاہ نہ کریں گے اور نہ ان سے خرید و فروخت کریں گے۔ اور سلامہ بن روح نے عقیل اور یحییٰ بن ضحاک سے روایت کیا، ان سے امام اوزاعی نے بیان کیا کہ مجھے ابن شہاب نے خبر دی، انہوں نے ( اپنی روایت میں ) بنو ہاشم اور بنوالمطلب کہا۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ بنوالمطلب زیادہ صحیح ہے۔' WHERE id = 1537;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے خالد بن عبداللہ نے بیان کیا، انہیں اسماعیل بن ابی خالد نے خبر دی، انہیں عبداللہ ابن ابی اوفی نے کہ رسول اللہ صلی اللہ علیہ وسلم نے عمرہ کیا تو آپ صلی اللہ علیہ وسلم نے کعبہ کا طواف کر کے مقام ابراہیم کے پیچھے دو رکعتیں پڑھیں۔ آپ صلی اللہ علیہ وسلم کے ساتھ کچھ لوگ تھے جو آپ صلی اللہ علیہ وسلم کے اور لوگوں کے درمیان آڑ بنے ہوئے تھے۔ ان میں سے ایک صاحب نے ابن ابی اوفی سے پوچھا کیا رسول اللہ صلی اللہ علیہ وسلم کعبہ کے اندر تشریف لے گئے تھے تو انہوں نے بتایا کہ ”نہیں۔“' WHERE id = 1547;
UPDATE hadiths SET urdu = 'ہم سے احمد بن سنان نے بیان کیا، ان سے یزید بن ہارون نے بیان کیا، انہیں ورقاء نے خبر دی، انہیں زید بن اسلم نے خبر دی، ان سے ان کے والد نے بیان کیا کہ میں نے دیکھا کہ عمر بن خطاب رضی اللہ عنہ نے حجر اسود کو بوسہ دیا اور پھر فرمایا کہ ”اگر میں رسول اللہ صلی اللہ علیہ وسلم کو تجھے بوسہ دیتے نہ دیکھتا تو میں کبھی تجھے بوسہ نہ دیتا۔“' WHERE id = 1557;
UPDATE hadiths SET urdu = 'ہم سے يحيىٰ بن بکیر نے بیان کیا، انہوں نے کہا کہ ہم سے لیث نے بیان کیا، انہوں نے کہا کہ ہم سے یونس نے بیان کیا، انہوں نے کہا کہ ہم سے ابن شہاب نے بیان کیا کہ مجھ سے حمید بن عبدالرحمٰن نے بیان کیا اور انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ ابوبکر صدیق رضی اللہ عنہ نے اس حج کے موقع پر جس کا امیر رسول اللہ صلی اللہ علیہ وسلم نے انہیں بنایا تھا۔ انہیں دسویں تاریخ کو ایک مجمع کے سامنے یہ اعلان کرنے کے لیے بھیجا تھا کہ اس سال کے بعد کوئی مشرک حج بیت اللہ نہیں کر سکتا اور نہ کوئی شخص ننگا رہ کر طواف کر سکتا ہے۔' WHERE id = 1568;
UPDATE hadiths SET urdu = 'اور عبدان نے کہا کہ مجھ کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں یونس نے خبر دی، انہیں زہری نے، انہوں نے کہا کہ ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ ابوذر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جب میں مکہ میں تھا تو میری ( گھر کی ) چھت کھلی اور جبرائیل علیہ السلام نازل ہوئے۔ انہوں نے میرا سینہ چاک کیا اور اسے زمزم کے پانی سے دھویا۔ اس کے بعد ایک سونے کا طشت لائے جو حکمت اور ایمان سے بھرا ہوا تھا۔ اسے انہوں نے میرے سینے میں ڈال دیا اور پھر سینہ بند کر دیا۔ اب وہ مجھے ہاتھ سے پکڑ کر آسمان دنیا کی طرف لے چلے۔ آسمان دنیا کے داروغہ سے جبرائیل علیہ السلام نے کہا دروازہ کھولو۔ انہوں نے دریافت کیا کون صاحب ہیں؟ کہا جبرائیل!۔' WHERE id = 1580;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد مروزی نے بیان کیا، انہوں نے کہا کہ ہمیں عبداللہ بن مبارک نے خبر دی، انہوں نے کہا کہ ہمیں عاصم احول نے خبر دی، انہوں نے کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے پوچھا کہ آپ لوگ صفا اور مروہ کی سعی کو برا سمجھتے تھے؟ انہوں نے فرمایا، ہاں! کیونکہ یہ عہد جاہلیت کا شعار تھا۔ یہاں تک کہ اللہ تعالیٰ نے یہ آیت نازل فرما دی ”صفا اور مروہ اللہ تعالیٰ کی نشانیاں ہیں۔ پس جو کوئی بیت اللہ کا حج یا عمرہ کرے اس پر ان کی سعی کرنے میں کوئی گناہ نہیں ہے۔“' WHERE id = 1590;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا کہ ہم سے سفیان بن عیینہ نے زہری سے بیان کیا اور ان سے سالم ابوالنصر نے بیان کیا، کہا کہ میں نے ام فضل کے غلام عمیر سے سنا، انہوں نے ام فضل رضی اللہ عنہا سے کہ عرفہ کے دن لوگوں کو رسول اللہ صلی اللہ علیہ وسلم کے روزے کے متعلق شک ہوا، اس لیے میں نے آپ کو پینے کے لیے کچھ بھیجا جسے آپ نے پی لیا۔' WHERE id = 1600;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے جویریہ نے نافع سے بیان کیا، انہوں نے کہا کہ عبداللہ بن عمر رضی اللہ عنہما مزدلفہ میں آ کر نماز مغرب اور عشاء ملا کر ایک ساتھ پڑھتے، البتہ آپ اس گھاٹی میں بھی مڑتے جہاں رسول اللہ صلی اللہ علیہ وسلم مڑے تھے۔ وہاں آپ قضائے حاجت کرتے پھر وضو کرتے لیکن نماز نہ پڑھتے، نماز آپ مزدلفہ میں آ کر پڑھتے تھے۔' WHERE id = 1610;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا کہ ہم کو سفیان ثوری نے خبر دی، کہا کہ ہم سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے قاسم نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ام المؤمنین سودہ رضی اللہ عنہا نے نبی کریم صلی اللہ علیہ وسلم سے مزدلفہ کی رات عام لوگوں سے پہلے روانہ ہونے کی اجازت چاہی آپ رضی اللہ عنہا بھاری بھر کم بدن کی عورت تھیں تو نبی کریم صلی اللہ علیہ وسلم نے انہیں اس کی اجازت دے دی۔' WHERE id = 1621;
UPDATE hadiths SET urdu = 'عروہ سے روایت ہے کہ عائشہ رضی اللہ عنہا نے انہیں نبی کریم صلی اللہ علیہ وسلم کے حج اور عمرہ ایک ساتھ کرنے کی خبر دی کہ اور لوگوں نے بھی آپ کے ساتھ حج اور عمرہ ایک ساتھ کیا تھا، بالکل اسی طرح جیسے مجھے سالم نے ابن عمر رضی اللہ عنہما سے اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے خبر دی تھی۔' WHERE id = 1632;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے زکریا نے بیان کیا، ان سے عامر نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کی قربانی کے لیے خود قلادے بٹے ہیں۔ ان کی مراد احرام سے پہلے کے قلادوں سے تھی۔' WHERE id = 1643;
UPDATE hadiths SET urdu = 'ہم سے سہل بن بکار نے بیان کیا، کہا کہ ہم سے وہیب نے بیان کیا، ان سے ایوب نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ظہر کی نماز مدینہ میں چار رکعت پڑھی اور عصر کی ذو الحلیفہ میں دو رکعات۔ رات آپ صلی اللہ علیہ وسلم نے وہیں گزاری، پھر جب صبح ہوئی تو آپ صلی اللہ علیہ وسلم اپنی اونٹنی پر سوار ہو کر تہلیل و تسبیح کرنے لگے۔ جب بیداء پہنچے تو آپ صلی اللہ علیہ وسلم نے دونوں ( حج و عمرہ ) کے لیے ایک ساتھ تلبیہ کہا، جب مکہ پہنچے ( اور عمرہ ادا کر لیا ) تو صحابہ رضی اللہ عنہم کو حکم دیا کہ حلال ہو جائیں۔ نبی کریم صلی اللہ علیہ وسلم نے خود اپنے ہاتھ سے سات اونٹ کھڑے کر کے نحر کئے اور مدینہ میں دو چتکبرے سینگوں والے مینڈھے ذبح کئے۔' WHERE id = 1653;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا کہ مجھے میرے باپ عثمان نے خبر دی، انہیں شعبہ نے، انہیں قیس بن مسلم نے، انہیں طارق بن شہاب نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ بطحاء میں تھے۔ ( جو مکہ کے قریب ایک جگہ ہے ) آپ صلی اللہ علیہ وسلم نے پوچھا کیا تو نے حج کی نیت کی ہے؟ میں نے کہا کہ ہاں، آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تو نے احرام کس چیز کا باندھا ہے میں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم کے احرام کی طرح باندھا ہے، آپ صلی اللہ علیہ وسلم نے فرمایا کہ تو نے اچھا کیا اب جا۔ چنانچہ ( مکہ پہنچ کر ) میں نے بیت اللہ کا طواف کیا اور صفا و مروہ کی سعی کی، پھر میں بنو قیس کی ایک خاتون کے پاس آیا اور انہوں نے میرے سر کی جوئیں نکالی۔ اس کے بعد میں نے حج کی لبیک پکاری۔ اس کے بعد میں عمر رضی اللہ عنہ کے عہد خلافت تک اسی کا فتویٰ دیتا رہا پھر جب میں نے عمر رضی اللہ عنہ سے اس کا ذکر کیا تو آپ رضی اللہ عنہ نے فرمایا کہ ہمیں کتاب اللہ پر بھی عمل کرنا چاہئے اور اس میں پورا کرنے کا حکم ہے، پھر رسول اللہ صلی اللہ علیہ وسلم کی سنت پر بھی عمل کرنا چاہئے اور نبی کریم صلی اللہ علیہ وسلم قربانی سے پہلے حلال نہیں ہوئے تھے۔' WHERE id = 1663;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، ان سے وہیب نے بیان کیا، ان سے ابن طاؤس نے بیان کیا، ان سے ان کے باپ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم سے قربانی کرنے، سر منڈانے، رمی جمار کرنے اور ان سے آگے پیچھے کرنے کے بارے میں دریافت کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی حرج نہیں۔' WHERE id = 1673;
UPDATE hadiths SET urdu = '(دوسری سند) اور ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے محمد بن بکر نے بیان کیا، کہا ہم کو ابن جریج نے خبر دی، انہیں عبیداللہ نے، انہیں نافع نے اور انہیں ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اجازت دی۔' WHERE id = 1683;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے بیان کیا کہ میں نے عائشہ رضی اللہ عنہا سے سنا، وہ فرماتی تھیں کہ میں نے خود اپنے ہاتھوں سے رسول اللہ صلی اللہ علیہ وسلم کے، جب آپ نے احرام باندھنا چاہا، خوشبو لگائی تھی اس طرح کھولتے وقت بھی جب آپ نے طواف الزیارۃ سے پہلے احرام کھولنا چاہا تھا ( آپ نے ہاتھ پھیلا کر خوشبو لگانے کی کیفیت بتائی ) ۔' WHERE id = 1693;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے بیان کیا، انہوں نے کہا کہ ہم سے خالد بن حارث نے بیان کیا، انہوں نے کہا کہ عبیداللہ سے محصب کے بارے میں پوچھا گیا تو انہوں نے نافع سے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم اور عمر اور ابن عمر رضی اللہ عنہم نے محصب میں قیام فرمایا تھا۔ نافع سے روایت ہے کہ عبداللہ بن عمر رضی اللہ عنہما محصب میں ظہر اور عصر پڑھتے تھے۔ میرا خیال ہے کہ انہوں نے مغرب ( پڑھنے کا بھی ) ذکر کیا، خالد نے بیان کیا کہ عشاء میں مجھے کوئی شک نہیں۔ اس کے پڑھنے کا ذکر ضرور کیا پھر تھوڑی دیر کے لیے وہاں سو رہتے نبی کریم صلی اللہ علیہ وسلم سے بھی ایسا ہی مذکور ہے۔' WHERE id = 1705;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن قطان نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء بن ابی رباح نے بیان کیا کہ میں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، انہوں نے ہمیں خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک انصاری خاتون ( ام سنان رضی اللہ عنہا ) سے ( ابن عباس رضی اللہ عنہما نے ان کا نام بتایا تھا لیکن مجھے یاد نہ رہا ) پوچھا کہ تو ہمارے ساتھ حج کیوں نہیں کرتی؟ وہ کہنے لگی کہ ہمارے پاس ایک اونٹ تھا، جس پر ابوفلاں ( یعنی اس کا خاوند ) اور اس کا بیٹا سوار ہو کر حج کے لیے چل دیئے اور ایک اونٹ انہوں نے چھوڑا ہے، جس سے پانی لایا جاتا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کے اچھا جب رمضان آئے تو عمرہ کر لینا کیونکہ رمضان کا عمرہ ایک حج کے برابر ہوتا ہے یا اسی جیسی کوئی بات آپ صلی اللہ علیہ وسلم نے فرمائی۔' WHERE id = 1717;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، ان سے غندر بن محمد بن جعفر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے قیس بن مسلم نے بیان کیا، ان سے طارق بن شہاب نے بیان کیا، اور ان سے ابوموسیٰ اشعری نے بیان کیا، انہوں نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بطحاء میں حاضر ہوا آپ وہاں ( حج کے لیے جاتے ہوئے اترے ہوئے تھے ) آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا تمہارا حج ہی کا ارادہ ہے؟ میں نے کہا، جی ہاں۔ آپ صلی اللہ علیہ وسلم نے پوچھا اور احرام کس چیز کا باندھا ہے؟ میں نے کہا میں نے اسی کا احرام باندھا ہے، جس کا نبی کریم صلی اللہ علیہ وسلم نے احرام باندھا ہو، آپ صلی اللہ علیہ وسلم نے فرمایا تو نے اچھا کیا، اب بیت اللہ کا طواف اور صفا اور مروہ کی سعی کر لے پھر احرام کھول ڈال، چنانچہ میں نے بیت اللہ کا طواف کیا اور صفا اور مروہ کی سعی، پھر میں بنو قیس کی ایک عورت کے پاس آیا اور انہوں نے میرے سر کی جوئیں نکالیں، اس کے بعد میں نے حج کا احرام باندھا۔ میں ( نبی کریم صلی اللہ علیہ وسلم کی وفات کے بعد ) اسی کے مطابق لوگوں کو مسئلہ بتایا کرتا تھا، جب عمر رضی اللہ عنہ کی خلافت کا دور آیا تو آپ رضی اللہ عنہ نے فرمایا کہ ہمیں کتاب اللہ پر عمل کرنا چاہے کہ اس میں ہمیں ( حج اور عمرہ ) پورا کرنے کا حکم ہوا ہے اور رسول اللہ صلی اللہ علیہ وسلم کی سنت پر عمل کرنا چاہیے کہ اس وقت آپ صلی اللہ علیہ وسلم نے احرام نہیں کھولا تھا جب تک ہدی کی قربانی نہیں ہو گئی تھی۔ لہٰذا ہدی ساتھ لانے والوں کے واسطے ایسا ہی کرنے کا حکم ہے۔' WHERE id = 1728;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہوں نے کہا کہ مجھے زید بن اسلم نے خبر دی، ان سے ان کے باپ نے بیان کیا کہ میں عبداللہ بن عمر رضی اللہ عنہما کے ساتھ مکہ کے راستے میں تھا کہ انہیں ( اپنی بیوی ) صفیہ بنت ابی عبید کی سخت بیماری کی خبر ملی اور وہ نہایت تیزی سے چلنے لگے، پھر جب سرخی غروب ہو گئی تو سواری سے نیچے اترے اور مغرب اور عشاء ایک ساتھ ملا کر پڑھیں، اس کے بعد فرمایا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا کہ جب جلدی چلنا ہوتا تو مغرب میں دیر کر کے دونوں ( عشاء اور مغرب ) کو ایک ساتھ ملا کر پڑھتے تھے۔' WHERE id = 1738;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، انہوں نے کہا کہ مجھ سے مجاہد نے بیان کیا، انہوں نے کہا کہ میں نے عبدالرحمٰن بن ابی لیلیٰ سے سنا، ان سے کعب بن عجرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم حدیبیہ میں میرے پاس آ کر کھڑے ہوئے تو جوئیں میرے سر سے برابر گر رہی تھیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا یہ جوئیں تو تمہارے لیے تکلیف دہ ہیں۔ میں نے کہا جی ہاں، آپ صلی اللہ علیہ وسلم نے فرمایا پھر سر منڈا لے یا آپ صلی اللہ علیہ وسلم نے صرف یہ لفظ فرمایا کہ منڈا لے۔ انہوں نے بیان کیا کہ یہ آیت میرے ہی بارے میں نازل ہوئی تھی کہ ”اگر تم میں کوئی مریض ہو یا اس کے سر میں کوئی تکلیف ہو“ آخر آیت تک، پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا تین دن کے روزے رکھ لے یا ایک فرق غلہ سے چھ مسکینوں کو کھانا دے یا جو میسر ہو اس کی قربانی کر دے۔' WHERE id = 1748;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عبیداللہ بن عبداللہ بن عتبہ بن مسعود نے، انہیں عبداللہ بن عباس رضی اللہ عنہما نے اور انہیں صعب بن جثامہ لیثی رضی اللہ عنہ نے کہ جب وہ ابواء یا ودان میں تھے تو انہوں نے رسول اللہ صلی اللہ علیہ وسلم کو ایک گورخر کا تحفہ دیا تو آپ نے اسے واپس کر دیا تھا، پھر جب آپ نے ان کے چہروں پر ناراضگی کا رنگ دیکھا تو آپ نے فرمایا واپسی کی وجہ صرف یہ ہے کہ ہم احرام باندھے ہوئے ہیں۔' WHERE id = 1758;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ عمرو بن دینار نے بیان کیا پہلی بات میں نے جو عطاء بن ابی رباح سے سنی تھی، انہوں نے بیان کیا کہ میں نے عبداللہ بن عباس رضی اللہ عنہما سے سنا، وہ کہہ رہے تھے کہ رسول اللہ صلی اللہ علیہ وسلم جب محرم تھے اس وقت آپ نے پچھنا لگوایا تھا۔ پھر میں نے انہیں یہ کہتے سنا کہ مجھ سے ابن عباس رضی اللہ عنہما سے طاؤس نے یہ حدیث بیان کی تھی۔ اس سے میں نے یہ سمجھا کہ شاید انہوں نے ان دونوں حضرات سے یہ حدیث سنی ہو گی ( متکلم عمرو ہیں اور دونوں حضرات سے مراد عطاء اور طاؤس رحمۃ اللہ علیہما ہیں ) ۔' WHERE id = 1768;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے وہیب نے بیان کیا ان سے عبداللہ بن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے مدینہ والوں کے لیے ذو الحلیفہ کو میقات بنایا، نجد والوں کے لیے قرن المنازل کو اور یمن والوں کے لیے یلملم کو۔ یہ میقات ان ملکوں کے باشندوں کے لیے ہے اور دوسرے ان تمام لوگوں کے لیے بھی جو ان ملکوں سے ہو کر مکہ آئیں اور حج اور عمرہ کا بھی ارادہ رکھتے ہوں، لیکن جو لوگ ان حدود کے اندر ہوں تو ان کی میقات وہی جگہ ہے جہاں سے وہ اپنا سفر شروع کریں یہاں تک کہ مکہ والوں کی میقات مکہ ہی ہے۔' WHERE id = 1778;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے ابن شہاب زہری نے، ان سے سلیمان بن یسار نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ فضل بن عباس رضی اللہ عنہما رسول اللہ صلی اللہ علیہ وسلم کی سواری پر پیچھے بیٹھے ہوئے تھے۔ اتنے میں قبیلہ خشعم کی ایک عورت آئی۔ فضل رضی اللہ عنہ اس کو دیکھنے لگے اور وہ فضل رضی اللہ عنہ کو دیکھنے لگی۔ اس لیے نبی کریم صلی اللہ علیہ وسلم فضل کا چہرہ دوسری طرف پھیرنے لگے، اس عورت نے کہا کہ اللہ کا فریضہ ( حج ) نے میرے بوڑھے والد کو اس حالت میں پا لیا ہے کہ وہ سواری پر بیٹھ بھی نہیں سکتے تو کیا میں ان کی طرف سے حج کر سکتی ہوں، آپ نے فرمایا کہ ہاں۔ یہ حجۃ الوداع کا واقعہ ہے۔' WHERE id = 1788;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہمیں مروان فزاری نے خبر دی، انہیں حمید طویل نے، انہوں نے بیان کیا کہ مجھ سے ثابت نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک بوڑھے شخص کو دیکھا جو اپنے دو بیٹوں کا سہارا لیے چل رہا ہے۔ آپ صلی اللہ علیہ وسلم نے پوچھا ان صاحب کا کیا حال ہے؟ لوگوں نے بتایا کہ انہوں نے کعبہ کو پیدل چلنے کی منت مانی ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ اس سے بےنیاز ہے کہ یہ اپنے کو تکلیف میں ڈالیں پھر آپ صلی اللہ علیہ وسلم نے انہیں سوار ہونے کا حکم دیا۔' WHERE id = 1798;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہمیں امام مالک نے خبر دی، انہیں ہشام بن عروہ نے، انہیں ان کے والد عروہ بن زبیر نے خبر دی، انہیں عبداللہ بن زبیر رضی اللہ عنہما نے اور ان سے سفیان بن ابی زہیر رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا کہ آپ نے فرمایا کہ یمن فتح ہو گا تو لوگ اپنی سواریوں کو دوڑاتے ہوئے لائیں گے اور اپنے گھر والوں کو اور ان کو جو ان کی بات مان جائیں گے سوار کر کے مدینہ سے ( واپس یمن کو ) لے جائیں گے کاش! انہیں معلوم ہوتا کہ مدینہ ہی ان کے لیے بہتر تھا اور عراق فتح ہو گا تو کچھ لوگ اپنی سواریوں کو تیز دوڑاتے ہوئے لائیں گے اور اپنے گھر والوں کو اور جو ان کی بات مانیں گے اپنے ساتھ ( عراق واپس ) لے جائیں گے کاش! انہیں معلوم ہوتا کہ مدینہ ہی ان کے لیے بہتر تھا۔' WHERE id = 1808;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے وہب بن جریر نے بیان کیا، ان سے ان کے والد نے بیان کیا، انہوں نے یونس بن شہاب سے سنا اور انہوں نے انس رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کے اے اللہ! جتنی مکہ میں برکت عطا فرمائی ہے مدینہ میں اس سے دگنی برکت کر۔ جریر کے ساتھ اس روایت کی متابعت عثمان بن عمر نے یونس کے واسطہ کے ساتھ کی ہے۔' WHERE id = 1818;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے جامع بن راشد نے بیان کیا، ان سے ابووائل نے اور ان سے حذیفہ رضی اللہ عنہ نے کہ عمر رضی اللہ عنہ نے پوچھا فتنہ کے متعلق رسول اللہ صلی اللہ علیہ وسلم کی حدیث کسی کو یاد ہے؟ حذیفہ رضی اللہ عنہ نے بیان کیا کہ میں نے سنا ہے، آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ انسان کے لیے اس کے بال بچے، اس کا مال اور اس کے پڑوسی فتنہ ( آزمائش و امتحان ) ہیں جس کا کفارہ نماز روزہ اور صدقہ بن جاتا ہے۔ عمر رضی اللہ عنہ نے کہا کہ میں اس کے متعلق نہیں پوچھتا میری مراد تو اس فتنہ سے ہے جو سمندر کی موجوں کی طرح امنڈ آئے گا۔ اس پر حذیفہ رضی اللہ عنہ نے کہا کہ آپ کے اور اس فتنہ کے درمیان ایک بند دروازہ ہے۔ ( یعنی آپ کے دور میں وہ فتنہ شروع نہیں ہو گا ) عمر رضی اللہ عنہ نے پوچھا وہ دروازہ کھل جائے گا یا توڑ دیا جائے گا؟ حذیفہ رضی اللہ عنہ نے بتایا کہ توڑ دیا جائے گا۔ عمر رضی اللہ عنہ نے فرمایا کہ پھر تو قیامت تک کبھی بند نہ ہو پائے گا۔ ہم نے مسروق سے کہا آپ حذیفہ رضی اللہ عنہ سے پوچھئے کہ کیا عمر رضی اللہ عنہ کو معلوم تھا کہ وہ دروازہ کون ہے، چنانچہ مسروق نے پوچھا تو آپ رضی اللہ عنہ نے فرمایا ہاں! بالکل اس طرح ( انہیں علم تھا ) جیسے رات کے بعد دن کے آنے کا علم ہوتا ہے۔' WHERE id = 1828;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ نے، ان سے اعمش نے، ان سے ابراہیم نے ان سے علقمہ نے بیان کیا کہ میں عبداللہ بن مسعود رضی اللہ عنہ کے ساتھ جا رہا تھا۔ آپ نے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے تو آپ صلی اللہ علیہ وسلم نے فرمایا اگر کوئی صاحب طاقت ہو تو اسے نکاح کر لینا چاہئے کیونکہ نظر کو نیچی رکھنے اور شرمگاہ کو بدفعلی سے محفوظ رکھنے کا یہ ذریعہ ہے اور کسی میں نکاح کرنے کی طاقت نہ ہو تو اسے روزے رکھنے چاہئیں کیونکہ وہ اس کی شہوت کو ختم کر دیتا ہے۔' WHERE id = 1838;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے، ان سے ابواسحاق نے اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ ( شروع اسلام میں ) محمد صلی اللہ علیہ وسلم کے صحابہ رضی اللہ عنہم جب روزہ سے ہوتے اور افطار کا وقت آتا تو کوئی روزہ دار اگر افطار سے پہلے بھی سو جاتا تو پھر اس رات میں بھی اور آنے والے دن میں بھی انہیں کھانے پینے کی اجازت نہیں تھی تاآنکہ پھر شام ہو جاتی، پھر ایسا ہوا کہ قیس بن صرمہ انصاری رضی اللہ عنہ بھی روزے سے تھے جب افطار کا وقت ہوا تو وہ اپنی بیوی کے پاس آئے اور ان سے پوچھا کیا تمہارے پاس کچھ کھانا ہے؟ انہوں نے کہا ( اس وقت کچھ ) نہیں ہے لیکن میں جاتی ہوں کہیں سے لاؤں گی، دن بھر انہوں نے کام کیا تھا اس لیے آنکھ لگ گئی جب بیوی واپس ہوئیں اور انہیں ( سوتے ہوئے ) دیکھا تو فرمایا افسوس تم محروم ہی رہے، لیکن دوسرے دن وہ دوپہر کو بیہوش ہو گئے جب اس کا ذکر نبی کریم صلی اللہ علیہ وسلم سے کیا گیا تو یہ آیت نازل ہوئی ”حلال کر دیا گیا تمہارے لیے رمضان کی راتوں میں اپنی بیویوں سے صحبت کرنا“ اس پر صحابہ رضی اللہ عنہم بہت خوش ہوئے اور یہ آیت نازل ہوئی ”کھاؤ پیو یہاں تک کہ ممتاز ہو جائے تمہارے لیے صبح کی سفید دھاری ( صبح صادق ) سیاہ دھاری ( صبح کاذب ) سے۔“' WHERE id = 1848;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ بن سعیدقطان نے بیان کیا، ان سے ہشام بن ابی عبداللہ نے، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ نے، ان سے ام سلمہ رضی اللہ عنہا کی بیٹی زینب نے اور ان سے ان کی والدہ (ام سلمہ رضی اللہ عنہا) نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ایک چادر میں ( لیٹی ہوئی ) تھی کہ مجھے حیض آ گیا۔ اس لیے میں چپکے سے نکل آئی اور اپنا حیض کا کپڑا پہن لیا۔ آپ صلی اللہ علیہ وسلم نے پوچھا کیا بات ہوئی؟ کیا حیض آ گیا ہے؟ میں نے کہا ہاں، پھر میں آپ صلی اللہ علیہ وسلم کے ساتھ اسی چادر میں چلی گئی اور ام سلمہ رضی اللہ عنہا اور رسول اللہ صلی اللہ علیہ وسلم ایک ہی برتن سے غسل ( جنابت ) کیا کرتے تھے اور نبی کریم صلی اللہ علیہ وسلم روزے سے ہونے کے باوجود ان کا بوسہ لیتے تھے۔' WHERE id = 1860;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے ابواسحاق شیبانی نے، انہوں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا کہا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ سفر میں تھے ( روزہ کی حالت میں ) نبی کریم صلی اللہ علیہ وسلم نے ایک صاحب ( بلال رضی اللہ عنہ ) سے فرمایا کہ اتر کر میرے لیے ستو گھول لے، انہوں نے عرض کی یا رسول اللہ! ابھی تو سورج باقی ہے، آپ صلی اللہ علیہ وسلم نے پھر فرمایا کہ اتر کر ستو گھول لے، اب کی مرتبہ بھی انہوں نے عرض کی یا رسول اللہ! ابھی سورج باقی ہے لیکن آپ کا حکم اب بھی یہی تھا کہ اتر کر میرے لیے ستو گھول لے، پھر آپ صلی اللہ علیہ وسلم نے ایک طرف اشارہ کر کے فرمایا جب تم دیکھو کہ رات یہاں سے شروع ہو چکی ہے تو روزہ دار کو افطار کر لینا چاہئے۔ اس کی متابعت جریر اور ابوبکر بن عیاش نے شیبانی کے واسطہ سے کی ہے اور ان سے ابواوفی رضی اللہ عنہ نے کہا کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ سفر میں تھا۔' WHERE id = 1871;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا کہ مجھ سے زید بن اسلم نے بیان کیا، ان سے عیاض نے اور ان سے ابوسعید رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کیا جب عورت حائضہ ہوتی ہے تو نماز اور روزے نہیں چھوڑ دیتی؟ یہی اس کے دین کا نقصان ہے۔' WHERE id = 1881;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، ان سے لیث بن سعد نے بیان کیا، ان سے یزید بن ہاد نے بیان کیا، ان سے عبداللہ بن خباب نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے، انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا کہ آپ صلی اللہ علیہ وسلم نے فرمایا مسلسل ( بلاسحری و افطاری ) روزے نہ رکھو، ہاں اگر کوئی ایسا کرنا ہی چاہے تو وہ سحری کے وقت تک ایسا کر سکتا ہے۔ صحابہ رضی اللہ عنہم نے عرض کی یا رسول اللہ! آپ تو ایسا کرتے ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا میں تمہاری طرح نہیں ہوں۔ میں تو رات اس طرح گزارتا ہوں کہ ایک کھلانے والا مجھے کھلاتا ہے اور ایک پلانے والا مجھے پلاتا ہے۔' WHERE id = 1893;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا کہ ہم کو ابوخالد احمر نے خبر دی، کہا کہ ہم کو حمید نے خبر دی، کہا کہ میں نے انس رضی اللہ عنہ سے نبی کریم صلی اللہ علیہ وسلم کے روزوں کے متعلق پوچھا۔ آپ نے فرمایا کہ جب بھی میرا دل چاہتا کہ آپ کو روزے سے دیکھوں تو میں آپ کو روزے سے ہی دیکھتا۔ اور بغیر روزے کے چاہتا تو بغیر روزے سے ہی دیکھتا۔ رات میں کھڑے ( نماز پڑھتے ) دیکھنا چاہتا تو اسی طرح نماز پڑھتے دیکھتا۔ اور سوتے ہوئے دیکھنا چاہتا تو اسی طرح دیکھتا۔ میں نے نبی کریم صلی اللہ علیہ وسلم کے مبارک ہاتھوں سے زیادہ نرم و نازک ریشم کے کپڑوں کو بھی نہیں دیکھا۔ اور نہ مشک و عنبر کو آپ کی خوشبو سے زیادہ خوشبودار پایا۔' WHERE id = 1903;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، انہوں نے کہا ہم سے مہدی نے بیان کیا، انہوں نے کہا کہ ہم سے غیلان نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے ابوالنعمان نے بیان کیا، انہوں نے کہا کہ ہم سے مہدی بن میمون نے، ان سے غیلان بن جریر نے، ان سے مطرف نے، ان سے عمران بن حصین رضی اللہ عنہما نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سوال کیا یا ( مطرف نے یہ کہا کہ ) سوال تو کسی اور نے کیا تھا لیکن وہ سن رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اے ابوفلاں! کیا تم نے اس مہینے کے آخر کے روزے رکھے؟ ابونعمان نے کہا کہ میرا خیال ہے کہ راوی نے کہا کہ آپ کی مراد رمضان سے تھی۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) کہتے ہیں کہ ثابت نے بیان کیا، ان سے مطرف نے، ان سے عمران رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے ( رمضان کے آخر کے بجائے ) شعبان کے آخر میں کا لفظ بیان کیا ( یہی صحیح ہے ) ۔' WHERE id = 1913;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے عبدالملک بن عمیر نے بیان کیا، کہا کہ میں نے قزعہ سے سنا، انہوں نے کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے سنا، آپ نبی کریم صلی اللہ علیہ وسلم کے ساتھ بارہ جہادوں میں شریک رہے تھے۔ انہوں نے کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے چار باتیں سنی ہیں جو مجھے بہت ہی پسند آئیں۔ آپ نے فرمایا کہ کوئی عورت دو دن ( یا اس سے زیادہ ) کے اندازے کا سفر اس وقت تک نہ کرے جب تک اس کے ساتھ اس کا شوہر یا کوئی اور محرم نہ ہو۔ اور عیدالفطر اور عید الاضحی کے دنوں میں روزہ رکھنا جائز نہیں ہے اور صبح کی نماز کے بعد سورج نکلنے تک اور عصر کی نماز کے بعد سورج ڈوبنے تک کوئی نماز جائز نہیں اور چوتھی بات یہ کہ تین مساجد کے سوا اور کسی جگہ کے لیے «شد الرحال» سفر نہ کیا جائے، ”مسجد الحرام، مسجد الاقصیٰ اور میری یہ مسجد ( مسجد نبوی ) ۔' WHERE id = 1924;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا کہ ہم سے یزید بن ابی عبید نے بیان کیا، ان سے سلمہ بن اکوع رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے بنو اسلم کے ایک شخص کو لوگوں میں اس بات کے اعلان کا حکم دیا تھا کہ جو کھا چکا ہو وہ دن کے باقی حصے میں بھی کھانے پینے سے رکا رہے اور جس نے نہ کھایا ہو اسے روزہ رکھ لینا چاہئے کیونکہ یہ عاشوراء کا دن ہے۔' WHERE id = 1935;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، کہا کہ ہم سے ابوسہیل نے بیان کیا، ان سے ان کے باپ مالک بن عامر نے اور ان سے عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، شب قدر کو رمضان کے آخری عشرہ کی طاق راتوں میں ڈھونڈو۔' WHERE id = 1945;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے یزید بن عبداللہ بن ہاد نے بیان کیا، ان سے محمد بن ابراہیم بن حارث تیمی نے بیان کیا، ان سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا، ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم رمضان کے دوسرے عشرے میں اعتکاف کیا کرتے تھے۔ ایک سال آپ صلی اللہ علیہ وسلم نے انہی دنوں میں اعتکاف کیا اور جب اکیسویں تاریخ کی رات آئی۔ یہ وہ رات ہے جس کی صبح آپ صلی اللہ علیہ وسلم اعتکاف سے باہر آ جاتے تھے، تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے میرے ساتھ اعتکاف کیا ہو وہ اب آخری عشرے میں بھی اعتکاف کرے۔ مجھے یہ رات ( خواب میں ) دکھائی گئی، لیکن پھر بھلا دی گئی۔ میں نے یہ بھی دیکھا کہ اسی کی صبح کو میں کیچڑ میں سجدہ کر رہا ہوں، اس لیے تم لوگ اسے آخری عشرہ کی طاق رات میں تلاش کرو، چنانچہ اسی رات بارش ہوئی، مسجد کی چھت چوں کہ کھجور کی شاخ سے بنی تھی اس لیے ٹپکنے لگی اور خود میں نے اپنی آنکھوں سے دیکھا کہ اکیسویں کی صبح کو رسول اللہ صلی اللہ علیہ وسلم کی پیشانی مبارک پر کیچڑ لگی ہوئی تھی۔' WHERE id = 1955;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا کہ مجھے میرے بھائی نے خبر دی، انہیں سلیمان نے، انہیں محمد بن ابی عتیق نے، انہیں ابن شہاب نے، انہیں علی بن حسین رضی اللہ عنہ نے کہ صفیہ رضی اللہ عنہا نے انہیں خبر دی (دوسری سند) اور ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، کہا کہ میں نے زہری سے سنا۔ وہ علی بن حسین رضی اللہ عنہ سے خبر دیتے تھے کہ صفیہ رضی اللہ عنہا نبی کریم صلی اللہ علیہ وسلم کے یہاں آئیں۔ آپ صلی اللہ علیہ وسلم اس وقت اعتکاف میں تھے۔ پھر جب وہ واپس ہونے لگیں تو آپ بھی ان کے ساتھ ( تھوڑی دور تک انہیں چھوڑنے ) آئے۔ ( آتے ہوئے ) ایک انصاری صحابی رضی اللہ عنہ نے آپ کو دیکھا۔ جب نبی کریم صلی اللہ علیہ وسلم کی نظر ان پر پڑی، تو فوراً آپ صلی اللہ علیہ وسلم نے انہیں بلایا، کہ سنو! یہ ( میری بیوی ) صفیہ رضی اللہ عنہا ہیں۔ ( سفیان نے ہی صفیہ کے بجائے بعض اوقات «هذه صفية» کے الفاظ کہے۔ ( اس کی وضاحت اس لیے ضروری سمجھی ) کہ شیطان انسان کے جسم میں خون کی طرح دوڑتا رہتا ہے۔ میں ( علی بن عبداللہ ) نے سفیان سے پوچھا کہ غالباً وہ رات کو آئی ہوں گی؟ تو انہوں نے فرمایا کہ رات کے سوا اور وقت ہی کون سا ہو سکتا تھا۔' WHERE id = 1966;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، ان سے زہیر نے بیان کیا، ان سے حمید نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب عبدالرحمٰن بن عوف رضی اللہ عنہ مدینہ آئے، تو رسول اللہ صلی اللہ علیہ وسلم نے ان کا بھائی چارہ سعد بن ربیع انصاری رضی اللہ عنہ سے کرا دیا۔ سعد رضی اللہ عنہ مالدار آدمی تھے۔ انہوں نے عبدالرحمٰن رضی اللہ عنہ سے کہا میں اور آپ میرے مال سے آدھا آدھا لے لیں۔ اور میں ( اپنی ایک بیوی سے ) آپ کی شادی کرا دوں۔ عبدالرحمٰن رضی اللہ عنہ نے اس کے جواب میں کہا اللہ تعالیٰ آپ کے اہل اور آپ کے مال میں برکت عطا فرمائے، مجھے تو آپ بازار کا راستہ بتا دیجئیے، پھر وہ بازار سے اس وقت تک واپس نہ ہوئے جب تک نفع میں کافی پنیر اور گھی نہ بچا لیا۔ اب وہ اپنے گھر والوں کے پاس آئے کچھ دن گزرے ہوں گے یا اللہ نے جتنا چاہا۔ اس کے بعد وہ آئے کہ ان پر زردی کا نشان تھا۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا یہ زردی کیسی ہے؟ عرض کیا، یا رسول اللہ! میں نے ایک انصاری عورت سے شادی کر لی ہے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ انہیں مہر میں کیا دیا ہے؟ عرض کیا ”سونے کی ایک گٹھلی“ یا ( یہ کہا کہ ) ”ایک گٹھلی برابر سونا“ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا اب ولیمہ کر، اگرچہ ایک بکری ہی کا ہو۔' WHERE id = 1976;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے ابن ابی ذئب نے بیان کیا، کہا کہ ہم سے سعید مقبری نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا لوگوں پر ایک ایسا زمانہ آئے گا کہ انسان کوئی پرواہ نہیں کرے گا کہ جو اس نے حاصل کیا ہے وہ حلال سے ہے یا حرام سے ہے۔' WHERE id = 1986;
UPDATE hadiths SET urdu = 'مجھ سے محمد نے بیان کیا، کہا کہ ہم سے عبداللہ بن یزید نے بیان کیا، ان سے سعید بن ابی ایوب نے بیان کیا، کہا کہ مجھ سے ابوالاسود نے بیان کیا، ان سے عروہ نے کہ عائشہ رضی اللہ عنہا نے فرمایا کہ رسول اللہ صلی اللہ علیہ وسلم کے صحابہ رضی اللہ عنہم اپنے کام اپنے ہی ہاتھوں سے کیا کرتے تھے اور ( زیادہ محنت و مشقت کی وجہ سے ) ان کے جسم سے ( پسینے کی ) بو آ جاتی تھی۔ اس لیے ان سے کہا گیا کہ اگر تم غسل کر لیا کرو تو بہتر ہو گا۔ اس کی روایت ہمام نے اپنے والد سے اور انہوں نے اپنے باپ سے اور انہوں نے عائشہ رضی اللہ عنہا سے کی ہے۔' WHERE id = 1997;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا کہ مجھ سے میرے باپ نے بیان کیا، کہ ہم سے اعمش نے بیان کیا، کہا کہ مجھ سے شقیق نے بیان کیا، اور ان سے ابومسعود رضی اللہ عنہ نے کہ انصار میں سے ایک صحابی جن کی کنیت ابوشعیب رضی اللہ عنہ تھی، تشریف لائے اور اپنے غلام سے جو قصاب تھا۔ فرمایا کہ میرے لیے اتنا کھانا تیار کر جو پانچ آدمی کے لیے کافی ہو۔ میں نے نبی کریم صلی اللہ علیہ وسلم کی اور آپ کے ساتھ اور چار آدمیوں کی دعوت کا ارادہ کیا، کیونکہ میں نے آپ صلی اللہ علیہ وسلم کے چہرہ مبارک پر بھوک کا اثر نمایاں دیکھا ہے۔ چنانچہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کو بلایا۔ آپ صلی اللہ علیہ وسلم کے ساتھ ایک اور صاحب بھی آ گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہمارے ساتھ ایک اور صاحب زائد آ گئے ہیں۔ مگر آپ چاہیں تو انہیں بھی اجازت دے سکتے ہیں، اور اگر چاہیں تو واپس کر سکتے ہیں۔ انہوں نے کہا کہ نہیں، بلکہ میں انہیں بھی اجازت دیتا ہوں۔' WHERE id = 2007;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا کہ ہم سے محمد بن ابی عدی نے بیان کیا، ان سے شعبہ نے، ان سے سلیمان نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے اور ان سے خباب بن ارت رضی اللہ عنہ نے کہ جاہلیت کے زمانہ میں میں لوہار کا کام کیا کرتا تھا۔ عاص بن وائل ( کافر ) پر میرا کچھ قرض تھا میں ایک دن اس پر تقاضا کرنے گیا۔ اس نے کہا کہ جب تک تو محمد صلی اللہ علیہ وسلم کا انکار نہیں کرے گا میں تیرا قرض نہیں دوں گا۔ میں نے جواب دیا کہ میں آپ کا انکار اس وقت تک نہیں کروں گا جب تک اللہ تعالیٰ تیری جان نہ لے لے، پھر تو دوبارہ اٹھایا جائے، اس نے کہا کہ پھر مجھے بھی مہلت دے کہ میں مر جاؤں، پھر دوبارہ اٹھایا جاؤں اور مجھے مال اور اولاد ملے اس وقت میں بھی تمہارا قرض ادا کر دوں گا۔ اس پر آیت نازل ہوئی «أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا * أطلع الغيب أم اتخذ عند الرحمن عهدا» ”کیا تم نے اس شخص کو دیکھا جس نے ہماری آیات کو نہ مانا اور کہا ( آخرت میں ) مجھے مال اور دولت دی جائے گی، کیا اسے غیب کی خبر ہے؟ یا اس نے اللہ تعالیٰ کے ہاں سے کوئی اقرار لے لیا ہے۔“' WHERE id = 2017;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا کہ ہم سے عبدالواحد نے بیان کیا، انہوں نے کہا کہ ہم سے ابوبردہ بن عبداللہ نے بیان کیا، انہوں نے کہا کہ میں نے ابوبردہ بن ابی موسیٰ سے سنا اور ان سے ان کے والد موسیٰ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا نیک ساتھی اور برے ساتھی کی مثال کستوری بیچنے والے عطار اور لوہار کی سی ہے۔ مشک بیچنے والے کے پاس سے تم دو اچھائیوں میں سے ایک نہ ایک ضرور پا لو گے۔ یا تو مشک ہی خرید لو گے ورنہ کم از کم اس کی خوشبو تو ضرور ہی پا سکو گے۔ لیکن لوہار کی بھٹی یا تمہارے بدن اور کپڑے کو جھلسا دے گی ورنہ بدبو تو اس سے تم ضرور پا لو گے۔' WHERE id = 2027;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی، انہیں نافع نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، خریدنے اور بیچنے والے دونوں کو اس وقت تک اختیار ہوتا ہے، جب تک وہ ایک دوسرے سے جدا نہ ہوں۔ مگر بیع خیار میں۔' WHERE id = 2037;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا کہ ہم سے زبیر نے بیان کیا، ان سے حمید نے، اور ان سے انس رضی اللہ عنہ نے کہ ایک شخص نے بقیع میں ( کسی کو ) پکارا ”اے ابوالقاسم“ نبی کریم صلی اللہ علیہ وسلم نے اس کی طرف دیکھا، تو اس شخص نے کہا کہ میں نے آپ کو نہیں پکارا۔ اس دوسرے آدمی کو پکارا تھا، آپ صلی اللہ علیہ وسلم نے فرمایا میرے نام پر نام رکھا کرو لیکن میری کنیت نہ رکھا کرو۔' WHERE id = 2047;
UPDATE hadiths SET urdu = 'ہم سے علی بن مدینی نے بیان کیا، کہا کہ ہم سے سفیان نے بیان کیا کہ عمرو بن دینار ان سے بیان کرتے تھے، اور ان سے زہری نے، ان سے مالک بن اوس نے، کہ انہوں نے پوچھا کہ آپ لوگوں میں سے کوئی بیع صرف ( یعنی دینار، درہم، اشرفی وغیرہ بدلنے کا کام ) کرتا ہے۔ طلحہ نے کہا کہ میں کرتا ہوں، لیکن اس وقت کر سکوں گا جب کہ ہمارا خزانچی غابہ سے آ جائے گا۔ سفیان نے بیان کیا کہ زہری سے ہم نے اسی طرح حدیث یاد کی تھی۔ اس میں کوئی زیادتی نہیں تھی۔ پھر انہوں نے کہا کہ مجھے مالک بن اوس نے خبر دی کہ انہوں نے عمر بن خطاب رضی اللہ عنہ سے سنا۔ وہ رسول اللہ صلی اللہ علیہ وسلم سے نقل کرتے تھے کہ آپ صلی اللہ علیہ وسلم نے فرمایا، سونا سونے کے بدلے میں ( خریدنا ) سود میں داخل ہے مگر یہ کہ نقدا نقد ہو۔ گیہوں، گیہوں کے بدلے میں ( خریدنا بیچنا ) سود میں داخل ہے مگر یہ کہ نقدا نقد ہو، کھجور، کھجور کے بدلے میں سود ہے مگر یہ کہ نقدا نقد ہو اور جَو، جَو کے بدلے میں سود ہے مگر یہ کہ نقدا نقد ہو۔' WHERE id = 2059;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے عبدالوہاب نے بیان کیا، ان سے محمد بن سیرین نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ دو طرح کے لباس پہننے منع ہیں۔ کہ کوئی آدمی ایک ہی کپڑے میں گوٹ مار کر بیٹھے، پھر اسے مونڈے پر اٹھا کر ڈال لے ( اور شرمگاہ کھلی رہے ) اور دو طرح کی بیع سے منع کیا ایک بیع ملامسۃ سے اور دوسری بیع منابذہ سے۔' WHERE id = 2070;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، ان سے سفیان نے، ان سے اسماعیل نے، ان سے قیس نے، انہوں نے جریر رضی اللہ عنہ سے یہ سنا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے اس بات کی شہادت پر کہ اللہ کے سوا کوئی معبود نہیں اور محمد صلی اللہ علیہ وسلم اللہ کے رسول ہیں۔ اور نماز قائم کرنے اور زکوٰۃ دینے اور ( اپنے مقررہ امیر کی بات ) سننے اور اس کی اطاعت کرنے پر اور ہر مسلمان کے ساتھ خیر خواہی کرنے کی بیعت کی تھی۔' WHERE id = 2081;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن قطان نے بیان کیا، ان سے عبیداللہ نے، کہا کہ مجھ سے نافع نے بیان کیا، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن قطان نے بیان کیا، ان سے عبیداللہ نے، کہا کہ مجھ سے نافع نے بیان کیا، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ' WHERE id = 2091;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم کو امام مالک نے خبر دی، انہیں نافع نے، انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے مزابنہ سے منع فرمایا، مزابنہ درخت پر لگی ہوئی کھجور کو ٹوٹی ہوئی کھجور کے بدلے ناپ کر اور درخت کے انگور کو خشک انگور کے بدلے میں ناپ کر بیچنے کو کہتے ہیں۔' WHERE id = 2105;
UPDATE hadiths SET urdu = 'ہم سے ابن مقاتل نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں حمید طویل نے اور انہیں انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے پکنے سے پہلے درخت پر کھجور کو بیچنے سے منع فرمایا ہے، ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ ( «حتى تزهو‏.‏» سے ) مراد یہ ہے کہ جب تک وہ پک کر سرخ نہ ہو جائیں۔' WHERE id = 2115;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن وہب نے بیان کیا، انہوں نے کہا کہ ہم سے عمر بن یونس نے بیان کیا، انہوں نے کہا کہ مجھ سے میرے باپ نے بیان کیا، انہوں نے کہا کہ مجھ سے اسحاق بن ابی طلحہ انصاری نے بیان کیا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے محاقلہ، مخاضرہ، ملامسہ، منابذہ اور مزابنہ سے منع فرمایا ہے۔' WHERE id = 2126;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ابراہیم علیہ السلام نے سارہ رضی اللہ عنہا کے ساتھ ( نمرود کے ملک سے ) ہجرت کی تو ایک ایسے شہر میں پہنچے جہاں ایک بادشاہ رہتا تھا یا ( یہ فرمایا کہ ) ایک ظالم بادشاہ رہتا تھا۔ اس سے ابراہیم علیہ السلام کے متعلق کسی نے کہہ دیا کہ وہ ایک نہایت ہی خوبصورت عورت لے کر یہاں آئے ہیں۔ بادشاہ نے آپ علیہ السلام سے پچھوا بھیجا کہ ابراہیم! یہ عورت جو تمہارے ساتھ ہے تمہاری کیا ہوتی ہے؟ انہوں نے فرمایا کہ یہ میری بہن ہے۔ پھر جب ابراہیم علیہ السلام سارہ رضی اللہ عنہا کے یہاں آئے تو ان سے کہا کہ میری بات نہ جھٹلانا، میں تمہیں اپنی بہن کہہ آیا ہوں۔ اللہ کی قسم! آج روئے زمین پر میرے اور تمہارے سوا کوئی مومن نہیں ہے۔ چنانچہ آپ علیہ السلام نے سارہ رضی اللہ عنہا کو بادشاہ کے یہاں بھیجا، یا بادشاہ سارہ رضی اللہ عنہا کے پاس گیا۔ اس وقت سارہ رضی اللہ عنہا وضو کر کے نماز پڑھنے کھڑی ہو گئی تھیں۔ انہوں نے اللہ کے حضور میں یہ دعا کی کہ ”اے اللہ! اگر میں تجھ پر اور تیرے رسول ( ابراہیم علیہ السلام ) پر ایمان رکھتی ہوں اور اگر میں نے اپنے شوہر کے سوا اپنی شرمگاہ کی حفاظت کی ہے، تو تو مجھ پر ایک کافر کو مسلط نہ کر۔“ اتنے میں بادشاہ تھرایا اور اس کا پاؤں زمین میں دھنس گیا۔ اعرج نے کہا کہ ابوسلمہ بن عبدالرحمٰن نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا، کہ سارہ رضی اللہ عنہا نے اللہ کے حضور میں دعا کی کہ اے اللہ! اگر یہ مر گیا تو لوگ کہیں گے کہ اسی نے مارا ہے۔ چنانچہ وہ پھر چھوٹ گیا اور سارہ رضی اللہ عنہا کی طرف بڑھا۔ سارہ رضی اللہ عنہا وضو کر کے پھر نماز پڑھنے لگی تھیں اور یہ دعا کرتی جاتی تھیں ”اے اللہ! اگر میں تجھ پر اور تیرے رسول پر ایمان رکھتی ہوں اور اپنے شوہر ( ابراہیم علیہ السلام ) کے سوا اور ہر موقع پر میں نے اپنی شرمگاہ کی حفاظت کی ہے تو تو مجھ پر اس کافر کو مسلط نہ کر۔“ چنانچہ وہ پھر تھرایا، کانپا اور اس کے پاؤں زمین میں دھنس گئے۔ عبدالرحمٰن نے بیان کیا کہ ابوسلمہ نے بیان کیا ابوہریرہ رضی اللہ عنہ سے کہ سارہ رضی اللہ عنہا نے پھر وہی دعا کی کہ ”اے اللہ! اگر یہ مر گیا تو لوگ کہیں گے کہ اسی نے مارا ہے۔“ اب دوسری مرتبہ یا تیسری مرتبہ بھی وہ بادشاہ چھوڑ دیا گیا۔ آخر وہ کہنے لگا کہ تم لوگوں نے میرے یہاں ایک شیطان بھیج دیا۔ اسے ابراہیم ( علیہ السلام ) کے پاس لے جاؤ اور انہیں آجر ( ہاجرہ ) کو بھی دے دو۔ پھر سارہ ابراہیم علیہ السلام کے پاس آئیں اور ان سے کہا کہ دیکھتے نہیں اللہ نے کافر کو کس طرح ذلیل کیا اور ساتھ میں ایک لڑکی بھی دلوا دی۔' WHERE id = 2137;
UPDATE hadiths SET urdu = 'مجھ سے بشر بن مرحوم نے بیان کیا، کہا کہ ہم سے یحییٰ بن سلیم نے بیان کیا، ان سے اسماعیل بن امیہ نے، ان سے سعید بن ابی سعید نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اللہ تعالیٰ کا ارشاد ہے کہ تین طرح کے لوگ ایسے ہوں گے جن کا قیامت کے دن میں مدعی بنوں گا، ایک وہ شخص جس نے میرے نام پر عہد کیا اور وہ توڑ دیا، وہ شخص جس نے کسی آزاد انسان کو بیچ کر اس کی قیمت کھائی اور وہ شخص جس نے کوئی مزدور اجرت پر رکھا، اس سے پوری طرح کام لیا، لیکن اس کی مزدوری نہیں دی۔' WHERE id = 2147;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن زرارہ نے بیان کیا، کہا کہ ہم کو اسماعیل بن علیہ نے خبر دی، انہیں ابن ابی نجیح نے خبر دی، انہیں عبداللہ بن کثیر نے، انہیں ابومنہال نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو ( مدینہ کے ) لوگ پھلوں میں ایک سال یا دو سال کے لیے بیع سلم کرتے تھے۔ یا انہوں نے یہ کہا کہ دو سال اور تین سال ( کے لیے کرتے تھے ) شک اسماعیل کو ہوا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص بھی کھجور میں بیع سلم کرے، اسے مقررہ پیمانے یا مقررہ وزن کے ساتھ کرنی چاہئیے۔' WHERE id = 2158;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا (دوسری سند) اور مجھ سے علی بن عبداللہ نے بیان کیا، ان سے شبابہ نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے ابوعمران نے بیان کیا، کہا کہ میں نے طلحہ بن عبداللہ سے سنا، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے پوچھا یا رسول اللہ! میرے دو پڑوسی ہیں، میں ان دونوں میں سے کس کے پاس ہدیہ بھیجوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ جس کا دروازہ تجھ سے زیادہ قریب ہو۔' WHERE id = 2176;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا کہ ہم سے ابواسامہ نے بیان کیا، ان سے یزید بن عبداللہ نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، مسلمانوں کی اور یہود و نصاریٰ کی مثال ایسی ہے کہ ایک شخص نے چند آدمیوں کو مزدور کیا کہ یہ سب اس کا ایک کام صبح سے رات تک مقررہ اجرت پر کریں۔ چنانچہ کچھ لوگوں نے یہ کام دوپہر تک کیا۔ پھر کہنے لگے کہ ہمیں تمہاری اس مزدوری کی ضرورت نہیں ہے جو تم نے ہم سے طے کی ہے بلکہ جو کام ہم نے کر دیا وہ بھی غلط رہا۔ اس پر اس شخص نے کہا کہ ایسا نہ کرو۔ اپنا کام پورا کر لو اور اپنی پوری مزدوری لے جاؤ، لیکن انہوں نے انکار کر دیا اور کام چھوڑ کر چلے گئے۔ آخر اس نے دوسرے مزدور لگائے اور ان سے کہا کہ باقی دن پورا کر لو تو میں تمہیں وہی مزدوری دوں گا جو پہلے مزدوروں سے طے کی تھی۔ چنانچہ انہوں نے کام شروع کیا، لیکن عصر کی نماز کا وقت آیا تو انہوں نے بھی یہی کیا کہ ہم نے جو تمہارا کام کر دیا ہے وہ بالکل بیکار رہا۔ وہ مزدوری بھی تم اپنے ہی پاس رکھو جو تم نے ہم سے طے کی تھی۔ اس شخص نے ان کو سمجھایا کہ اپنا باقی کام پورا کر لو۔ دن بھی اب تھوڑا ہی باقی رہ گیا ہے، لیکن وہ نہ مانے، آخر اس شخص نے دوسرے مزدور لگائے کہ یہ دن کا جو حصہ باقی رہ گیا ہے اس میں یہ کام کر دیں۔ چنانچہ ان لوگوں نے سورج غروب ہونے تک دن کے بقیہ حصہ میں کام پورا کیا اور پہلے اور دوسرے مزدوروں کی مزدوری بھی سب ان ہی کو ملی۔ تو مسلمانوں کی اور اس نور کی جس کو انہوں نے قبول کیا، یہی مثال ہے۔' WHERE id = 2187;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے حمید طویل نے بیان کیا، اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک پچھنا لگانے والے غلام ( ابوطیبہ ) کو بلایا، انہوں نے آپ صلی اللہ علیہ وسلم کے پچھنا لگایا۔ اور آپ صلی اللہ علیہ وسلم نے انہیں ایک یا دو صاع، یا ایک یا دو مد ( راوی حدیث شعبہ کو شک تھا ) اجرت دینے کے لیے حکم فرمایا۔ آپ صلی اللہ علیہ وسلم نے ( ان کے مالکوں سے بھی ) ان کے بارے میں سفارش فرمائی تو ان کا خراج کم کر دیا گیا۔' WHERE id = 2197;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا کہ ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے کہ جب عبدالرحمٰن بن عوف رضی اللہ عنہ ہمارے یہاں آئے تھے تو رسول اللہ صلی اللہ علیہ وسلم نے ان کا بھائی چارہ سعد بن ربیع رضی اللہ عنہ سے کرایا تھا۔' WHERE id = 2208;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے سلمہ بن کہیل نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم پر ایک شخص کا ایک خاص عمر کا اونٹ قرض تھا۔ وہ شخص تقاضا کرنے آیا تو آپ صلی اللہ علیہ وسلم نے ( اپنے صحابہ سے ) فرمایا کہ ادا کر دو۔ صحابہ رضی اللہ عنہم نے اس عمر کا اونٹ تلاش کیا لیکن نہیں ملا۔ البتہ اس سے زیادہ عمر کا ( مل سکا ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہی انہیں دے دو۔ اس پر اس شخص نے کہا کہ آپ نے مجھے پورا پورا حق دے دیا۔ اللہ تعالیٰ آپ کو بھی پورا بدلہ دے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں سب سے بہتر وہ لوگ ہیں جو قرض وغیرہ کو پوری طرح ادا کر دیتے ہیں۔' WHERE id = 2219;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، انہوں نے کہا کہ ہم سے ابواسامہ نے بیان کیا، انہوں نے کہا کہ ہم سے برید بن عبداللہ نے، انہوں نے کہا کہ ہم سے ابوبردہ نے بیان کیا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، امانت دار خزانچی جو خرچ کرتا ہے۔ بعض دفعہ یہ فرمایا کہ جو دیتا ہے حکم کے مطابق کامل اور پوری طرح جس چیز ( کے دینے ) کا اسے حکم ہو اور اسے دیتے وقت اس کا دل بھی خوش ہو، تو وہ بھی صدقہ کرنے والوں میں سے ایک ہے۔' WHERE id = 2231;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا کہ ہم سے یحییٰ بن سعید نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے خیبر کے پھل اور اناج کی آدھی پیداوار پر وہاں کے رہنے والوں سے معاملہ کیا تھا۔' WHERE id = 2241;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا کہ ہم کو عبداللہ بن مبارک نے خبر دی، انہیں امام اوزاعی نے خبر دی، انہیں رافع بن خدیج رضی اللہ عنہ کے غلام ابونجاشی نے، انہوں نے رافع بن خدیج بن رافع رضی اللہ عنہ سے سنا، اور انہوں نے اپنے چچا ظہیر بن رافع رضی اللہ عنہ سے، ظہیر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں ایک ایسے کام سے منع کیا تھا جس میں ہمارا ( بظاہر ذاتی ) فائدہ تھا۔ اس پر میں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے جو کچھ بھی فرمایا وہ حق ہے۔ ظہیر رضی اللہ عنہ نے بیان کیا کہ مجھے رسول اللہ صلی اللہ علیہ وسلم نے بلایا اور دریافت فرمایا کہ تم لوگ اپنے کھیتوں کا معاملہ کس طرح کرتے ہو؟ میں نے کہا کہ ہم اپنے کھیتوں کو ( بونے کے لیے ) نہر کے قریب کی زمین کی شرط پر دے دیتے ہیں۔ اسی طرح کھجور اور جَو کے چند وسق پر۔ یہ سن کر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایسا نہ کرو۔ یا خود اس میں کھیتی کیا کرو یا دوسروں سے کراؤ۔ ورنہ اسے یوں خالی ہی چھوڑ دو۔ رافع رضی اللہ عنہ نے بیان کیا کہ میں نے کہا ( آپ صلی اللہ علیہ وسلم کا یہ فرمان ) میں نے سنا اور مان لیا۔' WHERE id = 2251;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا کہ ہم کو عبیداللہ بن موسیٰ نے خبر دی، انہیں اسرائیل نے، انہیں ابوحصین نے، انہیں ابوصالح نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کان ( میں مرنے والے ) کا تاوان نہیں، کنویں ( میں گر کر مر جانے والے ) کا تاوان نہیں۔ اور کسی کا جانور ( اگر کسی آدمی کو مارے تو اس کا ) تاوان نہیں۔ گڑھے ہوئے مال میں سے پانچواں حصہ دینا ہو گا۔' WHERE id = 2264;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا کہ ہم سے سفیان ثوری نے بیان کیا، ان سے عمرو بن دینار نے، ان سے ابوصالح سمان نے، اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تین طرح کے آدمی ایسے ہیں جن سے قیامت کے دن اللہ تعالیٰ بات بھی نہ کرے گا اور نہ ان کی طرف نظر اٹھا کے دیکھے گا۔ وہ شخص جو کسی سامان کے متعلق قسم کھائے کہ اسے اس کی قیمت اس سے زیادہ دی جا رہی تھی جتنی اب دی جا رہی ہے حالانکہ وہ جھوٹا ہے۔ وہ شخص جس نے جھوٹی قسم عصر کے بعد اس لیے کھائی کہ اس کے ذریعہ ایک مسلمان کے مال کو ہضم کر جائے۔ وہ شخص جو اپنی ضرورت سے بچے پانی سے کسی کو روکے۔ اللہ تعالیٰ فرمائے گا کہ آج میں اپنا فضل اسی طرح تمہیں نہیں دوں گا جس طرح تم نے ایک ایسی چیز کے فالتو حصے کو نہیں دیا تھا جسے خود تمہارے ہاتھوں نے بنایا بھی نہ تھا۔ علی نے کہا کہ ہم سے سفیان نے عمرو سے کئی مرتبہ بیان کیا کہ انہوں نے ابوصالح سے سنا اور نبی کریم صلی اللہ علیہ وسلم تک اس حدیث کی سند پہنچاتے تھے۔' WHERE id = 2276;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم سے لیث نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سالم بن عبداللہ نے اور ان سے ان کے باپ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ پیوندکاری کے بعد اگر کسی شخص نے اپنا کھجور کا درخت بیچا تو ( اس سال کی فصل کا ) پھل بیچنے والے ہی کا رہتا ہے۔ ہاں اگر خریدار شرط لگا دے ( کہ پھل بھی خریدار ہی کا ہو گا ) تو یہ صورت الگ ہے۔ اور اگر کسی شخص نے کوئی مال والا غلام بیچا تو وہ مال بیچنے والے کا ہوتا ہے۔ ہاں اگر خریدار شرط لگا دے تو یہ صورت الگ ہے۔ یہ حدیث امام مالک سے، انہوں نے نافع سے، انہوں نے ابن عمر رضی اللہ عنہما سے بھی مروی ہے اس میں صرف غلام کا ذکر ہے۔' WHERE id = 2286;
UPDATE hadiths SET urdu = 'ہم سے مسلم نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، ان سے عبدالملک نے، ان سے ربعی بن حراش نے اور ان سے حذیفہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ ایک شخص کا انتقال ہوا ( قبر میں ) اس سے سوال ہوا، تمہارے پاس کوئی نیکی ہے؟ اس نے کہا کہ میں لوگوں سے خرید و فروخت کرتا تھا۔ ( اور جب کسی پر میرا قرض ہوتا ) تو میں مالداروں کو مہلت دیا کرتا تھا اور تنگ دستوں کے قرض کو معاف کر دیا کرتا تھا اس پر اس کی بخشش ہو گئی۔ ابومسعود رضی اللہ عنہ نے بیان کیا کہ میں نے یہی نبی کریم صلی اللہ علیہ وسلم سے سنا ہے۔' WHERE id = 2297;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے سلمہ نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ایک شخص قرض مانگنے اور سخت تقاضا کرنے لگا۔ صحابہ رضی اللہ عنہم نے اس کی گوشمالی کرنی چاہی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے چھوڑ دو، حقدار ایسی باتیں کہہ سکتا ہے۔' WHERE id = 2307;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، کہا کہ ہم سے ہمام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ایک یہودی نے ایک لڑکی کا سر دو پتھروں کے درمیان رکھ کر کچل دیا تھا۔ ( اس میں کچھ جان باقی تھی ) اس سے پوچھا گیا کہ تیرے ساتھ یہ کس نے کیا ہے؟ کیا فلاں نے، فلاں نے؟ جب اس یہودی کا نام آیا تو اس نے اپنے سر سے اشارہ کیا ( کہ ہاں ) یہودی پکڑا گیا اور اس نے بھی جرم کا اقرار کر لیا، نبی کریم صلی اللہ علیہ وسلم نے حکم دیا اور اس کا سر بھی دو پتھروں کے درمیان رکھ کر کچل دیا گیا۔' WHERE id = 2318;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا، کہا کہ ہم سے وہب بن جریر بن حازم نے بیان کیا، انہیں شعبہ نے خبر دی، انہیں اعمش نے، انہیں ابوالضحیٰ نے، انہیں مسروق نے، اور ان سے خباب رضی اللہ عنہ نے بیان کیا کہ میں جاہلیت کے زمانہ میں لوہے کا کام کرتا تھا اور عاص بن وائل ( کافر ) پر میرے کچھ روپے قرض تھے۔ میں اس کے پاس تقاضا کرنے گیا تو اس نے مجھ سے کہا کہ جب تک تو محمد ( صلی اللہ علیہ وسلم ) کا انکار نہیں کرے گا میں تیرا قرض ادا نہیں کروں گا۔ میں نے کہا ہرگز نہیں، اللہ کی قسم! میں محمد صلی اللہ علیہ وسلم کا انکار کبھی نہیں کر سکتا، یہاں تک کہ اللہ تعالیٰ تمہیں مارے اور پھر تم کو اٹھائے۔ وہ کہنے لگا کہ پھر مجھ سے بھی تقاضا نہ کر۔ میں جب مر کے دوبارہ زندہ ہوں گا تو مجھے ( دوسری زندگی میں ) مال اور اولاد دی جائے گی تو تمہارا قرض بھی ادا کر دوں گا۔ اس پر یہ آیت نازل ہوئی «أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا‏» ”تم نے اس شخص کو دیکھا جس نے ہماری آیتوں کا انکار کیا اور کہا کہ مجھے مال اور اولاد ضرور دی جائے گی۔“ آخر آیت تک۔' WHERE id = 2329;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا کہ ہم کو امام مالک نے خبر دی نافع سے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا، کوئی شخص کسی دوسرے کے دودھ کے جانور کو مالک کی اجازت کے بغیر نہ دوہے۔ کیا کوئی شخص یہ پسند کرے گا کہ ایک غیر شخص اس کے گودام میں پہنچ کر اس کا ذخیرہ کھولے اور وہاں سے اس کا غلہ چرا لائے، لوگوں کے مویشی کے تھن بھی ان کے لیے کھانا یعنی ( دودھ کے ) گودام ہیں۔ اس لیے انہیں بھی مالک کی اجازت کے بغیر نہ دوھا جائے۔' WHERE id = 2339;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ربیع نے بیان کیا، کہا کہ ہم سے شعبہ نے بیان کیا، کہا کہ ہم سے اشعث بن سلیم نے بیان کیا، کہ میں نے معاویہ بن سوید سے سنا، انہوں نے براء بن عازب رضی اللہ عنہ سے سنا، آپ نے بیان کیا تھا کہ ہمیں نبی کریم صلی اللہ علیہ وسلم نے سات چیزوں کا حکم فرمایا تھا اور سات ہی چیزوں سے منع بھی فرمایا تھا ( جن چیزوں کا حکم فرمایا تھا ان میں ) انہوں نے مریض کی عیادت، جنازے کے پیچھے چلنے، چھینکنے والے کا جواب دینے، سلام کا جواب دینے، مظلوم کی مدد کرنے، دعوت کرنے والے ( کی دعوت ) قبول کرنے، اور قسم پوری کرنے کا ذکر کیا۔' WHERE id = 2350;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے جبلہ نے بیان کیا کہ ہم بعض اہل عراق کے ساتھ مدینہ میں مقیم تھے۔ وہاں ہمیں قحط میں مبتلا ہونا پڑا۔ عبداللہ بن زبیر رضی اللہ عنہما کھانے کے لیے ہمارے پاس کھجور بھجوایا کرتے تھے۔ اور عبداللہ بن عمر رضی اللہ عنہما جب ہماری طرف سے گزرتے تو فرماتے کہ رسول اللہ صلی اللہ علیہ وسلم نے ( دوسرے لوگوں کے ساتھ مل کر کھاتے وقت ) دو کھجور کو ایک ساتھ ملا کر کھانے سے منع فرمایا ہے مگر یہ کہ تم میں سے کوئی شخص اپنے بھائی سے اجازت لے لے۔' WHERE id = 2360;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، انہوں نے کہا ہم سے ابوعمر حفص بن میسرہ نے بیان کیا، اور ان سے زید بن اسلم نے بیان کیا، ان سے عطاء بن یسار نے بیان کیا، اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا راستوں میں بیٹھنے سے بچو۔ صحابہ نے عرض کیا کہ ہم تو وہاں بیٹھنے پر مجبور ہیں۔ وہی ہمارے بیٹھنے کی جگہ ہوتی ہے کہ جہاں ہم باتیں کرتے ہیں۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر وہاں بیٹھنے کی مجبوری ہی ہے تو راستے کا حق بھی ادا کرو۔ صحابہ نے پوچھا اور راستے کا حق کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا، نگاہ نیچی رکھنا، کسی کو ایذاء دینے سے بچنا، سلام کا جواب دینا، اچھی باتوں کے لیے لوگوں کو حکم کرنا اور بری باتوں سے روکنا۔' WHERE id = 2370;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا کہ مجھ سے لیث نے بیان، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے، ان سے ابوبکر بن عبدالرحمٰن نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، زانی مومن رہتے ہوئے زنا نہیں کر سکتا۔ شراب خوار مومن رہتے ہوئے شراب نہیں پی سکتا۔ چور مومن رہتے ہوئے چوری نہیں کر سکتا۔ اور کوئی شخص مومن رہتے ہوئے لوٹ اور غارت گری نہیں کر سکتا کہ لوگوں کی نظریں اس کی طرف اٹھی ہوئی ہوں اور وہ لوٹ رہا ہو، سعید اور ابوسلمہ کی بھی ابوہریرہ رضی اللہ عنہ سے بحوالہ نبی کریم صلی اللہ علیہ وسلم اسی طرح روایت ہے۔ البتہ ان کی روایت میں لوٹ کا تذکرہ نہیں ہے۔' WHERE id = 2380;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہوں نے کہا کہ ہم سے اوزاعی نے بیان کیا، انہوں نے کہا کہ ہم سے ابوالنجاشی نے بیان کیا کہا کہ میں نے رافع بن خدیج رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ عصر کی نماز پڑھ کر اونٹ ذبح کرتے تو انہیں دس حصوں میں تقسیم کرتے اور پھر سورج غروب ہونے سے پہلے ہی ہم اس کا پکا ہوا گوشت بھی کھا لیتے۔' WHERE id = 2390;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زبیری نے، انہیں ابوسلمہ نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے شفعہ کا حق ایسے اموال ( زمین جائیداد وغیرہ ) میں دیا تھا جن کی تقسیم نہ ہوئی ہو۔ لیکن جب اس کی حد بندی ہو جائے اور راستے بھی بدل دیے جائیں تو پھر شفعہ کا کوئی حق باقی نہیں رہے گا۔' WHERE id = 2400;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا کہ ہم سے زکریا بن ابی زائدہ نے بیان کیا، ان سے عامر شعبی نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا گروی جانور پر اس کا خرچ نکالنے کے لیے سواری کی جائے، دودھ والا جانور گروی ہو تو اس کا دودھ پیا جائے۔' WHERE id = 2413;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، ان سے ابواسامہ نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا جس نے کسی مشترک غلام کے اپنے حصے کو آزاد کیا اور اس کے پاس غلام کی پوری قیمت ادا کرنے کے لیے مال بھی ہے تو پورا غلام اسے آزاد کرانا لازم ہے لیکن اگر اس کے پاس اتنا مال نہ ہو جس سے پورے غلام کی صحیح قیمت ادا کی جا سکے۔ تو پھر غلام کا جو حصہ آزاد ہو گیا وہی آزاد ہوا۔ ہم سے مسدد نے بیان کیا، ان سے بشر نے بیان کیا اور ان سے عبیداللہ نے اختصار کے ساتھ۔' WHERE id = 2424;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، ان سے عروہ بن زبیر نے بیان کیا کہ عائشہ رضی اللہ عنہا نے فرمایا عتبہ بن ابی وقاص نے اپنے بھائی سعد بن ابی وقاص رضی اللہ عنہ کو وصیت کی تھی کہ زمعہ کی باندی کے بچے کو اپنے قبضے میں لے لیں۔ اس نے کہا تھا کہ وہ لڑکا میرا ہے۔ پھر جب فتح مکہ کے موقع پر رسول اللہ صلی اللہ علیہ وسلم ( مکہ ) تشریف لائے، تو سعد رضی اللہ عنہ نے زمعہ کی باندی کے لڑکے کو لے لیا اور رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے، عبد بن زمعہ بھی ساتھ تھے۔ سعد رضی اللہ عنہ نے عرض کیا، یا رسول اللہ! یہ میرے بھائی کا لڑکا ہے، انہوں نے مجھے وصیت کی تھی کہ یہ انہیں کا لڑکا ہے۔ لیکن عبد بن زمعہ نے عرض کیا۔ یا رسول اللہ! یہ میرا بھائی ہے۔ جو زمعہ ( میرے والد ) کی باندی کا لڑکا ہے۔ انہیں کے ”فراش“ پر پیدا ہوا ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے زمعہ کی باندی کے لڑکے کو دیکھا تو واقعی وہ عتبہ کی صورت پر تھا۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا، اے عبد بن زمعہ! یہ تمہاری پرورش میں رہے گا۔ کیونکہ بچہ تمہارے والد ہی کے ”فرش“ پر پیدا ہوا ہے۔ آپ صلی اللہ علیہ وسلم نے ساتھ ہی یہ بھی فرما دیا کہ ”اے سودہ بن زمعہ! اس سے پردہ کیا کر“ یہ ہدایت آپ صلی اللہ علیہ وسلم نے اس لیے کی تھی کہ بچے میں عتبہ کی شباہت دیکھ لی تھی۔ سودہ رضی اللہ عنہا آپ صلی اللہ علیہ وسلم کی بیوی تھیں۔' WHERE id = 2434;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ہم سے واصل بن حیان نے جو کبڑے تھے، بیان کیا، کہا کہ میں نے معرور بن سوید سے سنا، انہوں نے کہا کہ میں نے ابوذر غفاری رضی اللہ عنہ کو دیکھا کہ ان کے بدن پر بھی ایک جوڑا تھا اور ان کے غلام کے بدن پر بھی اسی قسم کا ایک جوڑا تھا۔ ہم نے اس کا سبب پوچھا تو انہوں نے بتلایا کہ ایک دفعہ میری ایک صاحب ( یعنی بلال رضی اللہ عنہ سے ) سے کچھ گالی گلوچ ہو گئی تھی۔ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے میری شکایت کی، آپ صلی اللہ علیہ وسلم نے مجھ سے پوچھا کہ کیا تم نے انہیں ان کی ماں کی طرف سے عار دلائی ہے؟ پھر آپ صلی اللہ علیہ وسلم نے فرمایا، تمہارے غلام بھی تمہارے بھائی ہیں اگرچہ اللہ تعالیٰ نے انہیں تمہاری ماتحتی میں دے رکھا ہے۔ اس لیے جس کا بھی کوئی بھائی اس کے قبضہ میں ہو اسے وہی کھلائے جو وہ خود کھاتا ہے اور وہی پہنائے جو وہ خود پہنتا ہے اور ان پر ان کی طاقت سے زیادہ بوجھ نہ ڈالے۔ لیکن اگر ان کی طاقت سے زیادہ بوجھ ڈالو تو پھر ان کی خود مدد بھی کر دیا کرو۔' WHERE id = 2445;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا مجھے محمد بن زیاد نے خبر دی، انہوں نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے کہ جب کسی کا غلام کھانا لائے اور وہ اسے اپنے ساتھ ( کھلانے کے لیے ) نہ بٹھا سکے تو اسے ایک یا دو نوالے ضرور کھلا دے یا آپ صلی اللہ علیہ وسلم نے «لقمة أو لقمتين» کے بدل «أكلة أو أكلتين» فرمایا ( یعنی ایک یا دو لقمے ) کیونکہ اسی نے اس کو تیار کرنے کی تکلیف اٹھائی ہے۔' WHERE id = 2456;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا ہم سے ابن ابی حازم نے بیان کیا، ان سے ان کے والد نے یزید بن رومان سے، وہ عروہ سے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ آپ نے عروہ سے کہا، میرے بھانجے! رسول اللہ صلی اللہ علیہ وسلم کے عہد مبارک میں ( یہ حال تھا کہ ) ہم ایک چاند دیکھتے، پھر دوسرا دیکھتے، پھر تیسرا دیکھتے، اسی طرح دو دو مہینے گزر جاتے اور رسول اللہ صلی اللہ علیہ وسلم کے گھروں میں ( کھانا پکانے کے لیے ) آگ نہ جلتی تھی۔ میں نے پوچھا۔ خالہ اماں! پھر آپ لوگ زندہ کس طرح رہتی تھیں؟ آپ نے فرمایا کہ صرف دو کالی چیزوں کھجور اور پانی پر۔ البتہ رسول اللہ صلی اللہ علیہ وسلم کے چند انصاری پڑوسی تھے۔ جن کے پاس دودھ دینے والی بکریاں تھیں اور وہ رسول اللہ صلی اللہ علیہ وسلم کے یہاں بھی ان کا دودھ تحفہ کے طور پر پہنچا جایا کرتے تھے۔ آپ صلی اللہ علیہ وسلم اسے ہمیں بھی پلا دیا کرتے تھے۔' WHERE id = 2466;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک مرتبہ گوشت پیش کیا گیا اور یہ بتایا گیا کہ یہ بریرہ رضی اللہ عنہا کو کسی نے بطور صدقہ کے دیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ان کے لیے یہ صدقہ ہے اور ہمارے لیے ( جب ان کے یہاں سے پہنچا تو ) ہدیہ ہے۔“' WHERE id = 2476;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے ابن طاؤس نے بیان کیا، ان سے ان کے والد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اپنا ہبہ واپس لینے والا اس کتے کی طرح ہے جو قے کر کے پھر چاٹ جاتا ہے۔“' WHERE id = 2487;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث نے بیان کیا ابن ابی ملیکہ سے اور وہ مسور بن مخرمہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے چند قبائیں تقسیم کیں اور مخرمہ رضی اللہ عنہ کو اس میں سے ایک بھی نہیں دی۔ انہوں نے ( مجھ سے ) کہا، بیٹے چلو، رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں چلیں۔ میں ان کے ساتھ چلا۔ پھر انہوں نے کہا کہ اندر جاؤ اور نبی کریم صلی اللہ علیہ وسلم سے عرض کرو کہ میں آپ کا منتظر کھڑا ہوا ہوں، چنانچہ میں اندر گیا اور نبی کریم صلی اللہ علیہ وسلم کو بلا لایا۔ آپ صلی اللہ علیہ وسلم اس وقت انہیں قباؤں میں سے ایک قباء پہنے ہوئے تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے یہ تمہارے لیے چھپا رکھی تھی، لو اب یہ تمہاری ہے۔ مسور نے بیان کیا کہ ( میرے والد ) مخرمہ رضی اللہ عنہ نے قباء کی طرف دیکھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”مخرمہ! خوش ہو یا نہیں؟“' WHERE id = 2497;
UPDATE hadiths SET urdu = 'اور حمیدی نے بیان کیا کہ ہم سے سفیان نے بیان کیا کہ ہم سے عمرو نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے اور میں ایک سرکش اونٹ پر سوار تھا۔ نبی کریم صلی اللہ علیہ وسلم نے عمر رضی اللہ عنہ سے فرمایا کہ یہ اونٹ مجھے بیچ دے چنانچہ آپ صلی اللہ علیہ وسلم نے اسے خرید لیا اور پھر فرمایا عبداللہ! تو یہ اونٹ لے جا ( میں نے یہ تجھ کو بخش دیا ) ۔' WHERE id = 2508;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن مبارک نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا کہ ہم سے ایوب نے بیان کیا عکرمہ سے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہم مسلمانوں کو بری مثال نہ اختیار کرنی چاہئے۔ اس شخص کی سی جو اپنا دیا ہوا ہدیہ واپس لے لے، وہ اس کتے کی طرح ہے جو اپنی قے خود چاٹتا ہے۔“' WHERE id = 2518;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے اوزاعی نے بیان کیا، کہا کہ مجھ سے عطاء نے بیان کیا، ان سے جابر رضی اللہ عنہ نے بیان کیا کہ ہم میں سے بہت سے اصحاب کے پاس فالتو زمین بھی تھی، انہوں نے کہا تھا کہ تہائی یا چوتھائی یا نصف کی بٹائی پر ہم کیوں نہ اسے دے دیا کریں۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جس کے پاس زمین ہو تو اسے خود بونی چاہئے یا پھر کسی اپنے بھائی کو ہدیہ کر دینی چاہئے اور اگر ایسا نہیں کرتا تو پھر زمین اپنے پاس رکھے رہے۔“' WHERE id = 2528;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا ثابت سے اور ان سے انس رضی اللہ عنہ نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم کے پاس سے ایک جنازہ گزرا تو لوگوں نے اس میت کی تعریف کی، آپ صلی اللہ علیہ وسلم نے فرمایا ”واجب ہو گئی“ پھر دوسرا جنازہ گزرا تو لوگوں نے اس کی برائی کی، یا اس کے سوا اور الفاظ ( اسی مفہوم کو ادا کرنے کے لیے ) کہے ( راوی کو شبہ ہے ) آپ صلی اللہ علیہ وسلم نے اس پر بھی فرمایا ”واجب ہو گئی“ عرض کیا گیا۔ یا رسول اللہ! آپ نے اس جنازہ کے متعلق بھی فرمایا کہ واجب ہو گئی اور پہلے جنازہ پر بھی یہی فرمایا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”ایمان والی قوم کی گواہی ( بارگاہ الٰہی میں مقبول ہے ) یہ لوگ زمین پر اللہ کے گواہ ہیں۔“' WHERE id = 2538;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی منصور سے، انہوں نے ابراہیم نخعی سے، انہیں عبیدہ نے اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے بہتر میرے زمانہ کے لوگ ہیں، پھر وہ لوگ جو اس کے بعد ہوں گے، پھر وہ لوگ جو اس کے بعد ہوں گے اور اس کے بعد ایسے لوگوں کا زمانہ آئے گا جو قسم سے پہلے گواہی دیں گے اور گواہی سے پہلے قسم کھائیں گے۔“ ابراہیم نخعی رحمہ اللہ نے بیان کیا کہ ہمارے بڑے بزرگ شہادت اور عہد کا لفظ زبان سے نکالنے پر ہمیں مارتے تھے۔' WHERE id = 2548;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب نے خبر دی، کہا کہ ہم سے خالد حذاء نے بیان کیا، ان سے عبدالرحمٰن بن ابی بکرہ نے اور ان سے ان کے باپ نے بیان کیا کہ ایک شخص نے رسول اللہ صلی اللہ علیہ وسلم کے سامنے دوسرے شخص کی تعریف کی، تو آپ صلی اللہ علیہ وسلم نے فرمایا افسوس! تو نے اپنے ساتھی کی گردن کاٹ ڈالی۔ تو نے اپنے ساتھی کی گردن کاٹ ڈالی۔ کئی مرتبہ ( آپ صلی اللہ علیہ وسلم نے اسی طرح فرمایا ) پھر فرمایا کہ اگر کسی کے لیے اپنے کسی بھائی کی تعریف کرنی ضروری ہو جائے تو یوں کہے کہ میں فلاں شخص کو ایسا سمجھتا ہوں، آگے اللہ خوب جانتا ہے، میں اللہ کے سامنے کسی کو بےعیب نہیں کہہ سکتا۔ میں سمجھتا ہوں وہ ایسا ایسا ہے اگر اس کا حال جانتا ہو۔' WHERE id = 2558;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن نصر نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، انہیں معمر نے خبر دی، انہیں ہمام نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے چند آدمیوں سے قسم کھانے کے لیے کہا ( ایک ایسے مقدمے میں جس کے یہ لوگ مدعیٰ علیہ تھے ) قسم کے لیے سب ایک ساتھ آگے بڑھے۔ تو آپ صلی اللہ علیہ وسلم نے حکم دیا ”قسم کھانے کے لیے ان میں باہم قرعہ ڈالا جائے کہ پہلے کون قسم کھائے۔“' WHERE id = 2568;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، کہا ہم سے اعمش نے، کہا کہ ہم سے شعبی نے بیان کیا، انہوں نے نعمان بن بشیر رضی اللہ عنہما سے سنا، وہ کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ کی حدود میں سستی برتنے والے اور اس میں مبتلا ہو جانے والے کی مثال ایک ایسی قوم کی سی ہے جس نے ایک کشتی ( پر سفر کرنے کے لیے جگہ کے بارے میں ) قرعہ اندازی کی۔ پھر نتیجے میں کچھ لوگ نیچے سوار ہوئے اور کچھ اوپر۔ نیچے کے لوگ پانی لے کر اوپر کی منزل سے گزرتے تھے اور اس سے اوپر والوں کو تکلیف ہوتی تھی۔ اس خیال سے نیچے والا ایک آدمی کلہاڑی سے کشتی کا نیچے کا حصہ کاٹنے لگا ( تاکہ نیچے ہی سمندر سے پانی لے لیا کرے ) اب اوپر والے آئے اور کہنے لگے کہ یہ کیا کر رہے ہو؟ اس نے کہا کہ تم لوگوں کو ( میرے اوپر آنے جانے سے ) تکلیف ہوتی تھی اور میرے لیے بھی پانی ضروری تھا۔ اب اگر انہوں نے نیچے والے کا ہاتھ پکڑ لیا تو انہیں بھی نجات دی اور خود بھی نجات پائی۔ لیکن اگر اسے یوں ہی چھوڑ دیا تو انہیں بھی ہلاک کیا اور خود بھی ہلاک ہو گئے۔“' WHERE id = 2579;
UPDATE hadiths SET urdu = 'ہم سے یعقوب نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے باپ نے بیان کیا، ان سے قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جس نے ہمارے دین میں از خود کوئی ایسی چیز نکالی جو اس میں نہیں تھی تو وہ رد ہے۔ اس کی روایت عبداللہ بن جعفر مخرمی اور عبدالواحد بن ابی عون نے سعد بن ابراہیم سے کی ہے۔' WHERE id = 2589;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، کہا ہم کو معمر نے خبر دی ہمام سے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”انسان کے بدن کے ( تین سو ساٹھ جوڑوں میں سے ) ہر جوڑ پر ہر اس دن کا صدقہ واجب ہے جس میں سورج طلوع ہوتا ہے اور لوگوں کے درمیان انصاف کرنا بھی ایک صدقہ ہے۔“' WHERE id = 2599;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی۔ ان سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ انصار رضوان اللہ علیہم نے نبی کریم صلی اللہ علیہ وسلم کے سامنے ( مؤاخات کے بعد ) یہ پیش کش کی کہ ہمارے کھجور کے باغات آپ ہم میں اور ہمارے بھائیوں ( مہاجرین ) میں تقسیم فرما دیں، لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ اس پر انصار نے مہاجرین سے کہا کہ آپ لوگ ہمارے باغوں کے کام کر دیا کریں اور ہمارے ساتھ پھل میں شریک ہو جائیں، مہاجرین نے کہا کہ ہم نے سن لیا اور ہم ایسا ہی کریں گے۔' WHERE id = 2610;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا ‘ کہا ہم سے عبدالرزاق نے بیان کیا ‘ کہا مجھ کو معمر نے خبر دی ‘ کہا کہ مجھے زہری نے خبر دی ‘ کہا مجھے عروہ بن زبیر نے خبر دی اور ان سے مسور بن مخرمہ رضی اللہ عنہ اور مروان نے ‘ دونوں کے بیان سے ایک دوسرے کی حدیث کی تصدیق بھی ہوتی ہے۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم صلح حدیبیہ کے موقع پر ( مکہ ) جا رہے تھے ‘ ابھی آپ صلی اللہ علیہ وسلم راستے ہی میں تھے ‘ فرمایا خالد بن ولید قریش کے ( دو سو ) سواروں کے ساتھ ہماری نقل و حرکت کا اندازہ لگانے کے لیے مقام غمیم میں مقیم ہے ( یہ قریش کا مقدمۃ الجیش ہے ) اس لیے تم لوگ داہنی طرف سے جاؤ ‘ پس اللہ کی قسم خالد کو ان کے متعلق کچھ بھی علم نہ ہو سکا اور جب انہوں نے اس لشکر کا غبار اٹھتا ہوا دیکھا تو قریش کو جلدی جلدی خبر دینے گئے۔ ادھر نبی کریم صلی اللہ علیہ وسلم چلتے رہے یہاں تک کہ آپ صلی اللہ علیہ وسلم اس گھاٹی پر پہنچے جس سے مکہ میں اترتے ہیں تو آپ صلی اللہ علیہ وسلم کی سواری بیٹھ گئی۔ صحابہ اونٹنی کو اٹھانے کیلئے حل حل کہنے لگے لیکن وہ اپنی جگہ سے نہ اٹھی۔ صحابہ رضی اللہ عنہم نے کہا کہ قصواء اڑ گئی آپ صلی اللہ علیہ وسلم نے فرمایا قصواء اڑی نہیں اور نہ یہ اس کی عادت ہے ‘ اسے تو اس ذات نے روک لیا جس نے ہاتھیوں ( کے لشکر ) کو ( مکہ ) میں داخل ہونے سے روک لیا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس ذات کی قسم جس کے ہاتھ میں میری جان ہے قریش جو بھی ایسا مطالبہ رکھیں گے جس میں اللہ کی محرمات کی بڑائی ہو تو میں اس کا مطالبہ منظور کر لوں گا۔ آخر آپ صلی اللہ علیہ وسلم نے اونٹنی کو ڈانٹا تو وہ اٹھ گئی۔ راوی نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم صحابہ سے آگے نکل گئے اور حدیبیہ کے آخری کنارے ثمد ( ایک چشمہ یا گڑھا ) پر جہاں پانی کم تھا، آپ صلی اللہ علیہ وسلم نے پڑاؤ کیا۔ لوگ تھوڑا تھوڑا پانی استعمال کرنے لگے، انہوں نے پانی کو ٹھہرنے ہی نہیں دیا، سب کھینچ ڈالا۔ اب رسول اللہ صلی اللہ علیہ وسلم سے پیاس کی شکایت کی گئی تو آپ صلی اللہ علیہ وسلم نے اپنے ترکش میں سے ایک تیر نکال کر دیا کہ اس گڑھے میں ڈال دیں بخدا تیر گاڑتے ہی پانی انہیں سیراب کرنے کے لیے ابلنے لگا اور وہ لوگ پوری طرح سیراب ہو گئے۔ لوگ اسی حال میں تھے کہ بدیل بن ورقاء خزاعی رضی اللہ عنہ اپنی قوم خزاعہ کے کئی آدمیوں کو لے کر حاضر ہوا۔ یہ لوگ تہامہ کے رہنے والے تھے اور رسول اللہ صلی اللہ علیہ وسلم کے محرم راز بڑے خیرخواہ تھے۔ انہوں نے خبر دی کہ میں کعب بن لوئی اور عامر بن لوئی کو پیچھے چھوڑ کر آ رہا ہوں۔ جنہوں نے حدیبیہ کے پانی کے ذخیروں پر اپنا پڑاؤ ڈال دیا ہے ‘ ان کے ساتھ بکثرت دودھ دینے والی اونٹنیاں اپنے نئے نئے بچوں کے ساتھ ہیں۔ وہ آپ سے لڑیں گے اور آپ کے بیت اللہ پہنچنے میں رکاوٹ بنیں گے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا ہم کسی سے لڑنے نہیں آئے ہیں صرف عمرہ کے ارادے سے آئے ہیں اور واقعہ تو یہ ہے ( مسلسل لڑائیوں ) نے قریش کو بھی کمزور کر دیا ہے اور انہیں بڑا نقصان اٹھانا پڑا ہے ‘ اب اگر وہ چاہیں تو میں ایک مدت ان سے صلح کا معاہدہ کر لوں گا ‘ اس عرصہ میں وہ میرے اور عوام ( کفار مشرکین عرب ) کے درمیان نہ پڑیں پھر اگر میں کامیاب ہو جاؤں اور ( اس کے بعد ) وہ چاہیں تو اس دین ( اسلام ) میں وہ بھی داخل ہو سکتے ہیں ( جس میں اور تمام لوگ داخل ہو چکے ہوں گے ) لیکن اگر مجھے کامیابی نہیں ہوئی تو انہیں بھی آرام مل جائے گا اور اگر انہیں میری پیش کش سے انکار ہے تو اس ذات کی قسم جس کے ہاتھ میں میری جان ہے جب تک میرا سر تن سے جدا نہیں ہو جاتا، میں اس دین کے لیے برابر لڑتا رہوں گا یا پھر اللہ تعالیٰ اسے نافذ ہی فرما دے گا۔ بدیل رضی اللہ عنہ نے کہا کہ قریش تک آپ کی گفتگو میں پہچاؤں گا چنانچہ وہ واپس ہوئے اور قریش کے یہاں پہنچے اور کہا کہ ہم تمہارے پاس اس شخص ( نبی کریم صلی اللہ علیہ وسلم ) کے یہاں سے آ رہے ہیں اور ہم نے اسے ایک بات کہتے سنا ہے ‘ اگر تم چاہو تو تمہارے سامنے اسے بیان کر سکتے ہیں۔ قریش کے بے وقوفوں نے کہا کہ ہمیں اس کی ضرورت نہیں کہ تم اس شخص کی کوئی بات ہمیں سناؤ۔ جو لوگ صائب الرائے تھے ‘ انہوں نے کہا کہ ٹھیک ہے جو کچھ تم نے سنا ہے ہم سے بیان کر دو۔ انہوں نے کہا کہ میں نے اسے ( آپ صلی اللہ علیہ وسلم ) کو یہ کہتے سنا ہے اور پھر جو کچھ انہوں نے آپ صلی اللہ علیہ وسلم سے سنا تھا ‘ سب بیان کر دیا۔ اس پر عروہ بن مسعود رضی اللہ عنہ ( جو اس وقت تک کفار کے ساتھ تھے ) کھڑے ہوئے اور کہا اے قوم کے لوگو! کیا تم مجھ پر باپ کی طرح شفقت نہیں رکھتے۔ سب نے کہا کیوں نہیں ‘ ضرور رکھتے ہیں۔ عروہ نے پھر کہا کیا میں بیٹے کی طرح تمہارا خیرخواہ نہیں ہوں ‘ انہوں نے کہا کیوں نہیں۔ عروہ نے پھر کہا تم لوگ مجھ پر کسی قسم کی تہمت لگا سکتے ہو؟ انہوں نے کہا کہ نہیں۔ انہوں نے پوچھا کیا تمہیں معلوم نہیں ہے کہ میں نے عکاظ والوں کو تمہاری مدد کے لیے کہا تھا اور جب انہوں نے انکار کیا تو میں نے اپنے گھرانے ‘ اولاد اور ان تمام لوگوں کو تمہارے پاس لا کر کھڑا کر دیا تھا جنہوں نے میرا کہنا مانا تھا؟ قریش نے کہا کیوں نہیں ( آپ کی باتیں درست ہیں ) اس کے بعد انہوں نے کہا دیکھو اب اس شخص ( نبی کریم صلی اللہ علیہ وسلم ) نے تمہارے سامنے ایک اچھی تجویز رکھی ہے ‘ اسے تم قبول کر لو اور مجھے اس کے پاس ( گفتگو ) کے لیے جانے دو ‘ سب نے کہا آپ ضرور جایئے۔ چنانچہ عروہ بن مسعود رضی اللہ عنہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ صلی اللہ علیہ وسلم سے گفتگو شروع کی۔ آپ صلی اللہ علیہ وسلم نے ان سے بھی وہی باتیں کہیں جو آپ صلی اللہ علیہ وسلم بدیل سے کہہ چکے تھے ‘ عروہ رضی اللہ عنہ نے اس وقت کہا۔ اے محمد ( صلی اللہ علیہ وسلم ) ! بتائیے اگر آپ صلی اللہ علیہ وسلم نے اپنی قوم کو تباہ کر دیا تو کیا اپنے سے پہلے کسی بھی عرب کے متعلق سنا ہے کہ اس نے اپنے خاندان کا نام و نشان مٹا دیا ہو لیکن اگر دوسری بات واقع ہوئی ( یعنی ہم آپ صلی اللہ علیہ وسلم پر غالب ہوئے ) تو میں اللہ کی قسم تمہارے ساتھیوں کا منہ دیکھتا ہوں یہ مختلف جنسوں لوگ یہی کریں گے۔ اس وقت یہ سب لوگ بھاگ جائیں گے اور آپ کو تنہا چھوڑ دیں گے۔ اس پر ابوبکر رضی اللہ عنہ بولے «امصص بظر اللات» ۔ کیا ہم رسول اللہ صلی اللہ علیہ وسلم کے پاس سے بھاگ جائیں گے اور آپ صلی اللہ علیہ وسلم کو تنہا چھوڑ دیں گے۔ عروہ نے پوچھا کون صاحب ہیں؟ لوگوں نے بتایا کہ ابوبکر رضی اللہ عنہ ہیں۔ عروہ نے کہا اس ذات کی قسم جس کے ہاتھ میں میری جان ہے اگر تمہارا مجھ پر ایک احسان نہ ہوتا جس کا اب تک میں بدلہ نہیں دے سکا ہوں تو تمہیں ضرور جواب دیتا۔ بیان کیا کہ وہ نبی کریم صلی اللہ علیہ وسلم سے پھر گفتگو کرنے لگے اور گفتگو کرتے ہوئے آپ صلی اللہ علیہ وسلم کی داڑھی مبارک پکڑ لیا کرتے تھے۔ مغیرہ بن شعبہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کے پاس کھڑے تھے ‘ تلوار لٹکائے ہوئے اور سر پر خود پہنے۔ عروہ جب بھی نبی کریم صلی اللہ علیہ وسلم کی داڑھی مبارک کی طرف اپنا ہاتھ لے جاتے تو مغیرہ رضی اللہ عنہ تلوار کی نیام کو اس کے ہاتھ پر مارتے اور ان سے کہتے کہ رسول اللہ صلی اللہ علیہ وسلم کی داڑھی سے اپنا ہاتھ الگ رکھ۔ عروہ رضی اللہ عنہ نے اپنا سر اٹھایا اور پوچھا یہ کون صاحب ہیں؟ لوگوں نے بتایا کہ مغیرہ بن شعبہ۔ عروہ نے انہیں مخاطب کر کے کہا اے دغا باز! کیا میں نے تیری دغا بازی کی سزا سے تجھ کو نہیں بچایا؟ اصل میں مغیرہ رضی اللہ عنہ ( اسلام لانے سے پہلے ) جاہلیت میں ایک قوم کے ساتھ رہے تھے پھر ان سب کو قتل کر کے ان کا مال لے لیا تھا۔ اس کے بعد ( مدینہ ) آئے اور اسلام کے حلقہ بگوش ہو گئے ( تو رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ان کا مال بھی رکھ دیا کہ جو چاہیں اس کے متعلق حکم فرمائیں ) لیکن آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ تیرا اسلام تو میں قبول کرتا ہوں، رہا یہ مال تو میرا اس سے کوئی واسطہ نہیں۔ کیونکہ وہ دغا بازی سے ہاتھ آیا ہے جسے میں لے نہیں سکتا ‘ پھر عروہ رضی اللہ عنہ گھور گھور کر رسول اللہ صلی اللہ علیہ وسلم کے اصحاب کی نقل و حرکت دیکھتے رہے۔ پھر راوی نے بیان کیا کہ قسم اللہ کی اگر کبھی رسول اللہ صلی اللہ علیہ وسلم نے بلغم بھی تھوکا تو آپ صلی اللہ علیہ وسلم کے اصحاب نے اپنے ہاتھوں پر اسے لے لیا اور اسے اپنے چہرہ اور بدن پر مل لیا۔ کسی کام کا اگر آپ صلی اللہ علیہ وسلم نے حکم دیا تو اس کی بجا آوری میں ایک دوسرے پر لوگ سبقت لے جانے کی کوشش کرتے۔ آپ صلی اللہ علیہ وسلم وضو کرنے لگے تو ایسا معلوم ہوا کہ آپ صلی اللہ علیہ وسلم کے وضو کے پانی پر لڑائی ہو جائے گی ( یعنی ہر شخص اس پانی کو لینے کی کوشش کرتا تھا ) جب آپ صلی اللہ علیہ وسلم گفتگو کرنے لگے تو سب پر خاموشی چھا جاتی۔ آپ صلی اللہ علیہ وسلم کی تعظیم کا یہ حال تھا کہ آپ صلی اللہ علیہ وسلم کے ساتھی نظر بھر کر آپ صلی اللہ علیہ وسلم کو دیکھ بھی نہیں سکتے تھے۔ خیر عروہ جب اپنے ساتھیوں سے جا کر ملے تو ان سے کہا اے لوگو! قسم اللہ کی میں بادشاہوں کے دربار میں بھی وفد لے کر گیا ہوں ‘ قیصر و کسریٰ اور نجاشی سب کے دربار میں لیکن اللہ کی قسم میں نے کبھی نہیں دیکھا کہ کسی بادشاہ کے ساتھی اس کی اس درجہ تعظیم کرتے ہوں جتنی محمد صلی اللہ علیہ وسلم کے اصحاب آپ صلی اللہ علیہ وسلم کی تعظیم کرتے ہیں۔ قسم اللہ کی اگر محمد صلی اللہ علیہ وسلم نے بلغم بھی تھوک دیا تو ان کے اصحاب نے اسے اپنے ہاتھوں میں لے لیا اور اسے اپنے چہرہ اور بدن پر مل لیا۔ آپ صلی اللہ علیہ وسلم نے انہیں اگر کوئی حکم دیا تو ہر شخص نے اسے بجا لانے میں ایک دوسرے پر سبقت کی کوشش کی۔ آپ صلی اللہ علیہ وسلم نے اگر وضو کیا تو ایسا معلوم ہوتا کہ آپ صلی اللہ علیہ وسلم کے وضو پر لڑائی ہو جائے گی۔ آپ صلی اللہ علیہ وسلم نے جب گفتگو شروع کی تو ہر طرف خاموشی چھا گئی۔ ان کے دلوں میں آپ صلی اللہ علیہ وسلم کی تعظیم کا یہ عالم تھا کہ آپ صلی اللہ علیہ وسلم کو نظر بھر کر بھی نہیں دیکھ سکتے۔ انہوں نے تمہارے سامنے ایک بھلی صورت رکھی ہے ‘ تمہیں چاہئے کہ اسے قبول کر لو۔ اس پر بنو کنانہ کا ایک شخص بولا کہ اچھا مجھے بھی ان کے یہاں جانے دو ‘ لوگوں نے کہا تم بھی جا سکتے ہو۔ جب یہ رسول اللہ صلی اللہ علیہ وسلم اور آپ صلی اللہ علیہ وسلم کے اصحاب رضوان اللہ علیہم اجمعین کے قریب پہنچے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ فلاں شخص ہے ‘ ایک ایسی قوم کا فرد جو بیت اللہ کی قربانی کے جانوروں کی تعظیم کرتے ہیں۔ اس لیے قربانی کے جانور اس کے سامنے کر دو۔ صحابہ رضی اللہ عنہم نے قربانی کے جانور اس کے سامنے کر دیئے اور لبیک کہتے ہوئے اس کا استقبال کیا جب اس نے یہ منظر دیکھا تو کہنے لگا کہ سبحان اللہ قطعاً مناسب نہیں ہے کہ ایسے لوگوں کو کعبہ سے روکا جائے۔ اس کے بعد قریش میں سے ایک دوسرا شخص مکرز بن حفص نامی کھڑا ہوا اور کہنے لگا کہ مجھے بھی ان کے یہاں جانے دو۔ سب نے کہا کہ تم بھی جا سکتے ہو جب وہ آپ صلی اللہ علیہ وسلم اور صحابہ رضی اللہ عنہم سے قریب ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ مکرز ہے ایک بدترین شخص ہے۔ پھر وہ نبی کریم صلی اللہ علیہ وسلم سے گفتگو کرنے لگا۔ ابھی وہ گفتگو کر ہی رہا تھا کہ سہیل بن عمرو آ گیا۔ معمر نے ( سابقہ سند کے ساتھ ) بیان کیا کہ مجھے ایوب نے خبر دی اور انہیں عکرمہ نے کہ جب سہیل بن عمرو آیا تو نبی کریم صلی اللہ علیہ وسلم نے ( نیک فالی کے طور پر ) فرمایا تمہارا معاملہ آسان ( سہل ) ہو گیا۔ معمر نے بیان کیا کہ زہری نے اپنی حدیث میں اس طرح بیان کیا تھا کہ جب سہیل بن عمرو آیا تو کہنے لگا کہ ہمارے اور اپنے درمیان ( صلح ) کی ایک تحریر لکھ لو۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے کاتب کو بلوایا اور فرمایا کہ لکھو «بسم الله الرحمن الرحيم» سہیل کہنے لگا رحمن کو اللہ کی قسم میں نہیں جانتا کہ وہ کیا چیز ہے۔ البتہ تم یوں لکھ سکتے ہو «باسمك اللهم‏.‏» جیسے پہلے لکھا کرتے تھے مسلمانوں نے کہا کہ قسم اللہ کی ہمیں «بسم الله الرحمن الرحيم» کے سوا اور کوئی دوسرا جملہ نہ لکھنا چاہئے۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ «باسمك اللهم‏.‏» ہی لکھنے دو۔ پھر آپ صلی اللہ علیہ وسلم نے لکھوایا یہ محمد رسول اللہ کی طرف سے صلح نامہ کی دستاویز ہے۔ سہیل نے کہا اگر ہمیں یہ معلوم ہوتا کہ آپ رسول اللہ ہیں تو نہ ہم آپ صلی اللہ علیہ وسلم کو کعبہ سے روکتے اور نہ آپ سے جنگ کرتے۔ آپ تو صرف اتنا لکھئے کہ ”محمد بن عبداللہ“ اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا اللہ گواہ ہے کہ میں اس کا سچا رسول ہوں خواہ تم میری تکذیب ہی کرتے رہو ‘ لکھو جی ”محمد بن عبداللہ“ زہری نے بیان کیا کہ یہ سب کچھ ( نرمی اور رعایت ) صرف آپ صلی اللہ علیہ وسلم کے اس ارشاد کا نتیجہ تھا ( جو پہلے بدیل رضی اللہ عنہ سے کہہ چکے تھے ) کہ قریش مجھ سے جو بھی ایسا مطالبہ کریں گے جس سے اللہ تعالیٰ کی حرمتوں کی تعظیم مقصود ہو گی تو میں ان کے مطالبے کو ضرور مان لوں گا ‘ اس لیے نبی کریم صلی اللہ علیہ وسلم نے سہیل سے فرمایا لیکن صلح کے لیے پہلی شرط یہ ہو گی کہ تم لوگ ہمیں بیت اللہ کے طواف کرنے کے لیے جانے دو گے۔ سہیل نے کہا قسم اللہ کی ہم ( اس سال ) ایسا نہیں ہونے دیں گے ورنہ عرب کہیں گے ہم مغلوب ہو گئے تھے ( اس لیے ہم نے اجازت دے دی ) آئندہ سال کے لیے اجازت ہے۔ چنانچہ یہ بھی لکھ لیا۔ پھر سہیل نے لکھا کہ یہ شرط بھی ( لکھ لیجئے ) کہ ہماری طرف کا جو شخص بھی آپ کے یہاں جائے گا خواہ وہ آپ کے دین ہی پر کیوں نہ ہو آپ اسے ہمیں واپس کر دیں گے۔ مسلمانوں نے ( یہ شرط سن کر کہا ) سبحان اللہ! ( ایک شخص کو ) مشرکوں کے حوالے کس طرح کیا جا سکتا ہے جو مسلمان ہو کر آیا ہو۔ ابھی یہی باتیں ہو رہی تھیں کہ ابوجندل بن سہیل بن عمرو رضی اللہ عنہ اپنی بیڑیوں کو گھسیٹتے ہوئے آ پہنچے ‘ وہ مکہ کے نشیبی علاقے کی طرف سے بھاگے تھے اور اب خود کو مسلمانوں کے سامنے ڈال دیا تھا۔ سہیل نے کہا اے محمد! یہ پہلا شخص ہے جس کے لیے ( صلح نامہ کے مطابق ) میں مطالبہ کرتا ہوں کہ آپ صلی اللہ علیہ وسلم ہمیں اسے واپس کر دیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ابھی تو ہم نے ( صلح نامہ کی اس دفعہ کو ) صلح نامہ میں لکھا بھی نہیں ہے ( اس لیے جب صلح نامہ طے پا جائے گا اس کے بعد اس کا نفاذ ہونا چاہئے ) سہیل کہنے لگا کہ اللہ کی قسم پھر میں کسی بنیاد پر بھی آپ صلی اللہ علیہ وسلم سے صلح نہیں کروں گا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اچھا مجھ پر اس ایک کو دے کر احسان کر دو۔ اس نے کہا کہ میں اس سلسلے میں احسان بھی نہیں کر سکتا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں ہمیں احسان کر دینا چاہئے لیکن اس نے یہی جواب دیا کہ میں ایسا کبھی نہیں کر سکتا۔ البتہ مکرز نے کہا کہ چلئے ہم اس کا آپ صلی اللہ علیہ وسلم پر احسان کرتے ہیں مگر ( اس کی بات نہیں چلی ) ابوجندل رضی اللہ عنہ نے کہا مسلمانوں! میں مسلمان ہو کر آیا ہوں۔ کیا مجھے مشرکوں کے ہاتھ میں دے دیا جائے گا؟ کیا میرے ساتھ جو اذیتیں پہنچائی گئیں تھیں۔ راوی نے بیان کیا کہ عمر بن خطاب رضی اللہ عنہ نے کہا آخر میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا، کیا یہ واقعہ اور حقیقت نہیں کہ آپ صلی اللہ علیہ وسلم اللہ کے نبی ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کیوں نہیں! میں نے عرض کیا، کیا ہم حق پر نہیں ہیں اور کیا ہمارے دشمن باطل پر نہیں ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کیوں نہیں! میں نے کہا پھر اپنے دین کے معاملے میں کیوں دبیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا میں اللہ کا رسول ہوں ‘ اس کی حکم عدولی نہیں کر سکتا اور وہی میرا مددگار ہے۔ میں نے کہا کیا آپ صلی اللہ علیہ وسلم ہم سے یہ نہیں فرماتے تھے کہ ہم بیت اللہ جائیں گے اور اس کا طواف کریں گے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ٹھیک ہے لیکن کیا میں نے تم سے یہ کہا تھا کہ اسی سال ہم بیت اللہ پہنچ جائیں گے۔ عمر رضی اللہ عنہ نے بیان کیا کہ میں نے کہا نہیں ( آپ صلی اللہ علیہ وسلم نے اس قید کے ساتھ نہیں فرمایا تھا ) آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اس میں کوئی شبہ نہیں کہ تم بیت اللہ تک ضرور پہنچو گے اور ایک دن اس کا طواف کرو گے۔ انہوں نے بیان کیا کہ پھر ابوبکر رضی اللہ عنہ کے یہاں گیا اور ان سے بھی یہی پوچھا کہ ابوبکر! کیا یہ حقیقت نہیں کہ آپ صلی اللہ علیہ وسلم اللہ کے نبی ہیں؟ انہوں نے بھی کہا کہ کیوں نہیں۔ میں نے پوچھا کیا ہم حق پر نہیں ہیں؟ اور کیا ہمارے دشمن باطل پر نہیں ہیں؟ انہوں نے کہا کیوں نہیں! میں نے کہا کہ پھر اپنے دین کو کیوں ذلیل کریں۔ ابوبکر رضی اللہ عنہ نے کہا جناب! بلا شک و شبہ وہ اللہ کے رسول ہیں ‘ اور اپنے رب کی حکم عدولی نہیں کر سکتے اور رب ہی ان کا مددگار ہے پس ان کی رسی مضبوطی سے پکڑ لو ‘ اللہ گواہ ہے کہ وہ حق پر ہیں۔ میں نے کہا کیا آپ صلی اللہ علیہ وسلم ہم سے یہ نہیں کہتے تھے کہ عنقریب ہم بیت اللہ پہونچیں گے اور اس کا طواف کریں گے انہوں نے فرمایا کہ یہ بھی صحیح ہے لیکن کیا آپ صلی اللہ علیہ وسلم نے آپ سے یہ فرمایا تھا کہ اسی سال آپ بیت اللہ پہنچ جائیں گے۔ میں نے کہا کہ نہیں۔ پھر ابوبکر رضی اللہ عنہ نے کہا پھر اس میں بھی کوئی شک و شبہ نہیں کہ آپ ایک نہ ایک دن بیت اللہ پہنچیں گے اور اس کا طواف کریں گے۔ زہری نے بیان کیا کہ عمر رضی اللہ عنہ نے فرمایا بعد میں میں نے اپنی عجلت پسندی کی مکافات کے لیے نیک اعمال کئے۔ پھر جب صلح نامہ سے آپ فارغ ہو چکے تو صحابہ رضوان اللہ علیہم سے فرمایا کہ اب اٹھو اور ( جن جانوروں کو ساتھ لائے ہو ان کی ) قربانی کر لو اور سر بھی منڈوا لو۔ انہوں نے بیان کیا کہ اللہ گواہ ہے صحابہ میں سے ایک شخص بھی نہ اٹھا اور تین مرتبہ آپ صلی اللہ علیہ وسلم نے یہ جملہ فرمایا۔ جب کوئی نہ اٹھا تو نبی کریم صلی اللہ علیہ وسلم ام سلمہ کے خیمہ میں گئے اور ان سے لوگوں کے طرز عمل کا ذکر کیا۔ ام سلمہ رضی اللہ عنہا نے کہا اے اللہ کے نبی! کیا آپ یہ پسند کریں گے کہ باہر تشریف لے جائیں اور کسی سے کچھ نہ کہیں بلکہ اپنا قربانی کا جانور ذبح کر لیں اور اپنے حجام کو بلا لیں جو آپ کے بال مونڈ دے۔ چنانچہ آپ صلی اللہ علیہ وسلم باہر تشریف لائے۔ کسی سے کچھ نہیں کہا اور سب کچھ کیا ‘ اپنے جانور کی قربانی کر لی اور اپنے حجام کو بلوایا جس نے آپ صلی اللہ علیہ وسلم کے بال مونڈے۔ جب صحابہ نے دیکھا تو وہ بھی ایک دوسرے کے بال مونڈنے لگے ‘ ایسا معلوم ہوتا تھا کہ رنج و غم میں ایک دوسرے سے لڑ پڑیں گے۔ پھر آپ صلی اللہ علیہ وسلم کے پاس ( مکہ سے ) چند مومن عورتیں آئیں تو اللہ تعالیٰ نے یہ حکم نازل فرمایا «يا أيها الذين آمنوا إذا جاءكم المؤمنات مهاجرات فامتحنوهن‏» اے لوگو! جو ایمان لا چکے ہو جب تمہارے پاس مومن عورتیں ہجرت کر کے آئیں تو ان کا امتحان لے «بعصم الكوافر‏» تک۔ اس دن عمر رضی اللہ عنہ نے اپنی دو بیویوں کو طلاق دی جو اب تک مسلمان نہ ہوئی تھیں۔ ان میں سے ایک نے تو معاویہ بن ابی سفیان رضی اللہ عنہما سے نکاح کر لیا تھا اور دوسری سے صفوان بن امیہ نے۔ اس کے بعد رسول اللہ صلی اللہ علیہ وسلم مدینہ واپس تشریف لائے تو قریش کے ایک فرد ابوبصیر رضی اللہ عنہ ( مکہ سے فرار ہو کر ) حاضر ہوئے۔ وہ مسلمان ہو چکے تھے۔ قریش نے انہیں واپس لینے کے لیے دو آدمیوں کو بھیجا اور انہوں نے آ کر کہا کہ ہمارے ساتھ آپ کا معاہدہ ہو چکا ہے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے ابوبصیر رضی اللہ عنہ کو واپس کر دیا۔ قریش کے دونوں افراد جب انہیں واپس لے کر لوٹے اور ذوالحلیفہ پہنچے تو کھجور کھانے کے لیے اترے جو ان کے ساتھ تھی۔ ابوبصیر رضی اللہ عنہ نے ان میں سے ایک سے فرمایا قسم اللہ کی تمہاری تلوار بہت اچھی معلوم ہوتی ہے۔ دوسرے ساتھی نے تلوار نیام سے نکال دی۔ اس شخص نے کہا ہاں اللہ کی قسم نہایت عمدہ تلوار ہے ‘ میں اس کا بارہا تجربہ کر چکا ہوں۔ ابوبصیر رضی اللہ عنہ اس پر بولے کہ ذرا مجھے بھی تو دکھاؤ اور اس طرح اپنے قبضہ میں کر لیا پھر اس شخص نے تلوار کے مالک کو ایسی ضرب لگائی کہ وہ وہیں ٹھنڈا ہو گیا۔ اس کا دوسرا ساتھی بھاگ کر مدینہ آیا اور مسجد میں دوڑتا ہوا۔ داخل ہوا نبی کریم صلی اللہ علیہ وسلم نے جب اسے دیکھا تو فرمایا یہ شخص کچھ خوف زدہ معلوم ہوتا ہے۔ جب وہ آپ صلی اللہ علیہ وسلم کے قریب پہنچا تو کہنے لگا اللہ کی قسم میرا ساتھی تو مارا گیا اور میں بھی مارا جاؤں گا ( اگر آپ لوگوں نے ابوبصیر کو نہ روکا ) اتنے میں ابوبصیر بھی آ گئے اور عرض کیا اے اللہ کے نبی! اللہ کی قسم اللہ تعالیٰ نے آپ کی ذمہ داری پوری کر دی ‘ آپ مجھے ان کے حوالے کر چکے تھے لیکن اللہ تعالیٰ نے مجھے ان سے نجات دلائی۔ آپ صلی اللہ علیہ وسلم نے فرمایا ( تیری ماں کی خرابی ) اگر اس کا کوئی ایک بھی مددگار ہوتا تو پھر لڑائی کے شعلے بھڑک اٹھتے۔ جب انہوں نے آپ صلی اللہ علیہ وسلم کے یہ الفاظ سنے تو سمجھ گئے کہ آپ صلی اللہ علیہ وسلم پھر کفار کے حوالے کر دیں گے اس لیے وہاں سے نکل گئے اور سمندر کے کنارے پر آ گئے۔ راوی نے بیان کیا کہ اپنے گھر والوں ( مکہ سے ) چھوٹ کر ابوجندل بن سہیل رضی اللہ عنہ بھی ابوبصیر رضی اللہ عنہ سے جا ملے اور اب یہ حال تھا کہ قریش کا جو شخص بھی اسلام لاتا ( بجائے مدینہ آنے کے ) ابوبصیر رضی اللہ عنہ کے یہاں ( ساحل سمندر پر ) چلا جاتا۔ اس طرح سے ایک جماعت بن گئی اور اللہ گواہ ہے یہ لوگ قریش کے جس قافلے کے متعلق بھی سن لیتے کہ وہ شام جا رہا ہے تو اسے راستے ہی میں روک کر لوٹ لیتے اور قافلہ والوں کو قتل کر دیتے۔ اب قریش نے نبی کریم صلی اللہ علیہ وسلم کے یہاں اللہ اور رحم کا واسطہ دے کر درخواست بھیجی کہ آپ کسی کو بھیجیں ( ابوبصیر رضی اللہ عنہ اور ان کے دوسرے ساتھیوں کے یہاں کہ وہ قریش کی ایذا سے رک جائیں ) اور اس کے بعد جو شخص بھی آپ صلی اللہ علیہ وسلم کے یہاں جائے گا ( مکہ سے ) اسے امن ہے۔ چنانچہ آپ صلی اللہ علیہ وسلم نے ان کے یہاں اپنا آدمی بھیجا اور اللہ تعالیٰ نے یہ آیت نازل فرمائی «وهو الذي كف أيديهم عنكم وأيديكم عنهم ببطن مكة من بعد أن أظفركم عليهم‏» ”اور وہ ذات پروردگار جس نے روک دیا تھا تمہارے ہاتھوں کو ان سے اور ان کے ہاتھوں کو تم سے ( یعنی جنگ نہیں ہو سکی تھی ) وادی مکہ میں ( حدیبیہ میں ) بعد میں اس کے کہ تم کو غالب کر دیا تھا ان پر یہاں تک کہ بات جاہلیت کے دور کی بے جا حمایت تک پہنچ گئی تھی ) ۔“ ان کی حمیت ( جاہلیت ) یہ تھی کہ انہوں نے ( معاہدے میں بھی ) آپ کے لیے اللہ کے نبی ہونے کا اقرار نہیں کیا اسی طرح انہوں نے «بسم الله الرحمن الرحيم» نہیں لکھنے دیا اور آپ بیت اللہ جانے سے مانع بنے۔' WHERE id = 2621;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا سعد بن ابراہیم سے ‘ ان سے عامر بن سعد نے اور ان سے سعد بن ابی وقاص نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ( حجۃ الوداع میں ) میری عیادت کو تشریف لائے ‘ میں اس وقت مکہ میں تھا۔ نبی کریم صلی اللہ علیہ وسلم اس سر زمین پر موت کو پسند نہیں فرماتے تھے جہاں سے کوئی ہجرت کر چکا ہو۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ ابن عفراء ( سعد بن خولہ رضی اللہ عنہ ) پر رحم فرمائے۔“ میں عرض کیا یا رسول اللہ! میں اپنے سارے مال و دولت کی وصیت کر دوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”نہیں“ میں نے پوچھا پھر آدھے کی کر دوں؟ آپ صلی اللہ علیہ وسلم نے اس پر بھی یہی فرمایا ”نہیں“ میں نے پوچھا پھر تہائی کی کر دوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا تہائی کی کر سکتے ہو اور یہ بھی بہت ہے ‘ اگر تم اپنے وارثوں کو اپنے پیچھے مالدار چھوڑو تو یہ اس سے بہتر ہے کہ انہیں محتاج چھوڑو کہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں ‘ اس میں کوئی شبہ نہیں کہ جب تم اپنی کوئی چیز ( اللہ کے لیے خرچ کرو گے ) تو وہ خیرات ہے ‘ یہاں تک کہ وہ لقمہ بھی جو تم اپنی بیوی کے منہ میں ڈالو گے ( وہ بھی خیرات ہے ) اور ( ابھی وصیت کرنے کی کوئی ضرورت بھی نہیں ) ممکن ہے کہ اللہ تعالیٰ تمہیں شفاء دے اور اس کے بعد تم سے بہت سے لوگوں کو فائدہ ہو اور دوسرے بہت سے لوگ ( اسلام کے مخالف ) نقصان اٹھائیں۔ اس وقت سعد رضی اللہ عنہ کی صرف ایک بیٹی تھی۔' WHERE id = 2631;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا ‘ کہا ہم کو امام مالک نے خبر دی ‘ انہوں نے اسحاق بن عبداللہ بن ابی طلحہ سے، انہوں نے انس رضی اللہ عنہ سے سنا ‘ انہوں نے کہا نبی کریم صلی اللہ علیہ وسلم نے ابوطلحہ سے فرمایا ( جب انہوں نے اپنا باغ بیرحاء اللہ کی راہ میں دینا چاہا ) میں مناسب سمجھتا ہوں تو یہ باغ اپنے عزیزوں کو دیدے۔ ابوطلحہ نے کہا بہت خوب ایسا ہی کروں گا۔ پھر ابوطلحہ نے وہ باغ اپنے عزیزوں اور چچا کے بیٹوں میں تقسیم کر دیا اور ابن عباس رضی اللہ عنہما نے کہا جب ( سورۃ الشعراء کی ) یہ آیت اتری «وأنذر عشيرتك الأقربين‏» اور اپنے قریب کے ناطے والوں کو ( اللہ کے عذاب سے ) ڈرا تو آپ صلی اللہ علیہ وسلم قریش کے خاندانوں بنی فہر ‘ بنی عدی کو پکارنے لگے ( ان کو ڈرایا ) اور ابوہریرہ رضی اللہ عنہ نے کہا جب یہ آیت اتری «وأنذر عشيرتك الأقربين‏» آپ صلی اللہ علیہ وسلم نے فرمایا اے قریش کے لوگو! ( اللہ سے ڈرو ) ۔' WHERE id = 2641;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا ‘ کہا کہ ہم کو ہشام بن یوسف نے خبر دی ‘ انہیں ابن جریج نے خبر دی کہا کہ مجھے یعلیٰ بن مسلم نے خبر دی ‘ انہوں نے ابن عباس رضی اللہ عنہما کے غلام عکرمہ سے سنا اور انہیں ابن عباس رضی اللہ عنہما نے خبر دی کہ قبیلہ بنی ساعدہ کے بھائی سعد بن عبادہ رضی اللہ عنہ کی ماں کا انتقال ہوا تو وہ ان کی خدمت میں حاضر نہیں تھے ( بلکہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھ غزوہ دومۃ الجندل میں شریک تھے ) اس لیے وہ آپ صلی اللہ علیہ وسلم کے پاس آئے اور عرض کیا یا رسول اللہ! میری والدہ کا انتقال ہو گیا ہے اور میں اس وقت موجود نہیں تھا تو اگر میں ان کی طرف سے خیرات کروں تو انہیں اس کا فائدہ پہنچے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں! سعد رضی اللہ عنہ نے اس پر کہا کہ میں آپ کو گواہ بناتا ہوں کہ میرا باغ مخراف نامی ان کی طرف سے خیرات ہے۔' WHERE id = 2651;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا ‘ کہا ہم سے یزید بن زریع نے بیان کیا ‘ کہا ہم سے عبداللہ بن عون رضی اللہ عنہ نے بیان کیا ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ہم سے مسدد بن مسرہد نے بیان کیا ‘ کہا ہم سے یزید بن زریع نے بیان کیا ‘ کہا ہم سے عبداللہ بن عون رضی اللہ عنہ نے بیان کیا ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ' WHERE id = 2661;
UPDATE hadiths SET urdu = 'ہم سے حسن بن صباح نے بیان کیا ‘ کہا ہم سے محمد بن سابق نے بیان کیا ‘ کہا ہم سے مالک بن مغول نے بیان کیا ‘ کہا کہ میں نے ولید بن عیزار سے سنا ‘ ان سے سعید بن ایاس ابوعمرو شیبانی نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ ہم سے حسن بن صباح نے بیان کیا ‘ کہا ہم سے محمد بن سابق نے بیان کیا ‘ کہا ہم سے مالک بن مغول نے بیان کیا ‘ کہا کہ میں نے ولید بن عیزار سے سنا ‘ ان سے سعید بن ایاس ابوعمرو شیبانی نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے پوچھا کہ دین کے کاموں میں کون سا عمل افضل ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”وقت پر نماز پڑھنا۔“ میں نے پوچھا اس کے بعد؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”والدین کے ساتھ نیک سلوک کرنا۔“ میں نے پوچھا اور اس کے بعد؟ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے راستے میں جہاد کرنا۔“ پھر میں نے آپ صلی اللہ علیہ وسلم سے زیادہ سوالات نہیں کئے ‘ ورنہ آپ صلی اللہ علیہ وسلم اسی طرح ان کے جوابات عنایت فرماتے۔' WHERE id = 2671;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے سفیان نے بیان کیا انہوں نے ابوحازم سے اور ان سے سہل بن سعد رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کے راستے میں گزرنے والی ایک صبح و شام دنیا اور جو کچھ دنیا میں ہے سب سے بڑھ کر ہے۔“' WHERE id = 2682;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا ‘ کہا ہم کو شعیب نے خبر دی زہری سے ‘ دوسری سند اور مجھ سے اسماعیل نے بیان کیا ‘ کہا کہ مجھ سے میرے بھائی نے بیان کیا ‘ ان سے سلیمان نے ‘ میرا خیال ہے کہ محمد بن عتیق کے واسطہ سے ‘ ان سے ابن شہاب (زہری) نے اور ان سے خارجہ بن زید نے کہ زید بن ثابت رضی اللہ عنہ نے بیان کیا کہ جب قرآن مجید کو ایک مصحف ( کتابی ) کی صورت میں جمع کیا جانے لگا تو میں نے سورۃ الاحزاب کی ایک آیت نہیں پائی جس کی رسول اللہ صلی اللہ علیہ وسلم سے برابر آپ کی تلاوت کرتے ہوئے سنتا رہا تھا جب میں نے اسے تلاش کیا تو ) صرف خزیمہ بن ثابت انصاری رضی اللہ عنہ کے یہاں وہ آیت مجھے ملی۔ یہ خزیمہ رضی اللہ عنہ وہی ہیں جن کی اکیلے کی گواہی کو رسول اللہ صلی اللہ علیہ وسلم نے دو آدمیوں کی گواہی کے برابر قرار دیا تھا۔ وہ آیت یہ تھی «من المؤمنين رجال صدقوا ما عاهدوا الله عليه‏» ( سورۃ الاحزاب: 23 ) ”مومنوں میں سے کچھ مرد ایسے ہیں جنہوں نے وہ بات سچ کہی جس پر انہوں نے اللہ سے عہد کیا۔“' WHERE id = 2693;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے غندر نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ کہا میں نے قتادہ سے سنا ‘ کہا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کوئی شخص بھی ایسا نہ ہو گا جو جنت میں داخل ہونے کے بعد دنیا میں دوبارہ آنا پسند کرے ‘ خواہ اسے ساری دنیا مل جائے سوائے شہید کے۔ اس کی یہ تمنا ہو گی کہ دنیا میں دوبارہ واپس جا کر دس مرتبہ اور قتل ہو ( اللہ کے راستے میں ) کیونکہ وہ شہادت کی عزت وہاں دیکھتا ہے۔' WHERE id = 2703;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا کہا ہم سے زہری نے بیان کیا، کہا کہ مجھے عنبسہ بن سعید نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان فرمایا کہ میں جب رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو آپ صلی اللہ علیہ وسلم خیبر میں ٹھہرے ہوئے تھے اور خیبر فتح ہو چکا تھا، میں نے عرض کیا یا رسول اللہ! میرا بھی ( مال غنیمت میں ) حصہ لگائیے۔ سعید بن العاص کے ایک لڑکے ( ابان بن سعید رضی اللہ عنہ ) نے کہا یا رسول اللہ! ان کا حصہ نہ لگائیے۔ اس پر ابوہریرہ رضی اللہ عنہ بولے کہ یہ شخص تو ابن قوتل ( نعمان بن مالک رضی اللہ عنہ ) کا قاتل ہے۔ ابان بن سعید رضی اللہ عنہ نے کہا کتنی عجیب بات ہے کہ یہ جانور ( یعنی ابوہریرہ ابھی تو پہاڑ کی چوٹی سے بکریاں چراتے چراتے یہاں آ گیا ہے اور ایک مسلمان کے قتل کا مجھ پر الزام لگاتا ہے۔ اس کو یہ خبر نہیں کہ جسے اللہ تعالیٰ نے میرے ہاتھوں سے ( شہادت ) عزت دی اور مجھے اس کے ہاتھوں سے ذلیل ہونے سے بچا لیا ( اگر اس وقت میں مارا جاتا ) تو دوزخی ہوتا ‘ عنبسہ نے بیان کیا کہ اب مجھے یہ نہیں معلوم کہ آپ صلی اللہ علیہ وسلم نے ان کا بھی حصہ لگایا یا نہیں۔ سفیان نے بیان کیا ‘ کہا کہ مجھ سے سعیدی نے اپنے دادا کے واسطے سے بیان کیا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے۔ ابوعبداللہ ( امام بخاری رحمہ اللہ ) نے کہا کہ سعیدی سے مراد عمرو بن یحییٰ بن سعید بن عمرو بن سعید بن عاص ہیں۔' WHERE id = 2713;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو غزوہ احزاب ( خندق ) کے موقع پر دیکھا کہ آپ صلی اللہ علیہ وسلم مٹی ( خندق کھودنے کی وجہ سے جو نکلتی تھی ) خود ڈھو رہے تھے۔ مٹی سے آپ صلی اللہ علیہ وسلم کے پیٹ کی سفیدی چھپ گئی تھی اور یہ شعر کہہ رہے تھے «لولا أنت ما اهتدينا ولا تصدقنا ولا صلينا‏.‏ فأنزل السكينة علينا وثبت الأقدام إن لاقينا‏.‏ إن الألى قد بغوا علينا إذا أرادوا فتنة أبينا‏.‏» ”اے اللہ اگر تو نہ ہوتا تو ہم ہدایت نہ پاتے اور ہم نہ صدقہ دیتے، اور نہ نماز پڑھتے، پس تو ہم پر سکینت نازل فرما، اور جب ہم دشمن سے مقابلہ کریں، تو ہمیں ثابت قدم رکھ، بے شک ان لوگوں نے ہم پر ظلم کیا ہے، جب یہ کوئی فساد کرنا چاہتے ہیں تو ہم ان کی بات میں نہیں آتے۔“' WHERE id = 2723;
UPDATE hadiths SET urdu = 'ہم سے صدقہ نے بیان کیا ‘ کہا ہم کو ابن عیینہ نے خبر دی ‘ کہا ہم سے ابن منکدر نے بیان کیا ‘ انہوں نے جابر بن عبداللہ صلی اللہ علیہ وسلم سے سنا ‘ انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے صحابہ کو ( بنی قریظہ کی طرف خبر لانے کے لیے ) دعوت دی۔ صدقہ ( امام بخاری رحمہ اللہ کے استاد ) نے کہا کہ میرا خیال ہے یہ غزوہ خندق کا واقعہ ہے۔ تو زبیر رضی اللہ عنہ نے اس پر لبیک کہا پھر آپ صلی اللہ علیہ وسلم نے بلایا اور زبیر رضی اللہ عنہ نے لبیک کہا پھر تیسری بار آپ صلی اللہ علیہ وسلم نے بلایا اور اس مرتبہ بھی زبیر رضی اللہ عنہ نے لبیک کہا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا ہر نبی کے حواری ہوتے ہیں اور میرے حواری زبیر بن عوام ہیں۔' WHERE id = 2733;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا کہ میں نے قتادہ سے سنا کہ انس بن مالک رضی اللہ عنہ نے بیان کیا ( ایک رات ) مدینہ میں کچھ خطرہ سا محسوس ہوا تو نبی کریم صلی اللہ علیہ وسلم نے ہمارا ( ابوطلحہ رضی اللہ عنہ کا جو آپ کے عزیز تھے ) گھوڑا منگوایا، گھوڑے کا نام مندوب تھا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا ”خطرہ تو ہم نے کوئی نہیں دیکھا البتہ اس گھوڑے کو ہم نے سمندر پایا ہے۔“' WHERE id = 2743;
UPDATE hadiths SET urdu = 'ہم سے عبدالاعلیٰ بن حماد نے بیان کیا، کہا ہم سے یزید بن زریع نے بیان کیا، کہا ہم سے سعید نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ایک مرتبہ ( رات میں ) اہل مدینہ کو دشمن کا خطرہ ہوا تو نبی کریم صلی اللہ علیہ وسلم ابوطلحہ رضی اللہ عنہ کے ایک گھوڑے ( مندوب ) پر سوار ہوئے، گھوڑا سست رفتار تھا یا ( راوی نے یوں کہا کہ ) اس کی رفتار میں سستی تھی، پھر جب آپ صلی اللہ علیہ وسلم واپس ہوئے تو فرمایا کہ ہم نے تو تمہارے اس گھوڑے کو دریا پایا ( یہ بڑا ہی تیز رفتار ہے ) چنانچہ اس کے بعد کوئی گھوڑا اس سے آگے نہیں نکل سکتا تھا۔' WHERE id = 2753;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن عمر نمیری نے، انہوں نے کہا ہم سے یونس بن یزید ایلی نے بیان کیا، کہا میں نے ابن شہاب زہری سے سنا، کہا کہ میں نے عروہ بن زبیر، سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ سے عائشہ رضی اللہ عنہا کی حدیث سنی، ان چاروں نے عائشہ رضی اللہ عنہا کی یہ حدیث مجھ سے تھوڑی تھوڑی بیان کی۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم باہر تشریف لے جانا چاہتے ( جہاد کے لیے ) تو اپنی ازواج میں قرعہ ڈالتے اور جس کا نام نکل آتا انہیں آپ صلی اللہ علیہ وسلم اپنے ساتھ لے جاتے تھے۔ ایک غزوہ کے موقع پر آپ صلی اللہ علیہ وسلم نے ہمارے درمیان قرعہ اندازی کی تو اس مرتبہ میرا نام آیا اور میں آپ صلی اللہ علیہ وسلم کے ساتھ گئی، یہ پردے کا حکم نازل ہونے کے بعد کا واقعہ ہے۔' WHERE id = 2764;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کا، ان سے مطلب بن حنطب کے مولیٰ عمرو بن ابی عمرو نے اور انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ خیبر ( غزوہ کے موقع پر ) گیا، میں آپ صلی اللہ علیہ وسلم کی خدمت کیا کرتا تھا، پھر جب آپ صلی اللہ علیہ وسلم واپس ہوئے اور احد پہاڑ دکھائی دیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ وہ پہاڑ ہے جس سے ہم محبت کرتے ہیں اور وہ ہم سے محبت کرتا ہے۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے اپنے ہاتھ سے مدینہ کی طرف اشارہ کر کے فرمایا۔ اے اللہ! میں اس کے دونوں پتھریلے میدانوں کے درمیان کے خطے کو حرمت والا قرار دیتا ہوں، جس طرح ابراہیم علیہ السلام نے مکہ کو حرمت والا شہر قرار دیا تھا، اے اللہ! ہمارے صاع اور ہمارے مد میں برکت عطا فرما۔' WHERE id = 2774;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں معمر نے، انہیں زہری نے، انہیں ابن المسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ حبشہ کے کچھ لوگ نبی کریم صلی اللہ علیہ وسلم کے سامنے حراب ( چھوٹے نیزے ) کا کھیل دکھلا رہے تھے کہ عمر رضی اللہ عنہ آ گئے اور کنکریاں اٹھا کر انہیں ان سے مارا۔ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا ”عمر انہیں کھیل دکھانے دو۔“ علی بن مدینی نے یہ بیان زیادہ کیا کہ ہم سے عبدالرزاق نے بیان کیا، انہیں معمر نے خبر دی کہ مسجد میں ( یہ صحابہ رضی اللہ عنہم اپنے کھیل کا مظاہرہ کر رہے تھے ) ۔' WHERE id = 2785;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا کہ ہم کو شعیب نے خبر دی، انہیں زہری نے، ان سے سنان بن ابی سنان اور ابوسلمہ نے بیان کیا اور ان دونوں حضرات کو جابر رضی اللہ عنہ نے خبر دی۔ اور ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہیں ابراہیم بن سعد نے خبر دی، انہیں ابن شہاب نے خبر دی، انہیں سنان بن ابی سنان الدولی نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک لڑائی میں شریک تھے۔ ایک ایسے جنگل میں جہاں ببول کے درخت بکثرت تھے۔ قیلولہ کا وقت ہو گیا، تمام صحابہ سائے کی تلاش میں ( پوری وادی میں متفرق درختوں کے نیچے ) پھیل گئے اور نبی کریم صلی اللہ علیہ وسلم نے بھی ایک درخت کے نیچے قیام فرمایا۔ آپ صلی اللہ علیہ وسلم نے تلوار ( درخت کے تنے سے ) لٹکا دی تھی اور سو گئے تھے۔ جب آپ صلی اللہ علیہ وسلم بیدار ہوئے تو آپ صلی اللہ علیہ وسلم کے پاس ایک اجنبی موجود تھا۔ اس اجنبی نے کہا کہ اب تمہیں مجھ سے کون بچائے گا؟ پھر نبی کریم صلی اللہ علیہ وسلم نے آواز دی اور جب صحابہ رضی اللہ عنہم اجمعین آپ صلی اللہ علیہ وسلم کے قریب پہنچے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس شخص نے میری ہی تلوار مجھ پر کھینچ لی تھی اور مجھ سے کہنے لگا تھا کہ اب تمہیں میرے ہاتھ سے کون بچا سکے گا؟ میں نے کہا اللہ ( اس پر وہ شخص خود ہی دہشت زدہ ہو گیا ) اور تلوار نیام میں کر لی، اب یہ بیٹھا ہوا ہے۔ آپ صلی اللہ علیہ وسلم نے اسے کوئی سزا نہیں دی تھی۔' WHERE id = 2796;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا مجھ سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے جعفر بن عمرو بن امیہ نے اور ان سے ان کے والد نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ آپ صلی اللہ علیہ وسلم شانے کا گوشت ( چھری سے ) کاٹ کر کھا رہے تھے، پھر نماز کے لیے اذان ہوئی تو آپ صلی اللہ علیہ وسلم نے نماز پڑھی لیکن وضو نہیں کیا۔ ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی اور انہیں زہری نے ( اس روایت میں ) یہ زیادتی بھی موجود ہے کہ ( جب آپ صلی اللہ علیہ وسلم نماز کے لیے بلائے گئے تو ) آپ صلی اللہ علیہ وسلم نے چھری ڈال دی۔' WHERE id = 2806;
UPDATE hadiths SET urdu = 'ہم سے احمد بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں اسماعیل بن ابی خالد نے خبر دی اور انہوں نے عبداللہ بن ابی اوفی رضی اللہ عنہ سے سنا، آپ بیان کرتے تھے کہ غزوہ احزاب کے موقع پر رسول اللہ صلی اللہ علیہ وسلم نے یہ دعا کی تھی «اللهم منزل الكتاب سريع الحساب،‏‏‏‏ ‏‏‏‏ اللهم اهزم الأحزاب،‏‏‏‏ ‏‏‏‏ اللهم اهزمهم وزلزلهم» ”اے اللہ! کتاب کے نازل کرنے والے ( قیامت کے دن ) حساب بڑی سرعت سے لینے والے، اے اللہ! مشرکوں اور کفار کی جماعتوں کو ( جو مسلمانوں کا استیصال کرنے آئی ہیں ) شکست دے۔ اے اللہ! انہیں شکست دے اور انہیں جھنجھوڑ کر رکھ دے۔“' WHERE id = 2816;
UPDATE hadiths SET urdu = '(دوسری سند) ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے حمید نے اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم رات میں خیبر تشریف لے گئے اور آپ صلی اللہ علیہ وسلم کی عادت تھی کہ جب کسی قوم تک رات کے وقت پہنچتے تو صبح سے پہلے ان پر حملہ نہیں کرتے تھے۔ جب صبح ہوئی تو یہودی اپنے پھاوڑے اور ٹوکرے لے کر باہر ( کھیتوں میں کام کرنے کے لیے ) نکلے۔ جب انہوں نے اسلامی لشکر کو دیکھا تو چیخ پڑے محمد واللہ محمد لشکر سمیت آ گئے۔ پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اللہ کی ذات سب سے بڑی ہے۔ اب خیبر تو خراب ہو گیا کہ جب ہم کسی قوم کے میدان میں مجاہدانہ اتر آتے ہیں تو ( کفر سے ) ڈرائے ہوئے لوگوں کی صبح منحوس ہو جاتی ہے۔' WHERE id = 2827;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ عمری نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے نبی کریم صلی اللہ علیہ وسلم کے حوالہ سے۔ (دوسری سند) اور مجھ سے محمد بن صباح نے بیان کیا، کہا ہم سے اسماعیل بن زکریا نے بیان کیا، ان سے عبیداللہ نے، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ” ( خلیفہ وقت کے احکام ) سننا اور انہیں بجا لانا ( ہر مسلمان کے لیے ) واجب ہے، جب تک کہ گناہ کا حکم نہ دیا جائے۔ اگر گناہ کا حکم دیا جائے تو پھر نہ اسے سننا چاہئے اور نہ اس پر عمل کرنا چاہئے۔“' WHERE id = 2837;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، کہا کہ میں نے مالک بن انس سے سنا، انہوں نے زید بن اسلم سے پوچھا تھا اور زید نے کہا کہ میں نے اپنے باپ سے سنا تھا، وہ بیان کرتے تھے کہ عمر بن خطاب رضی اللہ عنہ نے فرمایا میں نے اللہ کے راستے میں ( جہاد کے لیے ) اپنا ایک گھوڑا ایک شخص کو سواری کے لیے دے دیا تھا۔ پھر میں نے دیکھا کہ ( بازار میں ) وہی گھوڑا بک ( فروخت ہو ) رہا ہے۔ میں نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کہ کیا میں اسے خرید سکتا ہوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس گھوڑے کو تم نہ خریدو اور اپنا صدقہ ( خواہ خرید کر ہی ہو ) واپس نہ لو۔' WHERE id = 2849;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا کہ ہم کو سفیان نے خبر دی، ان سے عمرو نے بیان کیا، کہا مجھ کو عطاء نے خبر دی، انہوں نے جابر بن عبداللہ رضی اللہ عنہ سے سنا آپ نے بیان کیا کہ ہم لوگ نبی کریم صلی اللہ علیہ وسلم کے زمانے میں قربانی کا گوشت بطور توشہ مدینہ لے جایا کرتے تھے ( یہ لے جانا بطور توشہ ہوا کرتا تھا، اس سے آپ کا مطلب ثابت ہوا ) ۔' WHERE id = 2859;
UPDATE hadiths SET urdu = 'سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک رحمہ اللہ نے، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے دشمن کے علاقے میں قرآن مجید لے کر جانے سے منع فرمایا تھا۔' WHERE id = 2869;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم کو محمد بن جعفر نے خبر دی، کہا کہ مجھے زید بن اسلم نے خبر دی، ان سے ان کے والد نے بیان کیا کہ میں عبداللہ بن عمر رضی اللہ عنہما کے ساتھ مکہ کے راستے میں تھا، اتنے میں ان کو صفیہ بنت ابی عبید رضی اللہ عنہا ( ان کی بیوی ) کے متعلق سخت بیماری کی خبر ملی۔ چنانچہ آپ نے تیز چلنا شروع کر دیا اور جب ( سورج غروب ہونے کے بعد ) شفق ڈوب گئی تو آپ سواری سے اترے اور مغرب اور عشاء کی نماز ملا کر پڑھی، پھر کہا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو دیکھا کہ جب آپ صلی اللہ علیہ وسلم تیزی کے ساتھ سفر کرنا چاہتے تو مغرب میں تاخیر کر کے دونوں نمازیں ( مغرب اور عشاء ) ایک ساتھ ادا فرماتے۔' WHERE id = 2879;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا ‘ کہا ہم سے غندر نے بیان کیا ‘ کہا ہم شعبہ نے بیان کیا ‘ ان سے محمد بن زیاد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایسے لوگوں پر اللہ کو تعجب ہو گا ‘ جو جنت میں بیڑیوں سمیت داخل ہوں گے ( یعنی مسلمانوں نے کافروں کو پکڑ کر بیڑیوں میں قید کر دیا پھر وہ مسلمان ہو گئے تو اللہ تعالیٰ ان کو اسلام کی وجہ سے جنت میں داخل کر دے گا تو اللہ تعالیٰ ایسے لوگوں پر تعجب کریں گے کہ یہ لوگ اپنے کفر کی وجہ سے پابہ زنجیر ہوئے اور اسلام لا کر جنت میں داخل ہو گئے۔)' WHERE id = 2889;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا ‘ کہا ہم سے یحییٰ قطان نے بیان کیا ‘ ان سے اسماعیل نے بیان کیا ‘ کہا مجھ سے قیس بن ابی حازم نے بیان کیا ‘ کہا کہ مجھ سے جریر بن عبداللہ رضی اللہ عنہ نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ذوالخلصہ کو ( برباد کر کے ) مجھے راحت کیوں نہیں دے دیتے۔ یہ ذوالخلصہ قبیلہ خثعم کا ایک بت خانہ تھا اور اسے «كعبة اليمانية» کہتے تھے۔ انہوں نے بیان کیا کہ پھر میں قبیلہ احمس کے ایک سو پچاس سواروں کو لے کر چلا۔ یہ سب حضرات بڑے اچھے گھوڑ سوار تھے۔ لیکن میں گھوڑے کی سواری اچھی طرح نہیں کر پاتا تھا۔ آپ صلی اللہ علیہ وسلم نے میرے سینے پر ( اپنے ہاتھ سے ) مارا ‘ میں نے انگشت ہائے مبارک کا نشان اپنے سینے پر دیکھا۔ فرمایا: اے اللہ! گھوڑے کی پشت پر اسے ثبات عطا فرما ‘ اور اسے دوسروں کو ہدایت کی راہ دکھانے والا اور خود ہدایت یافتہ بنا ‘ اس کے بعد جریر رضی اللہ عنہ روانہ ہوئے ‘ اور ذوالخلصہ کی عمارت کو گرا کر اس میں آگ لگا دی۔ پھر رسول اللہ صلی اللہ علیہ وسلم کو اس کی خبر بھجوائی۔ جریر رضی اللہ عنہ کے قاصد ( ابو ارطاۃ حصین بن ربیعہ ) نے خدمت نبوی میں حاضر ہو کر عرض کیا اس ذات کی قسم! جس نے آپ کو حق کے ساتھ مبعوث کیا ہے۔ میں اس وقت تک آپ کی خدمت میں حاضر نہیں ہوا ‘ جب تک ہم نے ذوالخلصہ کو ایک خالی پیٹ والے اونٹ کی طرح نہیں بنا دیا ‘ یا ( انہوں نے کہا ) خارش والے اونٹ کی طرح ( مراد ویرانی سے ہے ) جریر رضی اللہ عنہ نے بیان کیا کہ یہ سن کر آپ صلی اللہ علیہ وسلم نے قبیلہ احمس کے سواروں اور قبیلوں کے تمام لوگوں کے لیے پانچ مرتبہ برکتوں کی دعا فرمائی۔' WHERE id = 2899;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا ‘ کہا ہم سے ابوالاحوص نے بیان کیا ‘ ان سے ابواسحاق نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ میں نے دیکھا کہ غزوہ احزاب میں ( خندق کھودتے ہوئے ) رسول اللہ صلی اللہ علیہ وسلم خود مٹی اٹھا رہے تھے۔ یہاں تک کہ سینہ مبارک کے بال مٹی سے اٹ گئے تھے۔ آپ صلی اللہ علیہ وسلم کے ( جسم مبارک پر ) بال بہت گھنے تھے۔ اس وقت آپ صلی اللہ علیہ وسلم عبداللہ بن رواحہ رضی اللہ عنہ کا یہ شعر پڑھ رہے تھے ”اے اللہ! اگر تیری ہدایت نہ ہوتی تو ہم کبھی سیدھا راستہ نہ پاتے ‘ نہ صدقہ کر سکتے اور نہ نماز پڑھتے۔ اب تو، یا اللہ! ہمارے دلوں کو سکون اور اطمینان عطا فرما ‘ اور اگر ( دشمنوں سے مڈبھیڑ ہو جائے تو ہمیں ثابت قدم رکھ ‘ دشمنوں نے ہمارے اوپر زیادتی کی ہے۔ جب بھی وہ ہم کو فتنہ فساد میں مبتلا کرنا چاہتے ہیں تو ہم انکار کرتے ہیں۔“ آپ یہ شعر بلند آواز سے پڑھ رہے تھے۔)' WHERE id = 2911;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ انہوں نے کہا ہم سے جریر نے بیان کیا۔ ان سے منصور نے بیان کیا ‘ ان سے ابووائل نے بیان کیا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا ‘ انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ” «عاني» یعنی قیدی کو چھڑایا کرو ‘ بھوکے کو کھلایا کرو ‘ بیمار کی عیادت کرو۔“' WHERE id = 2922;
UPDATE hadiths SET urdu = 'عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ( ایک مرتبہ ) ابی بن کعب رضی اللہ عنہ کو ساتھ لے کر آپ صلی اللہ علیہ وسلم اس کھجور کے باغ میں تشریف لائے جس میں ابن صیاد موجود تھا۔ جب آپ صلی اللہ علیہ وسلم باغ میں داخل ہو گئے تو کھجور کے تنوں کی آڑ لیتے ہوئے آپ صلی اللہ علیہ وسلم آگے بڑھنے لگے۔ آپ چاہتے یہ تھے کہ اسے آپ کی موجودگی کا احساس نہ ہو سکے اور آپ اس کی باتیں سن لیں۔ ابن صیاد اس وقت اپنے بستر پر ایک چادر اوڑھے پڑا تھا اور کچھ گنگنا رہا تھا۔ اتنے میں اس کی ماں نے آپ صلی اللہ علیہ وسلم کو دیکھ لیا کہ آپ کھجور کے تنوں کی آڑ لے کر آگے آ رہے ہیں اور اسے آگاہ کر دیا کہ اے صاف! یہ اس کا نام تھا۔ ابن صیاد یہ سنتے ہی اچھل پڑا۔ آپ صلی اللہ علیہ وسلم نے فرمایا ‘ اگر اس کی ماں نے اسے یوں ہی رہنے دیا ہوتا تو حقیقت کھل جاتی۔' WHERE id = 2932;
UPDATE hadiths SET urdu = 'اور عبداللہ بن نمیر نے کہا ‘ کہ ہم سے عبیداللہ نے بیان کیا ‘ ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ ان کا ایک گھوڑا بھاگ گیا تھا اور دشمنوں نے اس کو پکڑ لیا تھا۔ پھر مسلمانوں کو غلبہ حاصل ہوا تو ان کا گھوڑا انہیں واپس کر دیا گیا۔ یہ واقعہ رسول اللہ صلی اللہ علیہ وسلم کے عہد مبارک کا ہے۔ اسی طرح ان کے ایک غلام نے بھاگ کر روم میں پناہ حاصل کر لی تھی۔ پھر جب مسلمانوں کو اس ملک پر غلبہ حاصل ہوا تو خالد بن ولید رضی اللہ عنہ نے ان کا غلام انہیں واپس کر دیا۔ یہ واقعہ نبی کریم صلی اللہ علیہ وسلم کے بعد کا ہے۔' WHERE id = 2942;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا ‘ کہا ہم سے شیبان نے بیان کیا ‘ ان سے منصور نے ‘ ان سے مجاہد نے ‘ ان سے طاؤس نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فتح مکہ کے دن فرمایا ”اب ہجرت ( مکہ سے مدینہ کے لیے ) باقی نہیں رہی ‘ البتہ حسن نیت اور جہاد باقی ہے۔ اس لیے جب تمہیں جہاد کے لیے بلایا جائے تو فوراً نکل جاؤ۔“' WHERE id = 2952;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا ‘ کہا ہم کو وکیع نے خبر دی ‘ انہیں شعبہ نے ‘ انہیں محارب بن دثار نے اور انہیں جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم جب مدینہ تشریف لائے ( غزوہ تبوک یا ذات الرقاع سے ) تو اونٹ یا گائے ذبح کی ( راوی کو شبہ ہے ) معاذ عنبری نے ( اپنی روایت میں ) کچھ زیادتی کے ساتھ کہا۔ ان سے شعبہ نے بیان کیا ‘ ان سے محارب بن دثار نے ‘ انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے مجھ سے اونٹ خریدا تھا۔ دو اوقیہ اور ایک درہم یا ( راوی کو شبہ ہے کہ دو اوقیہ ) دو درہم میں۔ جب آپ مقام صرار پر پہنچے تو آپ نے حکم دیا اور گائے ذبح کی گئی اور لوگوں نے اس کا گوشت کھایا۔ پھر جب آپ مدینہ منورہ پہنچے تو مجھے حکم دیا کہ پہلے مسجد میں جا کر دو رکعت نماز پڑھوں ‘ اس کے بعد مجھے میرے اونٹ کی قیمت وزن کر کے عنایت فرمائی۔' WHERE id = 2963;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا ‘ کہا کہ مجھ سے لیث بن سعد نے بیان کیا ‘ کہا کہ مجھ سے عبدالرحمٰن بن خالد نے بیان کیا ‘ ان سے ابن شہاب نے ‘ ان سے علی بن حسین زین العابدین نے کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ صفیہ رضی اللہ عنہا نے انہیں خبر دی کہ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ملنے کے لیے حاضر ہوئیں۔ نبی کریم صلی اللہ علیہ وسلم رمضان کے آخری عشرہ کا مسجد میں اعتکاف کئے ہوئے تھے۔ پھر وہ واپس ہونے کے لیے اٹھیں تو نبی کریم صلی اللہ علیہ وسلم بھی ان کے ساتھ اٹھے۔ جب آپ صلی اللہ علیہ وسلم اپنی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا کے دروازہ کے قریب پہنچے جو مسجد نبوی کے دروازے سے ملا ہوا تھا تو دو انصاری صحابی ( اسید بن حضیر رضی اللہ عنہ اور عباد بن بشر رضی اللہ عنہ ) وہاں سے گزرے۔ اور آپ صلی اللہ علیہ وسلم کو انہوں نے سلام کیا اور آگے بڑھنے لگے۔ لیکن آپ صلی اللہ علیہ وسلم نے ان سے فرمایا ‘ ذرا ٹھہر جاؤ ( میرے ساتھ میری بیوی صفیہ رضی اللہ عنہا ہیں یعنی کوئی دوسرا نہیں ) ان دونوں نے عرض کیا۔ سبحان اللہ ‘ یا رسول اللہ! ان حضرات پر آپ کا یہ فرمانا بڑا شاق گزرا۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ شیطان انسان کے اندر اس طرح دوڑتا رہتا ہے جیسے جسم میں خون دوڑتا ہے۔ مجھے یہی خطرہ ہوا کہ کہیں تمہارے دلوں میں بھی کوئی وسوسہ پیدا نہ ہو جائے۔' WHERE id = 2974;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا ‘ کہا ہم سے سفیان بن عیینہ نے بیان کیا ‘ ان سے محمد بن سوقہ نے ‘ ان سے منذر بن یعلیٰ نے اور ان سے محمد بن حنفیہ نے ‘ انہوں نے کہا کہ اگر علی رضی اللہ عنہ، عثمان رضی اللہ عنہ کو برا کہنے والے ہوتے تو اس دن ہوتے جب کچھ لوگ عثمان رضی اللہ عنہ کے عاملوں کی ( جو زکوٰۃ وصول کرتے تھے ) شکایت کرنے ان کے پاس آئے۔ انہوں نے مجھ سے کہا عثمان رضی اللہ عنہ کے پاس جا اور یہ زکوٰۃ کا پروانہ لے جا۔ ان سے کہنا کہ یہ پروانہ آپ صلی اللہ علیہ وسلم کا لکھوایا ہوا ہے۔ تم اپنے عاملوں کو حکم دو کہ وہ اسی کے مطابق عمل کریں۔ چنانچہ میں اسے لے کر عثمان رضی اللہ عنہ کی خدمت میں حاضر ہوا اور انہیں پیغام پہنچا دیا ‘ لیکن انہوں نے فرمایا کہ ہمیں اس کی کوئی ضرورت نہیں ( کیونکہ ہمارے پاس اس کی نقل موجود ہے ) میں نے جا کر علی رضی اللہ عنہ سے یہ واقعہ بیان کیا ‘ تو انہوں نے فرمایا کہ اچھا ‘ پھر اس پروانے کو جہاں سے اٹھایا ہے وہیں رکھ دو۔' WHERE id = 2984;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن راہویہ نے بیان کیا ‘ انہوں نے جریر سے سنا ‘ انہوں نے عبدالملک سے اور ان سے جابر بن سمرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب کسریٰ مر جائے گا تو اس کے بعد کوئی کسریٰ پیدا نہ ہو گا اور جب قیصر مر جائے گا تو اس کے بعد کوئی قیصر پیدا نہ ہو گا اور اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے تم لوگ ان دونوں کے خزانے اللہ کے راستے میں خرچ کرو گے۔“' WHERE id = 2994;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عبدالوہاب نے کہا کہ ہم سے حماد نے بیان کیا ‘ کہا ہم سے ایوب نے بیان کیا ‘ ان سے ابوقلابہ نے بیان کیا اور (ایوب نے ایک دوسری سند کے ساتھ اس طرح روایت کی ہے کہ) مجھ سے قاسم بن عاصم کلیبی نے بیان کیا اور کہا کہ قاسم کی حدیث (ابوقلابہ کی حدیث کی بہ نسبت) مجھے زیادہ اچھی طرح یاد ہے ‘ زہدم سے ‘ انہوں نے بیان کیا کہ ہم ابوموسیٰ اشعری رضی اللہ عنہ کی مجلس میں حاضر تھے ( کھانا لایا گیا اور ) وہاں مرغی کا ذکر ہونے لگا۔ بنی تمیم اللہ کے ایک آدمی سرخ رنگ والے وہاں موجود تھے۔ غالباً موالی میں سے تھے۔ انہیں بھی ابوموسیٰ رضی اللہ عنہ نے کھانے پر بلایا ‘ وہ کہنے لگے کہ میں نے مرغی کو گندی چیزیں کھاتے ایک مرتبہ دیکھا تھا تو مجھے بڑی نفرت ہوئی اور میں نے قسم کھا لی کہ اب کبھی مرغی کا گوشت نہ کھاؤں گا۔ ابوموسیٰ رضی اللہ عنہ نے کہا کہ قریب آ جاؤ ( تمہاری قسم پر ) میں تم سے ایک حدیث اسی سلسلے کی بیان کرتا ہوں ‘ قبیلہ اشعر کے چند لوگوں کو ساتھ لے کر میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( غزوہ تبوک کے لیے ) حاضر ہوا اور سواری کی درخواست کی۔ آپ صلی اللہ علیہ وسلم نے فرمایا ”اللہ کی قسم! میں تمہارے لیے سواری کا انتظام نہیں کر سکتا ‘ کیونکہ میرے پاس کوئی ایسی چیز نہیں ہے جو تمہاری سواری کے کام آ سکے۔“ پھر آپ صلی اللہ علیہ وسلم کی خدمت میں غنیمت کے کچھ اونٹ آئے ‘ تو آپ صلی اللہ علیہ وسلم نے ہمارے متعلق دریافت فرمایا ‘ اور فرمایا کہ قبیلہ اشعر کے لوگ کہاں ہیں؟ چنانچہ آپ صلی اللہ علیہ وسلم نے پانچ اونٹ ہمیں دیئے جانے کا حکم صادر فرمایا ‘ خوب موٹے تازے اور فربہ۔ جب ہم چلنے لگے تو ہم نے آپس میں کہا کہ جو نامناسب طریقہ ہم نے اختیار کیا اس سے آپ صلی اللہ علیہ وسلم کے اس عطیہ میں ہمارے لیے کوئی برکت نہیں ہو سکتی۔ چنانچہ ہم پھر آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ ہم نے پہلے جب آپ سے درخواست کی تھی تو آپ نے قسم کھا کر فرمایا تھا کہ میں تمہاری سواری کا انتظام نہیں کر سکوں گا۔ شاید آپ کو وہ قسم یاد نہ رہی ہو ‘ لیکن آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہاری سواری کا انتظام واقعی نہیں کیا ‘ وہ اللہ تعالیٰ ہے جس نے تمہیں یہ سواریاں دے دی ہیں۔ اللہ کی قسم! تم اس پر یقین رکھو کہ ان شاءاللہ جب بھی میں کوئی قسم کھاؤں ‘ پھر مجھ پر یہ بات ظاہر ہو جائے کہ بہتر اور مناسب طرز عمل اس کے سوا میں ہے تو میں وہی کروں گا جس میں اچھائی ہو گی اور قسم کا کفارہ دے دوں گا۔' WHERE id = 3005;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف فریابی نے بیان کیا، کہا ہم سے امام اوزاعی نے بیان کیا، ان سے زہری نے، ان سے سعید بن مسیب اور عروہ بن زبیر رضی اللہ عنہ نے کہ حکیم بن حزام رضی اللہ عنہ نے بیان کیا، میں نے رسول اللہ صلی اللہ علیہ وسلم سے کچھ روپیہ مانگا تو آپ صلی اللہ علیہ وسلم نے مجھے عطا فرمایا، پھر دوبارہ میں نے مانگا اور اس مرتبہ بھی آپ نے عطا فرمایا، پھر ارشاد فرمایا، حکیم! یہ مال دیکھنے میں سرسبز بہت میٹھا اور مزیدار ہے لیکن جو شخص اسے دل کی بے طمعی کے ساتھ لے اس کے مال میں تو برکت ہوتی ہے اور جو شخص اسے لالچ اور حرص کے ساتھ لے تو اس کے مال میں برکت نہیں ہوتی، بلکہ اس کی مثال اس شخص جیسی ہے جو کھائے جاتا ہے لیکن اس کا پیٹ نہیں بھرتا اور اوپر کا ہاتھ ( دینے والا ) نیچے کے ہاتھ ( لینے والے ) سے بہتر ہوتا ہے۔ حکیم بن حزام رضی اللہ عنہ نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! آپ کے بعد اب میں کسی سے کچھ بھی نہیں مانگوں گا، یہاں تک کہ اس دنیا میں سے چلا جاؤں گا۔ چنانچہ ( آپ صلی اللہ علیہ وسلم کی وفات کے بعد ) ابوبکر رضی اللہ عنہ انہیں دینے کے لیے بلاتے، لیکن وہ اس میں سے ایک پیسہ بھی لینے سے انکار کر دیتے۔ پھر عمر رضی اللہ عنہ ( اپنے زمانہ خلافت میں ) انہیں دینے کے لیے بلاتے اور ان سے بھی لینے سے انہوں نے انکار کر دیا۔ عمر رضی اللہ عنہ نے اس پر کہا کہ مسلمانو! میں انہیں ان کا حق دیتا ہوں جو اللہ تعالیٰ نے فئے کے مال سے ان کا حصہ مقرر کیا ہے۔ لیکن یہ اسے بھی قبول نہیں کرتے۔ حکیم بن حزام رضی اللہ عنہ کی وفات ہو گئی لیکن آپ صلی اللہ علیہ وسلم کے بعد انہوں نے کسی سے کوئی چیز نہیں لی۔' WHERE id = 3015;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے حمید بن ہلال نے اور ان سے عبداللہ بن مغفل رضی اللہ عنہ نے بیان کیا کہ ہم خیبر کے محل کا محاصرہ کئے ہوئے تھے۔ کسی شخص نے ایک کپی پھینکی جس میں چربی بھری ہوئی تھی۔ میں اسے لینے کے لیے لپکا، لیکن مڑ کر جو دیکھا تو پاس ہی نبی کریم صلی اللہ علیہ وسلم موجود تھے۔ میں شرم سے پانی پانی ہو گیا۔' WHERE id = 3025;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، ان سے سفیان بن عیینہ نے بیان کیا، ان سے سلیمان احول نے، انہوں نے سعید بن جبیر سے سنا اور انہوں نے ابن عباس رضی اللہ عنہما سے سنا آپ نے جمعرات کے دن کا ذکر کرتے ہوئے کہا، تمہیں معلوم ہے کہ جمعرات کا دن، ہائے! یہ کون سا دن ہے؟ اس کے بعد وہ اتنا روئے کہ ان کے آنسووں سے کنکریاں تر ہو گئیں۔ سعید نے کہا میں نے عرض کیا، یا ابوعباس! جمعرات کے دن سے کیا مطلب ہے؟ انہوں نے کہا کہ اسی دن رسول اللہ صلی اللہ علیہ وسلم کی تکلیف ( مرض الموت ) میں شدت پیدا ہوئی تھی اور آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ مجھے ( لکھنے کا ) ایک کاغذ دے دو تاکہ میں تمہارے لیے ایک ایسی کتاب لکھ جاؤں، جس کے بعد تم کبھی گمراہ نہ ہو۔ اس پر لوگوں کا اختلاف ہو گیا۔ پھر آپ صلی اللہ علیہ وسلم نے خود ہی فرمایا کہ نبی کی موجودگی میں جھگڑنا غیر مناسب ہے، دوسرے لوگ کہنے لگے، بھلا کیا آپ صلی اللہ علیہ وسلم بےکار باتیں فرمائیں گے اچھا، پھر پوچھ لو، یہ سن کر آپ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے میری حالت پر چھوڑ دو، کیونکہ اس وقت میں جس عالم میں ہوں، وہ اس سے بہتر ہے جس کی طرف تم مجھے بلا رہے ہو۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے تین باتوں کا حکم فرمایا، کہ مشرکوں کو جزیرہ عرب سے نکال دینا اور وفود کے ساتھ اسی طرح خاطر تواضع کا معاملہ کرنا، جس طرح میں کیا کرتا تھا۔ تیسری بات کچھ بھلی سی تھی، یا تو سعید نے اس کو بیان نہ کیا، یا میں بھول گیا۔ سفیان نے کہا یہ جملہ ( تیسری بات کچھ بھلی سی تھی ) سلیمان احول کا کلام ہے۔' WHERE id = 3037;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے عبداللہ بن مرہ نے، ان سے مسروق نے، ان سے عبداللہ بن عمرو رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، چار عادتیں ایسی ہیں کہ اگر یہ چاروں کسی ایک شخص میں جمع ہو جائیں تو وہ پکا منافق ہے۔ وہ شخص جو بات کرے تو جھوٹ بولے، اور جب وعدہ کرے، تو وعدہ خلافی کرے، اور جب معاہدہ کرے تو اسے پورا نہ کرے۔ اور جب کسی سے لڑے تو گالی گلوچ پر اتر آئے اور اگر کسی شخص کے اندر ان چاروں عادتوں میں سے ایک ہی عادت ہے، تو اس کے اندر نفاق کی ایک عادت ہے جب تک کہ وہ اسے چھوڑ نہ دے۔' WHERE id = 3047;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان ثوری نے خبر دی، انہیں جامع بن شداد نے، انہیں صفوان بن محرز نے اور ان سے عمران بن حصین رضی اللہ عنہما نے بیان کیا کہ بنی تمیم کے کچھ لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں آئے تو آپ نے ان سے فرمایا کہ اے بنی تمیم کے لوگو! تمہیں بشارت ہو۔ وہ کہنے لگے کہ بشارت جب آپ نے ہم کو دی ہے تو اب ہمیں کچھ مال بھی دیجئیے۔ اس پر آپ صلی اللہ علیہ وسلم کے چہرہ مبارک کا رنگ بدل گیا، پھر آپ کی خدمت میں یمن کے لوگ آئے تو آپ صلی اللہ علیہ وسلم نے ان سے بھی فرمایا کہ اے یمن والو! بنو تمیم کے لوگوں نے تو خوشخبری کو قبول نہیں کیا، اب تم اسے قبول کر لو۔ انہوں نے عرض کیا کہ ہم نے قبول کیا۔ پھر آپ مخلوق اور عرش الٰہی کی ابتداء کے بارے میں گفتگو فرمانے لگے۔ اتنے میں ایک ( نامعلوم ) شخص آیا اور کہا کہ عمران! تمہاری اونٹنی بھاگ گئی۔ ( عمران رضی اللہ عنہ کہتے ہیں ) کاش، میں آپ کی مجلس سے نہ اٹھتا تو بہتر ہوتا۔' WHERE id = 3058;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن فیروز داناج نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن سورج اور چاند دونوں تاریک ( بے نور ) ہو جائیں گے۔“' WHERE id = 3068;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا ہم سے ابن ابی مریم نے بیان کیا، انہوں نے کہا کہ ہمیں لیث نے خبر دی، ان سے ابن ابی جعفر نے بیان کیا، ان سے محمد بن عبدالرحمٰن نے بیان کیا، ان سے عروہ بن زبیر نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ عائشہ صدیقہ رضی اللہ عنہا نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا ”فرشتے «عنان» میں اترتے ہیں۔ اور «عنان» سے مراد بادل ہیں۔ یہاں فرشتے ان کاموں کا ذکر کرتے ہیں جن کا فیصلہ آسمان میں ہو چکا ہوتا ہے۔ اور یہیں سے شیاطین کچھ چوری چھپے باتیں اڑا لیتے ہیں۔ پھر کاہنوں کو اس کی خبر کر دیتے ہیں اور یہ کاہن سو جھوٹ اپنی طرف سے ملا کر اسے بیان کرتے ہیں۔“' WHERE id = 3078;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو یونس نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ سے عبیداللہ بن عبداللہ نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سب سے زیادہ سخی تھے اور آپ کی سخاوت رمضان شریف کے مہینے میں اور بڑھ جاتی، جب جبرائیل علیہ السلام آپ سے ملاقات کے لیے ہر روز آنے لگتے۔ جبرائیل علیہ السلام آپ صلی اللہ علیہ وسلم سے رمضان کی ہر رات میں ملاقات کے لیے آتے اور آپ سے قرآن کا دور کیا کرتے تھے۔ آپ صلی اللہ علیہ وسلم خصوصاً اس دور میں جب جبرائیل علیہ السلام روزانہ آپ سے ملاقات کے لیے آتے تو آپ خیرات و برکات میں تیز چلنے والی ہوا سے بھی زیادہ سخی ہو جاتے تھے اور عبداللہ بن مبارک سے روایت ہے، ان سے معمر نے اسی اسناد کے ساتھ اسی طرح بیان کیا اور ابوہریرہ رضی اللہ عنہ اور فاطمہ رضی اللہ عنہا نے نقل کیا نبی کریم صلی اللہ علیہ وسلم سے کہ جبرائیل علیہ السلام نبی کریم صلی اللہ علیہ وسلم کے ساتھ قرآن مجید کا دور کیا کرتے تھے۔' WHERE id = 3088;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عطاء بن ابی رباح نے، ان سے صفوان بن یعلیٰ نے اور ان سے ان کے والد (یعلیٰ بن امیہ رضی اللہ عنہ) نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ منبر پر سورۃ الزخرف کی اس آیت کی تلاوت فرما رہے تھے «ونادوا يا مالك‏» اور وہ دوزخی پکاریں گی اے مالک! ( یہ داروغہ جہنم کا نام ہے ) اور سفیان نے کہا کہ عبداللہ بن مسعود رضی اللہ عنہ کی رات میں یوں ہے «ونادوا يا مال‏.‏» ۔' WHERE id = 3098;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا کہ ہم سے نافع نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا، انہوں نے کہا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب کوئی شخص مرتا ہے تو ( روزانہ ) صبح و شام دونوں وقت اس کا ٹھکانا ( جہاں وہ آخرت میں رہے گا ) اسے دکھلایا جاتا ہے۔ اگر وہ جنتی ہے تو جنت میں اگر وہ دوزخی ہے تو دوزخ میں۔“' WHERE id = 3108;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے ابوحازم نے اور ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جنت میں ایک کوڑے کی جگہ دنیا سے اور جو کچھ دنیا میں ہے، سب سے بہتر ہے۔“' WHERE id = 3118;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن عباس نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے ان کے باپ نے، ان سے عبایہ بن رفاعہ نے بیان کیا، کہا مجھ کو رافع بن خدیج رضی اللہ عنہ نے خبر دی کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ بخار جہنم کے جوش مارنے کے اثر سے ہوتا ہے اس لیے اسے پانی سے ٹھنڈا کر لیا کرو۔' WHERE id = 3129;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے یونس نے بیان کیا، ان سے حمید بن بلال نے، ان سے ابوصالح نے ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر تم میں سے نماز پڑھنے میں کسی شخص کے سامنے سے کوئی گزرے تو اسے گزرنے سے روکے، اگر وہ نہ رکے تو پھر روکے اور اگر اب بھی نہ رکے تو اس سے لڑے وہ شیطان ہے۔“' WHERE id = 3140;
UPDATE hadiths SET urdu = 'ہم سے محمود بن غیلان نے بیان کیا، کہا ہم سے شبابہ نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک مرتبہ نماز پڑھی اور فارغ ہونے کے بعد فرمایا کہ شیطان میرے سامنے آ گیا تھا اور نماز تڑوانے کی کوششیں شروع کر دی تھیں، لیکن اللہ تعالیٰ نے مجھے اس پر غالب کر دیا۔ پھر حدیث کو تفصیل کے ساتھ آخر تک بیان کیا۔' WHERE id = 3150;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے صالح نے، ان سے ابن شہاب نے بیان کیا، کہا کہ مجھے عبدالحمید بن عبدالرحمٰن بن زید نے خبر دی، انہیں محمد بن سعد بن ابی وقاص (رضی اللہ عنہ) نے خبر دی اور ان سے ان کے والد سعد بن ابی وقاص نے بیان کیا کہ ایک دفعہ عمر رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہونے کی اجازت چاہی۔ اس وقت چند قریشی عورتیں ( خود آپ کی بیویاں ) آپ کے پاس بیٹھی آپ سے گفتگو کر رہی تھیں اور آپ سے ( خرچ میں ) بڑھانے کا سوال کر رہی تھیں۔ خوب آواز بلند کر کے۔ لیکن جونہی عمر رضی اللہ عنہ نے اجازت چاہی، وہ خواتین جلدی سے پردے کے پیچھے چلی گئیں۔ پھر رسول اللہ صلی اللہ علیہ وسلم نے انہیں اجازت دی، آپ صلی اللہ علیہ وسلم مسکرا رہے تھے۔ عمر رضی اللہ عنہ نے کہا، اللہ تعالیٰ ہمیشہ آپ کو ہنساتا رکھے۔ یا رسول اللہ! آپ نے فرمایا کہ مجھے ان عورتوں پر تعجب ہوا ابھی ابھی میرے پاس تھیں، لیکن جب تمہاری آواز سنی تو پردے کے پیچھے جلدی سے بھاگ گئیں۔ عمر رضی اللہ عنہ نے عرض کیا، لیکن آپ یا رسول اللہ! زیادہ اس کے مستحق تھے کہ آپ سے یہ ڈرتیں، پھر انہوں نے کہا: اے اپنی جانوں کے دشمنو! مجھ سے تو تم ڈرتی ہو اور نبی کریم صلی اللہ علیہ وسلم سے نہیں ڈرتیں۔ ازواج مطہرات بولیں کہ واقعہ یہی ہے کیونکہ آپ رسول اللہ صلی اللہ علیہ وسلم کے برخلاف مزاج میں بہت سخت ہیں۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے، اگر شیطان بھی کہیں راستے میں تم سے مل جائے، تو جھٹ وہ راستہ چھوڑ کر دوسرا راستہ اختیار کر لیتا ہے۔“' WHERE id = 3160;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، ان سے ابن وہب نے بیان کیا، کہا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، ان سے عروہ نے، انہوں نے عائشہ رضی اللہ عنہا سے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے گرگٹ ( چھپکلی ) کے متعلق فرمایا کہ وہ موذی جانور ہے لیکن میں نے آپ صلی اللہ علیہ وسلم سے اسے مار ڈالنے کا حکم نہیں سنا تھا اور سعد بن ابی وقاص بتاتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے اسے مار ڈالنے کا حکم فرمایا ہے۔' WHERE id = 3171;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا، انہوں نے کہا ہم سے سلیمان بن بلال نے بیان کیا، انہوں نے کہا کہ مجھ سے عتبہ بن مسلم نے بیان کیا، انہوں نے کہا کہ مجھے عبید بن حنین نے خبر دی، انہوں نے کہا کہ میں نے ابوہریرہ رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب مکھی کسی کے پینے ( یا کھانے کی چیز ) میں پڑ جائے تو اسے ڈبو دے اور پھر نکال کر پھینک دے۔ کیونکہ اس کے ایک پر میں بیماری ہے اور اس کے دوسرے ( پر ) میں شفاء ہوتی ہے۔“' WHERE id = 3183;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام نے اور انہیں ابوہریرہ رضی اللہ عنہ نے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا (عبدالرزاق کی) روایت کی طرح کہ اگر قوم بنی اسرائیل نہ ہوتی تو گوشت نہ سڑا کرتا اور اگر حواء نہ ہوتیں تو عورت اپنے شوہر سے دغا نہ کرتی۔' WHERE id = 3193;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن نصر نے بیان کیا، ہم سے محمد بن عبید نے بیان کیا، ہم سے ابوحیان یحییٰ بن سعید نے بیان کیا، ان سے ابوزرعہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک دعوت میں شریک تھے۔ آپ صلی اللہ علیہ وسلم کی خدمت میں دستی کا گوشت پیش کیا گیا جو آپ صلی اللہ علیہ وسلم کو بہت مرغوب تھا۔ آپ صلی اللہ علیہ وسلم نے اس دستی کی ہڈی کا گوشت دانتوں سے نکال کر کھایا۔ پھر فرمایا کہ میں قیامت کے دن لوگوں کا سردار ہوں گا۔ تمہیں معلوم ہے کہ کس طرح اللہ تعالیٰ ( قیامت کے دن ) تمام مخلوق کو ایک چٹیل میدان میں جمع کرے گا؟ اس طرح کہ دیکھنے والا سب کو ایک ساتھ دیکھ سکے گا۔ آواز دینے والے کی آواز ہر جگہ سنی جا سکے گی اور سورج بالکل قریب ہو جائے گا۔ ایک شخص اپنے قریب کے دوسرے شخص سے کہے گا، دیکھتے نہیں کہ سب لوگ کیسی پریشانی میں مبتلا ہیں؟ اور مصیبت کس حد تک پہنچ چکی ہے؟ کیوں نہ کسی ایسے شخص کی تلاش کی جائے جو اللہ پاک کی بارگاہ میں ہم سب کی شفاعت کے لیے جائے۔ کچھ لوگوں کا مشورہ ہو گا کہ دادا آدم علیہ السلام اس کے لیے مناسب ہیں۔ چنانچہ لوگ ان کی خدمت میں حاضر ہوں گے اور عرض کریں گے، اے باوا آدم! آپ انسانوں کے دادا ہیں۔ اللہ پاک نے آپ کو اپنے ہاتھ سے پیدا کیا تھا، اپنی روح آپ کے اندر پھونکی تھی، ملائکہ کو حکم دیا تھا اور انہوں نے آپ کو سجدہ کیا تھا اور جنت میں آپ کو ( پیدا کرنے کے بعد ) ٹھہرایا تھا۔ آپ اپنے رب کے حضور میں ہماری شفاعت کر دیں۔ آپ خود ملاحظہ فرما سکتے ہیں کہ ہم کس درجہ الجھن اور پریشانی میں مبتلا ہیں۔ وہ فرمائیں گے کہ ( گناہ گاروں پر ) اللہ تعالیٰ آج اس درجہ غضبناک ہے کہ کبھی اتنا غضبناک نہیں ہوا تھا اور نہ آئندہ کبھی ہو گا اور مجھے پہلے ہی درخت ( جنت ) کے کھانے سے منع کر چکا تھا لیکن میں اس فرمان کو بجا لانے میں کوتاہی کر گیا۔ آج تو مجھے اپنی ہی پڑی ہے ( نفسی نفسی ) تم لوگ کسی اور کے پاس جاؤ۔ ہاں، نوح علیہ السلام کے پاس جاؤ۔ چنانچہ سب لوگ نوح علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے، اے نوح علیہ السلام! آپ ( آدم علیہ السلام کے بعد ) روئے زمین پر سب سے پہلے نبی ہیں اور اللہ تعالیٰ نے آپ کو ”عبدشکور“ کہہ کر پکارا ہے۔ آپ ملاحظہ فرما سکتے ہیں کہ آج ہم کیسی مصیبت و پریشانی میں مبتلا ہیں؟ آپ اپنے رب کے حضور میں ہماری شفاعت کر دیجئیے۔ وہ بھی یہی جواب دیں گے کہ میرا رب آج اس درجہ غضبناک ہے کہ اس سے پہلے کبھی ایسا غضبناک نہیں ہوا تھا اور نہ کبھی اس کے بعد اتنا غضبناک ہو گا۔ آج تو مجھے خود اپنی ہی فکر ہے۔ ( نفسی نفسی ) تم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں جاؤ چنانچہ وہ لوگ میرے پاس آئیں گے۔ میں ( ان کی شفاعت کے لیے ) عرش کے نیچے سجدے میں گر پڑوں گا۔ پھر آواز آئے گی، اے محمد! سر اٹھاؤ اور شفاعت کرو، تمہاری شفاعت قبول کی جائے گی۔ مانگو تمہیں دیا جائے گا۔ محمد بن عبیداللہ نے بیان کیا کہ ساری حدیث میں یاد نہ رکھ سکا۔' WHERE id = 3203;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا کہ مجھے میرے بھائی عبدالحمید نے خبر دی، انہیں ابن ابی ذئب نے، انہیں سعید مقبری نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابراہیم علیہ السلام اپنے والد آذر سے قیامت کے دن جب ملیں گے تو ان کے ( والد کے ) چہرے پر سیاہی اور غبار ہو گا۔ ابراہیم علیہ السلام کہیں گے کہ کیا میں نے آپ سے نہیں کہا تھا کہ میری مخالفت نہ کیجئے۔ وہ کہیں گے کہ آج میں آپ کی مخالفت نہیں کرتا۔ ابراہیم علیہ السلام عرض کریں گے کہ اے رب! تو نے وعدہ فرمایا تھا کہ مجھے قیامت کے دن رسوا نہیں کرے گا۔ آج اس رسوائی سے بڑھ کر اور کون سی رسوائی ہو گی کہ میرے والد تیری رحمت سے سب سے زیادہ دور ہیں۔ اللہ تعالیٰ فرمائے گا کہ میں نے جنت کافروں پر حرام قرار دی ہے۔ پھر کہا جائے گا کہ اے ابراہیم! تمہارے قدموں کے نیچے کیا چیز ہے؟ وہ دیکھیں گے تو ایک ذبح کیا ہوا جانور خون میں لتھڑا ہوا وہاں پڑا ہو گا اور پھر اس کے پاؤں پکڑ کر اسے جہنم میں ڈال دیا جائے گا۔' WHERE id = 3213;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا ہم سے ہمارے والد نے بیان کیا، ان سے اعمش نے بیان کیا کہا کہ مجھ سے ابراہیم نے بیان کیا، ان سے علقمہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ جب یہ آیت اتری «الذين آمنوا ولم يلبسوا إيمانهم بظلم‏» ”جو لوگ ایمان لائے اور اپنے ایمان میں کسی قسم کے ظلم کی ملاوٹ نہ کی۔“ تو ہم نے عرض کیا: یا رسول اللہ! ہم میں ایسا کون ہو گا جس نے اپنی جان پر ظلم نہ کیا ہو گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ واقعہ وہ نہیں جو تم سمجھتے ہو۔ جس نے اپنے ایمان کے ساتھ ظلم کی ملاوٹ نہ کی۔ ( میں ظلم سے مراد ) شرک ہے کیا تم نے لقمان علیہ السلام کی اپنے بیٹے کو یہ نصیحت نہیں سنی کہ ”اے بیٹے! اللہ کے ساتھ شریک نہ کرنا، بیشک شرک بہت ہی بڑا ظلم ہے۔“' WHERE id = 3223;
UPDATE hadiths SET urdu = 'ہم سے احمد بن صالح نے بیان کیا ‘ کہا ہم سے عبداللہ بن وہب نے بیان کیا ‘ کہا کہ مجھے یونس نے خبر دی ‘ انہیں ابن شہاب نے ‘ انہیں ابوسلمہ بن عبدالرحمٰن اور سعید بن مسیب نے ‘ انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ہم ابراہیم علیہ السلام کے مقابلے میں شک کرنے کے زیادہ مستحق ہیں جب کہ انہوں نے کہا تھا کہ میرے رب! مجھے دکھا کہ تو مردوں کو کس طرح زندہ کرتا ہے۔ اللہ تعالیٰ نے فرمایا ”کہا کیا تم ایمان نہیں لائے ‘ انہوں نے عرض کیا کہ کیوں نہیں ‘ لیکن یہ صرف اس لیے تاکہ میرے دل کو اور زیادہ اطمینان ہو جائے۔“ اور اللہ لوط علیہ السلام پر رحم کر کہ وہ زبردست رکن ( یعنی اللہ تعالیٰ ) کی پناہ لیتے تھے اور اگر میں اتنی مدت تک قید خانے میں رہتا جتنی مدت تک یوسف علیہ السلام رہے تھے تو میں بلانے والے کے بات ضرور مان لیتا۔“' WHERE id = 3234;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا ‘ کہا ہم کو عبدالصمد نے خبر دی ‘ کہا ہم سے عبدالرحمٰن بن عبداللہ نے بیان کیا ‘ ان سے ان کے والد نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”شریف بن شریف بن شریف بن شریف ‘ یوسف بن یعقوب بن اسحاق بن ابراہیم علیہ السلام تھے۔“' WHERE id = 3244;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا ‘ کہا ہم سے لیث بن سعد نے بیان کیا ‘ کہا کہ مجھ سے عقیل نے بیان کیا ‘ ان سے ابن شہاب نے ‘ انہوں نے عروہ بن زبیر سے سنا ‘ انہوں نے بیان کیا کہ عائشہ رضی اللہ عنہا نے کہا ‘ پھر نبی کریم صلی اللہ علیہ وسلم ( غار حراء سے ) ام المؤمنین خدیجہ رضی اللہ عنہا کے پاس لوٹ آئے تو آپ صلی اللہ علیہ وسلم کا دل دھڑک رہا تھا۔ خدیجہ رضی اللہ عنہا آپ کو ورقہ بن نوفل کے پاس لے گئیں، وہ نصرانی ہو گئے تھے اور انجیل کو عربی میں پڑھتے تھے۔ ورقہ نے پوچھا کہ آپ کیا دیکھتے ہیں؟ آپ نے انہیں بتایا تو انہوں نے کہا کہ یہی ہیں وہ «ناموس» جنہیں اللہ تعالیٰ نے موسیٰ علیہ السلام کے پاس بھیجا تھا اور اگر میں تمہارے زمانے تک زندہ رہا تو میں تمہاری پوری مدد کروں گا۔ «ناموس» محرم راز کو کہتے ہیں جو ایسے راز سے بھی آگاہ ہو جو آدمی دوسروں سے چھپائے۔' WHERE id = 3254;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا ‘ کہا ہم سے روح بن عبادہ نے بیان کیا ‘ ان سے عوف بن ابوجمیلہ نے بیان کیا ‘ ان سے امام حسن بصری اور محمد بن سیرین اور خلاس بن عمرو نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ موسیٰ علیہ السلام بڑے ہی شرم والے اور بدن ڈھانپنے والے تھے۔ ان کی حیاء کی وجہ سے ان کے بدن کو کوئی حصہ بھی نہیں دیکھا جا سکتا تھا۔ بنی اسرائیل کے جو لوگ انہیں اذیت پہنچانے کے درپے تھے ‘ وہ کیوں باز رہ سکتے تھے ‘ ان لوگوں نے کہنا شروع کیا کہ اس درجہ بدن چھپانے کا اہتمام صرف اس لیے ہے کہ ان کے جسم میں عیب ہے یا کوڑھ ہے یا ان کے خصیتین بڑھے ہوئے ہیں یا پھر کوئی اور بیماری ہے۔ ادھر اللہ تعالیٰ کو یہ منظور ہوا کہ موسیٰ علیہ السلام کی ان کی ہفوات سے پاکی دکھلائے۔ ایک دن موسیٰ علیہ السلام اکیلے غسل کرنے کے لیے آئے ایک پتھر پر اپنے کپڑے ( اتار کر ) رکھ دیئے۔ پھر غسل شروع کیا۔ جب فارغ ہوئے تو کپڑے اٹھانے کے لیے بڑھے لیکن پتھر ان کے کپڑوں سمیت بھاگنے لگا۔ موسیٰ علیہ السلام نے اپنا عصا اٹھایا اور پتھر کے پیچھے دوڑے۔ یہ کہتے ہوئے کہ پتھر! میرا کپڑا دیدے۔ آخر بنی اسرائیل کی ایک جماعت تک پہنچ گئے اور ان سب نے آپ کو ننگا دیکھ لیا ‘ اللہ کی مخلوق میں سب سے بہتر حالت میں اور اس طرح اللہ تعالیٰ نے ان کی تہمت سے ان کی برات کر دی۔ اب پتھر بھی رک گیا اور آپ نے کپڑا اٹھا کر پہنا۔ پھر پتھر کو اپنے عصا سے مارنے لگے۔ اللہ کی قسم اس پتھر پر موسیٰ علیہ السلام کے مارنے کی وجہ سے تین یا چار یا پانچ جگہ نشان پڑ گئے تھے۔ اللہ تعالیٰ کے اس فرمان «يا أيها الذين آمنوا لا تكونوا كالذين آذوا موسى فبرأه الله مما قالوا وكان عند الله وجيها‏» ”تم ان کی طرح نہ ہو جانا جنہوں نے موسیٰ علیہ السلام کو اذیت دی تھی ‘ پھر ان کی تہمت سے اللہ تعالیٰ نے انہیں بری قرار دیا اور وہ اللہ کی بارگاہ میں بڑی شان والے اور عزت والے تھے۔“ میں اسی واقعہ کی طرف اشارہ ہے۔' WHERE id = 3265;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا ‘ کہا ہم سے شعبہ نے بیان کیا ‘ ان سے سعد بن ابراہیم نے ‘ انہوں نے حمید بن عبدالرحمٰن سے سنا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کسی شخص کے لیے یہ کہنا لائق نہیں کہ میں یونس بن متی سے افضل ہوں۔“' WHERE id = 3276;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، کہا ہم سے ابوالزناد نے بیان کیا، ان سے عبدالرحمٰن نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا اور انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا ”میری اور تمام انسانوں کی مثال ایک ایسے شخص کی سی ہے جس نے آگ روشن کی ہو۔ پھر پروانے اور کیڑے مکوڑے اس میں گرنے لگے ہوں۔“' WHERE id = 3286;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن موسیٰ نے بیان کیا، کہا کہ ہم کو ہشام نے خبر دی، انہیں معمر نے (دوسری سند) مجھ سے محمود نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا کہ ہم کو معمر نے خبر دی، ان سے زہری نے بیان کیا، کہا مجھ کو سعید بن مسیب نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس رات میری معراج ہوئی، میں نے موسیٰ علیہ السلام سے ملاقات کی تھی۔ راوی نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے ان کا حلیہ بیان کیا وہ…. میرا خیال ہے کہ معمر نے کہا…. دراز قامت اور سیدھے بالوں والے تھے جیسے قبیلہ شنوہ کے لوگ ہوتے ہیں۔ آپ نے بیان کیا کہ میں نے عیسیٰ علیہ السلام سے بھی ملاقات کی۔ آپ صلی اللہ علیہ وسلم نے ان کا بھی حلیہ بیان فرمایا کہ درمیانہ قد اور سرخ و سپید تھے، جیسے ابھی ابھی غسل خانے سے باہر آئے ہوں اور میں نے ابراہیم علیہ السلام سے بھی ملاقات کی تھی اور میں ان کی اولاد میں ان سے سب سے زیادہ مشابہ ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ میرے پاس دو برتن لائے گئے، ایک میں دودھ تھا اور دوسرے میں شراب۔ مجھ سے کہا گیا کہ جو آپ کا جی چاہے لے لو۔ میں نے دودھ کا برتن لے لیا اور پی لیا۔ اس پر مجھ سے کہا گیا کہ فطرت کی آپ نے راہ پا لی، یا فطرت کو آپ نے پا لیا۔ اس کے بجائے اگر آپ شراب کا برتن لیتے تو آپ کی امت گمراہ ہو جاتی۔' WHERE id = 3296;
UPDATE hadiths SET urdu = 'ہم سے ابن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے ابوقتادہ انصاری رضی اللہ عنہ کے غلام نافع نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تمہارا اس وقت کیا حال ہو گا جب عیسیٰ ابن مریم تم میں اتریں گے ( تم نماز پڑھ رہے ہو گے ) اور تمہارا امام تم ہی میں سے ہو گا۔“ اس روایت کی متابعت عقیل اور اوزاعی نے کی۔' WHERE id = 3307;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن اسحاق نے بیان کیا، کہا ہم سے عمرو بن عاصم نے بیان کیا، ان سے ہمام نے بیان کیا، ان سے اسحاق بن عبداللہ نے بیان کیا، کہا مجھ سے عبدالرحمٰن بن ابی حمزہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا (دوسری سند) اور مجھ سے محمد نے بیان کیا، کہا ہم سے عبداللہ بن رجاء نے بیان کیا، انہیں ہمام نے خبر دی، ان سے اسحاق بن عبداللہ نے بیان کیا، انہیں عبدالرحمٰن بن ابی عمرہ نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ بنی اسرائیل میں تین شخص تھے، ایک کوڑھی، دوسرا اندھا اور تیسرا گنجا، اللہ تعالیٰ نے چاہا کہ ان کا امتحان لے۔ چنانچہ اللہ تعالیٰ نے ان کے پاس ایک فرشتہ بھیجا۔ فرشتہ پہلے کوڑھی کے پاس آیا اور اس سے پوچھا کہ تمہیں سب سے زیادہ کیا چیز پسند ہے؟ اس نے جواب دیا کہ اچھا رنگ اور اچھی چمڑی کیونکہ مجھ سے لوگ پرہیز کرتے ہیں۔ بیان کیا کہ فرشتے نے اس پر اپنا ہاتھ پھیرا تو اس کی بیماری دور ہو گئی اور اس کا رنگ بھی خوبصورت ہو گیا اور چمڑی بھی اچھی ہو گئی۔ فرشتے نے پوچھا کس طرح کا مال تم زیادہ پسند کرو گے؟ اس نے کہا کہ اونٹ! یا اس نے گائے کہی، اسحاق بن عبداللہ کو اس سلسلے میں شک تھا کہ کوڑھی اور گنجے دونوں میں سے ایک نے اونٹ کی خواہش کی تھی اور دوسرے نے گائے کی۔ چنانچہ اسے حاملہ اونٹنی دی گئی اور کہا گیا کہ اللہ تعالیٰ تمہیں اس میں برکت دے گا، پھر فرشتہ گنجے کے پاس آیا اور اس سے پوچھا کہ تمہیں کیا چیز پسند ہے؟ اس نے کہا کہ عمدہ بال اور موجودہ عیب میرا ختم ہو جائے کیونکہ لوگ اس کی وجہ سے مجھ سے پرہیز کرتے ہیں۔ بیان کیا کہ فرشتے نے اس کے سر پر ہاتھ پھیرا اور اس کا عیب جاتا رہا اور اس کے بجائے عمدہ بال آ گئے۔ فرشتے نے پوچھا، کس طرح کا مال پسند کرو گے؟ اس نے کہا کہ گائے! بیان کیا کہ فرشتے نے اسے حاملہ گائے دے دی اور کہا کہ اللہ تعالیٰ اس میں برکت دے گا۔ پھر اندھے کے پاس فرشتہ آیا اور کہا کہ تمہیں کیا چیز پسند ہے؟ اس نے کہا کہ اللہ تعالیٰ مجھے آنکھوں کی روشنی دیدے تاکہ میں لوگوں کو دیکھ سکوں۔ بیان کیا کہ فرشتے نے ہاتھ پھیرا اور اللہ تعالیٰ نے اس کی بینائی اسے واپس دے دی۔ پھر پوچھا کہ کس طرح کا مال تم پسند کرو گے؟ اس نے کہا کہ بکریاں! فرشتے نے اسے حاملہ بکری دے دی۔ پھر تینوں جانوروں کے بچے پیدا ہوئے، یہاں تک کہ کوڑھی کے اونٹوں سے اس کی وادی بھر گئی، گنجے کی گائے بیل سے اس کی وادی بھر گئی اور اندھے کی بکریوں سے اس کی وادی بھر گئی۔ پھر دوبارہ فرشتہ اپنی اسی پہلی شکل میں کوڑھی کے پاس آیا اور کہا کہ میں ایک نہایت مسکین و فقیر آدمی ہوں، سفر کا تمام سامان و اسباب ختم ہو چکا ہے اور اللہ تعالیٰ کے سوا اور کسی سے حاجت پوری ہونے کی امید نہیں، لیکن میں تم سے اسی ذات کا واسطہ دے کر جس نے تمہیں اچھا رنگ اور اچھا چمڑا اور مال عطا کیا، ایک اونٹ کا سوال کرتا ہوں جس سے سفر کو پورا کر سکوں۔ اس نے فرشتے سے کہا کہ میرے ذمہ حقوق اور بہت سے ہیں۔ فرشتہ نے کہا، غالباً میں تمہیں پہچانتا ہوں، کیا تمہیں کوڑھ کی بیماری نہیں تھی جس کی وجہ سے لوگ تم سے گھن کھاتے تھے۔ تم ایک فقیر اور قلاش تھے۔ پھر تمہیں اللہ تعالیٰ نے یہ چیزیں عطا کیں؟ اس نے کہا کہ یہ ساری دولت تو میرے باپ دادا سے چلی آ رہی ہے۔ فرشتے نے کہا کہ اگر تم جھوٹے ہو تو اللہ تمہیں اپنی پہلی حالت پر لوٹا دے۔ پھر فرشتہ گنجے کے پاس اپنی اسی پہلی صورت میں آیا اور اس سے بھی وہی درخواست کی اور اس نے بھی وہی کوڑھی والا جواب دیا۔ فرشتے نے کہا کہ اگر تم جھوٹے ہو تو اللہ تعالیٰ تمہیں اپنی پہلی حالت پر لوٹا دے۔ اس کے بعد فرشتہ اندھے کے پاس آیا، اپنی اسی پہلی صورت میں اور کہا کہ میں ایک مسکین آدمی ہوں، سفر کے تمام سامان ختم ہو چکے ہیں اور سوا اللہ تعالیٰ کے کسی سے حاجت پوری ہونے کی توقع نہیں۔ میں تم سے اس ذات کا واسطہ دے کر جس نے تمہیں تمہاری بینائی واپس دی ہے، ایک بکری مانگتا ہوں جس سے اپنے سفر کی ضروریات پوری کر سکوں۔ اندھے نے جواب دیا کہ واقعی میں اندھا تھا اور اللہ تعالیٰ نے مجھے اپنے فضل سے بینائی عطا فرمائی اور واقعی میں فقیر و محتاج تھا اور اللہ تعالیٰ نے مجھے مالدار بنایا۔ تم جتنی بکریاں چاہو لے سکتے ہو، اللہ کی قسم جب تم نے اللہ کا واسطہ دیا ہے تو جتنا بھی تمہارا جی چاہے لے جاؤ، میں تمہیں ہرگز نہیں روک سکتا۔ فرشتے نے کہا کہ تم اپنا مال اپنے پاس رکھو، یہ تو صرف امتحان تھا اور اللہ تعالیٰ تم سے راضی اور خوش ہے اور تمہارے دونوں ساتھیوں سے ناراض ہے۔' WHERE id = 3319;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے داؤد بن ابی فرات نے بیان کیا، کہا ہم سے عبداللہ بن بریدہ نے بیان کیا، ان سے یحییٰ بن یعمر نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے طاعون کے بارے میں پوچھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ ایک عذاب ہے، اللہ تعالیٰ جس پر چاہتا ہے بھیجتا ہے لیکن اللہ تعالیٰ نے اس کو مومنوں کے لیے رحمت بنا دیا ہے۔ اگر کسی شخص کی بستی میں طاعون پھیل جائے اور وہ صبر کے ساتھ اللہ کی رحمت سے امید لگائے ہوئے وہیں ٹھہرا رہے کہ ہو گا وہی جو اللہ تعالیٰ نے قسمت میں لکھا ہے تو اسے شہید کے برابر ثواب ملے گا۔' WHERE id = 3329;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا ان سے منصور نے بیان کیا انہوں نے کہا میں نے ربعی بن حراش سے سنا وہ ابومسعود انصاری رضی اللہ عنہ سے روایت کرتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگلے پیغمبروں کے کلام میں سے لوگوں نے جو پایا یہ بھی ہے کہ جب تجھ میں حیاء نہ ہو پھر جو جی چاہے کر۔“' WHERE id = 3339;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ فخر اور تکبر ان چیخنے اور شور مچانے والے اونٹ والوں میں ہے اور بکری چرانے والوں میں نرم دلی اور ملائمت ہوتی ہے اور ایمان تو یمن میں ہے حکمت ( حدیث ) بھی یمنی ہے، ابوعبداللہ یعنی ( امام بخاری رحمہ اللہ ) نے کہا کہ یمن کا نام یمن اس لیے ہوا کہ یہ کعبہ کے دائیں جانب ہے اور شام کو شام اس لیے کہتے ہیں کہ یہ کعبہ کے بائیں جانب ہے۔ «المشأمة» بائیں جانب کو کہتے ہیں۔ بائیں ہاتھ کو «الشؤمى» کہتے ہیں اور بائیں جانب کو «الأشأم‏.» کہتے ہیں۔' WHERE id = 3351;
UPDATE hadiths SET urdu = 'ہم سے علی بن عیاش نے بیان کیا، کہا ہم سے جریر نے بیان کیا، کہا کہ مجھ سے عبدالواحد بن عبداللہ نصری نے بیان کیا، کہا کہ میں نے واثلہ بن اسقع رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سب سے بڑا بہتان اور سخت جھوٹ یہ ہے کہ آدمی اپنے باپ کے سوا کسی اور کو اپنا باپ کہے یا جو چیز اس نے خواب میں نہیں دیکھی۔ اس کے دیکھنے کا دعویٰ کرے۔ یا رسول اللہ صلی اللہ علیہ وسلم کی طرف ایسی حدیث منسوب کرے جو آپ نے نہ فرمائی ہو۔“' WHERE id = 3361;
UPDATE hadiths SET urdu = 'ہم سے ثابت بن محمد نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے عبداللہ بن مرہ نے، ان سے مسروق نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے ان سے نبی کریم صلی اللہ علیہ وسلم نے، اور سفیان نے زبید سے، انہوں نے ابراہیم سے، انہوں نے مسروق سے اور انہوں نے عبداللہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”وہ شخص ہم میں سے نہیں ہے جو ( نوحہ کرتے ہوئے ) اپنے رخسار پیٹے، گریبان پھاڑ ڈالے، اور جاہلیت کی پکار پکارے۔“' WHERE id = 3371;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ابوبکر رضی اللہ عنہ ان کے یہاں تشریف لائے تو وہاں ( انصار کی ) دو لڑکیاں دف بجا کر گا رہی تھیں۔ یہ حج کے ایام منیٰ کا واقعہ ہے۔ نبی کریم صلی اللہ علیہ وسلم روئے مبارک پر کپڑا ڈالے ہوئے لیٹے ہوئے تھے۔ ابوبکر رضی اللہ عنہ نے انہیں ڈانٹا تو نبی کریم صلی اللہ علیہ وسلم نے اپنے چہرہ مبارک سے کپڑا ہٹا کر فرمایا ”ابوبکر! انہیں چھوڑ دو، یہ عید کے دن ہیں، یہ منیٰ میں ٹھہرنے کے دن تھے۔“' WHERE id = 3381;
UPDATE hadiths SET urdu = 'مجھ سے اسحٰق بن راہویہ نے بیان کیا، کہا ہم کو فضل بن موسیٰ نے خبر دی، انہیں جعید بن عبدالرحمٰن نے کہ میں نے سائب بن یزید رضی اللہ عنہ کو چورانوے سال کی عمر میں دیکھا کہ خاصے قوی و توانا تھے۔ انہوں نے کہا کہ مجھے یقین ہے کہ میرے کانوں اور آنکھوں سے جو میں نفع حاصل کر رہا ہوں وہ صرف رسول اللہ صلی اللہ علیہ وسلم کی دعا کی برکت ہے۔ میری خالہ مجھے ایک مرتبہ آپ صلی اللہ علیہ وسلم کی خدمت میں لے گئیں۔ اور عرض کیا: یا رسول اللہ! یہ میرا بھانجا بیمار ہے، آپ اس کے لیے دعا فرما دیں۔ انہوں نے بیان کیا کہ پھر آپ صلی اللہ علیہ وسلم نے میرے لیے دعا فرمائی۔' WHERE id = 3391;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے کہ میں نے انس رضی اللہ عنہ سے پوچھا کیا رسول اللہ صلی اللہ علیہ وسلم نے کبھی خضاب بھی استعمال فرمایا تھا؟ انہوں نے کہا کہ آپ صلی اللہ علیہ وسلم نے کبھی خضاب نہیں لگایا۔ صرف آپ صلی اللہ علیہ وسلم کی دونوں کنپٹیوں پر ( سر میں ) چند بال سفید تھے۔' WHERE id = 3401;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم سے جب بھی دو چیزوں میں سے کسی ایک کے اختیار کرنے کے لیے کہا گیا تو آپ صلی اللہ علیہ وسلم نے ہمیشہ اسی کو اختیار فرمایا جس میں آپ کو زیادہ آسانی معلوم ہوئی بشرطیکہ اس میں کوئی گناہ نہ ہو۔ کیونکہ اگر اس میں گناہ کا کوئی شائبہ بھی ہوتا تو آپ اس سے سب سے زیادہ دور رہتے اور آپ صلی اللہ علیہ وسلم نے اپنی ذات کے لیے کبھی کسی سے بدلہ نہیں لیا۔ لیکن اگر اللہ کی حرمت کو کوئی توڑتا تو آپ صلی اللہ علیہ وسلم اس سے ضرور بدلہ لیتے تھے۔' WHERE id = 3411;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے ابن ابی عدی نے بیان کیا، ان سے سعید بن ابی عروبہ نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں ایک برتن حاضر کیا گیا ( پانی کا ) نبی کریم صلی اللہ علیہ وسلم اس وقت ( مدینہ کے نزدیک ) مقام زوراء میں تشریف رکھتے تھے، آپ صلی اللہ علیہ وسلم نے اس برتن میں ہاتھ رکھا تو اس میں سے پانی آپ صلی اللہ علیہ وسلم کی انگلیوں کے درمیان سے پھوٹنے لگا اور اسی پانی سے پوری جماعت نے وضو کیا۔ قتادہ نے کہا کہ میں نے انس رضی اللہ عنہ سے پوچھا: آپ لوگ کتنی تعداد میں تھے؟ انہوں نے فرمایا کہ تین سو رہے ہوں گے یا تین سو کے قریب رہے ہوں گے۔' WHERE id = 3423;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے حماد نے بیان کیا، ان سے عبدالعزیز نے اور ان سے انس رضی اللہ عنہ نے اس حدیث کو یونس سے بھی روایت کیا ہے۔ ان سے ثابت نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانے میں ایک سال قحط پڑا۔ آپ صلی اللہ علیہ وسلم جمعہ کی نماز کے لیے خطبہ دے رہے تھے کہ ایک شخص نے کھڑے ہو کر کہا: یا رسول اللہ! گھوڑے بھوک سے ہلاک ہو گئے اور بکریاں بھی ہلاک ہو گئیں۔ آپ اللہ تعالیٰ سے دعا کیجئے کہ وہ ہم پر پانی برسائے۔ نبی کریم صلی اللہ علیہ وسلم نے اپنے ہاتھ اٹھائے اور دعا کی۔ انس رضی اللہ عنہ نے بیان کیا کہ اس وقت آسمان شیشے کی طرح ( بالکل صاف ) تھا۔ اتنے میں ہوا چلی۔ اس نے ابر ( بادل ) کو اٹھایا پھر ابر کے بہت سے ٹکڑے جمع ہو گئے اور آسمان نے گویا اپنے دہانے کھول دیئے۔ ہم جب مسجد سے نکلے تو گھر پہنچتے پہنچتے پانی میں ڈوب چکے تھے۔ بارش یوں ہی دوسرے جمعہ تک برابر ہوتی رہی۔ دوسرے جمعہ کو وہی صاحب یا کوئی دوسرے پھر کھڑے ہوئے اور عرض کیا: اے اللہ کے رسول! مکانات گر گئے۔ دعا فرمائیے کہ اللہ تعالیٰ بارش کو روک دے۔ نبی کریم صلی اللہ علیہ وسلم مسکرائے اور فرمایا: اے اللہ! اب ہمارے چاروں طرف بارش برسا ( جہاں اس کی ضرورت ہو ) ہم پر نہ برسا۔ انس رضی اللہ عنہ کہتے ہیں کہ میں نے جو نظر اٹھائی تو دیکھا کہ اسی وقت ابر پھٹ کر مدینہ کے ارد گرد سر پیچ کی طرح ہو گیا تھا۔' WHERE id = 3433;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے عمرو نے، ان سے جابر بن عبداللہ رضی اللہ عنہما نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لوگوں پر ایک ایسا زمانہ آئے گا کہ جہاد کے لیے فوج جمع ہو گی، پوچھا جائے گا کہ فوج میں کوئی ایسے بزرگ بھی ہیں جنہوں نے رسول اللہ صلی اللہ علیہ وسلم کی صحبت اٹھائی ہو؟ ان سے کہا جائے گا کہ ہاں ہیں تو ان کے ذریعہ فتح کی دعا مانگی جائے گی۔ پھر ایک جہاد ہو گا اور پوچھا جائے گا: کیا فوج میں کوئی ایسے شخص ہیں جنہوں نے رسول اللہ صلی اللہ علیہ وسلم کے کسی صحابی کی صحبت اٹھائی ہو؟ ان سے کہا جائے گا کہ ہاں ہیں تو ان کے ذریعہ فتح کی دعا مانگی جائے گا۔ پھر ان کی دعا کی برکت سے فتح ہو گی۔' WHERE id = 3443;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن موسیٰ نے بیان کیا، کہا ہم سے ولید نے بیان کیا، کہا کہ مجھ سے ابن جابر نے، کہا کہ مجھ سے بسر بن عبیداللہ حضرمی نے، کہا کہ مجھ سے ابوادریس خولانی نے بیان کیا، انہوں نے حذیفہ بن یمان رضی اللہ عنہ سے سنا، وہ بیان کرتے تھے کہ دوسرے صحابہ کرام تو رسول اللہ صلی اللہ علیہ وسلم سے خیر کے متعلق سوال کیا کرتے تھے لیکن میں شر کے بارے میں پوچھتا تھا اس خوف سے کہ کہیں میں ان میں نہ پھنس جاؤں۔ تو میں نے ایک مرتبہ رسول اللہ صلی اللہ علیہ وسلم سے سوال کیا: یا رسول اللہ! ہم جاہلیت اور شر کے زمانے میں تھے۔ پھر اللہ تعالیٰ نے ہمیں یہ خیر و برکت ( اسلام کی ) عطا فرمائی، اب کیا اس خیر کے بعد پھر شر کا کوئی زمانہ آئے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، میں نے سوال کیا، اور اس شر کے بعد پھر خیر کا کوئی زمانہ آئے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، لیکن اس خیر پر کچھ دھواں ہو گا۔ میں نے عرض کیا وہ دھواں کیا ہو گا؟ آپ صلی اللہ علیہ وسلم نے جواب دیا کہ ایسے لوگ پیدا ہوں گے جو میری سنت اور طریقے کے علاوہ دوسرے طریقے اختیار کریں گے۔ ان میں کوئی بات اچھی ہو گی کوئی بری۔ میں نے سوال کیا: کیا اس خیر کے بعد پھر شر کا کوئی زمانہ آئے گا؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، جہنم کے دروازوں کی طرف بلانے والے پیدا ہوں گے، جو ان کی بات قبول کرے گا اسے وہ جہنم میں جھونک دیں گے۔ میں نے عرض کیا: یا رسول اللہ! ان کے اوصاف بھی بیان فرما دیجئیے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ لوگ ہماری ہی قوم و مذہب کے ہوں گے۔ ہماری ہی زبان بولیں گے۔ میں نے عرض کیا، پھر اگر میں ان لوگوں کا زمانہ پاؤں تو میرے لیے آپ کا حکم کیا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ مسلمانوں کی جماعت اور ان کے امام کو لازم پکڑنا، میں نے عرض کیا اگر مسلمانوں کی کوئی جماعت نہ ہو اور نہ ان کا کوئی امام ہو۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ان تمام فرقوں سے اپنے کو الگ رکھنا۔ اگرچہ تجھے اس کے لیے کسی درخت کی جڑ چبانی پڑے، یہاں تک کہ تیری موت آ جائے اور تو اسی حالت پر ہو ( تو یہ تیرے حق میں ان کی صحبت میں رہنے سے بہتر ہو گا ) ۔' WHERE id = 3455;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم ایک اعرابی کی عیادت کے لیے تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم جب بھی کسی مریض کی عیادت کے لیے تشریف لے جاتے تو فرماتے کوئی حرج نہیں، ان شاءاللہ یہ بخار گناہوں کو دھو دے گا۔ آپ صلی اللہ علیہ وسلم نے اس اعرابی سے بھی یہی فرمایا کہ کوئی حرج نہیں ان شاءاللہ ( یہ بخار ) گناہوں کو دھو دے گا۔ اس نے اس پر کہا: آپ کہتے ہیں گناہوں کو دھونے والا ہے۔ ہرگز نہیں۔ یہ تو نہایت شدید قسم کا بخار ہے یا ( راوی نے ) «تثور» کہا ( دونوں کا مفہوم ایک ہی ہے ) کہ بخار ایک بوڑھے کھوسٹ پر جوش مار رہا ہے جو قبر کی زیارت کرائے بغیر نہیں چھوڑے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اچھا تو پھر یوں ہی ہو گا۔' WHERE id = 3465;
UPDATE hadiths SET urdu = 'ہم سے احمد بن اسحٰق نے بیان کیا، کہا ہم سے عبیداللہ بن موسیٰ نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحٰق نے، ان سے عمرو بن میمون نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ سعد بن معاذ رضی اللہ عنہ عمرہ کی نیت سے ( مکہ ) آئے اور ابوصفوان امیہ بن خلف کے یہاں اترے۔ امیہ بھی شام جاتے ہوئے ( تجارت وغیرہ کے لیے ) جب مدینہ سے گزرتا تو سعد بن معاذ رضی اللہ عنہ کے یہاں قیام کیا کرتا تھا۔ امیہ نے سعد رضی اللہ عنہ سے کہا: ابھی ٹھہرو، جب دوپہر کا وقت ہو جائے اور لوگ غافل ہو جائیں ( تب طواف کرنا کیونکہ مکہ کے مشرک مسلمانوں کے دشمن تھے ) سعد رضی اللہ عنہ کہتے ہیں، چنانچہ میں نے جا کر طواف شروع کر دیا۔ سعد رضی اللہ عنہ ابھی طواف کر ہی رہے تھے کہ ابوجہل آ گیا اور کہنے لگا، یہ کعبہ کا طواف کون کر رہا ہے؟ سعد رضی اللہ عنہ بولے کہ میں سعد ہوں۔ ابوجہل بولا: تم کعبہ کا طواف خوب امن سے کر رہے ہو حالانکہ محمد صلی اللہ علیہ وسلم اور اس کے ساتھیوں کو پناہ دے رکھی ہے۔ سعد رضی اللہ عنہ نے کہا: ہاں ٹھیک ہے۔ اس طرح دونوں میں بات بڑھ گئی۔ پھر امیہ نے سعد رضی اللہ عنہ سے کہا: ابوالحکم ( ابوجہل ) کے سامنے اونچی آواز سے نہ بولو۔ وہ اس وادی ( مکہ ) کا سردار ہے۔ اس پر سعد رضی اللہ عنہ نے کہا: اللہ کی قسم اگر تم نے مجھے بیت اللہ کے طواف سے روکا تو میں بھی تمہاری شام کی تجارت خاک میں ملا دوں گا ( کیونکہ شام جانے کا صرف ایک ہی راستہ ہے جو مدینہ سے جاتا ہے ) بیان کیا کہ امیہ برابر سعد رضی اللہ عنہ سے یہی کہتا رہا کہ اپنی آواز بلند نہ کرو اور انہیں ( مقابلہ سے ) روکتا رہا۔ آخر سعد رضی اللہ عنہ کو اس پر غصہ آ گیا اور انہوں نے امیہ سے کہا۔ چل پرے ہٹ میں نے محمد صلی اللہ علیہ وسلم سے تیرے متعلق سنا ہے۔ آپ نے فرمایا تھا کہ تجھ کو ابوجہل ہی قتل کرائے گا۔ امیہ نے پوچھا: مجھے؟ سعد رضی اللہ عنہ کہا: ہاں تجھ کو۔ تب تو امیہ کہنے لگا۔ اللہ کی قسم محمد ( صلی اللہ علیہ وسلم ) جب کوئی بات کہتے ہیں تو وہ غلط نہیں ہوتی پھر وہ اپنی بیوی کے پاس آیا اور اس نے اس سے کہا تمہیں معلوم نہیں، میرے یثربی بھائی نے مجھے کیا بات بتائی ہے؟ اس نے پوچھا: انہوں نے کیا کہا؟ امیہ نے بتایا کہ محمد ( صلی اللہ علیہ وسلم ) کہہ چکے ہیں کہ ابوجہل مجھ کو قتل کرائے گا۔ وہ کہنے لگی۔ اللہ کی قسم محمد صلی اللہ علیہ وسلم غلط بات زبان سے نہیں نکالتے۔ پھر ایسا ہوا کہ اہل مکہ بدر کی لڑائی کے لیے روانہ ہونے لگے اور امیہ کو بھی بلانے والا آیا تو امیہ سے اس کی بیوی نے کہا، تمہیں یاد نہیں رہا تمہارا یثربی بھائی تمہیں کیا خبر دے گیا تھا۔ بیان کیا کہ اس یاددہانی پر امیہ نے چاہا کہ اس جنگ میں شرکت نہ کرے۔ لیکن ابوجہل نے کہا: تم وادی مکہ کے رئیس ہو۔ اس لیے کم از کم ایک یا دو دن کے لیے ہی تمہیں چلنا پڑے گا۔ اس طرح وہ ان کے ساتھ جنگ میں شرکت کے لیے نکلا اور اللہ تعالیٰ نے اس کو قتل کرا دیا۔' WHERE id = 3478;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا کہ ہم سے یحییٰ نے بیان کیا، ان سے عبداللہ نے بیان کیا، انہیں نافع نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”گھوڑے کی پیشانی کے ساتھ خیر و برکت قیامت تک کے لیے باندھ دی گئی ہے۔“' WHERE id = 3489;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد نے بیان کیا، کہا ہم سے ابوعامر نے بیان کیا، ان سے فلیح بن سلیمان نے بیان کیا، کہا کہ مجھ سے سالم ابوالنضر نے بیان کیا، ان سے بسر بن سعید نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے خطبہ دیا اور فرمایا کہ اللہ تعالیٰ نے اپنے ایک بندے کو دنیا میں اور جو کچھ اللہ کے پاس آخرت میں ہے ان دونوں میں سے کسی ایک کا اختیار دیا تو اس بندے نے وہ اختیار کر لیا جو اللہ کے پاس تھا۔ انہوں نے بیان کیا کہ اس پر ابوبکر رضی اللہ عنہ رونے لگے۔ ابوسعید کہتے ہیں کہ ہم کو ان کے رونے پر حیرت ہوئی کہ نبی کریم صلی اللہ علیہ وسلم تو کسی بندے کے متعلق خبر دے رہے ہیں جسے اختیار دیا گیا تھا، لیکن بات یہ تھی کہ خود آپ صلی اللہ علیہ وسلم ہی وہ بندے تھے جنہیں اختیار دیا گیا تھا اور ( واقعتاً ) ابوبکر رضی اللہ عنہ ہم میں سب سے زیادہ جاننے والے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے ایک مرتبہ فرمایا کہ اپنی صحبت اور مال کے ذریعہ مجھ پر ابوبکر کا سب سے زیادہ احسان ہے اور اگر میں اپنے رب کے سوا کسی کو جانی دوست بنا سکتا تو ابوبکر کو بناتا۔ لیکن اسلام کا بھائی چارہ اور اسلام کی محبت ان سے کافی ہے۔ دیکھو مسجد کی طرف تمام دروازے ( جو صحابہ کے گھروں کی طرف کھلتے تھے ) سب بند کر دیئے جائیں۔ صرف ابوبکر کا دروازہ رہنے دو۔' WHERE id = 3499;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے، ان سے زہری نے بیان کیا، کہا مجھ کو ابن المسیب نے خبر دی اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں سو رہا تھا کہ خواب میں میں نے اپنے آپ کو ایک کنویں پر دیکھا جس پر ڈول تھا۔ اللہ تعالیٰ نے جتنا چاہا میں نے اس ڈول سے پانی کھینچا، پھر اسے ابن ابی قحافہ ( ابوبکر رضی اللہ عنہ ) نے لے لیا اور انہوں نے ایک یا دو ڈول کھینچے، ان کے کھینچنے میں کچھ کمزوری سی معلوم ہوئی اللہ ان کی اس کمزوری کو معاف فرمائے۔ پھر اس ڈول نے ایک بہت بڑے ڈول کی صورت اختیار کر لی اور اسے عمر بن خطاب ( رضی اللہ عنہ ) نے اپنے ہاتھ میں لے لیا۔ میں نے ایسا شہ زور پہلوان آدمی نہیں دیکھا جو عمر ( رضی اللہ عنہ ) کی طرح ڈول کھینچ سکتا۔ انہوں نے اتنا پانی نکالا کہ لوگوں نے اپنے اونٹوں کو حوض سے سیراب کر لیا۔' WHERE id = 3509;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن یزید کوفی نے بیان کیا، کہا ہم سے ولید نے بیان کیا، ان سے اوزاعی نے، ان سے یحییٰ ابن ابی کثیر نے، ان سے محمد بن ابراہیم نے اور ان سے عروہ بن زبیر نے بیان کیا کہ میں نے عبداللہ بن عمر رضی اللہ عنہما سے مشرکین مکہ کی سب سے بڑی ظالمانہ حرکت کے بارے میں پوچھا جو انہوں نے رسول اللہ صلی اللہ علیہ وسلم کے ساتھ کی تھی تو انہوں نے بتلایا کہ میں نے دیکھا کہ عقبہ بن ابی معیط آپ صلی اللہ علیہ وسلم کے پاس آیا۔ آپ اس وقت نماز پڑھ رہے تھے، اس بدبخت نے اپنی چادر آپ کی گردن مبارک میں ڈال کر کھینچی جس سے آپ کا گلا بڑی سختی کے ساتھ پھنس گیا۔ اتنے میں ابوبکر رضی اللہ عنہ آئے اور اس بدبخت کو دفع کیا اور کہا کیا تم ایک ایسے شخص کو قتل کرنا چاہتے ہو جو یہ کہتا ہے کہ میرا پروردگار اللہ تعالیٰ ہے اور وہ تمہارے پاس اپنے پروردگار کی طرف سے کھلی ہوئی دلیلیں بھی لے کر آیا ہے۔' WHERE id = 3521;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ایک صاحب ( ذوالخویصرہ یا ابوموسیٰ ) نے رسول اللہ صلی اللہ علیہ وسلم سے قیامت کے بارے میں پوچھا کہ قیامت کب قائم ہو گی؟ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم نے قیامت کے لیے تیاری کیا کی ہے؟ انہوں نے عرض کیا کچھ بھی نہیں، سوا اس کے کہ میں اللہ اور اس کے رسول سے محبت رکھتا ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر تمہارا حشر بھی انہیں کے ساتھ ہو گا جن سے تمہیں محبت ہے۔“ انس رضی اللہ عنہ نے بیان کیا کہ ہمیں کبھی اتنی خوشی کسی بات سے بھی نہیں ہوئی جتنی آپ کی یہ حدیث سن کر ہوئی کہ ”تمہارا حشر انہیں کے ساتھ ہو گا جن سے تمہیں محبت ہے۔“ انس رضی اللہ عنہ نے کہا کہ میں بھی رسول اللہ صلی اللہ علیہ وسلم سے اور ابوبکر و عمر رضی اللہ عنہما سے محبت رکھتا ہوں اور ان سے اپنی اس محبت کی وجہ سے امید رکھتا ہوں کہ میرا حشر انہیں کے ساتھ ہو گا، اگرچہ میں ان جیسے عمل نہ کر سکا۔' WHERE id = 3531;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے، کہا ہم سے عثمان بن موہب نے بیان کیا کہ مصر والوں میں سے ایک نام نامعلوم آدمی آیا اور حج بیت اللہ کیا، پھر کچھ لوگوں کو بیٹھے ہوئے دیکھا تو اس نے پوچھا کہ یہ کون لوگ ہیں؟ کسی نے کہا کہ یہ قریشی ہیں۔ اس نے پوچھا کہ ان میں بزرگ کون صاحب ہیں؟ لوگوں نے بتایا کہ یہ عبداللہ بن عمر ہیں۔ اس نے پوچھا۔ اے ابن عمر! میں آپ سے ایک بات پوچھنا چاہتا ہوں۔ امید ہے کہ آپ مجھے بتائیں گے۔ کیا آپ کو معلوم ہے کہ عثمان رضی اللہ عنہ نے احد کی لڑائی سے راہ فرار اختیار کی تھی؟ ابن عمر رضی اللہ عنہما نے فرمایا کہ ہاں ایسا ہوا تھا۔ پھر انہوں نے پوچھا: کیا آپ کو معلوم ہے کہ وہ بدر کی لڑائی میں شریک نہیں ہوئے تھے؟ جواب دیا کہ ہاں ایسا ہوا تھا۔ اس نے پوچھا کیا آپ کو معلوم ہے کہ وہ بیعت رضوان میں بھی شریک نہیں تھے۔ جواب دیا کہ ہاں یہ بھی صحیح ہے۔ یہ سن کر اس کی زبان سے نکلا اللہ اکبر تو ابن عمر رضی اللہ عنہما نے کہا کہ قریب آ جاؤ، اب میں تمہیں ان واقعات کی تفصیل سمجھاؤں گا۔ احد کی لڑائی سے فرار کے متعلق میں گواہی دیتا ہوں کہ اللہ تعالیٰ نے انہیں معاف کر دیا ہے۔ بدر کی لڑائی میں شریک نہ ہونے کی وجہ یہ ہے کہ ان کے نکاح میں رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی تھیں اور اس وقت وہ بیمار تھیں اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ تمہیں ( مریضہ کے پاس ٹھہرنے کا ) اتنا ہی اجر و ثواب ملے گا جتنا اس شخص کو جو بدر کی لڑائی میں شریک ہو گا اور اسی کے مطابق مال غنیمت سے حصہ بھی ملے گا اور بیعت رضوان میں شریک نہ ہونے کی وجہ یہ ہے کہ اس موقع پر وادی مکہ میں کوئی بھی شخص ( مسلمانوں میں سے ) عثمان رضی اللہ عنہ سے زیادہ عزت والا اور بااثر ہوتا تو نبی کریم صلی اللہ علیہ وسلم اسی کو ان کی جگہ وہاں بھیجتے، یہی وجہ ہوئی تھی کہ آپ صلی اللہ علیہ وسلم نے انہیں ( قریش سے باتیں کرنے کے لیے ) مکہ بھیج دیا تھا اور جب بیعت رضوان ہو رہی تھی تو عثمان رضی اللہ عنہ مکہ جا چکے تھے، اس موقع پر نبی کریم صلی اللہ علیہ وسلم نے اپنے داہنے ہاتھ کو اٹھا کر فرمایا تھا کہ یہ عثمان کا ہاتھ ہے اور پھر اسے اپنے دوسرے ہاتھ پر ہاتھ رکھ کر فرمایا تھا کہ یہ بیعت عثمان کی طرف سے ہے۔ اس کے بعد ابن عمر رضی اللہ عنہما نے سوال کرنے والے شخص سے فرمایا کہ جا، ان باتوں کو ہمیشہ یاد رکھنا۔ ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سعید نے، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب احد پہاڑ پر چڑھے اور آپ کے ساتھ ابوبکر، عمر اور عثمان رضی اللہ عنہم بھی تھے تو پہاڑ کانپنے لگا۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا احد ٹھہر جا میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے اسے اپنے پاؤں سے مارا بھی تھا کہ تجھ پر ایک نبی، ایک صدیق اور دو شہید ہی تو ہیں۔' WHERE id = 3541;
UPDATE hadiths SET urdu = 'ہم سے احمد بن ابی بکر نے بیان کیا، کہا ہم سے محمد بن ابراہیم بن دینار ابوعبداللہ جہنی نے بیان کیا، ان سے ابن ابی ذئب نے، ان سے سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ لوگ کہتے ہیں کہ ابوہریرہ بہت احادیث بیان کرتا ہے، حالانکہ پیٹ بھرنے کے بعد میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ ہر وقت رہتا تھا، میں خمیری روٹی نہ کھاتا اور نہ عمدہ لباس پہنتا تھا ( یعنی میرا وقت علم کے سوا کسی دوسری چیز کے حاصل کرنے میں نہ جاتا ) اور نہ میری خدمت کے لیے کوئی فلاں یا فلانی تھی بلکہ میں بھوک کی شدت کی وجہ سے اپنے پیٹ سے پتھر باندھ لیا کرتا۔ بعض وقت میں کسی کو کوئی آیت اس لیے پڑھ کر اس کا مطلب پوچھتا تھا کہ وہ اپنے گھر لے جا کر مجھے کھانا کھلا دے، حالانکہ مجھے اس آیت کا مطلب معلوم ہوتا تھا، مسکینوں کے ساتھ سب سے بہتر سلوک کرنے والے جعفر بن ابی طالب رضی اللہ عنہ تھے، ہمیں اپنے گھر لے جاتے اور جو کچھ بھی گھر میں موجود ہوتا وہ ہم کو کھلاتے۔ بعض اوقات تو ایسا ہوتا کہ صرف شہد یا گھی کی کپی ہی نکال کر لاتے اور اسے ہم پھاڑ کر اس میں جو کچھ ہوتا اسے ہی چاٹ لیتے۔' WHERE id = 3551;
UPDATE hadiths SET urdu = 'ہم سے علی بن حفص نے بیان کیا، کہا ہم سے عبداللہ بن مبارک نے بیان کیا، کہا ہم کو ہشام بن عروہ نے خبر دی اور انہیں ان کے والد نے کہ جنگ یرموک کے موقع پر نبی کریم صلی اللہ علیہ وسلم کے صحابہ نے زبیر بن عوام رضی اللہ عنہ سے کہا آپ حملہ کیوں نہیں کرتے تاکہ ہم بھی آپ کے ساتھ حملہ کریں۔ چنانچہ انہوں نے ان ( رومیوں ) پر حملہ کیا۔ اس موقع پر انہوں نے ( رومیوں نے ) آپ کے دو کاری زخم شانے پر لگائے۔ درمیان میں وہ زخم تھا جو بدر کے موقع پر آپ کو لگا تھا۔ عروہ نے کہا کہ ( یہ زخم اتنے گہرے تھے کہ اچھے ہو جانے کے بعد ) میں بچپن میں ان زخموں کے اندر اپنی انگلیاں ڈال کر کھیلا کرتا تھا۔' WHERE id = 3562;
UPDATE hadiths SET urdu = '(دوسری سند) اور ہم سے علی نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، انہوں نے کہا کہ میں نے زہری سے مخزومیہ کی حدیث پوچھی تو وہ مجھ پر بہت غصہ ہو گئے۔ میں نے اس پر سفیان سے پوچھا کہ پھر آپ نے کسی اور ذریعہ سے اس حدیث کی روایت نہیں کی؟ انہوں نے بیان کیا کہ ایوب بن موسیٰ کی لکھی ہوئی ایک کتاب میں، میں نے یہ حدیث دیکھی۔ وہ زہری سے روایت کرتے تھے، وہ عروہ سے، وہ عائشہ رضی اللہ عنہا سے کہ بنی مخزوم کی ایک عورت نے چوری کر لی تھی۔ قریش نے ( اپنی مجلس میں ) سوچا کہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں اس عورت کی سفارش کے لیے کون جا سکتا ہے؟ کوئی اس کی جرات نہیں کر سکا، آخر اسامہ بن زید رضی اللہ عنہما نے سفارش کی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ بنی اسرائیل میں یہ دستور ہو گیا تھا کہ جب کوئی شریف آدمی چوری کرتا تو اسے چھوڑ دیتے اور اگر کوئی کمزور آدمی چوری کرتا تو اس کا ہاتھ کاٹتے۔ اگر آج فاطمہ ( رضی اللہ عنہا ) نے چوری کی ہوتی تو میں اس کا بھی ہاتھ کاٹتا۔' WHERE id = 3573;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے معتمر نے بیان کیا، انہوں نے کہا کہ میں نے اپنے والد سے سنا، انہوں نے بیان کیا کہ ہم سے ابوعثمان نے بیان کیا اور ان سے اسامہ بن زید رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم انہیں اور حسن رضی اللہ عنہ کو پکڑ کر یہ دعا کرتے تھے «اللهم إني أحبهما فأحبهما» ”اے اللہ! مجھے ان سے محبت ہے تو بھی ان سے محبت رکھ۔“ «أو كما قال‏.‏» ۔' WHERE id = 3585;
UPDATE hadiths SET urdu = 'ہم سے احمد بن واقد نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب نے ان سے حمید بن ہلال نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے کسی اطلاع کے پہنچنے سے پہلے زید، جعفر اور ابن رواحہ رضی اللہ عنہم کی شہادت کی خبر صحابہ کو سنا دی تھی۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اب اسلامی عَلم کو زید ( رضی اللہ عنہ ) لیے ہوئے ہیں اور وہ شہید کر دیئے گئے، اب جعفر ( رضی اللہ عنہ ) نے عَلم اٹھا لیا اور وہ بھی شہید کر دیئے گئے، اب ابن رواحہ ( رضی اللہ عنہ ) نے عَلم اٹھا لیا اور وہ بھی شہید کر دیئے گئے، نبی کریم صلی اللہ علیہ وسلم کی آنکھوں سے آنسو جاری تھے پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ اور آخر اللہ کی تلواروں میں سے ایک تلوار ( خالد بن ولید رضی اللہ عنہ ) نے عَلم اٹھا لیا اور اللہ تعالیٰ نے ان کے ہاتھ پر مسلمانوں کو فتح عنایت فرمائی۔' WHERE id = 3596;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا (امام بخاری رحمہ اللہ نے) اور ہم سے عمرو نے بیان کیا، کہا ہم کو شعبہ نے خبر دی، انہیں عمرو بن مرہ نے، انہیں مرہ نے اور انہیں ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مردوں میں تو بہت سے کامل پیدا ہوئے لیکن عورتوں میں مریم بنت عمران، فرعون کی بیوی آسیہ کے سوا اور کوئی کامل پیدا نہیں ہوئی، اور عائشہ کی فضیلت عورتوں پر ایسی ہے جیسے ثرید کی فضیلت بقیہ تمام کھانوں پر ہے۔“' WHERE id = 3607;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، ہم سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے، ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے یا ( یوں بیان کیا کہ ) ابوالقاسم صلی اللہ علیہ وسلم نے فرمایا کہ انصار جس وادی یا گھاٹی میں جائیں تو میں بھی انہیں کی وادی میں جاؤں گا۔ اور اگر میں ہجرت نہ کرتا تو میں انصار کا ایک فرد ہونا پسند کرتا۔ ابوہریرہ رضی اللہ عنہ نے کہا آپ پر میرے ماں باپ قربان ہوں آپ نے یہ کوئی ظلم والی بات نہیں فرمائی آپ کو انصار نے اپنے یہاں ٹھہرایا اور آپ کی مدد کی تھی یا ابوہریرہ رضی اللہ عنہ نے ( اس کے ہم معنی ) اور کوئی دوسرا کلمہ کہا۔' WHERE id = 3617;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ میں نے قتادہ سے سنا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا اور ان سے ابواسید رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بنو نجار کا گھرانہ انصار میں سے سب سے بہتر گھرانہ ہے پھر بنو عبدالاشہل کا، پھر بنو الحارث بن خزرج کا، پھر بنو ساعدہ بن کعب بن خزرج اکبر کا،، جو اوس کا بھائی تھا، خزرج اکبر اور اوس دونوں حارثہ کے بیٹے تھے اور انصار کا ہر گھرانہ عمدہ ہی ہے۔ سعد بن عبادہ رضی اللہ عنہ نے کہا کہ میرا خیال ہے کہ نبی کریم صلی اللہ علیہ وسلم نے انصار کے کئی قبیلوں کو ہم پر فضیلت دی ہے، ان سے کسی نے کہا تجھ کو بھی تو بہت سے قبیلوں پر آپ صلی اللہ علیہ وسلم نے فضیلت دی ہے اور عبدالصمد نے کہا کہ ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے بیان کیا: میں نے انس رضی اللہ عنہ سے سنا اور ان سے ابواسید رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث بیان کی، اس روایت میں سعد کے باپ کا نام عبادہ مذکور ہے۔' WHERE id = 3627;
UPDATE hadiths SET urdu = 'مجھ سے ابوعلی محمد بن یحییٰ نے بیان کیا، کہا ہم سے عبدان کے بھائی شاذان نے بیان کیا، کہا مجھ سے میرے باپ نے بیان کیا، ہمیں شعبہ بن حجاج نے خبر دی، ان سے ہشام بن زید نے بیان کیا کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ابوبکر اور عباس رضی اللہ عنہما انصار کی ایک مجلس سے گزرے، دیکھا کہ تمام اہل مجلس رو رہے ہیں، پوچھا آپ لوگ کیوں رو رہے ہیں؟ مجلس والوں نے کہا کہ ابھی ہم رسول اللہ صلی اللہ علیہ وسلم کی مجلس کو یاد کر رہے تھے جس میں ہم بیٹھا کرتے تھے ( یہ آپ صلی اللہ علیہ وسلم کے مرض الوفات کا واقعہ ہے ) اس کے بعد یہ آپ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ کو واقعہ کی اطلاع دی، بیان کیا کہ اس پر آپ صلی اللہ علیہ وسلم باہر تشریف لائے، سر مبارک پر کپڑے کی پٹی بندھی ہوئی تھی، راوی نے بیان کیا کہ پھر آپ منبر پر تشریف لائے اور اس کے بعد پھر کبھی منبر پر آپ تشریف نہ لا سکے، آپ نے اللہ کی حمد و ثنا کے بعد فرمایا میں تمہیں انصار کے بارے میں وصیت کرتا ہوں کہ وہ میرے جسم و جان ہیں، انہوں نے اپنی تمام ذمہ داریاں پوری کی ہیں لیکن اس کا بدلہ جو انہیں ملنا چاہیے تھا، وہ ملنا ابھی باقی ہے، اس لیے تم لوگ بھی ان کے نیک لوگوں کی نیکیوں کی قدر کرنا اور ان کے خطا کاروں سے درگزر کرتے رہنا۔' WHERE id = 3637;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا کہ میں نے شعبہ سے سنا، انہوں نے قتادہ سے سنا اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ابی بن کعب سے فرمایا کہ اللہ تعالیٰ نے مجھے حکم دیا ہے کہ میں تم کو سورۃ «لم يكن الذين كفروا‏» سناؤں۔ ابی بن کعب رضی اللہ عنہ بولے کیا اللہ تعالیٰ نے میرا نام لیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، اس پر ابی بن کعب رضی اللہ عنہ فرط مسرت سے رونے لگے۔' WHERE id = 3647;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے اسماعیل نے بیان کیا کہ میں نے عبداللہ بن ابی اوفی سے پوچھا رسول اللہ صلی اللہ علیہ وسلم نے خدیجہ رضی اللہ عنہا کو بشارت دی تھی؟ انہوں نے فرمایا کہ ہاں، جنت میں موتیوں کے ایک محل کی بشارت دی تھی، جہاں نہ کوئی شور و غل ہو گا اور نہ تھکن ہو گی۔' WHERE id = 3657;
UPDATE hadiths SET urdu = 'مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا کہ مجھے ابن جریج نے خبر دی، کہا کہ مجھے عمرو بن دینار نے خبر دی، انہوں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ جب کعبہ کی تعمیر ہو رہی تھی تو نبی کریم صلی اللہ علیہ وسلم اور عباس رضی اللہ عنہ اس کے لیے پتھر ڈھو رہے تھے عباس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے کہا اپنا تہبند گردن پر رکھ لیں اس طرح پتھر کی ( خراش لگنے سے ) بچ جائیں گے۔ آپ صلی اللہ علیہ وسلم نے جب ایسا کیا تو آپ زمین پر گر پڑے اور آپ کی نظر آسمان پر گڑ گئی جب ہوش ہوا تو آپ نے چچا سے فرمایا کہ میرا تہبند لائیں پھر انہوں نے آپ کا تہبند خوب مضبوط باندھ دیا۔' WHERE id = 3667;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن ابراہیم نے بیان کیا، کہا کہ میں نے ابواسامہ سے پوچھا، کیا تم لوگوں سے یحییٰ بن مہلب نے یہ حدیث بیان کی تھی کہ ان سے حصین نے بیان کیا، ان سے عکرمہ نے (قرآن مجید کی آیت میں) کے متعلق فرمایا کہ اس کے ( معنی ٰ ہیں ) بھرا ہوا پیالہ جس کا مسلسل دور چلے۔' WHERE id = 3677;
UPDATE hadiths SET urdu = 'ہم سے نعیم بن حماد نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، ان سے حصین نے، ان سے عمرو بن میمون نے بیان کیا کہ میں نے زمانہ جاہلیت میں ایک بندریا دیکھی اس کے چاروں طرف بہت سے بندر جمع ہو گئے تھے اس بندریا نے زنا کرایا تھا اس لیے سبھوں نے مل کر اسے رجم کیا اور ان کے ساتھ میں بھی پتھر مارنے میں شریک ہوا۔' WHERE id = 3687;
UPDATE hadiths SET urdu = 'مجھ سے عبیداللہ بن سعید نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا ہم سے مسعر نے بیان کیا، ان سے معن بن عبدالرحمٰن نے بیان کیا، کہا کہ میں نے اپنے والد سے سنا، انہوں نے بیان کیا کہ میں نے مسروق سے پوچھا کہ جس رات میں جنوں نے قرآن مجید سنا تھا اس کی خبر نبی کریم صلی اللہ علیہ وسلم کو کس نے دی تھی؟ مسروق نے کہا کہ مجھ سے تمہارے والد عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کو جنوں کی خبر ایک ببول کے درخت نے دی تھی۔' WHERE id = 3697;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ محمد بن میمون نے، ان سے اعمش نے، ان سے ابراہیم نخعی نے، ان سے ابومعمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ جس وقت چاند کے دو ٹکڑے ہوئے تو ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ منیٰ کے میدان میں موجود تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا تھا کہ لوگو! گواہ رہنا اور چاند کا ایک ٹکڑا دوسرے سے الگ ہو کر پہاڑ کی طرف چلا گیا تھا اور ابوالضحیٰ نے بیان کیا، ان سے مسروق نے، ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ شق قمر کا معجزہ مکہ میں پیش آیا تھا۔ ابراہیم نخعی کے ساتھ اس کی متابعت محمد بن مسلم نے کی ہے، ان سے ابونجیح نے بیان کیا، ان سے مجاہد نے، ان سے ابومعمر نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے۔' WHERE id = 3707;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی شیبہ نے بیان کیا، کہا ہم سے یزید بن ہارون نے بیان کیا، ان سے سلیم بن حیان نے، کہا ہم سے سعید بن میناء نے بیان کیا، ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے اصحمہ نجاشی کی نماز جنازہ پڑھی اور چار مرتبہ آپ صلی اللہ علیہ وسلم نے نماز میں تکبیر کہی۔ یزید بن ہارون کے ساتھ اس حدیث کو عبدالصمد بن عبدالوارث نے بھی ( سلیم بن حیان ) سے روایت کیا ہے۔' WHERE id = 3717;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے (دوسری سند) ،‏‏‏‏ امام بخاری نے کہا اور ہم سے احمد بن صالح نے بیان کیا، کہا ہم سے عنبسہ بن خالد نے بیان کیا، ہم سے یونس بن یزید نے بیان کیا، ان سے ابن شہاب نے بیان کیا کہ مجھے عبدالرحمٰن بن عبداللہ بن کعب بن مالک نے خبر دی اور انہیں عبداللہ بن کعب نے جب وہ نابینا ہو گئے تو وہ چلتے پھرتے وقت ان کو پکڑ کر لے چلتے تھے، انہوں نے بیان کیا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا کہ وہ غزوہ تبوک میں شریک نہ ہونے کا طویل واقعہ بیان کرتے تھے ابن بکیر نے اپنی روایت میں بیان کیا کہ کعب نے کہا کہ میں نبی کریم صلی اللہ علیہ وسلم کے پاس عقبہ کی رات میں حاضر تھا جب ہم نے اسلام پر قائم رہنے کا پختہ عہد کیا تھا، میرے نزدیک ( لیلۃالعقبہ کی بیعت ) بدر کی لڑائی میں حاضری سے بھی زیادہ پسندیدہ ہے اگرچہ لوگوں میں بدر کا چرچہ اس سے زیادہ ہے۔' WHERE id = 3727;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن یزید دمشقی نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن حمزہ نے بیان کیا، انہوں نے کہا کہ مجھ سے ابوعمرو اوزاعی نے بیان کیا، انہوں نے کہا کہ ہم سے عبدہ بن ابی لبابہ نے بیان کیا، ان سے مجاہد بن جبر مکی نے بیان کیا کہ عبداللہ بن عمر رضی اللہ عنہما کہا کرتے تھے کہ فتح مکہ کے بعد ( مکہ سے مدینہ کی طرف ) ہجرت باقی نہیں رہی۔' WHERE id = 3737;
UPDATE hadiths SET urdu = 'مجھ سے زکریا بن یحییٰ نے بیان کیا، ان سے ابواسامہ نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے اسماء رضی اللہ عنہا نے کہ عبداللہ بن زبیر رضی اللہ عنہما ان کے پیٹ میں تھے، انہیں دنوں جب حمل کی مدت بھی پوری ہو چکی تھی، میں مدینہ کے لیے روانہ ہوئی یہاں پہنچ کر میں نے قباء میں پڑاؤ کیا اور یہیں عبداللہ رضی اللہ عنہ پیدا ہوئے۔ پھر میں انہیں لے کر رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی اور آپ کی گود میں اسے رکھ دیا۔ نبی کریم صلی اللہ علیہ وسلم نے ایک کھجور طلب فرمائی اور اسے چبا کر آپ نے عبداللہ رضی اللہ عنہ کے منہ میں اسے رکھ دیا۔ چنانچہ سب سے پہلی چیز جو عبداللہ رضی اللہ عنہ کے پیٹ میں داخل ہوئی وہ آپ صلی اللہ علیہ وسلم کا مبارک لعاب تھا۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے ان کے لیے دعا فرمائی اور اللہ سے ان کے لیے برکت طلب کی۔ عبداللہ رضی اللہ عنہ سب سے پہلے بچے ہیں جن کی پیدائش ہجرت کے بعد ہوئی۔ زکریا کے ساتھ اس روایت کی متابعت خالد بن مخلد نے کی ہے۔ ان سے علی بن مسہر نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے اور ان سے اسماء رضی اللہ عنہا نے کہ جب نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہونے کو نکلیں تھیں تو وہ حاملہ تھیں۔' WHERE id = 3747;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن عبدالرحمٰن نے بیان کیا، کہا ہم سے محمد بن حمیر نے بیان کیا، کہا ہم سے ابراہیم بن ابی عبلہ نے بیان کیا، ان سے عقبہ بن وساج نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم کے خادم انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم ( مدینہ منورہ ) تشریف لائے تو ابوبکر رضی اللہ عنہ کے سوا اور کوئی آپ کے اصحاب میں ایسا نہیں تھا جس کے بال سفید ہو رہے ہوں، اس لیے آپ نے مہندی اور وسمہ کا خضاب استعمال کیا تھا۔' WHERE id = 3757;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہیں ابن شہاب نے خبر دی، انہیں خارجہ بن زید بن ثابت نے کہ (ان کی والدہ) ام علاء رضی اللہ عنہا (ایک انصاری خاتون جنہوں نے نبی کریم صلی اللہ علیہ وسلم سے بیعت کی تھی) نے انہیں خبر دی کہ جب انصار نے مہاجرین کی میزبانی کے لیے قرعہ ڈالا تو عثمان بن مظعون ان کے گھرانے کے حصے میں آئے تھے۔ ام علاء رضی اللہ عنہا نے بیان کیا کہ پھر عثمان رضی اللہ عنہ ہمارے یہاں بیمار پڑ گئے۔ میں نے ان کی پوری طرح تیمارداری کی وہ نہ بچ سکے۔ ہم نے انہیں ان کے کپڑوں میں لپیٹ دیا تھا۔ اتنے میں نبی کریم صلی اللہ علیہ وسلم بھی تشریف لائے تو میں نے کہا: ابوسائب! ( عثمان رضی اللہ عنہ کی کنیت ) تم پر اللہ کی رحمتیں ہوں، میری تمہارے متعلق گواہی ہے کہ اللہ تعالیٰ نے تمہیں اپنے اکرام سے نوازا ہے۔ یہ سن کر نبی کریم صلی اللہ علیہ وسلم نے فرمایا تمہیں یہ کیسے معلوم ہوا کہ اللہ تعالیٰ نے انہیں اپنے اکرام سے نوازا ہے؟ میں نے عرض کیا مجھے تو اس سلسلے میں کچھ خبر نہیں ہے۔ میرے ماں باپ آپ پر فدا ہوں یا رسول اللہ! لیکن اور کسے نوازے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس میں تو واقعی کوئی شک و شبہ نہیں کہ ایک یقینی امر ( موت ) ان کو آ چکا ہے۔ اللہ کی قسم کہ میں بھی ان کے لیے اللہ تعالیٰ سے خیر خواہی کی امید رکھتا ہوں لیکن میں حالانکہ اللہ کا رسول ہوں خود اپنے متعلق نہیں جان سکتا کہ میرے ساتھ کیا معاملہ ہو گا۔ ام علاء رضی اللہ عنہا نے عرض کیا پھر اللہ کی قسم کہ اس کے بعد میں اب کسی کے بارے میں اس کی پاکی نہیں کروں گی۔ انہوں نے بیان کیا کہ اس واقعہ پر مجھے بڑا رنج ہوا۔ پھر میں سو گئی تو میں نے خواب میں دیکھا کہ عثمان بن مظعون کے لیے ایک بہتا ہوا چشمہ ہے۔ میں آپ کی خدمت میں حاضر ہوئی اور آپ سے اپنا خواب بیان کیا تو آپ نے فرمایا کہ یہ ان کا عمل تھا۔' WHERE id = 3767;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے قرہ بن خالد نے بیان کیا، ان سے محمد بن سیرین نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر دس یہودی ( احبار و علماء ) مجھ پر ایمان لے آتے تو تمام یہود مسلمان ہو جاتے۔“' WHERE id = 3778;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، انہوں نے کہا کہ ہم سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے عبدالرحمٰن بن عبداللہ بن کعب نے، ان سے عبداللہ بن کعب نے بیان کیا، انہوں نے کہا کہ میں نے کعب بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جتنے غزوے کئے، میں غزوہ تبوک کے سوا سب میں حاضر رہا۔ البتہ غزوہ بدر میں شریک نہ ہو سکا تھا لیکن جو لوگ اس غزوے میں شریک نہ ہو سکے تھے، ان میں سے کسی پر اللہ نے عتاب نہیں کیا۔ کیونکہ رسول اللہ صلی اللہ علیہ وسلم قریش کے قافلے کو تلاش کرنے کے لیے نکلے تھے۔ ( لڑنے کی نیت سے نہیں گئے تھے ) مگر اللہ تعالیٰ نے ناگہانی مسلمانوں کو ان کے دشمنوں سے بھڑا دیا۔' WHERE id = 3788;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ بن نمیر نے بیان کیا، ہم سے ابواسامہ نے بیان کیا، ہم سے اسماعیل بن ابی خالد نے بیان کیا، ہم کو قیس بن ابوحازم نے خبر دی اور انہیں عبداللہ بن مسعود رضی اللہ عنہ نے کہ بدر کی لڑائی میں وہ ابوجہل کے قریب سے گزرے ابھی اس میں تھوڑی سی جان باقی تھی اس نے ان سے کہا اس سے بڑا کوئی اور شخص ہے جس کو تم نے مارا ہے؟' WHERE id = 3798;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، کہا کہ مجھ سے یوسف بن ماجشون نے بیان کیا، ان سے صالح بن ابراہیم بن عبدالرحمٰن بن عوف نے، ان سے ان کے والد ابراہیم نے ان کے دادا عبدالرحمٰن بن عوف رضی اللہ عنہ سے، انہوں نے بیان کیا کہ امیہ بن خلف سے ( ہجرت کے بعد ) میرا عہد نامہ ہو گیا تھا۔ پھر بدر کی لڑائی کے موقع پر انہوں نے اس کے اور اس کے بیٹے ( علی ) کے قتل کا ذکر کیا۔ بلال نے ( جب اسے دیکھ لیا تو ) کہا کہ اگر آج امیہ بچ نکلا تو میں آخرت میں عذاب سے بچ نہیں سکوں گا۔' WHERE id = 3809;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن عبدالرحیم نے بیان کیا ‘ ہم سے ابواحمد زبیری نے بیان کیا ‘ ہم سے عبدالرحمٰن بن غسیل نے ‘ ان سے حمزہ بن ابی اسید اور منذر بن ابی اسید نے اور ان سے ابواسید رضی اللہ عنہ نے بیان کیا کہ جنگ بدر میں رسول اللہ صلی اللہ علیہ وسلم نے ہمیں ہدایت کی تھی کہ جب کفار تمہارے قریب آ جائیں یعنی حملہ و ہجوم کریں ( اتنے کہ تمہارے نشانے کی زد میں آ جائیں ) تو پھر ان پر تیر برسانے شروع کرنا اور ( جب تک وہ تم سے قریب نہ ہوں ) اپنے تیر کو محفوظ رکھنا۔' WHERE id = 3821;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم نے بیان کیا، ہم کو عبدالوہاب ثقفی نے خبر دی، کہا ہم سے خالد حذاء نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے بدر کی لڑائی میں فرمایا تھا کہ یہ ہیں جبرائیل علیہ السلام اپنے گھوڑے کا سر تھامے ہوئے اور ہتھیار لگائے ہوئے۔' WHERE id = 3831;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا، انہیں سالم بن عبداللہ نے خبر دی، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے سنا اور انہوں نے عمر بن خطاب رضی اللہ عنہ سے بیان کیا کہ جب حفصہ بنت عمر رضی اللہ عنہما کے شوہر خنیس بن حذافہ سہمی رضی اللہ عنہ کی وفات ہو گئی، وہ رسول اللہ صلی اللہ علیہ وسلم کے اصحاب میں تھے اور بدر کی لڑائی میں انہوں نے شرکت کی تھی اور مدینہ میں ان کی وفات ہو گئی تھی۔ عمر رضی اللہ عنہ نے بیان کیا کہ میری ملاقات عثمان بن عفان رضی اللہ عنہ سے ہوئی تو میں نے ان سے حفصہ کا ذکر کیا اور کہا کہ اگر آپ چاہیں تو اس کا نکاح میں آپ سے کر دوں۔ انہوں نے کہا کہ میں سوچوں گا۔ اس لیے میں چند دنوں کے لیے ٹھہر گیا، پھر انہوں نے کہا کہ میری رائے یہ ہوئی ہے کہ ابھی میں نکاح نہ کروں۔ عمر رضی اللہ عنہ نے کہا کہ پھر میری ملاقات ابوبکر رضی اللہ عنہ سے ہوئی اور ان سے بھی میں نے یہی کہا کہ اگر آپ چاہیں تو میں آپ کا نکاح حفصہ بنت عمر سے کر دوں۔ ابوبکر رضی اللہ عنہ خاموش ہو گئے اور کوئی جواب نہیں دیا۔ ان کا یہ طریقہ عمل عثمان رضی اللہ عنہ سے بھی زیادہ میرے لیے باعث تکلیف ہوا۔ کچھ دنوں میں نے اور توقف کیا تو نبی کریم صلی اللہ علیہ وسلم نے خود حفصہ رضی اللہ عنہا کا پیغام بھیجا اور میں نے ان کا نکاح آپ صلی اللہ علیہ وسلم سے کر دیا۔ اس کے بعد ابوبکر رضی اللہ عنہ کی ملاقات مجھ سے ہوئی تو انہوں نے کہا، شاید آپ کو میرے اس طرز عمل سے تکلیف ہوئی ہو گی کہ جب آپ کی مجھ سے ملاقات ہوئی اور آپ نے حفصہ رضی اللہ عنہا کے متعلق مجھ سے بات کی تو میں نے کوئی جواب نہیں دیا۔ میں نے کہا کہ ہاں تکلیف ہوئی تھی۔ انہوں نے بتایا کہ آپ کی بات کا میں نے صرف اس لیے کوئی جواب نہیں دیا تھا کہ نبی کریم صلی اللہ علیہ وسلم نے ( مجھ سے ) حفصہ رضی اللہ عنہا کا ذکر کیا تھا ( مجھ سے مشورہ لیا تھا کہ میں اس سے نکاح کر لوں ) اور میں نبی کریم صلی اللہ علیہ وسلم کا راز فاش نہیں کر سکتا تھا۔ اگر آپ حفصہ رضی اللہ عنہا سے نکاح کا ارادہ چھوڑ دیتے تو بیشک میں ان سے نکاح کر لیتا۔' WHERE id = 3841;
UPDATE hadiths SET urdu = 'ہم سے ابوعاصم نے بیان کیا، کہا ہم سے ابن جریج نے، ان سے زہری نے، ان سے عطاء بن یزید لیثی نے، ان سے عبیداللہ بن عدی نے اور ان سے مقداد بن اسود رضی اللہ عنہ نے۔ (دوسری سند) امام بخاری نے کہا اور مجھ سے اسحاق بن منصور نے بیان کیا، کہا ہم سے یعقوب بن ابراہیم بن سعد نے، ان سے ابن شہاب کے بھتیجے (محمد بن عبداللہ) نے، اپنے چچا (محمد بن مسلم بن شہاب) سے بیان کیا، انہیں عطاء بن یزید لیثی ثم الجندعی نے خبر دی، انہیں عبیداللہ بن عدی بن خیار نے خبر دی اور انہیں مقداد بن عمرو کندی رضی اللہ عنہ نے، وہ بنی زہرہ کے حلیف تھے اور بدر کی لڑائی میں رسول اللہ صلی اللہ علیہ وسلم کے ساتھ تھے۔ انہوں نے خبر دی کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ اگر کسی موقع پر میری کسی کافر سے ٹکر ہو جائے اور ہم دونوں ایک دوسرے کو قتل کرنے کی کوشش میں لگ جائیں اور وہ میرے ایک ہاتھ پر تلوار مار کر اسے کاٹ ڈالے، پھر وہ مجھ سے بھاگ کر ایک درخت کی پناہ لے کر کہنے لگے ”میں اللہ پر ایمان لے آیا۔“ تو کیا یا رسول اللہ! اس کے اس اقرار کے بعد پھر بھی میں اسے قتل کر دوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر تم اسے قتل نہ کرنا۔ انہوں نے عرض کیا یا رسول اللہ! وہ پہلے میرا ایک ہاتھ بھی کاٹ چکا ہے؟ اور یہ اقرار میرے ہاتھ کاٹنے کے بعد کیا ہے؟ آپ صلی اللہ علیہ وسلم نے پھر بھی یہی فرمایا کہ اسے قتل نہ کرنا، کیونکہ اگر تو نے اسے قتل کر ڈالا تو اسے قتل کرنے سے پہلے جو تمہارا مقام تھا اب اس کا وہ مقام ہو گا اور تمہارا مقام وہ ہو گا جو اس کا مقام اس وقت تھا جب اس نے اس کلمہ کا اقرار نہیں کیا تھا۔' WHERE id = 3853;
UPDATE hadiths SET urdu = 'مجھ سے حسن بن مدرک نے بیان کیا، کہا ہم سے یحییٰ بن حماد نے بیان کیا، کہا ہم کو ابوعوانہ نے خبر دی، انہیں ابوبشر نے، ان سے سعید بن جبیر نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما کے سامنے کہا، ”سورۃ الحشر“ تو انہوں نے کہا کہ اسے ”سورۃ نضیر“ کہو ( کیونکہ یہ سورت بنو نضیر ہی کے بارے میں نازل ہوئی ہے ) اس روایت کی متابعت ہشیم سے ابوبشر نے کی ہے۔' WHERE id = 3863;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے بیان کیا، ان سے ابن اسحاق (عمرو بن عبیداللہ سبیعی) نے اور ان سے براء بن عازب رضی اللہ عنہ نے بیان کیا کہ جنگ احد کے موقع پر جب مشرکین سے مقابلہ کے لیے ہم پہنچے تو نبی کریم صلی اللہ علیہ وسلم نے تیر اندازوں کا ایک دستہ عبداللہ بن جبیر رضی اللہ عنہما کی ماتحتی میں ( پہاڑی پر ) مقرر فرمایا تھا اور انہیں یہ حکم دیا تھا کہ تم اپنی جگہ سے نہ ہٹنا، اس وقت بھی جب تم لوگ دیکھ لو کہ ہم ان پر غالب آ گئے ہیں پھر بھی یہاں سے نہ ہٹنا اور اس وقت بھی جب دیکھ لو کہ وہ ہم پر غالب آ گئے، تم لوگ ہماری مدد کے لیے نہ آنا۔ پھر جب ہماری مڈبھیڑ کفار سے ہوئی تو ان میں بھگدڑ مچ گئی۔ میں نے دیکھا کہ ان کی عورتیں پہاڑیوں پر بڑی تیزی کے ساتھ بھاگی جا رہی تھیں، پنڈلیوں سے اوپر کپڑے اٹھائے ہوئے، جس سے ان کے پازیب دکھائی دے رہے تھے۔ عبداللہ بن جبیر رضی اللہ عنہما کے ( تیرانداز ) ساتھی کہنے لگے کہ غنیمت غنیمت۔ اس پر عبداللہ رضی اللہ عنہ نے ان سے کہا کہ مجھے نبی کریم صلی اللہ علیہ وسلم نے تاکید کی تھی کہ اپنی جگہ سے نہ ہٹنا ( اس لیے تم لوگ مال غنیمت لوٹنے نہ جاؤ ) لیکن ان کے ساتھیوں نے ان کا حکم ماننے سے انکار کر دیا۔ ان کی اس حکم عدولی کے نتیجے میں مسلمانوں کو ہار ہوئی اور ستر مسلمان شہید ہو گئے۔ اس کے بعد ابوسفیان نے پہاڑی پر سے آواز دی، کیا تمہارے ساتھ محمد ( صلی اللہ علیہ وسلم ) موجود ہیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی جواب نہ دے، پھر انہوں نے پوچھا، کیا تمہارے ساتھ ابن ابی قحافہ موجود ہیں؟ آپ صلی اللہ علیہ وسلم نے اس کے جواب کی بھی ممانعت فرما دی۔ انہوں نے پوچھا، کیا تمہارے ساتھ ابن خطاب موجود ہیں؟ اس کے بعد وہ کہنے لگے کہ یہ سب قتل کر دیئے گئے۔ اگر زندہ ہوتے تو جواب دیتے۔ اس پر عمر رضی اللہ عنہ بے قابو ہو گئے اور فرمایا: اللہ کے دشمن تو جھوٹا ہے۔ اللہ نے ابھی انہیں تمہیں ذلیل کرنے لیے باقی رکھا ہے۔ ابوسفیان نے کہا، ہبل ( ایک بت ) بلند رہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کا جواب دو۔ صحابہ رضی اللہ عنہم نے عرض کیا کہ ہم کیا جواب دیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کہو، اللہ سب سے بلند اور بزرگ و برتر ہے۔ ابوسفیان نے کہا، ہمارے پاس عزیٰ ( بت ) ہے اور تمہارے پاس کوئی عزیٰ نہیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کا جواب دو۔ صحابہ رضی اللہ عنہم نے عرض کیا، کیا جواب دیں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ کہو، اللہ ہمارا حامی اور مددگار ہے اور تمہارا کوئی حامی نہیں۔ ابوسفیان نے کہا، آج کا دن بدر کے دن کا بدلہ ہے اور لڑائی کی مثال ڈول کی ہوتی ہے۔ ( کبھی ہمارے ہاتھ میں اور کبھی تمہارے ہاتھ میں ) تم اپنے مقتولین میں کچھ لاشوں کا مثلہ کیا ہوا پاؤ گے، میں نے اس کا حکم نہیں دیا تھا لیکن مجھے برا نہیں معلوم ہوا۔' WHERE id = 3875;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ان کے باپ نے، ان کے دادا سے کہ سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا، غزوہ احد کے موقع پر میں نے رسول اللہ صلی اللہ علیہ وسلم کو دیکھا اور آپ کے ساتھ دو اور اصحاب ( یعنی جبرائیل علیہ السلام اور میکائیل علیہ السلام انسانی صورت میں ) آئے ہوئے تھے۔ وہ آپ کو اپنی حفاظت میں لے کر کفار سے بڑی سختی سے لڑ رہے تھے۔ ان کے جسم پر سفید کپڑے تھے۔ میں نے انہیں نہ اس سے پہلے کبھی دیکھا تھا اور نہ اس کے بعد کبھی دیکھا۔' WHERE id = 3885;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم کو ابوحمزہ نے خبر دی، ان سے عثمان بن موہب نے بیان کیا کہ ایک صاحب بیت اللہ کے حج کے لیے آئے تھے۔ دیکھا کہ کچھ لوگ بیٹھے ہوئے ہیں۔ پوچھا کہ یہ بیٹھے ہوئے کون لوگ ہیں؟ لوگوں نے بتایا کہ یہ قریش ہیں۔ پوچھا کہ ان میں شیخ کون ہیں؟ بتایا کہ ابن عمر رضی اللہ عنہما۔ وہ صاحب ابن عمر رضی اللہ عنہما کے پاس آئے اور ان سے کہا کہ میں آپ سے ایک بات پوچھتا ہوں۔ آپ مجھ سے واقعات ( صحیح ) بیان کر دیجئیے۔ اس گھر کی حرمت کی قسم دے کر میں آپ سے پوچھتا ہوں۔ کیا آپ کو معلوم ہے کہ عثمان رضی اللہ عنہ نے غزوہ احد کے موقع پر راہ فرار اختیار کی تھی؟ انہوں نے کہا کہ ہاں صحیح ہے۔ انہوں نے پوچھا آپ کو یہ بھی معلوم ہے عثمان رضی اللہ عنہ بدر کی لڑائی میں شریک نہیں تھے؟ کہا کہ ہاں یہ بھی ہوا تھا۔ انہوں نے پوچھا اور آپ کو یہ بھی معلوم ہے کہ وہ بیعت رضوان ( صلح حدیبیہ ) میں بھی پیچھے رہ گئے تھے اور حاضر نہ ہو سکے تھے؟ انہوں نے کہا کہ ہاں یہ بھی صحیح ہے۔ اس پر ان صاحب نے ( مارے خوشی کے ) اللہ اکبر کہا لیکن ابن عمر رضی اللہ عنہما نے کہا۔ یہاں آؤ میں تمہیں بتاؤں گا اور جو سوالات تم نے کئے ہیں ان کی میں تمہارے سامنے تفصیل بیان کر دوں گا۔ احد کی لڑائی میں فرار سے متعلق جو تم نے کہا تو میں گواہی دیتا ہوں کہ اللہ تعالیٰ نے ان کی غلطی معاف کر دی ہے۔ بدر کی لڑائی میں ان کے نہ ہونے کے متعلق جو تم نے کہا تو اس کی وجہ یہ تھی۔ کہ ان کے نکاح میں رسول اللہ صلی اللہ علیہ وسلم کی صاحبزادی ( رقیہ رضی اللہ عنہا ) تھیں اور وہ بیمار تھیں۔ آپ نے فرمایا تھا کہ تمہیں اس شخص کے برابر ثواب ملے گا جو بدر کی لڑائی میں شریک ہو گا اور اسی کے برابر مال غنیمت سے حصہ بھی ملے گا۔ بیعت رضوان میں ان کی عدم شرکت کا جہاں تک سوال ہے تو وادی مکہ میں عثمان بن عفان رضی اللہ عنہ سے زیادہ کوئی شخص ہر دل عزیز ہوتا تو نبی کریم صلی اللہ علیہ وسلم ان کے بجائے اسی کو بھیجتے۔ اس لیے عثمان رضی اللہ عنہ کو وہاں بھیجنا پڑا اور بیعت رضوان اس وقت ہوئی جب وہ مکہ میں تھے۔ ( بیعت لیتے ہوئے ) نبی کریم صلی اللہ علیہ وسلم نے اپنے دائیں ہاتھ کو اٹھا کر فرمایا کہ یہ عثمان کا ہاتھ ہے اور اسے اپنے ( بائیں ) ہاتھ پر مار کر فرمایا کہ یہ بیعت عثمان کی طرف سے ہے۔ اب جا سکتے ہو۔ البتہ میری باتوں کو یاد رکھنا۔' WHERE id = 3896;
UPDATE hadiths SET urdu = 'مجھ سے عمرو بن علی نے بیان کیا، کہا ہم سے ابوعاصم نے بیان کیا، کہا ہم سے ابن جریج نے بیان کیا، ان سے عمرو بن دینار نے، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ اللہ تعالیٰ کا انتہائی غضب اس شخص پر نازل ہوا جسے اللہ کے نبی نے قتل کیا تھا۔ اللہ تعالیٰ کا انتہائی غضب اس شخص پر نازل ہوا جس نے ( یعنی عبداللہ بن قمیہ نے لعنتہ اللہ علیہ ) رسول اللہ صلی اللہ علیہ وسلم کے چہرہ مبارک کو خون آلود کیا تھا۔' WHERE id = 3906;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، انہوں نے جابر سے سنا کہ خبیب رضی اللہ عنہ کو ابوسروعہ ( عقبہ بن عامر ) نے قتل کیا تھا۔' WHERE id = 3916;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے عبیداللہ عمری نے، کہا کہ مجھے نافع نے خبر دی اور انہیں ابن عمر رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کے سامنے اپنے آپ کو انہوں نے غزوہ احد کے موقع پر پیش کیا ( تاکہ لڑنے والوں میں انہیں بھی بھرتی کر لیا جائے ) اس وقت وہ چودہ سال کے تھے تو نبی کریم صلی اللہ علیہ وسلم نے انہیں اجازت نہیں دی۔ لیکن غزوہ خندق کے موقع پر جب انہوں نے آپ صلی اللہ علیہ وسلم کے سامنے اپنے کو پیش کیا تو آپ صلی اللہ علیہ وسلم نے ان کو منظور فرما لیا۔ اس وقت وہ پندرہ سال کی عمر کے تھے۔' WHERE id = 3926;
UPDATE hadiths SET urdu = 'مجھ سے عبدہ بن عبداللہ نے بیان کیا ‘ کہا ہم سے عبدالصمد بن عبدالوارث نے بیان کیا ‘ ان سے عبدالرحمٰن بن عبداللہ بن دینار نے ‘ ان سے ان کے والد نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ سب سے پہلا غزوہ جس میں میں نے شرکت کی وہ غزوہ خندق ہے۔' WHERE id = 3936;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن ابی شیبہ نے بیان کیا ‘ کہا ہم سے عبداللہ بن نمیر نے بیان کیا ‘ ان سے ہشام بن عروہ نے ‘ ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ جوں ہی نبی کریم صلی اللہ علیہ وسلم جنگ خندق سے مدینہ واپس ہوئے اور ہتھیار اتار کر غسل کیا تو جبرائیل علیہ السلام آپ کے پاس آئے اور کہا: آپ نے ابھی ہتھیار اتار دیئے؟ اللہ کی قسم! ہم نے تو ابھی ہتھیار نہیں اتارے۔ چلئے ان پر حملہ کیجئے۔ آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کن پر؟ جبرائیل علیہ السلام نے کہا کہ ان پر اور انہوں نے ( یہود کے قبیلہ ) بنو قریظہ کی طرف اشارہ کیا۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے بنو قریظہ پر چڑھائی کی۔' WHERE id = 3946;
UPDATE hadiths SET urdu = 'اور ابن اسحاق نے بیان کیا ‘ انہوں نے وہب بن کیسان سے سنا ‘ انہوں نے جابر رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم غزوہ ذات الرقاع کے لیے مقام نخل سے روانہ ہوئے تھے۔ وہاں آپ کا قبیلہ غطفان کی ایک جماعت سے سامنا ہوا لیکن کوئی جنگ نہیں ہوئی اور چونکہ مسلمانوں پر کفار کے ( اچانک حملے کا ) خطرہ تھا۔ اس لیے نبی کریم صلی اللہ علیہ وسلم نے دو رکعت نماز خوف پڑھائی۔ اور یزید نے سلمہ بن الاکوع رضی اللہ عنہ کے واسطے سے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ غزوہ ذوالقرد میں شریک تھا۔' WHERE id = 3956;
UPDATE hadiths SET urdu = 'اور ابو الزبیر نے جابر رضی اللہ عنہ سے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ مقام نخل میں تھے تو آپ صلی اللہ علیہ وسلم نے نماز خوف پڑھائی اور ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کے ساتھ نماز خوف غزوہ نجد میں پڑھی تھی۔ یہ یاد رہے کہ ابوہریرہ رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ( سب سے پہلے ) غزوہ خیبر کے موقع پر حاضر ہوئے تھے۔' WHERE id = 3966;
UPDATE hadiths SET urdu = 'ہم سے خالد بن مخلد نے بیان کیا ‘ کہا ہم سے سلیمان بن بلال نے بیان کیا ‘ کہا کہ مجھ سے صالح بن کیسان نے بیان کیا ‘ ان سے عبیداللہ بن عبداللہ نے اور ان سے زید بن خالد رضی اللہ عنہ نے بیان کیا کہ حدیبیہ کے سال ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نکلے تو ایک دن، رات کو بارش ہوئی۔ نبی کریم صلی اللہ علیہ وسلم نے صبح کی نماز پڑھانے کے بعد ہم سے خطاب کیا اور دریافت فرمایا کہ معلوم ہے تمہارے رب نے کیا کہا؟ ہم نے عرض کیا کہ اللہ اور اس کے رسول کو زیادہ علم ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ صبح ہوئی تو میرے کچھ بندوں نے اس حالت میں صبح کی کہ ان کا ایمان مجھ پر تھا اور کچھ نے اس حالت میں صبح کی کہ وہ میرا انکار کئے ہوئے تھے۔ تو جس نے کہا کہ ہم پر یہ بارش اللہ کے رزق ‘ اللہ کی رحمت اور اللہ کے فضل سے ہوئی ہے تو وہ مجھ پر ایمان لانے والا ہے اور ستارے کا انکار کرنے والا ہے اور جو شخص یہ کہتا ہے کہ بارش فلاں ستارے کی تاثیر سے ہوئی ہے تو وہ ستاروں پر ایمان لانے والا اور میرے ساتھ کفر کرنے والا ہے۔' WHERE id = 3976;
UPDATE hadiths SET urdu = 'ہم سے حسن بن خلف نے بیان کیا ‘ کہا کہ مجھ سے اسحاق بن یوسف نے بیان کیا ‘ ان سے ابوبشر ورقاء بن عمر نے ‘ ان سے ابن ابی نجیح نے ‘ ان سے مجاہد نے بیان کیا ‘ ان سے عبدالرحمٰن بن ابی لیلیٰ نے بیان کیا اور ان سے کعب بن عجرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے انہیں دیکھا کہ جوئیں ان کے چہرے پر گر رہی ہیں تو آپ صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا اس سے تمہیں تکلیف ہوتی ہے؟ وہ بولے کہ جی ہاں ‘ اس پر آپ صلی اللہ علیہ وسلم نے انہیں سر منڈوانے کا حکم دیا۔ آپ اس وقت حدیبیہ میں تھے ( عمرہ کے لیے احرام باندھے ہوئے ) اور ان کو یہ معلوم نہیں ہوا تھا کہ وہ عمرہ سے روکے جائیں گے۔ حدیبیہ ہی میں ان کو احرام کھول دینا پڑے گا۔ بلکہ ان کی تو یہ آرزو تھی کہ مکہ میں کسی طرح داخل ہوا جائے۔ پھر اللہ تعالیٰ نے فدیہ کا حکم نازل فرمایا ( یعنی احرام کی حالت میں ) سر منڈوانے وغیرہ پر ‘ اس وقت آپ صلی اللہ علیہ وسلم نے کعب کو حکم دیا کہ ایک فرق اناج چھ مسکینوں کو کھلا دیں یا ایک بکری کی قربانی کریں یا تین دن روزے رکھیں۔' WHERE id = 3987;
UPDATE hadiths SET urdu = 'ہم سے اسحاق نے بیان کیا ‘ کہا ہم سے یحییٰ بن صالح نے بیان کیا ‘ کہا ہم سے معاویہ نے بیان کیا ‘ وہ سلام کے بیٹے ہیں ‘ ان سے یحییٰ نے ‘ ان سے ابوقلابہ نے اور انہیں ثابت بن ضحاک رضی اللہ عنہ نے خبر دی کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے درخت کے نیچے بیعت کی تھی۔' WHERE id = 3998;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد بن اسماء نے بیان کیا ‘ کہا ہم سے جویریہ نے بیان کیا ‘ انہیں نافع نے ‘ ان کو عبیداللہ بن عبداللہ اور سالم بن عبداللہ نے خبر دی کہ ان دونوں نے عبداللہ بن عمر رضی اللہ عنہما سے گفتگو کی ( دوسری سند ) امام بخاری رحمہ اللہ نے کہا اور ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ ان سے جویریہ نے بیان کیا اور ان سے نافع نے کہ عبداللہ بن عمر رضی اللہ عنہما کے کسی لڑکے نے ان سے کہا ‘ اگر اس سال آپ ( عمرہ کرنے ) نہ جاتے تو بہتر تھا کیونکہ مجھے ڈر ہے کہ آپ بیت اللہ تک نہیں پہنچ سکیں گے۔ اس پر انہوں نے کہا کہ ہم رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نکلے تھے تو کفار قریش نے بیت اللہ پہنچنے سے روک دیا تھا۔ چنانچہ آپ صلی اللہ علیہ وسلم نے اپنی قربانی کے جانور وہیں ( حدیبیہ میں ) ذبح کر دیئے اور سر کے بال منڈوا دیئے۔ صحابہ رضی اللہ عنہم نے بھی بال چھوٹے کروا لیے۔ آپ صلی اللہ علیہ وسلم نے اس کے بعد فرمایا کہ میں تمہیں گواہ بناتا ہوں کہ میں نے اپنے اوپر ایک عمرہ واجب کر لیا ہے ( اور اسی طرح تمام صحابہ رضی اللہ عنہم پر بھی وہ واجب ہو گیا ) اگر آج مجھے بیت اللہ تک جانے دیا گیا تو میں طواف کر لوں گا اور اگر مجھے روک دیا گیا تو میں بھی وہی کروں گا جو نبی کریم صلی اللہ علیہ وسلم نے کیا تھا۔ پھر تھوڑی دور چلے اور کہا کہ میں تمہیں گواہ بناتا ہوں کہ میں نے اپنے اوپر عمرہ کے ساتھ حج کو بھی ضروری قرار دے لیا ہے اور کہا میری نظر میں تو حج اور عمرہ دونوں ایک ہی جیسے ہیں ‘ پھر انہوں نے ایک طواف کیا اور ایک سعی کی ( جس دن مکہ پہنچے ) اور دونوں ہی کو پورا کیا۔' WHERE id = 4010;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا ‘ ان سے امام مالک رحمہ اللہ نے ‘ ان سے یحییٰ بن سعید نے ‘ ان سے بشیر بن یسار نے اور انہیں سوید بن نعمان رضی اللہ عنہ نے خبر دی کہ غزوہ خیبر کے لیے وہ بھی رسول اللہ صلی اللہ علیہ وسلم کے ساتھ نکلے تھے۔ ( بیان کیا ) جب ہم مقام صہبا میں پہنچے جو خیبر کے نشیب میں واقع ہے تو نبی کریم صلی اللہ علیہ وسلم نے عصر کی نماز پڑھی پھر آپ نے توشہ سفر منگوایا۔ ستو کے سوا اور کوئی چیز آپ کی خدمت میں نہیں لائی گئی۔ وہ ستو آپ کے حکم سے بھگویا گیا اور وہی آپ نے بھی کھایا اور ہم نے بھی کھایا۔ اس کے بعد مغرب کی نماز کے لیے آپ کھڑے ہوئے ( چونکہ وضو پہلے سے موجود تھا ) اس لیے نبی کریم صلی اللہ علیہ وسلم نے بھی صرف کلی کی اور ہم نے بھی ‘ پھر نماز پڑھی اور اس نماز کے لیے نئے سرے سے وضو نہیں کیا۔' WHERE id = 4020;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا ‘ کہا ہم سے عبدالواحد نے بیان کیا ‘ ان سے عاصم نے ‘ ان سے ابوعثمان نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم نے خیبر پر لشکر کشی کی یا یوں بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم ( خیبر کی طرف ) روانہ ہوئے تو ( راستے میں ) لوگ ایک وادی میں پہنچے اور بلند آواز کے ساتھ تکبیر کہنے لگے اللہ اکبر، اللہ اکبر، لا الہٰ الا اللہ ”اللہ سب سے بلند و برتر ہے ‘ اللہ سب سے بلند و برتر ہے ‘ اللہ کے سوا کوئی معبود نہیں۔“ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنی جانوں پر رحم کرو ‘ تم کسی بہرے کو یا ایسے شخص کو نہیں پکار رہے ہو ‘ جو تم سے دور ہو ‘ جسے تم پکار رہے ہو وہ سب سے زیادہ سننے والا اور تمہارے بہت نزدیک ہے بلکہ وہ تمہارے ساتھ ہے۔ میں آپ صلی اللہ علیہ وسلم کی سواری کے پیچھے تھا۔ میں نے جب «لا حول ولا قوة إلا بالله» کہا تو آپ صلی اللہ علیہ وسلم نے سن لیا۔ آپ صلی اللہ علیہ وسلم نے فرمایا: عبداللہ بن قیس! میں نے کہا لبیک یا رسول اللہ! آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا میں تمہیں ایک کلمہ نہ بتا دوں جو جنت کے خزانوں میں سے ایک خزانہ ہے؟ میں نے عرض کیا ضرور بتائیے، یا رسول اللہ! میرے ماں باپ آپ پر قربان ہوں۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ وہ کلمہ یہی ہے «لا حول ولا قوة إلا بالله» یعنی گناہوں سے بچنا اور نیکی کرنا یہ اسی وقت ممکن ہے جب اللہ کی مدد شامل ہو۔' WHERE id = 4030;
UPDATE hadiths SET urdu = 'مجھ سے عبید بن اسماعیل نے بیان کیا ‘ انہوں نے کہا ہم سے ابواسامہ نے بیان کیا ‘ انہوں نے کہا کہ ہم سے عبیداللہ نے ‘ ان سے نافع اور سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ غزوہ خیبر کے موقع پر نبی کریم صلی اللہ علیہ وسلم نے لہسن اور پالتو گدھوں کے کھانے سے منع فرمایا تھا۔ لہسن کھانے کی ممانعت کا ذکر صرف نافع سے منقول ہے اور پالتو گدھوں کے کھانے کی ممانعت صرف سالم سے منقول ہے۔' WHERE id = 4040;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا ‘ انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا ‘ ان سے یونس نے ‘ ان سے ابن شہاب نے ‘ ان سے سعید بن مسیب نے اور انہیں جبیر بن مطعم رضی اللہ عنہ نے خبر دی کہ میں اور عثمان بن عفان رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ ہم نے عرض کیا کہ آپ نے بنو مطلب کو تو خیبر کے خمس میں سے عنایت فرمایا ہے اور ہمیں نظر انداز کر دیا ہے حالانکہ آپ سے قرابت میں ہم اور وہ برابر تھے۔ آپ صلی اللہ علیہ وسلم نے فرمایا یقیناً بنو ہاشم اور بنو مطلب ایک ہیں۔ جبیر بن مطعم رضی اللہ نے بیان کیا کہ آپ صلی اللہ علیہ وسلم نے بنو عبد شمس اور بنو نوفل کو ( خمس میں سے ) کچھ نہیں دیا تھا۔' WHERE id = 4052;
UPDATE hadiths SET urdu = 'سعید نے بیان کیا ‘ کہا کہ مجھے میرے دادا نے خبر دی اور انہیں ابان بن سعید رضی اللہ عنہ نے کہ وہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور سلام کیا۔ ابوہریرہ رضی اللہ عنہ بولے کہ یا رسول اللہ! یہ تو ابن قوقل کا قاتل ہے اور ابان رضی اللہ عنہ نے ابوہریرہ رضی اللہ عنہ سے کہا حیرت ہے اس «وبر» پر جو قدوم الضان سے ابھی اترا ہے اور مجھ پر عیب لگاتا ہے ایک ایسے شخص پر کہ جس کے ہاتھ سے اللہ تعالیٰ نے انہیں ( ابن قوقل رضی اللہ عنہ کو ) عزت دی اور ایسا نہ ہونے دیا کہ ان کے ہاتھ سے مجھے ذلیل کرتا۔' WHERE id = 4062;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا ‘ ان سے سفیان بن عیینہ نے ‘ ان سے عمرو بن دینار نے ‘ ان سے عطاء ابن ابی رباح نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے بیت اللہ کے طواف میں رمل اور صفا و مروہ کے درمیان دوڑ ‘ مشرکین کے سامنے اپنی طاقت دکھانے کے لیے کی تھی۔' WHERE id = 4076;
UPDATE hadiths SET urdu = 'مجھ سے عمران بن میسرہ نے بیان کیا ‘ کہا ہم سے محمد بن فضیل نے بیان کیا ‘ ان سے حصین بن عبدالرحمٰن نے ‘ ان سے عامر شعبی نے اور ان سے نعمان بن بشیر نے کہ عبداللہ بن رواحہ رضی اللہ عنہ پر ( ایک مرتبہ کسی مرض میں ) بے ہوشی طاری ہوئی تو ان کی بہن عمرہ والدہ نعمان بن بشیر یہ سمجھ کر کہ کوئی حادثہ آ گیا ‘ عبداللہ بن رواحہ رضی اللہ عنہ کے لیے پکار کر رونے لگیں۔ ہائے میرے بھائی ہائے ‘ میرے ایسے اور ویسے۔ ان کے محاسن اس طرح ایک ایک کر کے گنانے لگیں لیکن جب عبداللہ رضی اللہ عنہ کو ہوش آیا تو انہوں نے کہا کہ تم جب میری کسی خوبی کا بیان کرتی تھیں تو مجھ سے پوچھا جاتا تھا کہ کیا تم واقعی ایسے ہی تھے۔' WHERE id = 4086;
UPDATE hadiths SET urdu = 'مجھ سے عیاش بن ولید نے بیان کیا ‘ کہا ہم سے عبدالاعلیٰ نے بیان کیا ‘ ان سے خالد نے بیان کیا ‘ ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم رمضان میں حنین کی طرف تشریف لے گئے۔ مسلمانوں میں بعض حضرات تو روزے سے تھے اور بعض نے روزہ نہیں رکھا تھا لیکن جب نبی کریم صلی اللہ علیہ وسلم اپنی سواری پر پوری طرح بیٹھ گئے تو آپ نے برتن میں دودھ یا پانی طلب فرمایا اور اسے اپنی اونٹنی پر یا اپنی ہتھیلی پر رکھا ( اور پھر پی لیا ) پھر آپ نے لوگوں کو دیکھا تو جن لوگوں نے پہلے سے روزہ نہیں رکھا تھا ‘ انہوں نے روزہ داروں سے کہا کہ اب روزہ توڑ لو۔' WHERE id = 4096;
UPDATE hadiths SET urdu = 'اور لیث نے بیان کیا کہ مجھ سے یونس نے بیان کیا ‘ کہا کہ مجھے نافع نے خبر دی اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم اپنی سواری پر فتح مکہ کے دن مکہ کے بالائی علاقہ کی طرف سے شہر میں داخل ہوئے۔ اسامہ بن زید رضی اللہ عنہما آپ کی سواری پر آپ صلی اللہ علیہ وسلم کے پیچھے بیٹھے ہوئے تھے۔ آپ کے ساتھ بلال رضی اللہ عنہ اور کعبہ کے حاجب عثمان بن طلحہ رضی اللہ عنہ بھی تھے۔ آخر اپنے اونٹ کو آپ نے مسجد ( کے قریب باہر ) بٹھایا اور بیت اللہ کی کنجی لانے کا حکم دیا پھر آپ بیت اللہ کے اندر تشریف لے گئے۔ آپ کے ساتھ اسامہ بن زید ‘ بلال اور عثمان بن طلحہ رضی اللہ عنہم بھی تھے۔ آپ اندر کافی دیر تک ٹھہرے ‘ جب باہر تشریف لائے تو لوگ جلدی سے آگے بڑھے۔ عبداللہ بن عمر رضی اللہ عنہما سب سے پہلے اندر جانے والوں میں تھے۔ انہوں نے بیت اللہ کے دروازے کے پیچھے بلال رضی اللہ عنہ کو کھڑے ہوئے دیکھا اور ان سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم نے کہاں نماز پڑھی تھی۔ انہوں نے وہ جگہ بتلائی جہاں آپ صلی اللہ علیہ وسلم نے نماز پڑھی تھی۔ عبداللہ بن عمر رضی اللہ عنہما نے کہا کہ میں یہ پوچھنا بھول گیا کہ نبی کریم صلی اللہ علیہ وسلم نے نماز میں کتنی رکعتیں پڑھی تھیں۔' WHERE id = 4107;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا ‘ کہا ہم سے ابوشہاب نے بیان کیا ‘ ان سے عاصم نے ‘ ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ سفر میں ( فتح مکہ کے بعد ) انیس دن تک تو نماز قصر پڑھتے تھے ‘ لیکن جب اس سے زیادہ مدت گزر جاتی تو پھر پوری نماز پڑھتے تھے۔' WHERE id = 4117;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے ابوعاصم نبیل نے بیان کیا، ان سے ابن جریج نے بیان کیا، کہا مجھ کو حسن بن مسلم نے خبر دی اور انہیں مجاہد نے کہ رسول اللہ صلی اللہ علیہ وسلم فتح مکہ کے دن خطبہ سنانے کھڑے ہوئے اور فرمایا ”جس دن اللہ تعالیٰ نے آسمان و زمین کو پیدا کیا تھا، اسی دن اس نے مکہ کو حرمت والا شہر قرار دے دیا تھا۔ پس یہ شہر اللہ کے حکم کے مطابق قیامت تک کے لیے حرمت والا رہے گا۔ جو مجھ سے پہلے کبھی کسی کے لیے حلال نہیں ہوا اور نہ میرے بعد کسی کے لیے حلال ہو گا اور میرے لیے بھی صرف ایک گھڑی کے لیے حلال ہوا تھا۔ یہاں حدود حرم میں شکار کے قابل جانور نہ چھیڑے جائیں۔ یہاں کے کانٹے دار درخت نہ کاٹے جائیں نہ یہاں کی گھاس اکھاڑی جائے اور یہاں پر گری پڑی چیز اس شخص کے سوا جو اعلان کرنے کا ارادہ رکھتا ہو اور کسی کے لیے اٹھانی جائز نہیں۔“ اس پر عباس بن عبدالمطلب رضی اللہ نے کہا: یا رسول اللہ! اذخر ( گھاس ) کی اجازت دے دیجئیے کیونکہ سناروں کے لیے اور مکانات ( کی تعمیر وغیرہ ) کے لیے یہ ضروری ہے۔ آپ صلی اللہ علیہ وسلم خاموش ہو گئے پھر فرمایا ”اذخر اس حکم سے الگ ہے اس کا ( کاٹنا ) حلال ہے۔“ دوسری روایت ابن جریج سے ( اسی سند سے ) ایسی ہی ہے انہوں نے عبدالکریم بن مالک سے، انہوں نے ابن عباس سے اور ابوہریرہ رضی اللہ عنہ نے بھی نبی کریم صلی اللہ علیہ وسلم سے ایسے ہی روایت کی ہے۔' WHERE id = 4129;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے عمرو بن دینار نے، ان سے ابو العباس نابینا شاعر نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے، انہوں نے بیان کیا کہ جب رسول اللہ صلی اللہ علیہ وسلم نے طائف کا محاصرہ کیا تو دشمن کا کچھ بھی نقصان نہیں کیا۔ آخر آپ نے فرمایا کہ اب ان شاءاللہ ہم واپس ہو جائیں گے۔ مسلمانوں کے لیے ناکام لوٹنا بڑا شاق گزرا۔ انہوں نے کہا کہ واہ بغیر فتح کے ہم واپس چلے جائیں ( راوی نے ) ایک مرتبہ «نذهب» کے بجائے «نقفل» کا لفظ استعمال کیا یعنی ہم۔۔۔ لوٹ جائیں اور طائف کو فتح نہ کریں ( یہ کیونکر ہو سکتا ہے ) اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر صبح سویرے میدان میں جنگ کے لیے آ جاؤ۔ پس وہ صحابہ سویرے ہی آ گئے لیکن ان کی بڑی تعداد زخمی ہو گئی۔ اب پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان شاءاللہ ہم کل واپس چلیں گے۔ صحابہ نے اسے بہت پسند کیا۔ آپ صلی اللہ علیہ وسلم اس پر ہنس پڑے۔ اور سفیان نے ایک مرتبہ بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مسکرا دئیے۔ حمیدی نے کہا کہ ہم سے سفیان نے یہ پوری خبر بیان کی۔' WHERE id = 4140;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے معاذ نے بیان کیا، کہا ہم سے عبداللہ بن عون نے، ان سے ہشام بن زید بن انس بن مالک نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب حنین کا دن ہوا تو قبیلہ ہوازن اور غطفان اپنے مویشی اور بال بچوں کو ساتھ لے کر جنگ کے لیے نکلے۔ اس وقت نبی کریم صلی اللہ علیہ وسلم کے ساتھ دس ہزار کا لشکر تھا۔ ان میں کچھ لوگ وہ بھی تھے، جنہیں نبی کریم صلی اللہ علیہ وسلم نے فتح مکہ کے بعد احسان رکھ کر چھوڑ دیا تھا، پھر ان سب نے پیٹھ پھیر لی اور نبی کریم صلی اللہ علیہ وسلم تنہا رہ گئے۔ اس دن آپ صلی اللہ علیہ وسلم نے دو مرتبہ پکارا دونوں پکار ایک دوسرے سے الگ الگ تھیں، آپ صلی اللہ علیہ وسلم نے دائیں طرف متوجہ ہو کر پکارا: اے انصاریو! انہوں نے جواب دیا ہم حاضر ہیں: یا رسول اللہ! آپ کو بشارت ہو، ہم آپ کے ساتھ ہیں، لڑنے کو تیار ہیں۔ پھر آپ بائیں طرف متوجہ ہوئے اور آواز دی، اے انصاریو! انہوں نے ادھر سے جواب دیا کہ ہم حاضر ہیں، یا رسول اللہ! بشارت ہو، ہم آپ کے ساتھ ہیں۔ آپ صلی اللہ علیہ وسلم اس وقت ایک سفید خچر پر سوار تھے پھر آپ اتر گئے اور فرمایا کہ میں اللہ کا بندہ اور اس کا رسول ہوں۔ انجام کار کافروں کو ہار ہوئی اور اس لڑائی میں بہت زیادہ غنیمت حاصل ہوئی۔ آپ صلی اللہ علیہ وسلم نے اسے مہاجرین میں اور قریشیوں میں تقسیم کر دیا ( جنہیں فتح مکہ کے موقع پر احسان رکھ کر چھوڑ دیا تھا ) انصار کو ان میں سے کچھ نہیں عطا فرمایا۔ انصار ( کے بعض نوجوانوں ) نے کہا کہ جب سخت وقت آتا ہے تو ہمیں بلایا جاتا ہے اور غنیمت دوسروں کو تقسیم کر دی جاتی ہے۔ یہ بات نبی کریم صلی اللہ علیہ وسلم تک پہنچی تو آپ نے انصار کو ایک خیمہ میں جمع کیا اور فرمایا اے انصاریو! کیا وہ بات صحیح ہے جو تمہارے بارے میں مجھے معلوم ہوئی ہے؟ اس پر وہ خاموش ہو گئے پھر آپ صلی اللہ علیہ وسلم نے فرمایا: اے انصاریو! کیا تم اس پر خوش نہیں ہو کہ لوگ دنیا اپنے ساتھ لے جائیں اور تم رسول اللہ کو اپنے گھر لے جاؤ۔ انصاریوں نے عرض کیا ہم اسی پر خوش ہیں۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر لوگ کسی وادی میں چلیں اور انصار کسی گھاٹی میں چلیں تو میں انصار ہی کی گھاٹی میں چلنا پسند کروں گا۔ اس پر ہشام نے پوچھا: اے ابوحمزہ! کیا آپ وہاں موجود تھے؟ انہوں نے کہا کہ میں آپ صلی اللہ علیہ وسلم سے غائب ہی کب ہوتا تھا۔' WHERE id = 4151;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے بیان کیا، ان سے عمارہ بن قعقاع بن شبرمہ نے بیان کیا، ان سے عبدالرحمٰن بن ابی نعیم نے بیان کیا، کہا کہ میں نے ابو سعید خدری رضی اللہ عنہ سے سنا وہ کہتے تھے کہ یمن سے علی بن ابی طالب رضی اللہ عنہ نے رسول اللہ صلی اللہ علیہ وسلم کے پاس بیری کے پتوں سے دباغت دئیے ہوئے چمڑے کے ایک تھیلے میں سونے کے چند ڈلے بھیجے۔ ان سے ( کان کی ) مٹی بھی ابھی صاف نہیں کی گئی تھی۔ راوی نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے وہ سونا چار آدمیوں میں تقسیم کر دیا۔ عیینہ بن بدر، اقرع بن حابس، زید بن خیل اور چوتھے علقمہ رضی اللہ عنہم تھے یا عامر بن طفیل رضی اللہ عنہ تھے۔ آپ کے اصحاب میں سے ایک صاحب نے اس پر کہا کہ ان لوگوں سے زیادہ ہم اس سونے کے مستحق تھے۔ راوی نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کو معلوم ہوا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ تم مجھ پر اعتبار نہیں کرتے حالانکہ اس اللہ نے مجھ پر اعتبار کیا ہے جو آسمان پر ہے اور اس کی جو آسمان پر ہے وحی میرے پاس صبح و شام آتی ہے۔ راوی نے بیان کیا کہ پھر ایک شخص جس کی آنکھیں دھنسی ہوئی تھیں، دونوں رخسار پھولے ہوئے تھے، پیشانی بھی ابھری ہوئی تھی، گھنی داڑھی اور سر منڈا ہوا، تہبند اٹھائے ہوئے تھا، کھڑا ہوا اور کہنے لگا: یا رسول اللہ! اللہ سے ڈرئیے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ افسوس تجھ پر، کیا میں اس روئے زمین پر اللہ سے ڈرنے کا سب سے زیادہ مستحق نہیں ہوں؟ راوی نے بیان کیا پھر وہ شخص چلا گیا۔ خالد بن ولید رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میں کیوں نہ اس شخص کی گردن مار دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں شاید وہ نماز پڑھتا ہو اس پر خالد رضی اللہ عنہ نے عرض کیا کہ بہت سے نماز پڑھنے والے ایسے ہیں جو زبان سے اسلام کا دعویٰ کرتے ہیں اور ان کے دل میں وہ نہیں ہوتا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کا حکم نہیں ہوا ہے کہ لوگوں کے دلوں کی کھوج لگاؤں اور نہ اس کا حکم ہوا کہ ان کے پیٹ چاک کروں۔ راوی نے کہا پھر نبی کریم صلی اللہ علیہ وسلم نے اس ( منافق ) کی طرف دیکھا تو وہ پیٹھ پھیر کر جا رہا تھا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی نسل سے ایک ایسی قوم نکلے گی جو کتاب اللہ کی تلاوت بڑی خوش الحانی کے ساتھ کرے گی لیکن وہ ان کے حلق سے نیچے نہیں اترے گا۔ دین سے وہ لوگ اس طرح نکل چکے ہوں گے جیسے تیر جانور کے پار نکل جاتا ہے اور میرا خیال ہے کہ آپ صلی اللہ علیہ وسلم نے یہ بھی فرمایا کہ اگر میں ان کے دور میں ہوا تو ثمود کی قوم کی طرح ان کو بالکل قتل کر ڈالوں گا۔' WHERE id = 4163;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن داؤد ابوالربیع نے بیان کیا، کہا ہم سے فلیح بن سلیمان نے بیان کیا کہ ان سے زہری نے، ان سے حمید بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے ابوبکر رضی اللہ عنہ کو حجۃ الوداع سے پہلے جس حج کا امیر بنا کر بھیجا تھا، اس میں ابوبکر رضی اللہ عنہ نے مجھے کئی آدمیوں کے ساتھ قربانی کے دن ( منیٰ ) میں اعلان کرنے کے لیے بھیجا تھا کہ اس سال کے بعد کوئی مشرک ( بیت اللہ ) کا حج کرنے نہ آئے اور نہ کوئی شخص بیت اللہ کا طواف ننگے ہو کر کرے۔' WHERE id = 4174;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں عبداللہ بن ابی حسین نے، کہا ہم کو نافع بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے عہد میں مسیلمہ کذاب آیا، اس دعویٰ کے ساتھ کہ اگر محمد صلی اللہ علیہ وسلم مجھے اپنے بعد ( اپنا نائب و خلیفہ ) بنا دیں تو میں ان کی اتباع کر لوں۔ اس کے ساتھ اس کی قوم ( بنو حنیفہ ) کا بہت بڑا لشکر تھا۔ نبی کریم صلی اللہ علیہ وسلم اس کی طرف تبلیغ کے لیے تشریف لے گئے۔ آپ صلی اللہ علیہ وسلم کے ساتھ ثابت بن قیس بن شماس رضی اللہ عنہ بھی تھے۔ آپ کے ہاتھ میں کھجور کی ایک ٹہنی تھی۔ جہاں مسیلمہ اپنی فوج کے ساتھ پڑاؤ کئے ہوئے تھا، آپ وہیں جا کر ٹھہر گئے اور آپ نے اس سے فرمایا اگر تو مجھ سے یہ ٹہنی مانگے گا تو میں تجھے یہ بھی نہیں دوں گا اور تو اللہ کے اس فیصلے سے آگے نہیں بڑھ سکتا جو تیرے بارے میں پہلے ہی ہو چکا ہے۔ تو نے اگر میری اطاعت سے روگردانی کی تو اللہ تعالیٰ تجھے ہلاک کر دے گا۔ میرا تو خیال ہے کہ تو وہی ہے جو مجھے خواب میں دکھایا گیا تھا۔ اب تیری باتوں کا جواب میری طرف سے ثابت بن قیس دیں گے، پھر آپ صلی اللہ علیہ وسلم واپس تشریف لائے۔' WHERE id = 4184;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے وہب بن جریر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس بن ابی حازم نے اور ان سے ابومسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ایمان تو ادھر ہے اور آپ نے اپنے ہاتھ سے یمن کی طرف اشارہ کیا اور بےرحمی اور سخت دلی اونٹ کی دم کے پیچھے پیچھے چلانے والوں میں ہے، جدھر سے شیطان کے دونوں سینگ نکلتے ہیں ( یعنی مشرق ) قبیلہ ربیعہ اور مضر کے لوگوں میں۔' WHERE id = 4195;
UPDATE hadiths SET urdu = 'مجھ سے بیان بن عمرو نے بیان کیا، کہا ہم سے نضر بن شمیل نے بیان کیا، انہیں شعبہ نے خبر دی، ان سے قیس بن مسلم نے بیان کیا، انہوں نے طارق بن شہاب سے سنا اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا۔ اس وقت آپ صلی اللہ علیہ وسلم وادی بطحاء ( سنگریزی زمین ) میں قیام کئے ہوئے تھے۔ آپ نے پوچھا تم نے حج کا احرام باندھ لیا؟ میں نے عرض کیا کہ جی ہاں۔ دریافت فرمایا، احرام کس طرح باندھا ہے؟ عرض کیا ( اس طرح ) کہ میں بھی اسی طرح احرام باندھتا ہوں جس طرح نبی کریم صلی اللہ علیہ وسلم نے باندھا ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پہلے ( عمرہ کرنے کے لیے ) بیت اللہ کا طواف کر، پھر صفا اور مروہ کی سعی کر، پھر حلال ہو جا۔ چنانچہ میں بیت اللہ کا طواف اور صفا اور مروہ کی سعی کر کے قبیلہ قیس کی ایک عورت کے گھر آیا اور انہوں نے میرے سر سے جوئیں نکالیں۔' WHERE id = 4205;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم سے ابن شہاب نے، ان سے عامر بن سعد بن ابی وقاص رضی اللہ عنہ نے اور ان سے ان کے والد سعد رضی اللہ عنہ نے بیان کیا کہ حجۃ الوداع کے موقع پر نبی کریم صلی اللہ علیہ وسلم میری عیادت کے لیے تشریف لائے۔ بیماری نے مجھے موت کے منہ میں لا ڈالا تھا۔ میں نے عرض کیا: یا رسول اللہ! جیسا کہ آپ نے ملاحظہ فرمایا ہے، میرا مرض اس حد کو پہنچ گیا ہے اور میرے پاس مال ہے، جس کی وارث خالی میری ایک لڑکی ہے، تو کیا میں اپنا دو تہائی مال خیرات کر دوں؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ میں نے عرض کیا، آدھا کر دوں۔ فرمایا کہ نہیں۔ میں نے فرمایا کیا پھر تہائی کر دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تہائی بھی بہت ہے۔ تم اپنے وارثوں کو مالدار چھوڑ کر جاؤ تو یہ اس سے بہتر ہے کہ انہیں محتاج چھوڑو اور وہ لوگوں کے سامنے ہاتھ پھیلاتے پھریں اور تم جو کچھ بھی خرچ کرو گے، اگر اس سے اللہ کی رضا مقصود رہی تو تمہیں اس پر ثواب ملے گا۔ حتیٰ کہ اس لقمہ پر بھی تمہیں ثواب ملے گا جو تم اپنی بیوی کے منہ میں رکھو گے۔ میں نے عرض کیا: یا رسول اللہ! ( بیماری کی وجہ سے ) کیا میں اپنے ساتھیوں کے ساتھ ( مدینہ ) نہیں جا سکوں گا؟ فرمایا اگر تم نہیں جا سکے تب بھی اگر تم اللہ کی رضا جوئی کے لیے کوئی عمل کرو گے تو تمہارا درجہ اللہ کے یہاں اور بلند ہو گا اور امید ہے کہ تم ابھی زندہ رہو گے اور تم سے کچھ لوگوں ( مسلمانوں ) کو نفع پہنچے گا اور کچھ لوگوں ( اسلام کے دشمنوں ) کو نقصان پہنچے گا۔ اے اللہ! میرے ساتھیوں کی ہجرت کو کامل فرما اور انہیں پیچھے نہ ہٹا لیکن نقصان میں تو سعد بن خولہ رہے۔ نبی کریم صلی اللہ علیہ وسلم نے ان کے مکہ میں وفات پا جانے کی وجہ سے ظاہر فرمایا۔' WHERE id = 4216;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد جعفی نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سالم بن عبداللہ نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مقام حجر سے گزرے تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ ان لوگوں کی بستیوں سے جنہوں نے اپنی جانوں پر ظلم کیا تھا، جب گزرنا ہو تو روتے ہوئے ہی گزرو، ایسا نہ ہو کہ تم پر بھی وہی عذاب آ جائے جو ان پر آیا تھا۔ پھر آپ صلی اللہ علیہ وسلم نے سر مبارک پر چادر ڈال لی اور بڑی تیزی کے ساتھ چلنے لگے، یہاں تک کہ اس وادی سے نکل آئے۔' WHERE id = 4226;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عبیداللہ بن عبداللہ نے، ان سے عبداللہ بن عباس رضی اللہ عنہما نے اور ان سے ام فضل بنت حارث رضی اللہ عنہا نے بیان کیا کہ میں نے سنا رسول اللہ صلی اللہ علیہ وسلم مغرب کی نماز میں «والمرسلات عرفا‏» کی قرآت کر رہے تھے، اس کے بعد پھر آپ نے ہمیں کبھی نماز نہیں پڑھائی، یہاں تک کہ اللہ تعالیٰ نے آپ کی روح قبض کر لی۔' WHERE id = 4236;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، کہا ہم سے ابوعوانہ وضاح یشکری نے بیان کیا، ان سے ہلال بن ابی حمید وزان نے، ان سے عروہ بن زبیر نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے اپنے مرض الموت میں فرمایا کہ اللہ تعالیٰ نے یہودیوں کو اپنی رحمت سے دور کر دیا کہ انہوں نے اپنے انبیاء کی قبروں کو سجدہ گاہ بنا لیا تھا۔ عائشہ رضی اللہ عنہا نے کہا کہ اگر یہ بات نہ ہوتی تو آپ صلی اللہ علیہ وسلم کی قبر بھی کھلی رکھی جاتی لیکن آپ کو یہ خطرہ تھا کہ کہیں آپ کی قبر کو بھی سجدہ نہ کیا جانے لگے۔' WHERE id = 4247;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم کو ازہر بن سعد سمان نے خبر دی، کہا ہم کو عبداللہ بن عون نے خبر دی، انہیں ابراہیم نخعی نے اور ان سے اسود بن یزید نے بیان کیا کہ عائشہ رضی اللہ عنہا کے سامنے اس کا ذکر آیا کہ نبی کریم صلی اللہ علیہ وسلم نے علی رضی اللہ عنہ کو کوئی ( خاص ) وصیت کی تھی؟ تو انہوں نے بتلایا کون کہتا ہے، میں خود نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھی، آپ میرے سینے سے ٹیک لگائے ہوئے تھے، آپ نے طشت منگوایا، پھر ایک طرف جھک گئے اور آپ کی وفات ہو گئی۔ اس وقت مجھے بھی کچھ معلوم نہیں ہوا، پھر علی رضی اللہ عنہ کو آپ نے کب وصی بنا دیا۔' WHERE id = 4260;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن رجاء نے بیان کیا، انہوں نے بیان کیا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے بیان کیا کہ میں نے زید بن ارقم رضی اللہ عنہ سے پوچھا کہ نبی کریم صلی اللہ علیہ وسلم کے ساتھ تم نے کتنے غزوے کئے تھے؟ انہوں نے بتایا کہ سترہ۔ میں نے پوچھا اور نبی کریم صلی اللہ علیہ وسلم نے کتنے غزوے کئے تھے؟ فرمایا کہ انیس۔' WHERE id = 4271;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے حبیب نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ عمر رضی اللہ عنہ نے فرمایا، ہم میں سب سے بہتر قاری قرآن ابی بن کعب رضی اللہ عنہ ہیں اور ہم میں سب سے زیادہ علی رضی اللہ عنہ میں قضاء یعنی فیصلے کرنے کی صلاحیت ہے۔ اس کے باوجود ہم ابی رضی اللہ عنہ کی اس بات کو تسلیم نہیں کرتے جو ابی رضی اللہ عنہ کہتے ہیں کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے جن آیات کی بھی تلاوت سنی ہے، میں انہیں نہیں چھوڑ سکتا۔ حالانکہ اللہ تعالیٰ نے خود فرمایا ہے «ما ننسخ من آية أو ننسأها‏» الخ کہ ”ہم نے جو آیت بھی منسوخ کی یا اسے بھلایا تو پھر اس سے اچھی آیت لائے۔“' WHERE id = 4281;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، انہوں نے کہا ہم سے امام مالک نے بیان کیا، ان سے عبداللہ بن دینار نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ لوگ مسجد قباء میں صبح کی نماز پڑھ رہے تھے کہ ایک صاحب ( مدینہ سے ) آئے اور کہا کہ رات رسول اللہ صلی اللہ علیہ وسلم پر قرآن نازل ہوا ہے اور آپ کو حکم ہوا ہے کہ کعبہ کی طرف منہ کر لیں۔ اس لیے آپ لوگ بھی کعبہ کی طرف پھر جائیں۔ اس وقت ان کا منہ شام کی طرف تھا۔ چنانچہ سب نمازی کعبہ کی طرف پھر گئے۔' WHERE id = 4291;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے بیان کیا، انہیں نافع نے خبر دی اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ عاشوراء کے دن جاہلیت میں ہم روزہ رکھتے تھے لیکن جب رمضان کے روزے نازل ہو گئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس کا جی چاہے عاشوراء کا روزہ رکھے اور جس کا جی چاہے نہ رکھے۔' WHERE id = 4301;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا ہم سے ابوغسان محمد بن مطرف نے بیان کیا، انہوں نے کہا مجھ سے ابوحازم سلمہ بن دینار نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ ہم سے سعید بن ابی مریم نے بیان کیا، انہوں نے کہا ہم سے ابوغسان محمد بن مطرف نے بیان کیا، انہوں نے کہا مجھ سے ابوحازم سلمہ بن دینار نے بیان کیا، ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ' WHERE id = 4311;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے محمد بن منکدر نے اور انہوں نے جابر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ یہودی کہتے تھے کہ اگر عورت سے ہمبستری کے لیے کوئی پیچھے سے آئے گا تو بچہ بھینگا پیدا ہو گا۔ اس پر یہ آیت نازل ہوئی «نساؤكم حرث لكم فأتوا حرثكم أنى شئتم‏» کہ ”تمہاری بیویاں تمہاری کھیتی ہیں، سو اپنے کھیت میں آؤ جدھر سے چاہو۔“' WHERE id = 4324;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام نے خبر دی، انہیں ابن جریج نے، انہوں نے عبداللہ بن ابی ملیکہ سے سنا، وہ عبداللہ بن عباس رضی اللہ عنہما سے بیان کرتے تھے، ابن جریج نے کہا اور میں نے ابن ابی ملیکہ کے بھائی ابوبکر بن ابی ملیکہ سے بھی سنا، وہ عبید بن عمیر سے روایت کرتے تھے کہ ایک دن عمر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کے اصحاب سے دریافت کیا کہ آپ لوگ جانتے ہو یہ آیت کس سلسلے میں نازل ہوئی ہے «أيود أحدكم أن تكون له جنة‏» ”کیا تم میں سے کوئی یہ پسند کرتا ہے کہ اس کا ایک باغ ہو۔“ سب نے کہا کہ اللہ زیادہ جاننے والا ہے۔ یہ سن کر عمر رضی اللہ عنہ بہت خفا ہو گئے اور کہا، صاف جواب دیں کہ آپ لوگوں کو اس سلسلے میں کچھ معلوم ہے یا نہیں۔ ابن عباس رضی اللہ عنہما نے عرض کیا: امیرالمؤمنین! میرے دل میں ایک بات آتی ہے۔ عمر رضی اللہ عنہ نے فرمایا: بیٹے! تمہیں کہو اور اپنے کو حقیر نہ سمجھو۔ ابن عباس رضی اللہ عنہما نے عرض کیا کہ اس میں عمل کی مثال بیان کی گئی ہے۔ عمر رضی اللہ عنہ نے پوچھا، کیسے عمل کی؟ ابن عباس رضی اللہ عنہما نے عرض کیا کہ عمل کی۔ عمر رضی اللہ عنہ نے کہا کہ یہ ایک مالدار شخص کی مثال ہے جو اللہ کی اطاعت میں نیک عمل کرتا رہتا ہے۔ پھر اللہ شیطان کو اس پر غالب کر دیتا ہے، وہ گناہوں میں مصروف ہو جاتا ہے اور اس کے اگلے نیک اعمال سب غارت ہو جاتے ہیں۔' WHERE id = 4334;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں سعید بن مسیب نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ہر بچہ جب پیدا ہوتا ہے تو شیطان اسے پیدا ہوتے ہی چھوتا ہے، جس سے وہ بچہ چلاتا ہے، سوا مریم اور ان کے بیٹے ( عیسیٰ علیہ السلام ) کے۔ پھر ابوہریرہ رضی اللہ عنہ نے کہا کہ اگر تمہارا جی چاہے تو یہ آیت پڑھ لو «وإني أعيذها بك وذريتها من الشيطان الرجيم» یہ کلمہ مریم علیہ السلام کی ماں نے کہا تھا، اللہ نے ان کی دعا قبول کی اور مریم اور عیسیٰ علیہما السلام کو شیطان کے ہاتھ لگانے سے بچا لیا۔' WHERE id = 4344;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم سے ابن شہاب نے بیان کیا، ان سے سعید بن مسیب اور ابوسلمہ بن عبدالرحمٰن نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم جب کسی پر بددعا کرنا چاہتے یا کسی کے لیے دعا کرنا چاہتے تو رکوع کے بعد کرتے «سمع الله لمن حمده،‏‏‏‏ اللهم ربنا لك الحمد» کے بعد۔ بعض اوقات آپ صلی اللہ علیہ وسلم نے یہ دعا بھی کی ”اے اللہ! ولید بن ولید، سلمہ بن ہشام اور عیاش بن ابی ربیعہ کو نجات دے، اے اللہ! مضر والوں کو سختی کے ساتھ پکڑ لے اور ان میں ایسی قحط سالی لا، جیسی یوسف علیہ السلام کے زمانے میں ہوئی تھی۔“ آپ صلی اللہ علیہ وسلم بلند آواز سے یہ دعا کرتے اور آپ نماز فجر کی بعض رکعت میں یہ دعا کرتے۔ اے اللہ، فلاں اور فلاں کو اپنی رحمت سے دور کر دے۔ عرب کے چند خاص قبائل کے حق میں آپ ( یہ بددعا کرتے تھے ) یہاں تک کہ اللہ تعالیٰ نے آیت نازل کی «ليس لك من الأمر شىء‏» کہ ”آپ کو اس امر میں کوئی دخل نہیں۔“' WHERE id = 4355;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے عبدالرحمٰن بن مہدی نے بیان کیا، ان سے امام مالک بن انس نے، ان سے مخرمہ بن سلیمان نے، ان سے کریب نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ میں ایک رات اپنی خالہ میمونہ رضی اللہ عنہا کے یہاں سو گیا، ارادہ یہ تھا کہ آج رسول اللہ صلی اللہ علیہ وسلم کی نماز دیکھوں گا۔ میری خالہ نے آپ کے لیے گدا بچھا دیا اور آپ صلی اللہ علیہ وسلم اس کے طول میں لیٹ گئے پھر ( جب آخری رات میں بیدار ہوئے تو ) چہرہ مبارک پر ہاتھ پھیر کر نیند کے آثار دور کئے۔ پھر سورۃ آل عمران کی آخری دس آیات پڑھیں، اس کے بعد آپ ایک مشکیزے کے پاس آئے اور اس سے پانی لے کر وضو کیا اور نماز پڑھنے کے لیے کھڑے ہو گئے۔ میں بھی کھڑا ہو گیا اور جو کچھ آپ نے کیا تھا وہی سب کچھ میں نے بھی کیا اور آپ کے پاس آ کر آپ کے بازو میں میں بھی کھڑا ہو گیا۔ آپ صلی اللہ علیہ وسلم نے میرے سر پر اپنا دایاں ہاتھ رکھا اور میرے کان کو ( شفقت سے ) پکڑ کر ملنے لگے۔ پھر آپ صلی اللہ علیہ وسلم نے دو رکعت تہجد کی نماز پڑھی، پھر دو رکعت نماز پڑھی، پھر دو رکعت نماز پڑھی، پھر دو رکعت نماز پڑھی، پھر دو رکعت نماز پڑھی، پھر دو رکعت نماز پڑھی، پھر وتر کی نماز پڑھی۔' WHERE id = 4365;
UPDATE hadiths SET urdu = 'ہم سے صلت بن محمد نے بیان کیا، انہوں نے کہا ہم سے ابواسامہ نے بیان کیا، ان سے ادریس نے، ان سے طلحہ بن مصرف نے، ان سے سعید بن جبیر نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ( آیت میں ) «ولكل جعلنا موالي‏» سے مراد وارث ہیں اور «والذين عاقدت أيمانكم‏» کی تفسیر یہ ہے کہ شروع میں جب مہاجرین مدینہ آئے تو قرابت داروں کے علاوہ انصار کے وارث مہاجرین بھی ہوتے تھے۔ اس بھائی چارہ کی وجہ سے جو نبی کریم صلی اللہ علیہ وسلم نے مہاجرین اور انصار کے درمیان کرایا تھا، پھر جب یہ آیت نازل ہوئی کہ «ولكل جعلنا موالي‏» تو پہلا طریقہ منسوخ ہو گیا پھر بیان کیا کہ «والذين عاقدت أيمانكم‏» سے وہ لوگ مراد ہیں، جن سے دوستی اور مدد اور خیر خواہی کی قسم کھا کر عہد کیا جائے۔ لیکن اب ان کے لیے میراث کا حکم منسوخ ہو گیا مگر وصیت کا حکم رہ گیا۔ اس اسناد میں ابواسامہ نے ادریس سے اور ادریس نے طلحہ بن مصرف سے سنا ہے۔' WHERE id = 4375;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے مغیرہ بن نعمان نے بیان کیا، کہا میں نے سعید بن جبیر سے سنا، انہوں نے بیان کیا کہ علماء کوفہ کا اس آیت کے بارے میں اختلاف ہو گیا تھا۔ چنانچہ میں ابن عباس رضی اللہ عنہما کی خدمت میں اس کے لیے سفر کر کے گیا اور ان سے اس کے متعلق پوچھا۔ انہوں نے فرمایا کہ یہ آیت «ومن يقتل مؤمنا متعمدا فجزاؤه جهنم‏» ”اور جو کوئی مسلمان کو جان بوجھ کر قتل کرے اس کی سزا دوزخ ہے۔“ نازل ہوئی اور اس باب کی یہ سب سے آخری آیت ہے اسے کسی آیت نے منسوخ نہیں کیا ہے۔' WHERE id = 4385;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، کہا ہم سے ابواسامہ حماد بن اسامہ نے بیان کیا، کہا ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے آیت «ويستفتونك في النساء قل الله يفتيكم فيهن‏» ”لوگ آپ سے عورتوں کے بارے میں فتویٰ مانگتے ہیں۔ آپ کہہ دیں کہ اللہ تمہیں ان کے بارے میں ( وہی ) فتویٰ دیتا ہے“ آیت «وترغبون أن تنكحوهن‏» تک۔ انہوں نے بیان کیا کہ یہ آیت ایسے شخص کے بارے میں نازل ہوئی کہ اگر اس کی پرورش میں کوئی یتیم لڑکی ہو اور وہ اس کا ولی اور وارث بھی ہو اور لڑکی اس کے مال میں بھی حصہ دار ہو۔ یہاں تک کہ کھجور کے درخت میں بھی۔ اب وہ شخص خود اس لڑکی سے نکاح کرنا چاہے، کیونکہ اسے یہ پسند نہیں کہ کسی دوسرے سے اس کا نکاح کر دے کہ وہ اس کے اس مال میں حصہ دار بن جائے، جس میں لڑکی حصہ دار تھی، اس وجہ سے اس لڑکی کا کسی دوسرے شخص سے نکاح نہ ہونے دے تو ایسے شخص کے بارے میں یہ آیت نازل ہوئی تھی۔' WHERE id = 4395;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے محمد بن عبداللہ انصاری نے بیان کیا، کہا ہم سے عبداللہ بن عون نے بیان کیا، کہا کہ مجھ سے سلمان ابورجاء، ابوقلابہ کے غلام نے بیان کیا اور ان سے ابوقلابہ نے کہ وہ ( امیرالمؤمنین ) عمر بن عبدالعزیز رحمہ اللہ خلیفہ کے پیچھے بیٹھے ہوئے تھے ( مجلس میں قسامت کا ذکر آ گیا ) لوگوں نے کہا کہ قسامت میں قصاص لازم ہو گا۔ آپ سے پہلے خلفاء راشدین نے بھی اس میں قصاص لیا ہے۔ پھر عمر بن عبدالعزیز رحمہ اللہ ابوقلابہ کی طرف متوجہ ہوئے وہ پیچھے بیٹھے ہوئے تھے اور پوچھا: عبداللہ بن زید تمہاری کیا رائے ہے، یا یوں کہا کہ ابوقلابہ! آپ کی کیا رائے ہے؟ میں نے کہا کہ مجھے تو کوئی ایسی صورت معلوم نہیں ہے کہ اسلام میں کسی شخص کا قتل جائز ہو، سوا اس کے کہ کسی نے شادی شدہ ہونے کے باوجود زنا کیا ہو، یا ناحق کسی کو قتل کیا ہو، یا ( پھر ) اللہ اور اس کے رسول سے لڑا ہو ( مرتد ہو گیا ہو ) ۔ اس پر عنبسہ نے کہا کہ ہم سے انس رضی اللہ عنہ نے اس طرح حدیث بیان کی تھی۔ ابوقلابہ بولے کہ مجھ سے بھی انہوں نے یہ حدیث بیان کی تھی۔ بیان کیا کہ کچھ لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور اسلام پر بیعت کرنے کے بعد نبی کریم صلی اللہ علیہ وسلم سے کہا کہ ہمیں اس شہر مدینہ کی آب و ہوا موافق نہیں آئی۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ ہمارے یہ اونٹ چرنے جا رہے ہیں تم بھی ان کے ساتھ چلے جاؤ اور ان کا دودھ اور پیشاب پیو ( کیونکہ ان کے مرض کا یہی علاج تھا ) چنانچہ وہ لوگ ان اونٹوں کے ساتھ چلے گئے اور ان کا دودھ اور پیشاب پیا۔ جس سے انہیں صحت حاصل ہو گئی۔ اس کے بعد انہوں نے ( نبی کریم صلی اللہ علیہ وسلم کے چرواہے ) کو پکڑ کر قتل کر دیا اور اونٹ لے کر بھاگے۔ اب ایسے لوگوں سے بدلہ لینے میں کیا تامل ہو سکتا تھا۔ انہوں نے ایک شخص کو قتل کیا اور اللہ اور اس کے رسول سے لڑے اور نبی کریم صلی اللہ علیہ وسلم کو خوفزدہ کرنا چاہا۔ عنبسہ نے اس پر کہا: سبحان اللہ! میں نے کہا، کیا تم مجھے جھٹلانا چاہتے ہو؟ انہوں نے کہا کہ ( نہیں ) یہی حدیث انس رضی اللہ عنہ نے مجھ سے بھی بیان کی تھی۔ میں نے اس پر تعجب کیا کہ تم کو حدیث خوب یاد رہتی ہے۔ ابوقلابہ نے بیان کیا کہ عنبسہ نے کہا، اے شام والو! جب تک تمہارے یہاں ابوقلابہ یا ان جیسے عالم موجود رہیں گے، تم ہمیشہ اچھے رہو گے۔' WHERE id = 4405;
UPDATE hadiths SET urdu = 'ہم سے ابوالنعمان نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، کہا ہم سے ثابت نے، ان سے انس بن مالک نے کہ ( حرمت نازل ہونے کے بعد ) جو شراب بہائی گئی تھی وہ «فضيخ‏.‏» کی تھی۔ امام بخاری رحمہ اللہ نے بیان کیا کہ مجھ سے محمد نے ابوالنعمان سے اس زیادتی کے ساتھ بیان کیا کہ انس رضی اللہ عنہ نے کہا: میں صحابہ کی ایک جماعت کو ابوطلحہ رضی اللہ عنہ کے گھر شراب پلا رہا تھا کہ شراب کی حرمت نازل ہوئی۔ نبی کریم صلی اللہ علیہ وسلم نے منادی کو حکم دیا اور انہوں نے اعلان کرنا شروع کیا۔ ابوطلحہ رضی اللہ عنہ نے کہا: باہر جا کے دیکھو یہ آواز کیسی ہے۔ بیان کیا کہ میں باہر آیا اور کہا کہ ایک منادی اعلان کر رہا ہے کہ ”خبردار ہو جاؤ، شراب حرام ہو گئی ہے۔“ یہ سنتے ہی انہوں نے مجھ کو کہا کہ جاؤ اور شراب بہا دو۔ راوی نے بیان کیا، مدینہ کی گلیوں میں شراب بہنے لگی۔ راوی نے بیان کیا کہ ان دنوں «فضيخ‏.‏» شراب استعمال ہوتی تھی۔ بعض لوگوں نے شراب کو جو اس طرح بہتے دیکھا تو کہنے لگے معلوم ہوتا ہے کہ کچھ لوگوں نے شراب سے اپنا پیٹ بھر رکھا تھا اور اسی حالت میں انہیں قتل کر دیا گیا ہے۔ بیان کیا کہ پھر اللہ تعالیٰ نے یہ آیت نازل کی «ليس على الذين آمنوا وعملوا الصالحات جناح فيما طعموا‏» ”جو لوگ ایمان رکھتے ہیں اور نیک کام کرتے رہتے ہیں، ان پر اس چیز میں کوئی گناہ نہیں جس کو انہوں نے کھا لیا۔“' WHERE id = 4415;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے ابن مہدی نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے ابوالعالیہ نے بیان کیا کہ مجھ سے تمہارے نبی کے چچا زاد بھائی یعنی ابن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کسی کے لیے مناسب نہیں کہ مجھے یونس بن متی علیہ السلام سے بہتر بتائے۔' WHERE id = 4425;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ نے بیان کیا، انہوں نے کہا ہم سے سلیمان بن عبدالرحمٰن اور موسیٰ بن ہارون نے بیان کیا، انہوں نے کہا کہ ہم سے ولید بن مسلم نے بیان کیا، کہا ہم سے عبداللہ بن علاء بن زبیر نے بیان کیا، کہا کہ مجھ سے بسر بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابوادریس خولانی نے بیان کیا، کہا کہ میں نے ابودرداء رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ابوبکر اور عمر رضی اللہ عنہما کے درمیان کچھ بحث سی ہو گئی تھی۔ عمر رضی اللہ عنہ ابوبکر رضی اللہ عنہ پر غصہ ہو گئے اور ان کے پاس سے آنے لگے۔ ابوبکر رضی اللہ عنہ بھی ان کے پیچھے پیچھے ہو گئے، معافی مانگتے ہوئے۔ لیکن عمر رضی اللہ عنہ نے انہیں معاف نہیں کیا اور ( گھر پہنچ کر ) اندر سے دروازہ بند کر لیا۔ اب ابوبکر رضی اللہ عنہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے۔ ابودرداء رضی اللہ عنہ نے بیان کیا کہ ہم لوگ اس وقت نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے یہ صاحب ( یعنی ابوبکر رضی اللہ عنہ ) لڑ آئے ہیں۔ راوی نے بیان کیا کہ عمر رضی اللہ عنہ بھی اپنے طرز عمل پر نادم ہوئے اور نبی کریم صلی اللہ علیہ وسلم کی طرف چلے اور سلام کر کے آپ صلی اللہ علیہ وسلم کے قریب بیٹھ گئے۔ پھر نبی کریم صلی اللہ علیہ وسلم سے سارا واقعہ بیان کیا۔ ابودرداء رضی اللہ عنہ نے بیان کیا کہ آپ بہت ناراض ہوئے۔ ادھر ابوبکر رضی اللہ عنہ باربار یہ عرض کرتے کہ یا رسول اللہ! واقعی میری ہی زیادتی تھی۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم لوگ مجھے میرے ساتھی سے جدا کرنا چاہتے ہو؟ کیا تم لوگ میرے ساتھی کو مجھ سے جدا کرنا چاہتے ہو؟ جب میں نے کہا تھا کہ اے انسانو! بیشک میں اللہ کا رسول ہوں، تم سب کی طرف، تو تم لوگوں نے کہا کہ تم جھوٹ بولتے ہو، اس وقت ابوبکر نے کہا تھا کہ آپ سچے ہیں۔ ابوعبداللہ نے کہا «غامر» کے معنی حدیث میں یہ ہے کہ ابوبکر رضی اللہ عنہ نے بھلائی میں سبقت کی ہے۔' WHERE id = 4435;
UPDATE hadiths SET urdu = 'ہم سے حسن بن عبدالعزیز نے بیان کیا، کہا ہم سے عبداللہ بن یحییٰ نے، کہا ہم سے حیوہ بن شریح نے، انہوں نے بکر بن عمرو سے، انہوں نے بکیر سے، انہوں نے نافع سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے کہ ایک شخص ( حبان یا علاء بن عرار نامی ) نے پوچھا: ابوعبدالرحمٰن! آپ نے قرآن کی یہ آیت نہیں سنی «وإن طائفتان من المؤمنين اقتتلوا‏» کہ ”جب مسلمانوں کی دو جماعتیں لڑنے لگیں“ الخ، اس آیت کے بموجب تم ( علی اور معاویہ رضی اللہ عنہما دونوں سے ) کیوں نہیں لڑتے جیسے اللہ نے فرمایا «فقاتلوا التي تبغيإ» ۔ انہوں نے کہا میرے بھتیجے! اگر میں اس آیت کی تاویل کر کے مسلمانوں سے نہ لڑوں تو یہ مجھ کو اچھا معلوم ہوتا ہے بہ نسبت اس کے کہ میں اس آیت «ومن يقتل مؤمنا متعمدا‏» کی تاویل کروں۔ وہ شخص کہنے لگا اچھا اس آیت کو کیا کرو گے جس میں مذکور ہے «وقاتلوهم حتى لا تكون فتنة‏» کہ ”ان سے لڑو تاکہ فتنہ باقی نہ رہے اور سارا دین اللہ کا ہو جائے۔“ عبداللہ بن عمر رضی اللہ عنہما نے کہا ( واہ، واہ ) یہ لڑائی تو ہم نبی کریم صلی اللہ علیہ وسلم کے عہد میں کر چکے، اس وقت مسلمان بہت تھوڑے تھے اور مسلمان کو اسلام اختیار کرنے پر تکلیف دی جاتی۔ قتل کرتے، قید کرتے یہاں تک کہ اسلام پھیل گیا۔ مسلمان بہت ہو گئے اب فتنہ جو اس آیت میں مذکور ہے وہ کہاں رہا۔ جب اس شخص نے دیکھا کہ عبداللہ بن عمر رضی اللہ عنہما کسی طرح لڑائی پر اس کے موافق نہیں ہوتے تو کہنے لگا اچھا بتلاؤ علی رضی اللہ عنہ اور عثمان رضی اللہ عنہ کے بارے میں تمہارا کیا اعتقاد ہے؟ انہوں نے کہا ہاں یہ کہو تو سنو، علی اور عثمان رضی اللہ عنہما کے بارے میں اپنا اعتقاد بیان کرتا ہوں۔ عثمان رضی اللہ عنہ کا جو قصور تم بیان کرتے ہو ( کہ وہ جنگ احد میں بھاگ نکلے ) تو اللہ نے ان کا یہ قصور معاف کر دیا مگر تم کو یہ معافی پسند نہیں ( جب تو اب تک ان پر قصور لگاتے جاتے ہو ) اور علی رضی اللہ عنہ تو ( سبحان اللہ ) نبی کریم صلی اللہ علیہ وسلم کے چچا زاد بھائی اور آپ داماد بھی تھے اور ہاتھ سے اشارہ کر کے بتلایا یہ ان کا گھر ہے جہاں تم دیکھ رہے ہو۔' WHERE id = 4445;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعد نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے حصین نے، ان سے زید بن وہب نے بیان کیا کہ میں مقام ربذہ میں ابوذر غفاری رضی اللہ عنہ کی خدمت میں حاضر ہوا اور عرض کیا کہ اس جنگل میں آپ نے کیوں قیام کو پسند کیا؟ فرمایا کہ ہم شام میں تھے۔ ( مجھ میں اور وہاں کے حاکم معاویہ رضی اللہ عنہ میں اختلاف ہو گیا ) میں نے یہ آیت پڑھی «والذين يكنزون الذهب والفضة ولا ينفقونها في سبيل الله فبشرهم بعذاب أليم‏» کہ ”اور جو لوگ سونا اور چاندی جمع کر کے رکھتے ہیں اور اس کو خرچ نہیں کرتے اللہ کی راہ میں، آپ انہیں ایک درد ناک عذاب کی خبر سنا دیں۔“ تو معاویہ رضی اللہ عنہ کہنے لگے کہ یہ آیت ہم مسلمانوں کے بارے میں نہیں ہے ( جب وہ زکوٰۃ دیتے رہیں ) بلکہ اہل کتاب کے بارے میں ہے۔ فرمایا کہ میں نے اس پر کہا کہ یہ ہمارے بارے میں بھی ہے اور اہل کتاب کے بارے میں بھی ہے۔' WHERE id = 4455;
UPDATE hadiths SET urdu = 'ہم سے عبید بن اسماعیل نے بیان کیا، ان سے ابواسامہ نے، ان سے عبیداللہ بن عمری نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے کہ جب عبداللہ بن ابی ( منافق ) کا انتقال ہوا تو اس کے لڑکے عبداللہ بن عبداللہ ( جو پختہ مسلمان تھے ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ آپ اپنی قمیص ان کے والد کے کفن کے لیے عنایت فرما دیں۔ نبی کریم صلی اللہ علیہ وسلم نے قمیص عنایت فرمائی۔ پھر انہوں نے عرض کی کہ آپ نماز جنازہ بھی پڑھا دیں۔ نبی کریم صلی اللہ علیہ وسلم نماز جنازہ پڑھانے کے لیے بھی آگے بڑھ گئے۔ اتنے میں عمر رضی اللہ عنہ نے آپ صلی اللہ علیہ وسلم کا دامن پکڑ لیا اور عرض کیا: یا رسول اللہ! اس کی نماز جنازہ پڑھانے جا رہے ہیں، جبکہ اللہ تعالیٰ نے آپ کو اس سے منع بھی فرما دیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اللہ تعالیٰ نے مجھے اختیار دیا ہے فرمایا ہے «استغفر لهم أو لا تستغفر لهم إن تستغفر لهم سبعين مرة‏» کہ ”آپ ان کے لیے استغفار کریں خواہ نہ کریں۔ اگر آپ ان کے لیے ستر بار بھی استغفار کریں گے ( تب بھی اللہ انہیں نہیں بخشے گا ) ۔“ اس لیے میں ستر مرتبہ سے بھی زیادہ استغفار کروں گا۔ ( ممکن ہے کہ اللہ تعالیٰ زیادہ استغفار کرنے سے معاف کر دے ) عمر رضی اللہ عنہ بولے لیکن یہ شخص تو منافق ہے۔ ابن عمر رضی اللہ عنہما نے بیان کیا کہ آخر نبی کریم صلی اللہ علیہ وسلم نے اس کی نماز جنازہ پڑھائی۔ اس کے بعد اللہ تعالیٰ نے یہ حکم نازل فرمایا «ولا تصل على أحد منهم مات أبدا ولا تقم على قبره‏» کہ ”اور ان میں سے جو کوئی مر جائے اس پر کبھی بھی نماز نہ پڑھئے اور نہ اس کی قبر پر کھڑا ہوئیے۔“' WHERE id = 4465;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، انہوں نے کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم مدینہ تشریف لائے تو یہود عاشوراء کا روزہ رکھتے تھے۔ انہوں نے بتایا کہ اسی دن موسیٰ علیہ السلام کو فرعون پر فتح ملی تھی۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے صحابہ سے فرمایا کہ موسیٰ علیہ السلام کے ہم ان سے بھی زیادہ مستحق ہیں اس لیے تم بھی روزہ رکھو۔' WHERE id = 4475;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویس نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے عبداللہ بن عمر نمیری نے بیان کیا، ان سے یونس بن یزید ایلی نے بیان کیا کہا کہ میں زہری سے سنا، انہوں نے عروہ بن زبیر، سعید بن مسیب، علقمہ بن وقاص اور عبیداللہ بن عبداللہ سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہما کے اس واقعہ کے متعلق سنا جس میں تہمت لگانے والوں نے ان پر تہمت لگائی تھی اور پھر اللہ تعالیٰ نے ان کی پاکی نازل کی۔ ان تمام لوگوں نے مجھ سے اس قصہ کا کچھ کچھ ٹکڑا بیان کیا۔ نبی کریم صلی اللہ علیہ وسلم نے ( عائشہ رضی اللہ عنہا سے ) فرمایا کہ اگر تم بَری ہو تو عنقریب اللہ تعالیٰ تمہاری پاکی نازل کر دے گا لیکن اگر تو آلودہ ہو گئی ہے تو اللہ سے مغفرت طلب کر اور اس کے حضور میں توبہ کر ( عائشہ رضی اللہ عنہا نے بیان کیا کہ ) میں نے اس پر کہا: اللہ کی قسم! میری اور آپ کی مثال یوسف علیہ السلام کے والد جیسی ہے ( اور انہیں کی کہی ہوئی بات میں بھی دہراتی ہوں کہ ) «فصبر جميل والله المستعان على ما تصفون‏» ”سو صبر کرنا ( ہی ) اچھا ہے اور تم جو کچھ بیان کرتے ہو اس پر اللہ ہی مدد کرے گا۔“ اس کے بعد اللہ تعالیٰ نے عائشہ رضی اللہ عنہا کی پاکی میں سورۃ النور کی «إن الذين جاءوا بالإفك‏» سے آخر تک دس آیات اتاریں۔' WHERE id = 4485;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن المنذر نے بیان کیا، انہوں نے کہا ہم سے معن نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک رحمہ اللہ نے بیان کیا، ان سے عبداللہ بن دینار نے بیان کیا، اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے اصحاب حجر کے متعلق فرمایا تھا کہ اس قوم کی بستی سے جب گزرنا ہی پڑ گیا ہے تو روتے ہوئے گزرو اور اگر روتے ہوئے نہیں گزر سکتے تو پھر اس میں نہ جاؤ۔ کہیں تم پر بھی وہی عذاب نہ آئے جو ان پر آیا تھا۔' WHERE id = 4497;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو ابوحیان (یحییٰ بن سعید) تیمی نے خبر دی۔ انہیں ابوزرعہ (ہرم) بن عمرو بن جریر نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں گوشت لایا گیا اور دست کا حصہ آپ کو پیش کیا گیا۔ تو آپ نے اپنے دانتوں سے اسے ایک بار نوچا اور نبی کریم صلی اللہ علیہ وسلم کو دست کا گوشت بہت پسند تھا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن میں سب لوگوں کا سردار ہوں گا تمہیں معلوم بھی ہے یہ کون سا دن ہو گا؟ اس دن دنیا کے شروع سے قیامت کے دن تک کی ساری خلقت ایک چٹیل میدان میں جمع ہو گی کہ ایک پکارنے والے کی آواز سب کے کانوں تک پہنچ سکے گی اور ایک نظر سب کو دیکھ سکے گی۔ سورج بالکل قریب ہو جائے گا اور لوگوں کی پریشانی اور بےقراری کی کوئی حد نہ رہے گی جو برداشت سے باہر ہو جائے گی۔ لوگ آپس میں کہیں گے، دیکھتے نہیں کہ ہماری کیا حالت ہو گئی ہے۔ کیا ایسا کوئی مقبول بندہ نہیں ہے جو اللہ پاک کی بارگاہ میں تمہاری شفاعت کرے؟ بعض لوگ بعض سے کہیں گے کہ آدم علیہ السلام کے پاس چلنا چاہئے۔ چنانچہ سب لوگ آدم علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے آپ انسانوں کے پردادا ہیں، اللہ تعالیٰ نے آپ کو اپنے ہاتھ سے پیدا کیا اور اپنی طرف سے خصوصیت کے ساتھ آپ میں روح پھونکی۔ فرشتوں کو حکم دیا اور انہوں نے آپ کو سجدہ کیا اس لیے آپ رب کے حضور میں ہماری شفاعت کر دیں، آپ دیکھ رہے ہیں کہ ہم کس حال کو پہنچ چکے ہیں۔ آدم علیہ السلام کہیں گے کہ میرا رب آج انتہائی غضبناک ہے۔ اس سے پہلے اتنا غضبناک وہ کبھی نہیں ہوا تھا اور نہ آج کے بعد کبھی اتنا غضب ناک ہو گا اور رب العزت نے مجھے بھی درخت سے روکا تھا لیکن میں نے اس کی نافرمانی کی، پس نفسی، نفسی، نفسی مجھ کو اپنی فکر ہے تم کسی اور کے پاس جاؤ۔ ہاں نوح علیہ السلام کے پاس جاؤ۔ چنانچہ سب لوگ نوح علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے، اے نوح! آپ سب سے پہلے پیغمبر ہیں جو اہل زمین کی طرف بھیجے گئے تھے اور آپ کو اللہ نے ”شکر گزار بندہ“ ( عبد شکور ) کا خطاب دیا۔ آپ ہی ہمارے لیے اپنے رب کے حضور میں شفاعت کر دیں، آپ دیکھ رہے ہیں کہ ہم کس حالت کو پہنچ گئے ہیں۔ نوح علیہ السلام بھی کہیں گے کہ میرا رب آج اتنا غضبناک ہے کہ اس سے پہلے کبھی اتنا غضبناک نہیں تھا اور نہ آج کے بعد کبھی اتنا غضبناک ہو گا اور مجھے ایک دعا کی قبولیت کا یقین دلایا گیا تھا جو میں نے اپنی قوم کے خلاف کر لی تھی۔ نفسی، نفسی، نفسی آج مجھ کو اپنے ہی نفس کی فکر ہے تم میرے سوا کسی اور کے پاس جاؤ، ابراہیم علیہ السلام کے پاس جاؤ۔ سب لوگ ابراہیم علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے، اے ابراہیم! آپ اللہ کے نبی اور اللہ کے خلیل ہیں روئے زمین میں منتخب، آپ ہماری شفاعت کیجئے، آپ ملاحظہ فرما رہے ہیں کہ ہم کس حالت کو پہنچ چکے ہیں۔ ابراہیم علیہ السلام بھی کہیں گے کہ آج میرا رب بہت غضبناک ہے؟ اتنا غضبناک نہ وہ پہلے ہوا تھا اور نہ آج کے بعد ہو گا اور میں نے تین جھوٹ بولے تھے ( راوی ) ابوحیان نے اپنی روایت میں تینوں کا ذکر کیا ہے۔ نفسی، نفسی، نفسی مجھ کو اپنے نفس کی فکر ہے۔ میرے سوا کسی اور کے پاس جاؤ۔ ہاں موسیٰ علیہ السلام پاس کے جاؤ۔ سب لوگ موسیٰ علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے اے موسیٰ! آپ اللہ کے رسول ہیں، اللہ تعالیٰ نے آپ کو اپنی طرف سے رسالت اور اپنے کلام کے ذریعہ فضیلت دی۔ آپ ہماری شفاعت اپنے رب کے حضور میں کریں، آپ ملاحظہ فرما سکتے ہیں کہ ہم کس حالت کو پہنچ چکے ہیں۔ موسیٰ علیہ السلام کہیں گے کہ آج اللہ تعالیٰ بہت غضبناک ہے، اتنا غضبناک کہ وہ نہ پہلے کبھی ہوا تھا اور نہ آج کے بعد کبھی ہو گا اور میں نے ایک شخص کو قتل کر دیا تھا، حالانکہ اللہ کی طرف سے مجھے اس کا کوئی حکم نہیں ملا تھا۔ نفسی، نفسی، نفسی بس مجھ کو آج اپنی فکر ہے، میرے سوا کسی اور کے پاس جاؤ۔ ہاں عیسیٰ علیہ السلام کے پاس جاؤ۔ سب لوگ عیسیٰ علیہ السلام کی خدمت میں حاضر ہوں گے اور عرض کریں گے۔ اے عیسیٰ! آپ اللہ کے رسول اور اس کا کلمہ ہیں جسے اللہ نے مریم علیھا السلام پر ڈالا تھا اور اللہ کی طرف سے روح ہیں، آپ نے بچپن میں ماں کی گود ہی میں لوگوں سے بات کی تھی، ہماری شفاعت کیجئے، آپ ملاحظہ فرما سکتے ہیں کہ ہماری کیا حالت ہو چکی ہے۔ عیسیٰ بھی کہیں گے کہ میرا رب آج اس درجہ غضبناک ہے کہ نہ اس سے پہلے کبھی اتنا غضبناک ہوا تھا اور نہ کبھی ہو گا اور آپ کسی لغزش کا ذکر نہیں کریں گے ( صرف ) اتنا کہیں گے، نفسی، نفسی، نفسی میرے سوا کسی اور کے پاس جاؤ۔ ہاں، محمد ( صلی اللہ علیہ وسلم ) کے پاس جاؤ۔ سب لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوں گے اور عرض کریں گے، اے محمد ( صلی اللہ علیہ وسلم ) ! آپ اللہ کے رسول اور سب سے آخری پیغمبر ہیں اور اللہ تعالیٰ نے آپ کے تمام اگلے پچھلے گناہ معاف کر دیئے ہیں، اپنے رب کے دربار میں ہماری شفاعت کیجئے۔ آپ خود ملاحظہ فرما سکتے ہیں کہ ہم کس حالت کو پہنچ چکے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آخر میں آگے بڑھوں گا اور عرش تلے پہنچ کر اپنے رب عزوجل کے لیے سجدہ میں گر پڑوں گا، پھر اللہ تعالیٰ مجھ پر اپنی حمد اور حسن ثناء کے دروازے کھول دے گا کہ مجھ سے پہلے کسی کو وہ طریقے اور وہ محامد نہیں بتائے تھے۔ پھر کہا جائے گا، اے محمد! اپنا سر اٹھایئے، مانگئے آپ کو دیا جائے گا۔ شفاعت کیجئے، آپ کی شفاعت قبول ہو جائے گی۔ اب میں اپنا سر اٹھاؤں گا اور عرض کروں گا۔ اے میرے رب! میری امت، اے میرے رب! میری امت پر کرم کر، کہا جائے گا اے محمد! اپنی امت کے ان لوگوں کو جن پر کوئی حساب نہیں ہے، جنت کے داہنے دروازے سے داخل کیجئے ویسے انہیں اختیار ہے، جس دروازے سے چاہیں دوسرے لوگوں کے ساتھ داخل ہو سکتے ہیں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس ذات کی قسم! جس کے ہاتھ میں میری جان ہے۔ جنت کے دروازے کے دونوں کناروں میں اتنا فاصلہ ہے جتنا مکہ اور حمیر میں ہے یا جتنا مکہ اور بصریٰ میں ہے۔' WHERE id = 4507;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہشیم بن بشیر نے بیان کیا، کہا ہم سے ابوبشر نے بیان کیا، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے اللہ تعالیٰ کے ارشاد «ولا تجهر بصلاتك ولا تخافت بها‏» ”اور آپ نماز میں نہ تو بہت پکار کر پڑھئے اور نہ ( بالکل ) چپکے ہی چپکے“ کے متعلق فرمایا کہ یہ آیت اس وقت نازل ہوئی تھی جب رسول اللہ صلی اللہ علیہ وسلم مکہ میں ( کافروں کے ڈر سے ) چھپے رہتے تو اس زمانہ میں جب آپ اپنے صحابہ کے ساتھ نماز پڑھتے تو قرآن مجید کی تلاوت بلند آواز سے کرتے، مشرکین سنتے تو قرآن کو بھی گالی دیتے اور اس کے نازل کرنے والے اور اس کے لانے والے کو بھی۔ اسی لیے اللہ تعالیٰ نے اپنے نبی سے کہا کہ آپ نماز نہ تو بہت پکار کر پڑھیں ( یعنی قرآت خوب جہر کے ساتھ نہ کریں ) کہ مشرکین سن کر گالیاں دیں اور نہ بالکل چپکے ہی چپکے کہ آپ کے صحابہ بھی نہ سن سکیں، بلکہ درمیانی آواز میں پڑھا کریں۔' WHERE id = 4517;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ (مسلم بن صبیح) نے، ان سے مسروق بن اجدع نے بیان کیا کہ میں نے خباب بن ارت رضی اللہ عنہ سے سنا، انہوں نے کہا کہ میں عاص بن وائل سہمی کے پاس اپنا حق مانگنے گیا تو وہ کہنے لگا کہ جب تک تم محمد صلی اللہ علیہ وسلم سے کفر نہیں کرو گے میں تمہیں مزدوری نہیں دوں گا۔ میں نے اس پر کہا کہ یہ کبھی نہیں کر سکتا۔ یہاں تک کہ تم مرنے کے بعد پھر زندہ کئے جاؤ۔ اس پر وہ بولا، کیا مرنے کے بعد پھر مجھے زندہ کیا جائے گا؟ میں نے کہا ہاں، ضرور، کہنے لگا کہ پھر وہاں بھی میرے پاس مال اولاد ہو گی اور میں وہیں تمہاری مزدوری بھی دے دوں گا۔ اس پر یہ آیت نازل ہوئی «أفرأيت الذي كفر بآياتنا وقال لأوتين مالا وولدا‏» کہ ”بھلا آپ نے اس شخص کو بھی دیکھا جو ہماری نشانیوں سے کفر کرتا ہے اور کہتا ہے کہ مجھے مال اور اولاد مل کر رہیں گے۔“ اس حدیث کو سفیان ثوری اور شعبہ اور حفص اور ابومعاویہ اور وکیع نے بھی اعمش سے روایت کیا ہے۔' WHERE id = 4527;
UPDATE hadiths SET urdu = 'مجھ سے ابراہیم بن حارث نے بیان کیا، کہا ہم سے یحییٰ بن ابی بکیر نے، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابوحصین نے ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے آیت «ومن الناس من يعبد الله على حرف‏» ”اور انسانوں میں کوئی ایسا بھی ہوتا ہے جو اللہ کی عبادت کنارہ پر ( کھڑا ہو کر ) کرتا ہے۔“ کے متعلق فرمایا کہ بعض لوگ مدینہ آتے ( اور اپنے اسلام کا اظہار کرتے ) اس کے بعد اگر اس کی بیوی کے یہاں لڑکا پیدا ہوتا اور گھوڑی بھی بچہ دیتی تو وہ کہتے کہ یہ دین ( اسلام ) بڑا اچھا دین ہے، لیکن اگر ان کے یہاں لڑکا نہ پیدا ہوتا اور گھوڑی بھی کوئی بچہ نہ دیتی تو کہتے کہ یہ تو برا دین ہے اس پر مذکور بالا آیت نازل ہوئی۔' WHERE id = 4537;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، انہیں ابن جریج نے خبر دی کہ ابن ابی ملیکہ نے کہا کہ میں نے ام المؤمنین عائشہ رضی اللہ عنہا سے سنا وہ مذکورہ بالا آیت «إذ تلقونه بألسنتكم‏» ( جب تم اپنی زبانوں سے اسے منہ در منہ نقل کر رہے تھے ) پڑھ رہی تھیں۔' WHERE id = 4547;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن موسیٰ نے بیان کیا، کہا ہم کو ہشام بن یوسف نے خبر دی، انہیں ابن جریج نے خبر دی، کہا کہ مجھے قاسم بن ابی بزہ نے خبر دی، انہوں نے سعید بن جبیر سے پوچھا کہ اگر کوئی شخص کسی مسلمان کو جان بوجھ کر قتل کر دے تو کیا اس کی اس گناہ سے توبہ قبول ہو سکتی ہے؟ انہوں نے کہا کہ نہیں۔ ( ابن ابی بزہ نے بیان کیا کہ ) میں نے اس پر یہ آیت پڑھی «ولا يقتلون النفس التي حرم الله إلا بالحق‏» کہ ”اور جس جان کو اللہ نے حرام قرار دیا ہے اسے قتل نہ کرتے، مگر ہاں حق کے ساتھ۔“ سعید بن جبیر نے کہا کہ میں نے بھی یہ آیت ابن عباس رضی اللہ عنہما کے سامنے پڑھی تھی تو انہوں نے کہا تھا کہ مکی آیت اور مدنی آیت جو اس سلسلہ میں سورۃ نساء میں ہے اس سے اس کا حکم منسوخ ہو گیا ہے۔' WHERE id = 4557;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے بیان کیا۔ انہیں سعید بن مسیب نے خبر دی اور ان سے ان کے والد (مسیب بن حزن) نے بیان کیا کہ جب ابوطالب کی وفات کا وقت قریب ہوا تو رسول اللہ صلی اللہ علیہ وسلم ان کے پاس آئے، ابوجہل اور عبداللہ بن ابی امیہ بن مغیرہ وہاں پہلے ہی سے موجود تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ چچا! آپ صرف کلمہ «لا إله إلا الله» پڑھ دیجئیے تاکہ اس کلمہ کے ذریعہ اللہ کی بارگاہ میں آپ کی شفاعت کروں۔ اس پر ابوجہل اور عبداللہ بن ابی امیہ بولے کیا تم عبدالمطلب کے مذہب سے پھر جاؤ گے؟ نبی کریم صلی اللہ علیہ وسلم باربار ان سے یہی کہتے رہے ( کہ آپ صرف ایک کلمہ پڑھ لیں ) اور یہ دونوں بھی اپنی بات ان کے سامنے باربار دہراتے رہے ( کہ کیا تم عبدالمطلب کے مذہب سے پھر جاؤ گے؟ ) آخر ابوطالب کی زبان سے جو آخری کلمہ نکلا وہ یہی تھا کہ وہ عبدالمطلب کے مذہب پر ہی قائم ہیں۔ انہوں نے «لا إله إلا الله» پڑھنے سے انکار کر دیا۔ راوی نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم! میں آپ کے لیے طلب مغفرت کرتا رہوں گا تاآنکہ مجھے اس سے روک نہ دیا جائے۔ پھر اللہ تعالیٰ نے یہ آیت نازل کی «ما كان للنبي والذين آمنوا أن يستغفروا للمشركين‏» ”نبی اور ایمان والوں کے لیے یہ مناسب نہیں ہے کہ وہ مشرکین کے لیے دعائے مغفرت کریں۔“ اور خاص ابوطالب کے بارے میں یہ آیت نازل ہوئی نبی کریم صلی اللہ علیہ وسلم سے کہا گیا «إنك لا تهدي من أحببت ولكن الله يهدي من يشاء‏» کہ ”جس کو تم چاہو ہدایت نہیں کر سکتے، البتہ اللہ ہدایت دیتا ہے اسے جس کے لیے وہ ہدایت چاہتا ہے۔“ ابن عباس رضی اللہ عنہما نے کہا «أولي القوة‏» سے یہ مراد ہے کہ کئی زور دار آدمی مل کر بھی اس کی کنجیاں نہیں اٹھا سکتے تھے۔ «لتنوء‏» کا مطلب ڈھوئی جاتی تھیں۔ «فارغا‏» کا معنی یہ ہے کہ موسیٰ کی ماں کے دل میں موسیٰ کے سوا اور کوئی خاص نہیں رہا تھا۔ «الفرحين‏» کا معنی خوشی سے اتراتے ہوئے۔ «قصيه‏» یعنی اس کے پیچھے پیچھے چلی جا۔ «قصص» کے معنی بیان کرنے کے ہوتے ہیں جیسے سورۃ یوسف میں فرمایا «نحن نقص عليك‏»،‏‏‏‏ «عن جنب‏» یعنی دور سے «عن جنابة» کا بھی یہی معنی ہے اور «عن اجتناب» کا بھی یہی ہے۔ «يبطش» ‏‏‏‏ بہ کسرہ طاء اور «يبطش‏.‏» بہ ضمہ طاء دونوں قرآت ہیں۔ «يأتمرون‏» مشورہ کر رہے ہیں۔ «عدوان» اور «عدو» اور «تعدي» سب کا ایک ہی مفہوم ہے یعنی حد سے بڑھ جانا ظلم کرنا۔ «آنس‏» کا معنی دیکھنا۔ «جذوة» لکڑی کا موٹا ٹکڑا جس کے سر ے پر آگ لگی ہو مگر اس میں شعلہ نہ ہو اور «شهاب» جو آیت «اواتیکم بشهاب قبس» میں ہے اس سے مراد ایسی جلتی ہوئی لکڑی جس میں شعلہ ہو۔ «حيات» یعنی سانپوں کی مختلف قسمیں ( جیسے ) جان، افعی، اسود وغیرہ «ردءا‏» یعنی مددگار، پشت پناہ۔ ابن عباس رضی اللہ عنہا نے «يصدقني‏» بہ ضمہ قاف پڑھا ہے۔ اوروں نے کہا «سنشد‏» کا معنی یہ ہے کہ ہم تیری مدد کریں گے عرب لوگ کا محاورہ ہے جب کسی کو قوت دیتے ہیں تو کہتے ہیں «جعلت له عضدا‏.‏» ۔ «مقبوحين» ‏‏‏‏ کا معنی ہلاک کئے گئے۔ «وصلنا‏» ہم نے اس کو بیان کیا اور پورا کیا۔ «يجبى‏» کچھے آتے ہیں۔ «بطرت‏» شرارت کی۔ «في أمها رسولا‏»،‏‏‏‏ «أم القرى» مکہ اور اس کے اطراف کو کہتے ہیں۔ «تكن‏» کا معنی چھپاتی ہیں۔ عرب لوگ کہتے ہیں «أكننت» ‏‏‏‏ یعنی میں نے اس کو چھپا لیا۔ «كننته» کا بھی یہی معنی ہے۔ «ويكأن الله‏» کا معنی «ألم تر أن الله» کے یعنی کیا تو نے نہیں دیکھا۔ «يبسط الرزق لمن يشاء ويقدر‏» یعنی اللہ جس کو چاہتا ہے فراغت سے روزی دیتا ہے جسے چاہتا ہے تنگی سے دیتا ہے۔' WHERE id = 4567;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، کہا ہم سے موسیٰ بن عقبہ نے بیان کیا، کہا کہ مجھ سے سالم نے بیان کیا اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے آزاد کئے ہوئے غلام زید بن حارثہ کو ہم ہمیشہ زید بن محمد کہہ کر پکارا کرتے تھے، یہاں تک کہ قرآن کریم میں آیت نازل ہوئی «ادعوهم لآبائهم هو أقسط عند الله‏» کہ ”انہیں ان کے باپوں کی طرف منسوب کرو کہ یہی اللہ کے نزدیک سچی اور ٹھیک بات ہے۔“' WHERE id = 4577;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ایوب سختیانی نے، ان سے ابوقلابہ نے کہ انس بن مالک رضی اللہ عنہ نے کہا کہ اس آیت یعنی آیت پردہ ( کے شان نزول ) کے متعلق میں سب سے زیادہ جانتا ہوں، جب زینب رضی اللہ عنہا سے رسول اللہ صلی اللہ علیہ وسلم نے نکاح کیا اور وہ آپ کے ساتھ آپ کے گھر ہی میں تھیں تو آپ صلی اللہ علیہ وسلم نے کھانا تیار کروایا اور قوم کو بلایا ( کھانے سے فارغ ہونے کے بعد ) لوگ بیٹھے باتیں کرتے رہے۔ نبی کریم صلی اللہ علیہ وسلم باہر جاتے اور پھر اندر آتے ( تاکہ لوگ اٹھ جائیں ) لیکن لوگ بیٹھے باتیں کرتے رہے۔ اس پر یہ آیت نازل ہوئی «يا أيها الذين آمنوا لا تدخلوا بيوت النبي إلا أن يؤذن لكم إلى طعام غير ناظرين إناه‏» کہ ”اے ایمان والو! نبی کے گھروں میں مت جایا کرو۔ سوائے اس وقت کے جب تمہیں ( کھانے کے لیے ) آنے کی اجازت دی جائے۔ ایسے طور پر کہ اس کی تیاری کے منتظر نہ رہو۔“ اللہ تعالیٰ کے ارشاد «من وراء حجاب‏» تک اس کے بعد پردہ ڈال دیا گیا اور لوگ کھڑے ہو گئے۔' WHERE id = 4587;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے ابراہیم تیمی نے، ان سے ان کے والد نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ آفتاب غروب ہونے کے وقت میں مسجد میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ موجود تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ابوذر! تمہیں معلوم ہے یہ آفتاب کہاں غروب ہوتا ہے؟ میں نے عرض کیا اللہ اور اس کے رسول کو زیادہ علم ہے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ یہ چلتا رہتا ہے یہاں تک کہ عرش کے نیچے سجدہ کرتا ہے جیسا کہ ارشاد باری ہے «والشمس تجري لمستقر لها ذلك تقدير العزيز العليم‏» کہ ”اور آفتاب اپنے ٹھکانے کی طرف چلتا رہتا ہے، یہ زبردست علم والے کا ٹھہرایا ہوا اندازہ ہے۔“' WHERE id = 4597;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا کہ مجھ سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عبدالرحمٰن بن خالد بن مسافر نے بیان کیا، ان سے ابن شہاب نے اور ان سے ابوسلمہ اور ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ قیامت کے دن اللہ ساری زمین کو اپنی مٹھی میں لے گا اور آسمان کو اپنے داہنے ہاتھ میں لپیٹ لے گا۔ پھر فرمائے گا «أنا الملك،‏‏‏‏ أين ملوك الأرض» ”آج حکومت صرف میری ہے، دنیا کے بادشاہ آج کہاں ہیں؟“' WHERE id = 4607;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ نے بیان کیا، کہا ہم سے وکیع نے بیان کیا، ان سے اعمش نے، ان سے ابوالضحیٰ نے، ان سے مسروق نے بیان کیا کہ میں عبداللہ بن مسعود رضی اللہ عنہ کی خدمت میں حاضر ہوا۔ انہوں نے کہا کہ یہ بھی علم ہی ہے کہ تمہیں اگر کوئی بات معلوم نہیں ہے تو اس کے متعلق یوں کہہ دو کہ اللہ ہی زیادہ جاننے والا ہے۔ اللہ تعالیٰ نے اپنے نبی صلی اللہ علیہ وسلم سے فرمایا کہ آپ اپنی قوم سے کہہ دیں کہ میں تم سے کسی اجرت کا طالب نہیں ہوں اور نہ میں بناوٹی باتیں کرتا ہوں جب قریش آپ صلی اللہ علیہ وسلم کو تکلیف پہنچانے اور آپ کے ساتھ معاندانہ روش میں برابر بڑھتے ہی رہے تو آپ صلی اللہ علیہ وسلم نے ان کے لیے بددعا کی کہ اے اللہ! ان کے خلاف میری مدد ایسے قحط کے ذریعہ کر جیسا کہ یوسف علیہ السلام کے زمانہ میں پڑا تھا۔ چنانچہ قحط پڑا اور بھوک کی شدت کا یہ حال ہوا کہ لوگ ہڈیاں اور مردار کھانے لگ گئے۔ لوگ آسمان کی طرف دیکھتے تھے لیکن فاقہ کی وجہ سے دھویں کے سوا اور کچھ نظر نہ آتا۔ آخر انہوں نے کہا کہ ”اے ہمارے پروردگار! ہم سے اس عذاب کو دور کر، ہم ضرور ایمان لے آئیں گے۔ لیکن اللہ تعالیٰ نے ان سے کہہ دیا تھا کہ اگر ہم نے یہ عذاب دور کر دیا تو پھر بھی تم اپنی پہلی حالت پر لوٹ آؤ گے۔“ نبی کریم صلی اللہ علیہ وسلم نے ان کے حق میں دعا کی اور یہ عذاب ان سے ہٹ گیا لیکن وہ پھر بھی کفر و شرک پر ہی جمے رہے، اس کا بدلہ اللہ تعالیٰ نے بدر کی لڑائی میں لیا۔ یہی واقعہ آیت «يوم تأتي السماء بدخان مبين‏» آخر تک میں بیان ہوا ہے۔' WHERE id = 4617;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ نے بیان کیا، ان سے امام مالک نے، ان سے زید بن اسلم نے، ان سے ان کے والد نے کہ رسول اللہ صلی اللہ علیہ وسلم ایک سفر میں جا رہے تھے۔ عمر رضی اللہ عنہ بھی آپ کے ساتھ تھے۔ رات کا وقت تھا عمر بن خطاب رضی اللہ عنہ نے سوال کیا لیکن نبی کریم صلی اللہ علیہ وسلم نے کوئی جواب نہیں دیا۔ پھر انہوں نے سوال کیا اور اس مرتبہ بھی آپ صلی اللہ علیہ وسلم نے جواب نہیں دیا، تیسری مرتبہ بھی انہوں نے سوال کیا لیکن آپ نے جواب نہیں دیا۔ اس پر عمر رضی اللہ عنہ نے کہا، عمر کی ماں اسے روئے! نبی کریم صلی اللہ علیہ وسلم سے تم نے تین مرتبہ سوال میں اصرار کیا، لیکن نبی کریم صلی اللہ علیہ وسلم نے تمہیں کسی مرتبہ جواب نہیں دیا۔ عمر رضی اللہ عنہ نے بیان کیا کہ پھر میں نے اپنے اونٹ کو حرکت دی اور لوگوں سے آگے بڑھ گیا۔ مجھے خوف تھا کہ کہیں میرے بارے میں قرآن مجید کی کوئی آیت نہ نازل ہو۔ ابھی تھوڑی ہی دیر ہوئی تھی کہ ایک پکارنے والے کی آواز میں نے سنی جو مجھے ہی پکار رہا تھا۔ میں نے کہا کہ مجھے تو خوف تھا ہی کہ میرے بارے میں کوئی آیت نہ نازل ہو جائے۔ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور سلام کیا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھ پر آج رات ایک سورت نازل ہوئی ہے جو مجھے اس ساری کائنات سے زیادہ عزیز ہے جس پر سورج طلوع ہوتا ہے پھر آپ نے سورۃ الفتح کی تلاوت فرمائی۔' WHERE id = 4627;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن ولید نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے خالد نے، ان سے ابوقلابہ نے اور ان سے ثابت بن ضحاک نے اور وہ ( صلح حدیبیہ کے دن ) درخت کے نیچے بیعت کرنے والوں میں شامل تھے۔' WHERE id = 4637;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں محمد بن عبدالرحمٰن بن نوفل نے، انہیں عروہ نے، انہیں زینب بنت ابی سلمہ نے اور ان سے ام المؤمنین ام سلمہ رضی اللہ عنہا نے بیان کیا کہ ( حج کے موقع پر ) میں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ میں بیمار ہوں آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر سواری پر بیٹھ کر لوگوں کے پیچھے سے طواف کرے چنانچہ میں نے طواف کیا اور نبی کریم صلی اللہ علیہ وسلم اس وقت خانہ کعبہ کے پہلو میں نماز پڑھتے ہوئے سورۃ والطور و کتاب مسطور کی تلاوت کر رہے تھے۔' WHERE id = 4647;
UPDATE hadiths SET urdu = 'ہم سے نصر بن علی نے بیان کیا، کہا ہم کو ابواحمد زبیری نے خبر دی، کہا ہم کو اسرائیل نے خبر دی، ان سے ابواسحاق نے، ان سے اسود بن یزید نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ سب سے پہلے نازل ہونے والی سجدہ والی سورت سورۃ النجم ہے۔ بیان کیا کہ پھر رسول اللہ صلی اللہ علیہ وسلم نے ( اس کی تلاوت کے بعد ) سجدہ کیا اور جتنے لوگ آپ کے پیچھے تھے سب ہی نے آپ صلی اللہ علیہ وسلم کے ساتھ سجدہ کیا، سوا ایک شخص کے، میں نے دیکھا کہ اس نے اپنی ہتھیلی میں مٹی اٹھائی اور اسی پر سجدہ کر لیا۔ بعد میں ( بدر کی لڑائی میں ) میں نے اسے دیکھا کہ کفر کی حالت میں وہ قتل کیا ہوا پڑا ہے۔ وہ شخص امیہ بن خلف تھا۔' WHERE id = 4657;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے «فهل من مدكر‏» ( دال مہملہ سے ) پڑھا تھا۔' WHERE id = 4667;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے بنو نضیر کے کھجوروں کے درخت جلا دیئے تھے اور انہیں کاٹ ڈالا تھا۔ یہ درخت مقام بویرہ میں تھے پھر اس کے متعلق اللہ تعالیٰ نے آیت نازل کی «ما قطعتم من لينة أو تركتموها قائمة على أصولها فبإذن الله وليخزي الفاسقين‏» کہ ”جو کھجوروں کے درخت تم نے کاٹے یا انہیں ان کی جڑوں پر قائم رہنے دیا سو یہ دونوں اللہ ہی کے حکم کے موافق ہیں اور تاکہ نافرمانوں کو ذلیل کرے۔“' WHERE id = 4677;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا کہ ہم سے زہری نے بیان کیا، کہا کہ مجھ سے ابوادریس نے بیان کیا اور انہوں نے عبادہ بن صامت رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کیا تم مجھ سے اس بات پر بیعت کرو گے کہ اللہ تعالیٰ کے ساتھ کسی کو شریک نہ ٹھہراؤ گے اور نہ زنا کرو گے اور نہ چوری کرو گے۔“ آپ صلی اللہ علیہ وسلم نے سورۃ النساء کی آیتیں پڑھیں۔ سفیان نے اس حدیث میں اکثر یوں کہا کہ آپ نے یہ آیت پڑھی۔ پھر تم میں سے جو شخص اس شرط کو پورا کرے گا تو اس کا اجر اللہ پر ہے اور جو کوئی ان میں سے کسی شرط کی خلاف ورزی کر بیٹھا اور اس پر اسے سزا بھی مل گئی تو سزا اس کے لیے کفارہ بن جائے گی لیکن کسی نے اپنے کسی عہد کے خلاف کیا اور اللہ نے اسے چھپا لیا تو وہ اللہ کے حوالے ہے اللہ چاہے تو اسے اس پر عذاب دے اور اگر چاہے معاف کر دے، سفیان کے ساتھ اس حدیث کو عبدالرزاق نے بھی معمر سے روایت کیا انہوں نے زہری سے اور یوں ہی کہا آیت پڑھی۔' WHERE id = 4687;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، ان سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے اور ان سے زید بن ارقم رضی اللہ عنہما نے بیان کیا کہ میں نے اپنے چچا کے ساتھ تھا میں نے عبداللہ بن ابی ابن سلول کو کہتے سنا کہ جو لوگ رسول ( صلی اللہ علیہ وسلم ) کے پاس ہیں ان پر کچھ خرچ نہ کرو تاکہ وہ منتشر ہو جائیں اور اگر اب ہم مدینہ واپس لوٹیں گے تو ہم میں سے جو عزت والے ہیں ان ذلیلوں کو نکال باہر کر دیں گے۔ میں نے اس کا ذکر اپنے چچا سے کیا اور انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا جب نبی کریم صلی اللہ علیہ وسلم نے ان ہی کی تصدیق کر دی تو مجھے اس کا اتنا افسوس ہوا کہ پہلے کبھی کسی بات پر نہ ہوا ہو گا، میں غم سے اپنے گھر میں بیٹھ گیا۔ میرے چچا نے کہا کہ تمہارا کیا ایسا خیال تھا کہ نبی کریم صلی اللہ علیہ وسلم نے تمہیں جھٹلایا اور تم پر خفا ہوئے ہیں؟ پھر اللہ تعالیٰ نے یہ آیت نازل کی «إذا جاءك المنافقون قالوا نشهد إنك لرسول الله‏» ”جب منافق آپ کے پاس آتے ہیں تو کہتے ہیں کہ آپ بیشک اللہ کے رسول ہیں“ نبی کریم صلی اللہ علیہ وسلم نے مجھے بلوا کر اس آیت کی تلاوت فرمائی اور فرمایا کہ اللہ تعالیٰ نے تمہاری تصدیق نازل کر دی ہے۔' WHERE id = 4697;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے یحییٰ بن سعید انصاری نے بیان کیا، کہا میں نے عبید بن حنین سے سنا، انہوں نے بیان کیا کہ میں نے ابن عباس رضی اللہ عنہما سے سنا وہ بیان کرتے تھے کہ میں نے عمر رضی اللہ عنہ سے ایک بات پوچھنے کا ارادہ کیا اور عرض کیا امیرالمؤمنین! وہ کون دو عورتیں تھیں جنہوں نے رسول اللہ صلی اللہ علیہ وسلم کے ستانے کے لیے منصوبہ بنایا تھا؟ ابھی میں نے اپنی بات پوری بھی نہیں کی تھی کہ انہوں نے کہا وہ عائشہ اور حفصہ رضی اللہ عنہما تھیں۔' WHERE id = 4707;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن منصور نے بیان کیا، کہا ہم سے عبدالصمد نے بیان کیا، کہا ہم سے حرب نے بیان کیا کہ ہم سے یحییٰ نے بیان کیا، کہا کہ میں نے ابوسلمہ سے پوچھا کہ قرآن مجید کی کون سی آیت سب سے پہلے نازل ہوئی تھی؟ فرمایا کہ «يا أيها المدثر‏» میں نے کہا کہ مجھے خبر ملی ہے کہ «اقرأ باسم ربك الذي خلق‏» سب سے پہلے نازل ہوئی تھی۔ ابوسلمہ نے بیان کیا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے پوچھا تھا کہ قرآن کی کون سی آیت سب سے پہلے نازل ہوئی تھی؟ انہوں نے فرمایا کہ «يا أيها المدثر‏» ”اے کپڑے میں لپٹنے والے!“ میں نے ان سے یہی کہا تھا کہ مجھے خبر ملی ہے کہ «اقرأ باسم ربك‏» سب سے پہلے نازل ہوئی تھی تو انہوں نے کہا کہ میں تمہیں وہی خبر دے رہا ہوں جو میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں نے غار حرا میں تنہائی اختیار کی جب میں وہ مدت پوری کر چکا اور نیچے اتر کر وادی کے بیچ میں پہنچا تو مجھے پکارا گیا۔ میں نے اپنے آگے پیچھے دائیں بائیں دیکھا اور مجھے دکھائی دیا کہ فرشتہ آسمان اور زمین کے درمیان کرسی پر بیٹھا ہے۔ پھر میں خدیجہ ( رضی اللہ عنہا ) کے پاس آیا اور ان سے کہا کہ مجھے کپڑا اوڑھا دو اور میرے اوپر ٹھنڈا پانی ڈالو اور مجھ پر یہ آیت نازل ہوئی «يا أيها المدثر * قم فأنذر * وربك فكبر‏» ”اے کپڑے میں لپٹنے والے! اٹھئیے پھر لوگوں کو عذاب آخرت سے ڈرایئے اور اپنے پروردگار کی بڑائی کیجئے۔“' WHERE id = 4717;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہ مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا مجھ سے ابراہیم نے بیان کیا، ان سے اسود نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک غار میں تھے کہ نبی کریم صلی اللہ علیہ وسلم پر سورۃ والمرسلات نازل ہوئی، پھر نبی کریم صلی اللہ علیہ وسلم نے اس کی تلاوت کی اور میں نے اسے آپ ہی کے منہ سے یاد کر لیا۔ وحی سے آپ کی منہ کی تازگی اس وقت بھی باقی تھی کہ اتنے میں غار کی طرف ایک سانپ لپکا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اسے مار ڈالو۔ ہم اس کی طرف بڑھے لیکن وہ بھاگ گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ وہ بھی تمہارے شر سے اس طرح بچ نکلا جیسا کہ تم اس کے شر سے بچ گئے۔ عمر بن حفص نے کہا مجھے یہ حدیث یاد ہے، میں نے اپنے والد سے سنی تھی، انہوں نے اتنا اور بڑھایا تھا کہ وہ غار منیٰ میں تھا۔' WHERE id = 4728;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا مجھ سے میرے والد نے، کہا ہم سے اعمش نے، ان سے ابراہیم نخعی نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ کے کچھ شاگرد ابو الدرداء رضی اللہ عنہ کے یہاں ( شام ) آئے انہوں نے انہیں تلاش کیا اور پا لیا۔ پھر ان سے پوچھا کہ تم میں کون عبداللہ بن مسعود رضی اللہ عنہ کی قرآت کے مطابق قرآت کر سکتا ہے؟ شاگروں نے کہا کہ ہم سب کر سکتے ہیں۔ پھر پوچھا کسے ان کی قرآت زیادہ محفوظ ہے؟ سب نے علقمہ کی طرف اشارہ کیا۔ انہوں نے دریافت کیا انہیں سورۃ «والليل إذا يغشى‏» کی قرآت کرتے کس طرح سنا ہے؟ علقمہ نے کہا کہ «والذكر والأنثى‏» ( بغیر خلق کے ) کہا کہ میں گواہی دیتا ہوں کہ میں نے بھی رسول اللہ صلی اللہ علیہ وسلم کو اسی طرح قرآت کرتے ہوئے سنا ہے۔ لیکن یہ لوگ ( یعنی شام والے ) چاہتے ہیں کہ «وما خلق الذكر والأنثى‏» پڑھوں۔ اللہ کی قسم میں ان کی پیروی نہیں کروں گا۔' WHERE id = 4738;
UPDATE hadiths SET urdu = 'محمد بن شہاب نے بیان کیا، انہیں ابوسلمہ رضی اللہ عنہ نے خبر دی اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم وحی کے کچھ دنوں کے لیے رک جانے کا ذکر فرما رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں چل رہا تھا کہ میں نے اچانک آسمان کی طرف سے ایک آواز سنی۔ میں نے نظر اٹھا کر دیکھا تو وہی فرشتہ ( جبرائیل علیہ السلام ) جو میرے پاس غار حرا میں آیا تھا، آسمان اور زمین کے درمیان کرسی پر بیٹھا ہوا نظر آیا۔ میں ان سے بہت ڈرا اور گھر واپس آ کر میں نے کہا کہ مجھے چادر اڑھا دو چنانچہ گھر والوں نے مجھے چادر اڑھا دی، پھر اللہ تعالیٰ نے یہ آیت نازل کی «يا أيها المدثر * قم فأنذر * وربك فكبر * وثيابك فطهر * والرجز فاهجر‏» ”اے کپڑے میں لپٹنے والے! اٹھئیے پھر لوگوں کو ڈرایئے اور اپنے پروردگار کی بڑائی بیان کیجئے اور اپنے کپڑوں کو پاک رکھیئے۔“ ابوسلمہ رضی اللہ عنہ نے کہا کہ «الرجز» جاہلیت کے بت تھے جن کی وہ پرستش کیا کرتے تھے۔ راوی نے بیان کیا کہ پھر وحی برابر آنے لگی۔' WHERE id = 4749;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شیبان بن عبدالرحمٰن نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کو معراج ہوئی نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں ایک نہر پر پہنچا جس کے دونوں کناروں پر خولدار موتیوں کے ڈیرے لگے ہوئے تھے۔ میں نے پوچھا اے جبرائیل! یہ نہر کیسی ہے؟ انہوں نے بتایا کہ یہ حوض کوثر ہے ( جو اللہ نے آپ کو دیا ہے ) ۔' WHERE id = 4759;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم سے شعیب نے بیان کیا، انہوں نے کہا ہم سے ابوالزناد نے بیان کیا، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ مجھے ابن آدم نے جھٹلایا حالانکہ اس کے لیے یہ بھی مناسب نہیں تھا۔ مجھے جھٹلانا یہ ہے کہ ( ابن آدم ) کہتا ہے کہ میں اس کو دوبارہ نہیں پیدا کروں گا حالانکہ میرے لیے دوبارہ پیدا کرنا اس کے پہلی مرتبہ پیدا کرنے سے زیادہ مشکل نہیں۔ اس کا مجھے گالی دینا یہ ہے کہ کہتا ہے کہ اللہ نے اپنا بیٹا بنایا ہے حالانکہ میں ایک ہوں۔ بےنیاز ہوں نہ میرے لیے کوئی اولاد ہے اور نہ میں کسی کی اولاد ہوں اور نہ کوئی میرے برابر ہے۔' WHERE id = 4769;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم سے ابن شہاب نے بیان کیا، ان سے عبید بن سباق نے اور ان سے زید بن ثابت رضی اللہ عنہ نے بیان کیا کہ جنگ یمامہ میں ( صحابہ کی بہت بڑی تعداد کے ) شہید ہو جانے کے بعد ابوبکر رضی اللہ عنہ نے مجھے بلا بھیجا۔ اس وقت عمر رضی اللہ عنہ میرے پاس آئے اور انہوں نے کہا کہ یمامہ کی جنگ میں بہت بڑی تعداد میں قرآن کے قاریوں کی شہادت ہو گئی ہے اور مجھے ڈر ہے کہ اسی طرح کفار کے ساتھ دوسری جنگوں میں بھی قراء قرآن بڑی تعداد میں قتل ہو جائیں گے اور یوں قرآن کے جاننے والوں کی بہت بڑی تعداد ختم ہو جائے گی۔ اس لیے میرا خیال ہے کہ آپ قرآن مجید کو ( باقاعدہ کتابی شکل میں ) جمع کرنے کا حکم دے دیں۔ میں نے عمر رضی اللہ عنہ سے کہا کہ آپ ایک ایسا کام کس طرح کریں گے جو رسول اللہ صلی اللہ علیہ وسلم نے ( اپنی زندگی میں ) نہیں کیا؟ عمر رضی اللہ عنہ نے اس کا یہ جواب دیا کہ اللہ کی قسم! یہ تو ایک کارخیر ہے۔ عمر رضی اللہ عنہ یہ بات مجھ سے باربار کہتے رہے۔ آخر اللہ تعالیٰ نے اس مسئلہ میں میرا بھی سینہ کھول دیا اور اب میری بھی وہی رائے ہو گئی جو عمر رضی اللہ عنہ کی تھی۔ زید رضی اللہ عنہ نے بیان کیا کہ ابوبکر رضی اللہ عنہ نے کہا آپ ( زید رضی اللہ عنہ ) جوان اور عقلمند ہیں، آپ کو معاملہ میں متہم بھی نہیں کیا جا سکتا اور آپ رسول اللہ صلی اللہ علیہ وسلم کی وحی لکھتے بھی تھے، اس لیے آپ قرآن مجید کو پوری تلاش اور محنت کے ساتھ ایک جگہ جمع کر دیں۔ اللہ کی قسم! اگر یہ لوگ مجھے کسی پہاڑ کو بھی اس کی جگہ سے دوسری جگہ ہٹانے کے لیے کہتے تو میرے لیے یہ کام اتنا مشکل نہیں تھا جتنا کہ ان کا یہ حکم کہ میں قرآن مجید کو جمع کر دوں۔ میں نے اس پر کہا کہ آپ لوگ ایک ایسے کام کو کرنے کی ہمت کیسے کرتے ہیں جو رسول اللہ صلی اللہ علیہ وسلم نے خود نہیں کیا تھا۔ ابوبکر رضی اللہ عنہ نے کہا: اللہ کی قسم! یہ ایک عمل خیر ہے۔ ابوبکر رضی اللہ عنہ یہ جملہ برابر دہراتے رہے، یہاں تک کہ اللہ تعالیٰ نے میرا بھی ان کی اور عمر رضی اللہ عنہ کی طرح سینہ کھول دیا۔ چنانچہ میں نے قرآن مجید ( جو مختلف چیزوں پر لکھا ہوا موجود تھا ) کی تلاش شروع کر دی اور قرآن مجید کو کھجور کی چھلی ہوئی شاخوں، پتلے پتھروں سے، ( جن پر قرآن مجید لکھا گیا تھا ) اور لوگوں کے سینوں کی مدد سے جمع کرنے لگا۔ سورۃ التوبہ کی آخری آیتیں مجھے ابوخزیمہ انصاری رضی اللہ عنہ کے پاس لکھی ہوئی ملیں، یہ چند آیات مکتوب شکل میں ان کے سوا اور کسی کے پاس نہیں تھیں «لقد جاءكم رسول من أنفسكم عزيز عليه ما عنتم‏» سے سورۃ براۃ ( سورۃ توبہ ) کے خاتمہ تک۔ جمع کے بعد قرآن مجید کے یہ صحیفے ابوبکر رضی اللہ عنہ کے پاس محفوظ تھے۔ پھر ان کی وفات کے بعد عمر رضی اللہ عنہ نے جب تک وہ زندہ رہے اپنے ساتھ رکھا پھر وہ ام المؤمنین حفصہ بنت عمر رضی اللہ عنہا کے پاس محفوظ رہے۔' WHERE id = 4780;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، ان سے ابوحمزہ (محمد بن میمون) نے ان سے اعمش نے، ان سے شقیق نے بیان کیا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا میں ان جڑواں سورتوں کو جانتا ہوں جنہیں نبی کریم صلی اللہ علیہ وسلم ہر رکعت میں دو دو پڑھتے تھے پھر عبداللہ بن مسعود رضی اللہ عنہ مجلس سے کھڑے ہو گئے ( اور اپنے گھر ) چلے گئے۔ علقمہ بھی آپ کے ساتھ اندر گئے۔ جب علقمہ رضی اللہ عنہ باہر نکلے تو ہم نے ان سے انہیں سورتوں کے متعلق پوچھا۔ انہوں نے کہا یہ شروع مفصل کی بیس سورتیں ہیں، ان کی آخری سورتیں وہ ہیں جن کی اول میں «حم» ہے۔ «حم الدخان» اور «عم يتساءلون‏.‏» بھی ان ہی میں سے ہیں۔' WHERE id = 4790;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے بیان کیا، کہا مجھ سے حبیب بن عبدالرحمٰن نے بیان کیا، ان سے حفص بن عاصم نے اور ان سے ابوسعید بن معلی رضی اللہ عنہ نے کہ میں نماز میں مشغول تھا تو رسول اللہ صلی اللہ علیہ وسلم نے مجھے بلایا اس لیے میں کوئی جواب نہیں دے سکا، پھر میں نے ( آپ کی خدمت میں حاضر ہو کر ) عرض کیا: یا رسول اللہ! میں نماز پڑھ رہا تھا۔ اس پر آپ صلی اللہ علیہ وسلم نے فرمایا کیا اللہ تعالیٰ نے تمہیں حکم نہیں فرمایا ہے «استجيبوا لله وللرسول إذا دعاكم‏» کہ ”اللہ کے رسول جب تمہیں پکاریں تو ان کی پکار پر فوراً اللہ کے رسول کے لیے لبیک کہا کرو۔“ پھر آپ صلی اللہ علیہ وسلم نے فرمایا مسجد سے نکلنے سے پہلے قرآن کی سب سے بڑی سورت میں تمہیں کیوں نہ سکھا دوں۔ پھر آپ نے میرا ہاتھ پکڑ لیا اور جب ہم مسجد سے باہر نکلنے لگے تو میں نے عرض کیا: یا رسول اللہ! آپ نے ابھی فرمایا تھا کہ مسجد کے باہر نکلنے سے پہلے آپ مجھے قرآن کی سب سے بڑی سورت بتائیں گے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہاں وہ سورت «الحمد لله رب العالمين» ہے یہی وہ سات آیات ہیں جو ( ہر نماز میں ) باربار پڑھی جاتی ہیں اور یہی وہ قرآن عظیم ہے جو مجھے دیا گیا ہے۔' WHERE id = 4800;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عروہ بن زبیر نے اور انہیں عائشہ رضی اللہ عنہا نے کہ رسول اللہ صلی اللہ علیہ وسلم جب بیمار پڑتے تو معوذات کی سورتیں پڑھ کر اسے اپنے اوپر دم کرتے ( اس طرح کہ ہوا کے ساتھ کچھ تھوک بھی نکلتا ) پھر جب ( مرض الموت میں ) آپ کی تکلیف بڑھ گئی تو میں ان سورتوں کو پڑھ کر نبی کریم صلی اللہ علیہ وسلم کے ہاتھوں سے برکت کی امید میں آپ کے جسد مبارک پر پھیرتی تھی۔' WHERE id = 4810;
UPDATE hadiths SET urdu = 'ہم سے علی بن ابراہیم نے بیان کیا، انہوں نے کہا ہم سے روح بن عبادہ نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے سلیمان نے، انہوں نے کہا میں نے ذکوان سے سنا اور انہوں نے ابوہریرہ رضی اللہ عنہ سے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ رشک تو بس دو ہی آدمیوں پر ہونا چاہئے ایک اس پر جسے اللہ تعالیٰ نے قرآن کا علم دیا اور وہ رات دن اس کی تلاوت کرتا رہتا ہے کہ اس کا پڑوسی سن کر کہہ اٹھے کہ کاش مجھے بھی اس جیسا علم قرآن ہوتا اور میں بھی اس کی طرح عمل کرتا اور وہ دوسرا جسے اللہ نے مال دیا اور وہ اسے حق کے لیے لٹا رہا ہے ( اس کو دیکھ کر ) دوسرا شخص کہہ اٹھتا ہے کہ کاش میرے پاس بھی اس کے جتنا مال ہوتا اور میں بھی اس کی طرح خرچ کرتا۔' WHERE id = 4820;
UPDATE hadiths SET urdu = 'ہم سے یعقوب بن ابراہیم نے بیان کیا، کہا ہم سے ہشیم نے بیان کیا، کہا ہم کو ابوبشر نے خبر دی، انہیں سعید بن جبیر نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ میں نے محکم سورتیں رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں سب یاد کر لی تھیں، میں نے پوچھا کہ محکم سورتیں کون سی ہیں؟ کہا کہ مفصل۔' WHERE id = 4831;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن عاصم نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے کہ انس رضی اللہ عنہ سے پوچھا گیا کہ رسول اللہ صلی اللہ علیہ وسلم کی قرآت کیسی تھی؟ انہوں نے بیان کیا کہ مد کے ساتھ۔ پھر آپ نے «بسم الله الرحمن الرحيم» پڑھا اور کہا کہ «بسم الله» ( میں اللہ کی لام ) کو مد کے ساتھ پڑھتے «الرحمن» ( میں میم ) کو مد کے ساتھ پڑھتے اور «الرحيم‏.» ( میں حاء کو ) مد کے ساتھ پڑھتے۔' WHERE id = 4842;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، کہا ہم سے عبدالواحد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، ان سے ابراہیم نے بیان کیا، ان سے عبیدہ سلمانی نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ مجھ سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ مجھے قرآن مجید پڑھ کر سناؤ۔ میں نے عرض کیا: کیا میں سناؤں؟آپ پر تو قرآن مجید نازل ہوتا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں کسی سے سننا محبوب رکھتا ہوں۔' WHERE id = 4853;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص بن غیاث نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا ہم سے اعمش نے بیان کیا، کہا کہ مجھ سے عمارہ نے بیان کیا، ان سے عبدالرحمٰن بن یزید نے بیان کیا، کہا کہ میں علقمہ اور اسود ( رحمہم اللہ ) کے ساتھ عبداللہ بن مسعود رضی اللہ عنہ کی خدمت میں حاضر ہوا، انہوں نے ہم سے کہا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں نوجوان تھے اور ہمیں کوئی چیز میسر نہیں تھی۔ نبی کریم صلی اللہ علیہ وسلم نے ہم سے فرمایا کہ نوجوانوں کی جماعت! تم میں جسے بھی نکاح کرنے کے لیے مالی طاقت ہو اسے نکاح کر لینا چاہئے کیونکہ یہ نظر کو نیچی رکھنے والا اور شرمگاہ کی حفاظت کرنے والا عمل ہے اور جو کوئی نکاح کی بوجہ غربت طاقت نہ رکھتا ہو اسے چاہیے کہ روزہ رکھے کیونکہ روزہ اس کی خواہشات نفسانی کو توڑ دے گا۔' WHERE id = 4863;
UPDATE hadiths SET urdu = 'اور اصبغ نے کہا کہ مجھے ابن وہب نے خبر دی، انہیں یونس بن یزید نے، انہیں ابن شہاب نے، انہیں ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا کہ یا رسول اللہ! میں نوجوان ہوں اور مجھے اپنے پر زنا کا خوف رہتا ہے۔ میرے پاس کوئی ایسی چیز نہیں جس پر میں کسی عورت سے شادی کر لوں۔ آپ میری یہ بات سن کر خاموش رہے۔ دوبارہ میں نے اپنی یہی بات دہرائی لیکن آپ اس مرتبہ بھی خاموش رہے۔ سہ بارہ میں نے عرض کیا آپ پھر بھی خاموش رہے۔ میں نے چوتھی مرتبہ عرض کیا آپ صلی اللہ علیہ وسلم نے فرمایا اے ابوہریرہ! جو کچھ تم کرو گے اسے ( لوح محفوظ میں ) لکھ کر قلم خشک ہو چکا ہے۔ خواہ اب تم خصی ہو جاؤ یا باز رہو۔ یعنی خصی ہونا بیکار محض ہے۔' WHERE id = 4873;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے ثابت بنانی اور شعیب بن حبحاب نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے صفیہ رضی اللہ عنہا کو آزاد کیا اور ان کی آزادی کو ان کا مہر قرار دیا۔' WHERE id = 4883;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سلیمان تیمی نے بیان کیا، انہوں نے ابوعثمان نہدی سے سنا اور انہوں نے اسامہ بن زید رضی اللہ عنہما سے روایت کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے اپنے بعد مردوں کے لیے عورتوں کے فتنہ سے بڑھ کر نقصان دینے والا اور کوئی فتنہ نہیں چھوڑا ہے۔' WHERE id = 4893;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ ہم سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے اور ان سے زینب بنت ابی سلمہ نے اور ان سے ام حبیبہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! آپ ابوسفیان کی صاحبزادی ( غرہ یا درہ یا حمنہ ) کو چاہتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر میں اس کے ساتھ کیا کروں گا؟ میں نے عرض کیا کہ اس سے آپ نکاح کر لیں۔ فرمایا کیا تم اسے پسند کرو گی؟ میں نے عرض کیا میں کوئی تنہا تو ہوں نہیں اور میں اپنی بہن کے لیے یہ پسند کرتی ہوں کہ وہ بھی میرے ساتھ آپ کے تعلق میں شریک ہو جائے۔ اس پر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ وہ میرے لیے حلال نہیں ہے میں نے عرض کیا مجھے معلوم ہوا ہے کہ آپ نے ( زینب سے ) نکاح کا پیغام بھیجا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ام سلمہ کی لڑکی کے پاس؟ میں نے کہا کہ جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ واہ واہ، اگر وہ میری ربیبہ نہ ہوتی جب بھی وہ میرے لیے حلال نہ ہوتی۔ مجھے اور اس کے والد ابوسلمہ کو ثویبہ نے دودھ پلایا تھا۔ دیکھو تم آئندہ میرے نکاح کے لیے اپنی لڑکیوں اور بہنوں کو نہ پیش کیا کرو۔ اور لیث بن سعد نے بھی اس حدیث کو ہشام سے روایت کیا ہے اس میں ابوسلمہ کی بیٹی کا نام درہ مذکور ہے۔' WHERE id = 4903;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے مرحوم بن عبدالعزیز بصریٰ نے بیان کیا، کہا کہ میں نے ثابت بنانی سے سنا، انہوں نے بیان کیا کہ میں انس رضی اللہ عنہ کے پاس تھا اور ان کے پاس ان کی بیٹی بھی تھیں۔ انس رضی اللہ عنہ نے بیان کیا کہ ایک خاتون رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں اپنے آپ کو آپ صلی اللہ علیہ وسلم کے لیے پیش کرنے کی غرض سے حاضر ہوئیں اور عرض کیا: یا رسول اللہ! کیا آپ کو میری ضرورت ہے؟ اس پر انس رضی اللہ عنہ کی بیٹی بولیں کہ وہ کیسی بےحیاء عورت تھی۔ ہائے، بےشرمی! ہائے بےشرمی! انس رضی اللہ عنہ نے ان سے کہا وہ تم سے بہتر تھیں، ان کو نبی کریم صلی اللہ علیہ وسلم کی طرف رغبت تھی، اس لیے انہوں نے اپنے آپ کو نبی کریم صلی اللہ علیہ وسلم کے لیے پیش کیا۔' WHERE id = 4915;
UPDATE hadiths SET urdu = 'ہم سے احمد بن عمرو نے بیان کیا، کہا کہ مجھ سے میرے والد حفص بن عبداللہ نے بیان کیا، کہا کہ مجھ سے ابراہیم بن طہمان نے بیان کیا، ان سے یونس نے، ان سے حسن بصری نے آیت «فلا تعضلوهن‏» کی تفسیر میں بیان کیا کہ مجھ سے معقل بن یسار رضی اللہ عنہ نے بیان کیا کہ یہ آیت میرے ہی بارے میں نازل ہوئی تھی میں نے اپنی ایک بہن کا نکاح ایک شخص سے کر دیا تھا۔ اس نے اسے طلاق دے دی لیکن جب عدت پوری ہوئی تو وہ شخص ( ابوالبداح ) میری بہن سے پھر نکاح کا پیغام لے کر آیا۔ میں نے اس سے کہا کہ میں نے تم سے اس کا ( اپنی بہن ) کا نکاح کیا اسے تمہاری بیوی بنایا اور تمہیں عزت دی لیکن تم نے اسے طلاق دیدی اور اب پھر تم نکاح کا پیغام لے کر آئے ہو۔ ہرگز نہیں، اللہ کی قسم! اب میں تمہیں کبھی اسے نہیں دوں گا۔ وہ شخص ابوالبداح کچھ برا آدمی نہ تھا اور عورت بھی اس کے یہاں واپس جانا چاہتی تھی اس لیے اللہ تعالیٰ نے یہ آیت نازل کی «فلا تعضلوهن‏» کہ ”تم عورتوں کو مت روکو“ میں نے عرض کیا کہ یا رسول اللہ! اب میں کر دوں گا۔ بیان کیا کہ پھر انہوں نے اپنی بہن کا نکاح اس شخص سے کر دیا۔' WHERE id = 4925;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے اور (دوسری سند) اور لیث نے بیان کیا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب زہری نے، کہا مجھ کو عروہ بن زبیر نے خبر دی کہ انہوں نے عائشہ رضی اللہ عنہا سے سوال کیا کہ اے ام المؤمنین! اس آیت میں کیا حکم بیان ہوا ہے؟ «وإن خفتم أن لا تقسطوا في اليتامى‏» ”اور اگر تمہیں خوف ہو کہ تم یتیموں کے بارے میں انصاف نہ کر سکو گے۔“ «ما ملكت أيمانكم‏» تک۔ عائشہ رضی اللہ عنہا نے کہا: میرے بھانجے! اس آیت میں اس یتیم لڑکی کا حکم یبان ہوا ہے جو اپنے ولی کی پرورش میں ہو اور ولی کو اس کے حسن اور اس کے مال کی وجہ سے اس کی طرف توجہ ہو اور وہ اس کا مہر کم کر کے اس سے نکاح کرنا چاہتا ہو تو ایسے لوگوں کو ایسی یتیم لڑکیوں سے نکاح سے ممانعت کی گئی ہے سوائے اس صورت کے کہ وہ ان کے مہر کے بارے میں انصاف کریں ( اور اگر انصاف نہیں کر سکتے تو انہیں ان کے سوا دوسری عورتوں سے نکاح کا حکم دیا گیا ہے۔ عائشہ رضی اللہ عنہا نے کہا کہ لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کے بعد مسئلہ پوچھا تو اللہ تعالیٰ نے آیت «ويستفتونك في النساء‏» ”اور آپ سے عورتوں کے بارے میں پوچھتے ہیں“ سے «وترغبون‏» تک نازل کی۔ اللہ تعالیٰ نے اس آیت میں یہ حکم نازل کیا کہ یتیم لڑکیاں جب صاحب مال اور صاحب جمال ہوتی ہیں تب تو مہر میں کمی کر کے اس سے نکاح کرنا رشتہ لگانا پسند کرتے ہیں اور جب دولت مندی یا خوبصورتی نہیں رکھتی اس وقت اس کو چھوڑ کر دوسری عورتوں سے نکاح کر دیتے ہیں ( یہ کیا بات ) ان کو چاہئے کہ جیسے مال و دولت اور حسن و جمال نہ ہونے کی صورت میں اس کو چھوڑ دیتے ہیں ایسے ہی اس وقت بھی چھوڑ دیں جب وہ مالدار اور خوبصورت ہو البتہ اگر انصاف سے چلیں اور اس کا پورا مہر مقرر کریں تو خیر نکاح کر لیں۔' WHERE id = 4935;
UPDATE hadiths SET urdu = 'ہم سے عبیداللہ بن موسیٰ نے بیان کیا، کہا ان سے زکریا نے جو ابوزائدہ کے صاحبزادے ہیں، ان سے سعد بن ابراہیم نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کسی عورت کے لیے جائز نہیں کہ اپنی کسی ( سوکن ) بہن کی طلاق کی شرط اس لیے لگائے تاکہ اس کے حصہ کا پیالہ بھی خود انڈیل لے کیونکہ اسے وہی ملے گا جو اس کے مقدر میں ہو گا۔' WHERE id = 4946;
UPDATE hadiths SET urdu = 'ہم سے فضیل بن یعقوب نے بیان کیا، کہا ہم سے محمد بن سابق نے بیان کیا، ان سے اسرائیل نے بیان کیا، ان سے ہشام بن عروہ نے ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ وہ ایک دلہن کو ایک انصاری مرد کے پاس لے گئیں تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عائشہ! تمہارے پاس لہو ( دف بجانے والا ) نہیں تھا، انصار کو دف پسند ہے۔' WHERE id = 4956;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے منصور بن صفیہ نے، ان سے ان کی والدہ صفیہ بنت شیبہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے اپنی ایک بیوی کا ولیمہ دو مد ( تقریباً پونے دو سیر ) جَو سے کیا تھا۔' WHERE id = 4966;
UPDATE hadiths SET urdu = 'ہم سے سعید بن ابی مریم نے بیان کیا، کہا ہم سے ابوغسان محمد بن مطرف نے بیان کیا، کہا کہ مجھ سے ابوحازم (سلمہ بن دینار) نے بیان کیا، ان سے سہل بن سعد ساعدی رضی اللہ عنہ نے بیان کیا کہ جب ابواسید ساعدی رضی اللہ عنہ نے شادی کی تو انہوں نے نبی کریم صلی اللہ علیہ وسلم اور آپ کے صحابہ کو دعوت دی، اس موقعہ پر کھانا ان کی دلہن ام اسید ہی نے تیار کیا تھا اور انہوں نے ہی مردوں کے سامنے کھانا رکھا۔ انہوں نے پتھر کے ایک بڑے پیالے میں رات کے وقت کھجوریں بھگو دی تھی اور جب نبی کریم صلی اللہ علیہ وسلم کھانے سے فارغ ہوئے تو انہوں نے ہی اس کا شربت بنایا اور نبی کریم صلی اللہ علیہ وسلم کے سامنے ( تحفہ کے طور پر ) پینے کے لیے پیش کیا۔' WHERE id = 4976;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عرعرہ نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے بیان کیا، ان سے زرارہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر عورت اپنے شوہر سے ناراضگی کی وجہ سے اس کے بستر سے الگ تھلگ رات گزارنے تو فرشتے اس پر اس وقت تک لعنت بھیجتے ہیں جب تک وہ اپنی اس حرکت سے باز نہ آ جائے۔' WHERE id = 4987;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عبداللہ بن زمعہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم میں کوئی شخص اپنی بیوی کو غلاموں کی طرح نہ مارے کہ پھر دوسرے دن اس سے ہمبستر ہو گا۔' WHERE id = 4997;
UPDATE hadiths SET urdu = 'ہم سے فروہ نے بیان کیا، کہا ہم سے علی بن مسہر نے بیان کیا، ان سے ہشام بن عروہ نے، ان سے ان کے والد عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے کہا رسول اللہ صلی اللہ علیہ وسلم عصر کی نماز سے فارغ ہو کر اپنی ازواج مطہرات کے پاس تشریف لے جاتے اور ان میں سے کسی ایک کے قریب بھی بیٹھتے۔ ایک دن نبی کریم صلی اللہ علیہ وسلم حفصہ رضی اللہ عنہا کے یہاں گئے اور معمول سے زیادہ کافی دیر تک ٹھہرے رہے۔' WHERE id = 5008;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا، انہوں نے کہا ہم سے معتمر بن سلیمان نے بیان کیا، انہوں نے کہا ہم سے عبیداللہ بن عمرعمری نے، ان سے محمد بن منکدر نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں جنت میں داخل ہوا یا ( آپ صلی اللہ علیہ وسلم نے یہ فرمایا کہ ) میں جنت میں گیا، وہاں میں نے ایک محل دیکھا میں نے پوچھا یہ محل کس کا ہے؟ فرشتوں نے بتایا کہ عمر بن خطاب رضی اللہ عنہ کا میں نے چاہا کہ اس کے اندر جاؤں لیکن رک گیا کیونکہ تمہاری غیرت مجھے معلوم تھی۔ اس پر عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میرے ماں باپ آپ پر فدا ہوں، اے اللہ کے نبی! کیا میں آپ پر غیرت کروں گا۔' WHERE id = 5018;
UPDATE hadiths SET urdu = 'ہم سے اسحاق بن ابراہیم حنظلی نے بیان کیا، ان سے عیسیٰ بن یونس نے بیان کیا، ان سے اوزاعی نے، ان سے زہری نے، ان سے عروہ نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم میرے لیے اپنی چادر سے پردہ کئے ہوئے ہیں۔ میں حبشہ کے ان لوگوں کو دیکھ رہی تھی جو مسجد میں ( جنگی ) کھیل کا مظاہرہ کر رہے تھے، آخر میں ہی اکتا گئی۔ اب تم سمجھ لو ایک کم عمر لڑکی جس کو کھیل تماشہ دیکھنے کا بڑا شوق ہے کتنی دیر تک دیکھتی رہی ہو گی۔' WHERE id = 5028;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ولید نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے سیار نے، ان سے شعبی نے اور ان سے جابر بن عبداللہ رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ( غزوہ تبوک سے واپسی کے وقت ) فرمایا، جب رات کے وقت تم مدینہ میں پہنچو تو اس وقت تک اپنے گھروں میں نہ جانا جب تک ان کی بیویاں جو مدینہ منورہ میں موجود نہیں تھے، اپنا موئے زیر ناف صاف نہ کر لیں اور جن کے بال پراگندہ ہوں وہ کنگھا نہ کر لیں۔ جابر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ضروری ہے کہ جب تم گھر پہنچو تو خوب خوب «كيس» کیجؤ۔ شعبی کے ساتھ اس حدیث کو عبیداللہ نے بھی وہب بن کیسان سے، انہوں نے جابر رضی اللہ عنہ سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے روایت کیا، اس میں بھی «كيس» کا ذکر ہے۔' WHERE id = 5038;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے، ان سے قتادہ نے، ان سے ابوغالب یونس بن جبیر نے کہ میں نے ابن عمر رضی اللہ عنہما سے عرض کیا: ایک شخص نے اپنی بیوی کو اس وقت طلاق دی جب وہ حائضہ تھی ( اس کا کیا حکم؟ ) اس پر انہوں نے کہا تم ابن عمر رضی اللہ عنہما کو جانتے ہو؟ ابن عمر رضی اللہ عنہما نے اپنی بیوی کو اس وقت طلاق دی تھی جب وہ حائضہ تھیں۔ پھر عمر رضی اللہ عنہ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے، اس کے متعلق آپ سے پوچھا۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں حکم دیا کہ ( ابن عمر اس وقت اپنی بیوی سے ) رجعت کر لیں، پھر جب وہ حیض سے پاک ہو جائیں تو اس وقت اگر ابن عمر چاہیں، انہیں طلاق دیں۔ میں نے عرض کیا: کیا اسے بھی نبی کریم صلی اللہ علیہ وسلم نے طلاق شمار کیا تھا؟ ابن عمر رضی اللہ عنہما نے کہا اگر کوئی عاجز ہے اور حماقت کا ثبوت دے تو اس کا علاج ہے۔' WHERE id = 5050;
UPDATE hadiths SET urdu = 'ہم سے فروہ بن ابی المغراء نے بیان کیا، کہا ہم سے علی بن مسہر نے، ان سے ہشام بن عروہ نے، ان سے ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم شہد اور میٹھی چیزیں پسند کرتے تھے۔ نبی کریم صلی اللہ علیہ وسلم عصر کی نماز سے فارغ ہو کر جب واپس آتے تو اپنی ازواج کے پاس واپس تشریف لے جاتے اور بعض سے قریب بھی ہوتے تھے۔ ایک دن نبی کریم صلی اللہ علیہ وسلم حفصہ بنت عمر رضی اللہ عنہا کے پاس تشریف لے گئے اور معمول سے زیادہ دیر ان کے گھر ٹھہرے۔ مجھے اس پر غیرت آئی اور میں نے اس کے بارے میں پوچھا تو معلوم ہوا کہ حفصہ رضی اللہ عنہا کو ان کی قوم کی کسی خاتون نے انہیں شہد کا ایک ڈبہ دیا ہے اور انہوں نے اسی کا شربت نبی کریم صلی اللہ علیہ وسلم کے لیے پیش کیا ہے۔ میں نے اپنے جی میں کہا: اللہ کی قسم! میں تو ایک حیلہ کروں گی، پھر میں نے سودہ بنت زمعہ رضی اللہ عنہا سے کہا کہ نبی کریم صلی اللہ علیہ وسلم تمہارے پاس آئیں گے اور جب آئیں تو کہنا کہ معلوم ہوتا ہے آپ نے مغافیر کھا رکھا ہے؟ ظاہر ہے کہ نبی کریم صلی اللہ علیہ وسلم اس کے جواب میں انکار کریں گے۔ اس وقت کہنا کہ پھر یہ بو کیسی ہے جو آپ کے منہ سے معلوم کر رہی ہوں؟ اس پر نبی کریم صلی اللہ علیہ وسلم کہیں گے کہ حفصہ نے شہد کا شربت مجھے پلایا ہے۔ تم کہنا کہ غالباً اس شہد کی مکھی نے مغافیر کے درخت کا عرق چوسا ہو گا۔ میں بھی نبی کریم صلی اللہ علیہ وسلم سے یہی کہوں گی اور صفیہ تم بھی یہی کہنا۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ سودہ رضی اللہ عنہ کہتی تھیں کہ اللہ کی قسم! نبی کریم صلی اللہ علیہ وسلم جونہی دروازے پر آ کر کھڑے ہوئے تو تمہارے خوف سے میں نے ارادہ کیا کہ نبی کریم صلی اللہ علیہ وسلم سے وہ بات کہوں جو تم نے مجھ سے کہی تھی۔ چنانچہ جب نبی کریم صلی اللہ علیہ وسلم سودہ رضی اللہ عنہا کے قریب تشریف لے گئے تو انہوں نے کہا: یا رسول اللہ! کیا آپ نے مغافیر کھایا ہے؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ نہیں۔ انہوں نے کہا، پھر یہ بو کیسی ہے جو آپ کے منہ سے محسوس کرتی ہوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ حفصہ نے مجھے شہد کا شربت پلایا ہے۔ اس پر سودہ رضی اللہ عنہ بولیں اس شہد کی مکھی نے مغافیر کے درخت کا عرق چوسا ہو گا۔ پھر جب نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے تو میں نے بھی یہی بات کہی اس کے بعد جب صفیہ رضی اللہ عنہا کے یہاں تشریف لے گئے تو انہوں نے بھی اسی کو دہرایا۔ اس کے بعد جب پھر نبی کریم صلی اللہ علیہ وسلم حفصہ رضی اللہ عنہا کے یہاں تشریف لے گئے تو انہوں نے عرض کیا: یا رسول اللہ! وہ شہد پھر نوش فرمائیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مجھے اس کی ضرورت نہیں ہے۔ عائشہ رضی اللہ عنہا نے بیان کیا کہ اس پر سودہ بولیں، واللہ! ہم نبی کریم صلی اللہ علیہ وسلم کو روکنے میں کامیاب ہو گئے، میں نے ان سے کہا کہ ابھی چپ رہو۔' WHERE id = 5060;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ اور ہمام نے بیان کیا، ان سے قتادہ نے، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ میں نے انہیں غلام دیکھا تھا۔ آپ کی مراد بریرہ رضی اللہ عنہا کے شوہر ( مغیث ) سے تھی۔' WHERE id = 5071;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے کہا، ان سے سفیان بن عیینہ نے، ان سے یحییٰ بن سعید نے، ان سے منبعث کے مولیٰ یزید نے کہ نبی کریم صلی اللہ علیہ وسلم سے کھوئی ہوئی بکری کے متعلق سوال کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے پکڑ لو، کیونکہ یا وہ تمہاری ہو گی ( اگر ایک سال تک اعلان کے بعد اس کا مالک نہ ملا ) ۔ تمہارے کسی بھائی کی ہو گی یا پھر بھیڑیے کی ہو گی ( اگر انہی جنگلوں میں پھرتی رہی ) اور آپ صلی اللہ علیہ وسلم سے کھوئے ہوئے اونٹ کے متعلق سوال کیا گیا تو آپ غصہ ہو گئے اور غصہ کی وجہ سے آپ کے دونوں رخسار سرخ ہو گئے اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں اس سے کیا غرض! اس کے پاس ( مضبوط ) کھر ہیں ( جس کی وجہ سے چلنے میں اسے کوئی دشواری نہیں ہو گی ) اس کے پاس مشکیزہ ہے جس سے وہ پانی پیتا رہے گا اور درخت کے پتے کھاتا رہے گا، یہاں تک کہ اس کا مالک اسے پالے گا۔ اور نبی کریم صلی اللہ علیہ وسلم سے لقطہٰ کے متعلق سوال کیا گیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اس کی رسی کا ( جس سے وہ بندھا ہو ) اور اس کے ظرف کا ( جس میں وہ رکھا ہو ) اعلان کرو اور اس کا ایک سال تک اعلان کرو، پھر اگر کوئی ایسا شخص آ جائے جو اسے پہچانتا ہو ( اور اس کا مالک ہو تو اسے دے دو ) ورنہ اسے اپنے مال کے ساتھ ملا لو۔ سفیان بن عیینہ نے بیان کیا کہ پھر میں ربیعہ بن عبدالرحمٰن سے ملا اور مجھے ان سے اس کے سوا اور کوئی چیز محفوظ نہیں ہے۔ میں نے ان سے پوچھا تھا کہ گم شدہ چیزوں کے بارے میں منبعث کے مولیٰ یزید کی حدیث کے بارے میں آپ کا کیا خیال ہے؟ کیا وہ زید بن خالد سے منقول ہے؟ تو انہوں نے کہا کہ ہاں ( سفیان نے بیان کیا کہ ہاں ) یحییٰ نے بیان کیا کہ ربیعہ نے منبعث کے مولیٰ یزید سے بیان کیا، ان سے زید بن خالد نے۔ سفیان نے بیان کیا کہ پھر میں نے ربیعہ سے ملاقات کی اور ان سے اس کے متعلق پوچھا۔' WHERE id = 5083;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے جبلہ بن سحیم نے بیان کیا، انہوں نے ابن عمر رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ مہینہ اتنے، اتنے اور اتنے دنوں کا ہوتا ہے۔ آپ کی مراد تیس دن سے تھی۔ پھر فرمایا اور اتنے، اتنے اور اتنے دنوں کا بھی ہوتا ہے۔ آپ کا اشارہ انتیس دنوں کی طرف تھا۔ ایک مرتبہ آپ صلی اللہ علیہ وسلم نے تیس کی طرف اشارہ کیا اور دوسری مرتبہ انتیس کی طرف۔' WHERE id = 5093;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا کہ عمرو نے کہا کہ میں نے سعید بن جبیر سے سنا، انہوں نے بیان کیا کہ میں نے ابن عمر رضی اللہ عنہما سے لعان کرنے والوں کا حکم پوچھا تو انہوں نے بیان کیا کہ ان کے متعلق رسول اللہ صلی اللہ علیہ وسلم نے فرمایا تھا کہ تمہارا حساب تو اللہ تعالیٰ کے ذمہ ہے۔ تم میں سے ایک جھوٹا ہے۔ اب تمہیں تمہاری بیوی پر کوئی اختیار نہیں۔ ان صحابی نے عرض کیا کہ میرا مال واپس کرا دیجئیے ( جو مہر میں دیا گیا تھا ) ۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اب وہ تمہارا مال نہیں ہے۔ اگر تم اس کے معاملہ میں سچے ہو تو تمہارا یہ مال اس کے بدلہ میں ختم ہو چکا کہ تم نے اس کی شرمگاہ کو حلال کیا تھا اور اگر تم نے اس پر جھوٹی تہمت لگائی تھی پھر تو وہ تم سے بعید تر ہے۔ سفیان نے بیان کیا کہ یہ حدیث میں نے عمرو سے یاد کی اور ایوب نے بیان کیا کہ میں نے سعید بن جبیر سے سنا، کہا کہ میں نے ابن عمر رضی اللہ عنہما سے ایسے شخص کے متعلق پوچھا جس نے اپنی بیوی سے لعان کیا ہو تو آپ نے اپنی دو انگلیوں سے اشارہ کیا۔ سفیان نے اس اشارہ کو اپنی دو شہادت اور بیچ کی انگلیوں کو جدا کر کے بتایا کہ نبی کریم صلی اللہ علیہ وسلم نے قبیلہ بنی عجلان کے میاں بیوی کے درمیان جدائی کرائی تھی اور فرمایا تھا کہ اللہ جانتا ہے کہ تم میں سے ایک جھوٹا ہے، تو کیا وہ رجوع کر لے گا؟ آپ نے تین مرتبہ یہ فرمایا۔ علی بن عبداللہ مدینی نے کہا کہ سفیان بن عیینہ نے مجھ سے کہا، میں نے یہ حدیث جیسے عمرو بن دینار اور ایوب سے سن کر یاد رکھی تھی ویسی ہی تجھ سے بیان کر دی۔' WHERE id = 5103;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن سلام نے بیان کیا، کہا ہم کو عبدالوہاب ثقفی نے خبر دی، ان سے یونس بن عبید نے بیان کیا، ان سے امام حسن بصری نے بیان کیا کہ معقل بن یسار رضی اللہ عنہ نے اپنی بہن جمیلہ کا نکاح کیا، پھر ( ان کے شوہر نے ) انہیں ایک طلاق دی۔' WHERE id = 5117;
UPDATE hadiths SET urdu = 'ہم سے فضل بن دکین نے بیان کیا، کہا ہم سے عبدالسلام بن حرب نے بیان کیا، ان سے ہشام بن حسان نے، ان سے حفصہ بنت سیرین نے اور ان سے ام عطیہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو عورت اللہ اور آخرت کے دن پر ایمان رکھتی ہو اس کے لیے جائز نہیں کہ تین دن سے زیادہ کسی کا سوگ منائے سوا شوہر کے وہ اس کے سوگ میں نہ سرمہ لگائے نہ رنگا ہوا کپڑا پہنے مگر یمن کا دھاری دار کپڑا ( جو بننے سے پہلے ہی رنگا گیا ہو ) ۔' WHERE id = 5129;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ فرماتا ہے کہ اے ابن آدم! تو خرچ کر تو میں تجھ کو دیئے جاؤں گا۔' WHERE id = 5139;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن زبیر حمیدی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے عبیداللہ بن ابی یزید نے بیان کیا، انہوں نے مجاہد سے سنا، انہوں نے عبداللہ بن ابی لیلیٰ سے سنا، ان سے علی بن ابی طالب رضی اللہ عنہ بیان کرتے تھے کہ فاطمہ رضی اللہ عنہا رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئی تھیں اور آپ سے ایک خادم مانگا تھا، پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا میں تمہیں ایک ایسی چیز نہ بتا دوں جو تمہارے لیے اس سے بہتر ہو۔ سوتے وقت تینتیس ( 33 ) مرتبہ «سبحان الله»،‏‏‏‏ تینتیس ( 33 ) مرتبہ «الحمد الله» اور چونتیس ( 34 ) مرتبہ «الله اكبر» پڑھ لیا کرو۔ سفیان بن عیینہ نے کہا کہ ان میں سے ایک کلمہ چونتیس بار کہہ لے۔ علی رضی اللہ عنہ نے کہا کہ پھر میں نے ان کلموں کو کبھی نہیں چھوڑا۔ ان سے پوچھا گیا جنگ صفین کی راتوں میں بھی نہیں؟ کہا کہ صفین کی راتوں میں بھی نہیں۔' WHERE id = 5149;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں عروہ نے خبر دی، ان کو ابوسلمہ کی صاحبزادی زینب نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام حبیبہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! میری بہن ( عزہ بنت ابی سفیان ) بنت ابی سفیان سے نکاح کر لیجئے۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ اور تم اسے پسند بھی کرو گی ( کہ تمہاری بہن تمہاری سوکن بن جائے ) ؟ میں نے عرض کیا جی ہاں، اس سے خالی تو میں اب بھی نہیں ہوں اور میں پسند کرتی ہوں کہ اپنی بہن کو بھی بھلائی میں اپنے ساتھ شریک کر لوں۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ یہ میرے لیے جائز نہیں ہے۔ ( دو بہنوں کو ایک ساتھ نکاح میں جمع کرنا ) میں نے عرض کیا: یا رسول اللہ! واللہ اس طرح کی باتیں ہو رہی ہیں کہ آپ درہ بنت ابی سلمہ سے نکاح کا ارادہ رکھتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ ام سلمہ کی بیٹی۔ جب میں نے عرض کیا، جی ہاں تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر وہ میری پرورش میں نہ ہوتی جب بھی وہ میرے لیے حلال نہیں تھی وہ تو میرے رضاعی بھائی کی لڑکی ہے۔ مجھے اور ابوسلمہ کو ثوبیہ نے دودھ پلایا تھا۔ پس تم میرے لیے اپنی لڑکیوں اور بہنوں کو نہ پیش کیا کرو۔ اور شعیب نے بیان کیا، ان سے زہری نے اور ان سے عروہ نے، کہا کہ ثوبیہ کو ابولہب نے آزاد کیا تھا۔' WHERE id = 5159;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا، ان سے ان کے والد نے بیان کیا، انہوں نے کہا کہ ابوعثمان نہدی نے بھی بیان کیا اور ان سے عبدالرحمٰن بن ابی بکر رضی اللہ عنہما نے بیان کیا کہ ہم ایک سو تیس آدمی نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے۔ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تم میں سے کسی کے پاس کھانا ہے۔ ایک صاحب نے اپنے پاس سے ایک صاع کے قریب آٹا نکالا، اسے گوندھ لیا گیا، پھر ایک مشرک لمبا تڑنگا اپنی بکریاں ہانکتا ہوا ادھر آ گیا۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے دریافت فرمایا کہ یہ بیچنے کی ہیں یا عطیہ ہیں یا نبی کریم صلی اللہ علیہ وسلم نے ( عطیہ کے بجائے ) ہبہ فرمایا۔ اس شخص نے کہا کہ نہیں بلکہ بیچنے کی ہیں۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اس سے ایک بکری خریدی پھر ذبح کی گئی اور آپ نے اس کی کلیجی بھونے جانے کا حکم دیا اور قسم اللہ کی ایک سو تیس لوگوں کی جماعت میں کوئی شخص ایسا نہیں رہا جسے نبی کریم صلی اللہ علیہ وسلم نے اس بکری کی کلیجی کا ایک ایک ٹکڑا کاٹ کر نہ دیا ہو مگر وہ موجود تھا تو اسے وہیں دے دیا اور اگر وہ موجود نہیں تھا تو اس کا حصہ محفوظ رکھا، پھر اس بکری کے گوشت کو پکا کر دو بڑے کونڈوں میں رکھا اور ہم سب نے ان میں سے پیٹ بھر کر کھایا پھر بھی دونوں کونڈوں میں کھانا بچ گیا تو میں نے اسے اونٹ پر لاد لیا۔ عبدالرحمٰن راوی نے ایسا ہی کوئی کلمہ کہا۔' WHERE id = 5169;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ دو آدمیوں کا کھانا تین کے لیے کافی ہے اور تین کا چار کے لیے کافی ہے۔' WHERE id = 5179;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کی، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ میری خالہ نے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں ساہنہ کا گوشت، پنیر اور دودھ ہدیتاً پیش کیا تو ساہنہ کا گوشت آپ کے دستر خوان پر رکھا گیا اور اگر ساہنہ حرام ہوتا تو آپ کے دستر خوان پر نہیں رکھا جا سکتا تھا لیکن آپ نے دودھ پیا اور پنیر کھایا۔' WHERE id = 5189;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے وہب بن جریر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے اسماعیل بن ابی خالد نے، ان سے قیس بن ابی حازم نے اور ان سے سعد بن ابی وقاص رضی اللہ عنہ نے بیان کیا کہ میں نے اپنے آپ کو نبی کریم صلی اللہ علیہ وسلم کے ساتھ ان سات آدمیوں میں سے ساتواں پایا ( جنہوں نے اسلام سب سے پہلے قبول کیا تھا ) اس وقت ہمارے پاس کھانے کے لیے یہی کیکر کے پھل یا پتے کے سوا اور کچھ نہیں ہوتا۔ یہ کھاتے کھاتے ہم لوگوں کا پاخانہ بھی بکری کی مینگنیوں کی طرح ہو گیا تھا یا اب یہ زمانہ ہے کہ بنی اسد قبیلے کے لوگ مجھ کو شریعت کے احکام سکھلاتے ہیں۔ اگر میں ابھی تک اس حال میں ہوں کہ بنی اسد کے لوگ مجھ کو شریعت کے احکام سکھلائیں تب تو میں تباہ ہی ہو گیا میری محنت برباد ہو گئی۔' WHERE id = 5199;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں زہری نے، انہیں جعفر بن عمر بن امیہ ضمری نے، انہیں ان کے والد نے، انہوں نے بیان کیا کہ میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم بکری کے شانہ میں سے گوشت کاٹ رہے تھے، پھر آپ نے اس میں سے کھایا۔ پھر آپ کو نماز کے لیے بلایا گیا تو آپ کھڑے ہو گئے اور چھری ڈال دی اور نماز پڑھی لیکن نیا وضو نہیں کیا۔' WHERE id = 5209;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن شیبہ نے بیان کیا، کہا کہ مجھے ابن ابی الفدیک نے خبر دی، انہیں ابن ابی ذئب نے، انہیں مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں پیٹ بھرنے کے بعد ہر وقت نبی کریم صلی اللہ علیہ وسلم کے ساتھ ہی رہا کرتا تھا۔ اس وقت میں روٹی نہیں کھاتا تھا۔ نہ ریشم پہنتا تھا، نہ فلاں اور فلانی میری خدمت کرتے تھے ( بھوک کی شدت کی وجہ سے بعض اوقات ) میں اپنے پیٹ پر کنکریاں لگا لیتا اور کبھی میں کسی سے کوئی آیت پڑھنے کے لیے کہتا حالانکہ وہ مجھے یاد ہوتی۔ مقصد صرف یہ ہوتا کہ وہ مجھے اپنے ساتھ لے جائے اور کھانا کھلا دے اور مسکینوں کے لیے سب سے بہترین شخص جعفر بن ابی طالب رضی اللہ عنہ تھے، ہمیں اپنے گھر ساتھ لے جاتے اور جو کچھ بھی گھر میں ہوتا کھلا دیتے تھے۔ کبھی تو ایسا ہوتا کہ گھی کا ڈبہ نکال کر لاتے اور اس میں کچھ نہ ہوتا۔ ہم اسے پھاڑ کر اس میں جو کچھ لگا ہوتا چاٹ لیتے تھے۔' WHERE id = 5219;
UPDATE hadiths SET urdu = 'اور محمد بن یوسف نے بیان کیا، ان سے سفیان نے بیان کیا، ان سے منصور ابن صفیہ نے، ان سے ان کی والدہ نے بیان کیا اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کی وفات ہو گئی اور ہم پانی اور کھجور ہی سے ( اکثر دنوں میں ) پیٹ بھرتے رہے۔' WHERE id = 5230;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ابوصفوان عبداللہ بن سعید نے بیان کیا، کہا ہم کو یونس نے خبر دی، ان سے ابن شہاب نے بیان کیا، ان سے عطاء نے بیان کیا کہ جابر بن عبداللہ رضی اللہ عنہما کہتے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے لہسن یا پیاز کھائی ہو تو اسے چاہئے کہ ہم سے دور رہے، یا یہ فرمایا کہ ہماری مسجد سے دور رہے۔' WHERE id = 5240;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے اور لیث نے بیان کیا، کہا انہوں نے کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہیں جعفر بن عمرو بن امیہ رضی اللہ عنہ نے خبر دی، انہیں ان کے والد عمرو بن امیہ نے خبر دی کہ انہوں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم اپنے ہاتھ سے بکری کے شانے کا گوشت کاٹ کاٹ کر کھا رہے تھے، پھر آپ کو نماز کے لیے بلایا گیا تو آپ گوشت اور چھری جس سے آپ کاٹ رہے تھے، چھوڑ کر کھڑے ہو گئے اور نماز پڑھائی اور اس نماز کے لیے نیا وضو نہیں کیا۔' WHERE id = 5250;
UPDATE hadiths SET urdu = 'اور اصبغ بن فرج نے بیان کیا کہ مجھے عبداللہ بن وہب نے خبر دی، انہیں جریر بن حازم نے، انہیں ایوب سختیانی نے، انہیں محمد بن سیرین نے کہ ہم سے سلمان بن عامر الضبی رضی اللہ عنہ نے بیان کیا، کہا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ لڑکے کے ساتھ اس کا عقیقہ لگا ہوا ہے اس لیے اس کی طرف سے جانور ذبح کرو اور اس سے بال دور کرو ( سر منڈا دو یا ختنہ کرو ) ۔' WHERE id = 5261;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ جس نے مویشی کی حفاظت یا شکار کی غرض کے سوا کسی اور وجہ سے کتا پالا اس کے ثواب سے روزانہ دو قیراط کی کمی ہو جاتی ہے۔' WHERE id = 5271;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، کہا کہ مجھ سے ابن وہب نے بیان کیا، انہیں عمرو نے خبر دی، ان سے ابوالنضر نے بیان کیا، ان سے ابوقتادہ کے غلام نافع اور توامہ کے غلام ابوصالح نے کہ انہوں نے ابوقتادہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں مکہ اور مدینہ کے درمیان راستے میں نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھا۔ دوسرے لوگ تو احرام باندھے ہوئے تھے لیکن میں احرام میں نہیں تھا اور ایک گھوڑے پر سوار تھا۔ میں پہاڑوں پر چڑھنے کا بڑا عادی تھا پھر اچانک میں نے دیکھا کہ لوگ للچائی ہوئی نظروں سے کوئی چیز دیکھ رہے ہیں۔ میں نے جو دیکھا تو ایک گورخر تھا۔ میں نے ان سے پوچھا کہ یہ کیا ہے؟ لوگوں نے کہا ہمیں معلوم نہیں! میں نے کہا کہ یہ تو گورخر ہے۔ لوگوں نے کہا کہ جو تم نے دیکھا ہے وہی ہے۔ میں اپنا کوڑا بھول گیا تھا اس لیے ان سے کہا کہ مجھے میرا کوڑا دے دو لیکن انہوں نے کہا کہ ہم اس میں تمہاری کوئی مدد نہیں کریں گے ( کیونکہ ہم محرم ہیں ) میں نے اتر کر خود کوڑا اٹھایا اور اس کے پیچھے سے اسے مارا، وہ وہیں گر گیا پھر میں نے اسے ذبح کیا اور اپنے ساتھیوں کے پاس اسے لے کر آیا۔ میں نے کہا کہ اب اٹھو اور اسے اٹھاؤ، انہوں نے کہا کہ ہم اسے نہیں چھوئیں گے۔ چنانچہ میں ہی اسے اٹھا کر ان کے پاس لایا۔ بعض نے تو اس کا گوشت کھایا لیکن بعض نے انکار کر دیا پھر میں نے ان سے کہا کہ اچھا میں اب تمہارے لیے نبی کریم صلی اللہ علیہ وسلم سے رکنے کی درخواست کروں گا۔ میں نبی کریم صلی اللہ علیہ وسلم کے پاس پہنچا اور آپ سے واقعہ بیان کیا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے پاس اس میں سے کچھ باقی بچا ہے؟ میں نے عرض کیا جی ہاں۔ فرمایا کھاؤ کیونکہ یہ ایک کھانا ہے جو اللہ تعالیٰ نے تم کو کھلایا ہے۔' WHERE id = 5281;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، کہا ہم سے جویریہ نے بیان کیا، ان سے نافع نے، ان سے بنی سلمہ کے ایک صاحب (ابن کعب بن مالک) نے کہ انہوں نے ابن عمر رضی اللہ عنہما کو یہ خبر دی کہ کعب بن مالک رضی اللہ عنہ کی ایک لونڈی اس پہاڑی پر جو ”سوق مدنی“ میں ہے اور جس کا نام سلع ہے، بکریاں چرایا کرتی تھی۔ ایک بکری مرنے کے قریب ہو گئی تو اس نے ایک پتھر توڑ کر اس سے بکری کو ذبح کر لیا، پھر لوگوں نے رسول اللہ صلی اللہ علیہ وسلم سے اس کا ذکر کیا تو نبی کریم صلی اللہ علیہ وسلم نے اسے کھانے کی اجازت عطا فرمائی۔' WHERE id = 5291;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے ہشام نے، ان سے فاطمہ بنت منذر نے کہ اسماء بنت ابی بکر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کے زمانہ میں ہم نے ایک گھوڑے کو نحر کیا ( اس کے سینے کے اوپر کے حصہ میں چھری مار کر ) پھر اسے کھایا۔ اس کی متابعت وکیع اور ابن عیینہ نے ہشام سے «نحر‏.‏» کے ذکر کے ساتھ کی۔' WHERE id = 5301;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے، کہا مجھ سے نافع نے بیان کیا اور ان سے عبداللہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے پالتو گدھوں کے گوشت کی ممانعت کی تھی۔ اس روایت کی متابعت ابن مبارک نے کی تھی، ان سے نافع نے اور ابواسامہ نے بیان کیا، ان سے عبیداللہ نے اور ان سے سالم نے اسی طرح سے بیان کیا۔' WHERE id = 5311;
UPDATE hadiths SET urdu = 'ہم سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید بن عبداللہ نے، ان سے بردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نیک اور برے دوست کی مثال مشک ساتھ رکھنے والے اور بھٹی دھونکنے والے کی سی ہے ( جس کے پاس مشک ہے اور تم اس کی محبت میں ہو ) وہ اس میں سے یا تمہیں کچھ تحفہ کے طور پر دے گا یا تم اس سے خرید سکو گے یا ( کم از کم ) تم اس کی عمدہ خوشبو سے تو محظوظ ہو ہی سکو گے اور بھٹی دھونکنے والا یا تمہارے کپڑے ( بھٹی کی آگ سے ) جلا دے گا یا تمہیں اس کے پاس سے ایک ناگوار بدبودار دھواں پہنچے گا۔' WHERE id = 5322;
UPDATE hadiths SET urdu = 'ہم سے ابن سلام نے بیان کیا، کہا ہم کو عمر بن عبید الطنافسی نے خبر دی، انہیں سعید بن مسروق نے، ان سے عبایہ بن رفاعہ نے، ان سے ان کے دادا رافع بن خدیج رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ ایک سفر میں تھے۔ ایک اونٹ بدک کر بھاگ پڑا، پھر ایک آدمی نے تیر سے اسے مارا اور اللہ تعالیٰ نے اسے روک دیا۔ بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ اونٹ بھی بعض اوقات جنگلی جانوروں کی طرح بدکتے ہیں، اس لیے ان میں سے جو تمہارے قابو سے باہر ہو جائیں، ان کے ساتھ ایسا ہی کیا کرو۔ رافع نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! ہم اکثر غزوات اور دوسرے سفروں میں رہتے ہیں اور جانور ذبح کرنا چاہتے ہیں لیکن ہمارے پاس چھریاں نہیں ہوتیں۔ فرمایا کہ دیکھ لیا کرو جو آلہ خون بہا دے یا ( آپ نے بجائے «نهر» کے ) «أنهر» فرمایا اور اس پر اللہ کا نام لیا گیا ہو تو اسے کھاؤ۔ البتہ دانت اور ناخن نہ ہو کیونکہ دانت ہڈی ہے اور ناخن حبش والوں کی چھری ہے۔' WHERE id = 5332;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے عبدالوہاب نے بیان کیا، ان سے ایوب نے، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم سینگ والے دو چتکبرے مینڈھوں کی طرف متوجہ ہوئے اور انہیں اپنے ہاتھ سے ذبح کیا۔ اس کی متابعت وہیب نے کی، ان سے ایوب نے اور اسماعیل اور حاکم بن وردان نے بیان کیا کہ ان سے ایوب نے، ان سے محمد بن سیرین نے اور ان سے انس رضی اللہ عنہ نے بیان کیا۔' WHERE id = 5342;
UPDATE hadiths SET urdu = 'ہم سے حجاج بن منہال نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے، انہوں نے کہا کہ ہم سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سینگ والے دو چتکبرے مینڈھوں کی قربانی کیا کرتے تھے اور نبی کریم صلی اللہ علیہ وسلم اپنا پاؤں ان کی گردنوں کے اوپر رکھتے اور انہیں اپنے ہاتھ سے ذبح کرتے تھے۔' WHERE id = 5352;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، انہوں نے کہا ہم کو یعقوب بن ابراہیم بن سعد نے خبر دی، انہیں ابن شہاب کے بھتیجے نے، انہیں ان کے چچا ابن شہاب (محمد بن مسلم) نے، انہیں سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ قربانی کا گوشت تین دن تک کھاؤ۔ عبداللہ بن عمر رضی اللہ عنہما منیٰ سے کوچ کرتے وقت روٹی زیتون کے تیل سے کھاتے کیونکہ وہ قربانی کے گوشت سے ( تین دن کے بعد ) پرہیز کرتے تھے۔' WHERE id = 5362;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی بکر مقدمی نے بیان کیا، انہوں نے کہا ہم سے یوسف ابومعشر براء نے بیان کیا، انہوں نے کہا کہ میں نے سعید بن عبداللہ سے سنا، انہوں نے کہا کہ مجھ سے بکر بن عبداللہ نے بیان کیا اور انہوں نے کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ جب شراب حرام کی گئی تو وہ کچی اور پختہ کھجوروں سے تیار کی جاتی تھی۔' WHERE id = 5372;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے، کہ ان سے سفیان بن عیینہ نے، ان سے سفیان ثوری نے، ان سے ابراہیم تیمی نے، ان سے حارث بن سوید نے اور ان سے علی رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے دباء اور مزفت ( خاص قسم کے برتن جن میں شراب بنتی تھی ) کے استعمال کی بھی ممانعت کر دی تھی۔ ہم سے عثمان نے بیان کیا، کہا ہم سے جریر نے بیان کیا، کہا ان سے اعمش نے یہی حدیث بیان کی۔' WHERE id = 5382;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، انہوں نے سفیان بن عیینہ سے سنا، انہوں نے کہا کہ ہم کو سالم ابوالنضر نے خبر دی، انہوں نے ام الفضل (والدہ عبداللہ بن عباس) کے غلام عمیر سے سنا، وہ ام الفضل رضی اللہ عنہا سے بیان کرتے ہیں، انہوں نے بیان کیا کہ عرفہ کے دن رسول اللہ صلی اللہ علیہ وسلم کے روزہ کے بارے میں صحابہ کرام رضی اللہ عنہم کو شبہ تھا۔ اس لیے میں نے آپ کے لیے ایک برتن میں دودھ بھیجا اور نبی کریم صلی اللہ علیہ وسلم نے اسے پی لیا۔ حمیدی کہتے ہیں کبھی سفیان اس حدیث کو یوں بیان کرتے تھے کہ عرفہ کے دن رسول اللہ صلی اللہ علیہ وسلم کے روزہ کے بارے میں لوگوں کو شبہ تھا اس لیے ام الفضل نے نبی کریم صلی اللہ علیہ وسلم کے لیے ( دودھ ) بھیجا۔ کبھی سفیان اس حدیث کو مرسلاً ام الفضل سے روایت کرتے تھے سالم اور عمیر کا نام نہ لیتے۔ جب ان سے پوچھتے کہ یہ حدیث مرسل ہے یا مرفوع متصل تو وہ اس وقت کہتے ( مرفوع متصل ہے ) ام فضل سے مروی ہے ( جو صحابیہ تھیں ) ۔' WHERE id = 5392;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، کہا کہ مجھے ہشام نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم شیرینی اور شہد کو دوست رکھتے تھے۔' WHERE id = 5402;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے عطاء بن ابی رباح نے اور ان سے جابر بن عبداللہ انصاری رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ تم جب سونے لگو تو چراغ بجھا دو۔ دروازے بند کر دو، مشکوں کے منہ باندھ دو اور کھانے پینے کے برتنوں کو ڈھانپ دو۔ جابر رضی اللہ عنہ نے کہا کہ میرا خیال ہے کہ یہ بھی کہا خواہ لکڑی ہی کے ذریعہ سے ڈھک سکو جو اس کی چوڑائی میں بسم اللہ کہہ کر رکھ دی جائے۔' WHERE id = 5412;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، انہوں نے کہا کہ مجھ سے امام مالک بن انس نے بیان کیا، ان سے نافع نے، ان سے زید بن عبداللہ بن عمر نے، ان سے عبداللہ بن عبدالرحمٰن بن ابی بکر صدیق رضی اللہ عنہ نے بیان کیا اور ان سے نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ ام سلمہ رضی اللہ عنہا نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص چاندی کے برتن میں کوئی چیز پیتا ہے تو وہ شخص اپنے پیٹ میں دوزخ کی آگ بھڑکا رہا ہے۔' WHERE id = 5422;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ نے بیان کیا، انہوں نے کہا ہم سے سفیان سے بیان کیا، ان سے اعمش نے (دوسری سند) اور امام بخاری رحمہ اللہ نے کہا کہ مجھ سے بشر بن محمد نے بیان کیا، انہوں نے کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو شعبہ نے خبر دی، انہیں اعمش نے، انہیں ابووائل نے، انہیں مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے ( مرض وفات کی تکلیف ) رسول اللہ صلی اللہ علیہ وسلم سے زیادہ اور کسی میں نہیں دیکھی۔' WHERE id = 5433;
UPDATE hadiths SET urdu = 'ہم سے معلی بن اسد نے بیان کیا، کہا ہم سے عبدالعزیز بن مختار نے بیان کیا، کہا ہم سے خالد نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم ایک دیہاتی کے پاس اس کی عیادت کے لیے تشریف لے گئے۔ راوی نے بیان کیا کہ جب نبی کریم صلی اللہ علیہ وسلم کسی کی عیادت کو تشریف لے جاتے تو مریض سے فرماتے «لا بأس طهور إن شاء الله» ”کوئی فکر کی بات نہیں۔ ان شاءاللہ یہ مرض گناہوں سے پاک کرنے والا ہے“ لیکن اس دیہاتی نے آپ کے ان مبارک کلمات کے جواب میں کہا کہ آپ کہتے ہیں کہ یہ پاک کرنے والا ہے ہرگز نہیں بلکہ یہ بخار ایک بوڑھے پر غالب آ گیا ہے اور اسے قبر تک پہنچا کے رہے گا۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایسا ہی ہو گا۔' WHERE id = 5443;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن یحییٰ ابوزکریا نے بیان کیا، کہا ہم کو سلیمان بن بلال نے خبر دی، ان سے یحییٰ بن سعید نے، کہ میں نے قاسم بن محمد سے سنا، انہوں نے بیان کیا کہ ( سر کے شدید درد کی وجہ سے ) عائشہ رضی اللہ عنہا نے کہا: ہائے رے سر! اس پر رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر ایسا میری زندگی میں ہو گیا ( یعنی تمہارا انتقال ہو گیا ) تو میں تمہارے لیے استغفار اور دعا کروں گا۔ عائشہ رضی اللہ عنہا نے کہا افسوس، اللہ کی قسم! میرا خیال ہے کہ آپ میرا مر جانا ہی پسند کرتے ہیں اور اگر ایسا ہو گیا تو آپ تو اسی دن رات اپنی کسی بیوی کے یہاں گزاریں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا بلکہ میں خود درد سر میں مبتلا ہوں۔ میرا ارادہ ہوتا تھا کہ ابوبکر رضی اللہ عنہ اور ان کے بیٹے کو بلا بھیجوں اور انہیں ( خلافت کی ) وصیت کر دوں۔ کہیں ایسا نہ ہو کہ میرے بعد کہنے والے کچھ اور کہیں ( کہ خلافت ہمارا حق ہے ) یا آرزو کرنے والے کسی اور بات کی آرزو کریں ( کہ ہم خلیفہ ہو جائیں ) پھر میں نے اپنے جی میں کہا ( اس کی ضرورت ہی کیا ہے ) خود اللہ تعالیٰ ابوبکر رضی اللہ عنہ کے سوا اور کسی کو خلیفہ نہ ہونے دے گا نہ مسلمان اور کسی کی خلافت ہی قبول کریں گے۔' WHERE id = 5453;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر (محمد بن جعفر) نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے محمد بن منکدر نے، کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میرے یہاں تشریف لائے میں بیمار تھا نبی کریم صلی اللہ علیہ وسلم نے وضو کیا اور وضو کا پانی مجھ پر ڈالا یا فرمایا کہ اس پر یہ پانی ڈال دو اس سے مجھے ہوش آ گیا۔ میں نے عرض کیا کہ میں تو کلالہ ہوں ( جس کے والد اور اولاد نہ ہو ) میرے ترکہ میں تقسیم کیسے ہو گی اس پر میراث کی آیت نازل ہوئی۔' WHERE id = 5463;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ہمام نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ ( عرینہ کے ) کچھ لوگوں کو مدینہ منورہ کی آب و ہوا موافق نہیں آئی تھی تو نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ وہ آپ ( نبی کریم صلی اللہ علیہ وسلم ) کے چرواہے کے ہاں چلے جائیں یعنی اونٹوں میں اور ان کا دودھ اور پیشاب پئیں۔ چنانچہ وہ لوگ نبی کریم صلی اللہ علیہ وسلم کے چرواہے کے پاس چلے گئے اور اونٹوں کا دودھ اور پیشاب پیا جب وہ تندرست ہو گئے تو انہوں نے چرواہے کو قتل کر دیا اور اونٹوں کو ہانک کر لے گئے۔ آپ کو جب اس کا علم ہوا تو آپ نے انہیں تلاش کرنے کے لیے لوگوں کو بھیجا جب انہیں لایا گیا تو نبی کریم صلی اللہ علیہ وسلم کے حکم سے ان کے بھی ہاتھ اور پاؤں کاٹ دیئے گئے اور ان کی آنکھوں میں سلائی پھیر دی گئی ( جیسا کہ انہوں نے چرواہے کے ساتھ کیا تھا ) ۔ قتادہ نے بیان کیا کہ مجھ سے محمد بن سیرین نے بیان کیا کہ یہ حدود کے نازل ہونے سے پہلے کا واقعہ ہے۔' WHERE id = 5473;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابان نے بیان کیا، انہوں نے کہا ہم سے عبدالرحمٰن بن غسیل نے بیان کیا، انہوں نے کہا کہ مجھ سے عاصم بن عمر نے بیان کیا، ان سے جابر بن عبداللہ رضی اللہ عنہما نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تمہاری دوائیوں میں کوئی بھلائی ہے تو شہد کے شربت میں ہے اور پچھنا لگوانے میں ہے اور آگ سے داغنے میں ہے لیکن میں آگ سے داغ کر علاج کو پسند نہیں کرتا۔' WHERE id = 5486;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے محمد بن جعفر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے قتادہ نے، ان سے ابوالمتوکل نے اور ان سے ابوسعید رضی اللہ عنہ نے کہ ایک صاحب رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا کہ میرے بھائی کو دست آ رہے ہیں نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہیں شہد پلاؤ۔ انہوں نے پلایا اور پھر واپس آ کر کہا کہ میں نے انہیں شہد پلایا لیکن ان کے دستوں میں کوئی کمی نہیں ہوئی۔ آپ صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اللہ تعالیٰ نے سچ فرمایا اور تمہارے بھائی کا پیٹ جھوٹا ہے ( آخر شہد ہی سے اسے شفاء ہوئی ) ۔ محمد بن جعفر کے ساتھ اس حدیث کو نضر بن شمیل نے بھی شعبہ سے روایت کیا ہے۔' WHERE id = 5497;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو امام مالک نے خبر دی، انہیں ابن شہاب نے، انہیں عبدالحمید بن عبدالرحمٰن بن زید بن خطاب نے، انہیں عبداللہ بن عبداللہ بن حارث بن نوفل نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ عمر بن خطاب رضی اللہ عنہ شام تشریف لے جا رہے تھے جب آپ مقام سرغ پر پہنچے تو آپ کی ملاقات فوجوں کے امراء ابوعبیدہ بن جراح رضی اللہ عنہ اور آپ کے ساتھیوں سے ہوئی۔ ان لوگوں نے امیرالمؤمنین کو بتایا کہ طاعون کی وبا شام میں پھوٹ پڑی ہے۔ ابن عباس رضی اللہ عنہما نے بیان کیا کہ اس پر عمر رضی اللہ عنہ نے کہا کہ میرے پاس مہاجرین اولین کو بلا لاؤ۔ آپ انہیں بلا لائے تو عمر رضی اللہ عنہ نے ان سے مشورہ کیا اور انہیں بتایا کہ شام میں طاعون کی وبا پھوٹ پڑی ہے، مہاجرین اولین کی رائیں مختلف ہو گئیں۔ بعض لوگوں نے کہا کہ صحابہ رسول اللہ صلی اللہ علیہ وسلم کے ساتھیوں کی باقی ماندہ جماعت آپ کے ساتھ ہے اور یہ مناسب نہیں ہے کہ آپ انہیں اس وبا میں ڈال دیں۔ عمر رضی اللہ عنہ نے کہا کہ اچھا اب آپ لوگ تشریف لے جائیں پھر فرمایا کہ انصار کو بلاؤ۔ میں انصار کو بلا کر لایا آپ نے ان سے بھی مشورہ کیا اور انہوں نے بھی مہاجرین کی طرح اختلاف کیا کوئی کہنے لگا چلو، کوئی کہنے لگا لوٹ جاؤ۔ امیرالمؤمنین نے فرمایا کہ اب آپ لوگ بھی تشریف لے جائیں پھر فرمایا کہ یہاں پر جو قریش کے بڑے بوڑھے ہیں جو فتح مکہ کے وقت اسلام قبول کر کے مدینہ آئے تھے انہیں بلا لاؤ، میں انہیں بلا کر لایا۔ ان لوگوں میں کوئی اختلاف رائے پیدا نہیں ہوا سب نے کہا کہ ہمارا خیال ہے کہ آپ لوگوں کو ساتھ لے کر واپس لوٹ چلیں اور وبائی ملک میں لوگوں کو نہ لے کر جائیں۔ یہ سنتے ہی عمر رضی اللہ عنہ نے لوگوں میں اعلان کرا دیا کہ میں صبح کو اونٹ پر سوار ہو کر واپس مدینہ منورہ لوٹ جاؤں گا تم لوگ بھی واپس چلو۔ صبح کو ایسا ہی ہوا ابوعبیدہ ابن جراح رضی اللہ عنہ نے کہا کیا اللہ کی تقدیر سے فرار اختیار کیا جائے گا۔ عمر رضی اللہ عنہ نے کہا: کاش! یہ بات کسی اور نے کہی ہوتی ہاں ہم اللہ کی تقدیر سے فرار اختیار کر رہے ہیں لیکن اللہ ہی کی تقدیر کی طرف۔ کیا تمہارے پاس اونٹ ہوں اور تم انہیں لے کر کسی ایسی وادی میں جاؤ جس کے دو کنارے ہوں ایک سرسبز شاداب اور دوسرا خشک۔ کیا یہ واقعہ نہیں کہ اگر تم سرسبز کنارے پر چراؤ گے تو وہ بھی اللہ کی تقدیر سے ہو گا۔ اور خشک کنارے پر چراؤ گے تو وہ بھی اللہ کی تقدیر سے ہی ہو گا۔ بیان کیا کہ پھر عبدالرحمٰن بن عوف رضی اللہ عنہ آ گئے وہ اپنی کسی ضرورت کی وجہ سے اس وقت موجود نہیں تھے انہوں نے بتایا کہ میرے پاس مسئلہ سے متعلق ایک علم ہے۔ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے آپ صلی اللہ علیہ وسلم نے فرمایا کہ جب تم کسی سر زمین میں ( وبا کے متعلق ) سنو تو وہاں نہ جاؤ اور جب ایسی جگہ وبا آ جائے جہاں تم خود موجود ہو تو وہاں سے مت نکلو۔ راوی نے بیان کیا کہ اس پر عمر رضی اللہ عنہ نے اللہ تعالیٰ کی حمد کی اور پھر واپس ہو گئے۔' WHERE id = 5508;
UPDATE hadiths SET urdu = 'ہم سے محمد بن خالد نے بیان کیا، کہا ہم سے محمد بن وہب بن عطیہ دمشقی نے بیان کیا، کہا ہم سے محمد بن حرب نے بیان کیا، کہا ہم سے محمد بن ولید زبیدی نے بیان کیا، کہا ہم کو زہری نے خبر دی، انہیں عروہ بن زبیر نے، انہیں زینب بنت ابی سلمہ رضی اللہ عنہا نے اور ان سے ام سلمہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ان کے گھر میں ایک لڑکی دیکھی جس کے چہرے پر ( نظر بد لگنے کی وجہ سے ) کالے دھبے پڑ گئے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس پر دم کرا دو کیونکہ اسے نظر بد لگ گئی ہے۔ اور عقیل نے کہا ان سے زہری نے، انہیں عروہ نے خبر دی اور انہوں نے اسے نبی کریم صلی اللہ علیہ وسلم سے مرسلاً روایت کیا ہے۔ محمد بن حرب کے ساتھ اس حدیث کو عبداللہ بن سالم نے بھی زبیدی سے روایت کیا ہے۔' WHERE id = 5518;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر (جعفر) ان سے ابوالمتوکل علی بن داؤد نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم کے چند صحابہ ( 300 نفر ) ایک سفر کے لیے روانہ ہوئے جسے انہیں طے کرنا تھا راستے میں انہوں نے عرب کے ایک قبیلہ میں پڑاؤ کیا اور چاہا کہ قبیلہ والے ان کی مہمانی کریں لیکن انہوں نے انکار کیا، پھر اس قبیلہ کے سردار کو بچھو نے کاٹ لیا اسے اچھا کرنے کی ہر طرح کی کوشش انہوں نے کر ڈالی لیکن کسی سے کچھ فائدہ نہیں ہوا۔ آخر انہیں میں سے کسی نے کہا کہ یہ لوگ جنہوں نے تمہارے قبیلہ میں پڑاؤ کر رکھا ہے ان کے پاس بھی چلو، ممکن ہے ان میں سے کسی کے پاس کوئی منتر ہو۔ چنانچہ وہ صحابہ کے پاس آئے اور کہا لوگو! ہمارے سردار کو بچھو نے کاٹ لیا ہے ہم نے ہر طرح کی بہت کوشش اس کے لیے کر ڈالی لیکن کسی سے کوئی فائدہ نہیں ہوا کیا تم لوگوں میں سے کسی کے پاس اس کے لیے منتر ہے؟ صحابہ میں سے ایک صاحب ( ابو سعید خدری رضی اللہ عنہ ) نے کہا کہ ہاں واللہ میں جھاڑنا جانتا ہوں لیکن ہم نے تم سے کہا تھا کہ ہماری مہمانی کرو ( ہم مسافر ہیں ) تو تم نے انکار کر دیا تھا اس لیے میں بھی اس وقت تک نہیں جھاڑوں گا جب تک تم میرے لیے اس کی مزدوری نہ ٹھہرا دو۔ چنانچہ ان لوگوں نے کچھ بکریوں ( 30 ) پر معاملہ کر لیا۔ اب یہ صحابی روانہ ہوئے۔ یہ زمین پر تھوکتے جاتے اور «‏‏‏‏الحمد لله رب العالمين» ‏‏‏‏ پڑھتے جاتے اس کی برکت سے وہ ایسا ہو گیا جیسے اس کی رسی کھل گئی ہو اور وہ اس طرح چلنے لگا جیسے اسے کوئی تکلیف ہی نہ رہی ہو۔ بیان کیا کہ پھر وعدہ کے مطابق قبیلہ والوں نے ان صحابی کی مزدوری ( 30 بکریاں ) ادا کر دی بعض لوگوں نے کہا کہ ان کو تقسیم کر لو لیکن جنہوں نے جھاڑا تھا انہوں نے کہا کہ ابھی نہیں، پہلے ہم رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوں پوری صورت حال آپ کے سامنے بیان کر دیں پھر دیکھیں نبی کریم صلی اللہ علیہ وسلم ہمیں کیا حکم فرماتے ہیں۔ چنانچہ سب لوگ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے تو آپ سے اس کا ذکر کیا آپ صلی اللہ علیہ وسلم نے فرمایا کہ تمہیں کیسے معلوم ہو گیا تھا کہ اس سے دم کیا جا سکتا ہے؟ تم نے اچھا کیا جاؤ ان کو تقسیم کر لو اور میرا بھی اپنے ساتھ ایک حصہ لگاؤ۔' WHERE id = 5528;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان ابن عیینہ نے بیان کیا، ان سے زہری نے، ان سے ابوبکر بن عبدالرحمٰن بن حارث نے اور ان سے ابومسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے کتے کی قیمت، زنا کی اجرت اور کاہن کی کہانت کی وجہ سے ملنے والے ہدیہ سے منع فرمایا ہے۔' WHERE id = 5539;
UPDATE hadiths SET urdu = 'اور ابوسلمہ سے روایت ہے انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ کوئی شخص اپنے بیمار اونٹوں کو کسی کے صحت مند اونٹوں میں نہ لے جائے۔ ابوہریرہ رضی اللہ عنہ نے پہلی حدیث کا انکار کیا۔ ہم نے ( ابوہریرہ رضی اللہ عنہ سے ) عرض کیا کہ آپ ہی نے ہم سے یہ حدیث نہیں بیان کی ہے کہ چھوت یہ نہیں ہوتا پھر وہ ( غصہ میں ) حبشی زبان بولنے لگے۔ ابوسلمہ بن عبدالرحمٰن نے بیان کیا کہ اس حدیث کے سوا میں نے ابوہریرہ رضی اللہ عنہ کو اور کوئی حدیث بھولتے نہیں دیکھا۔' WHERE id = 5549;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق بن راہویہ نے بیان کیا، کہا ہم کو ابن شمیل نے خبر دی، کہا ہم کو عمر بن ابی زائدہ نے خبر دی، کہا ہم کو عون بن ابی جحیفہ نے خبر دی، ان سے ان کے والد ابوجحیفہ رضی اللہ عنہ نے بیان کیا کہ پھر میں نے دیکھا کہ بلال رضی اللہ عنہ ایک نیزہ لے کر آئے اور اسے زمین میں گاڑ دیا پھر نماز کے لیے تکبیر کہی گئی۔ میں نے دیکھا کہ رسول اللہ صلی اللہ علیہ وسلم ایک جوڑا پہنے ہوئے باہر تشریف لائے جسے آپ نے سمیٹ رکھا تھا۔ پھر آپ نے نیزہ کے سامنے کھڑے ہو کر دو رکعت نماز عید پڑھائی اور میں نے دیکھا کہ انسان اور جانور نبی کریم صلی اللہ علیہ وسلم کے سامنے نیزہ کے باہر کی طرف سے گزر رہے تھے۔' WHERE id = 5561;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، کہا ہم کو یحییٰ بن سعید نے خبر دی، ان سے عبیداللہ نے بیان کیا، کہا مجھ کو نافع نے خبر دی، ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ جب عبداللہ بن ابی کی وفات ہوئی تو اس کے لڑکے ( عبداللہ ) جو مخلص اور اکابر صحابہ میں تھے رسول اللہ صلی اللہ علیہ وسلم ! کی خدمت میں حاضر ہوئے اور عرض کیا: یا رسول اللہ! اپنی قمیص مجھے عطا فرمایئے تاکہ میں اپنے باپ کو اس کا کفن دوں اور آپ ان کی نماز جنازہ پڑھا دیں اور ان کے لیے دعائے مغفرت کریں چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اپنی قمیص انہیں عطا فرمائی اور فرمایا کہ نہلا دھلا کر مجھے اطلاع دینا۔ چنانچہ جب نہلا دھلا لیا تو نبی کریم صلی اللہ علیہ وسلم کو اطلاع دی نبی کریم صلی اللہ علیہ وسلم تشریف لائے تاکہ اس کی نماز جنازہ پڑھائیں لیکن عمر رضی اللہ عنہ نے آپ کو پکڑ لیا اور عرض کیا: یا رسول اللہ! کیا اللہ تعالیٰ نے آپ کو منافقین پر نماز جنازہ پڑھنے سے منع نہیں فرمایا ہے؟ اور فرمایا ہے «استغفر لهم أو لا تستغفر لهم إن تستغفر لهم سبعين مرة فلن يغفر الله لهم‏» کہ ”ان کے لیے مغفرت کی دعا کرو یا مغفرت کی دعا نہ کرو اگر تم ستر مرتبہ بھی ان کے لیے مغفرت کی دعا کرو گے تب بھی اللہ انہیں ہرگز نہیں بخشے گا۔“ پھر یہ آیت نازل ہوئی «ولا تصل على أحد منهم مات أبدا‏» کہ ”اور ان میں سے کسی پر بھی جو مر گیا ہو ہرگز نماز نہ پڑھئیے۔“ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے ان کی نماز جنازہ پڑھنی چھوڑ دی۔' WHERE id = 5571;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، انہوں نے کہا کہ میں نے زہری سے سنا، انہوں نے کہا کہ مجھے سالم نے خبر دی، انہیں ان کے والد (عبداللہ بن عمر رضی اللہ عنہما) نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ محرم قمیص نہ پہنے , نہ عمامہ پہنے , نہ پاجامہ , نہ برنس اور نہ کوئی ایسا کپڑا پہنے جس میں زعفران اور ورس لگا ہو اور نہ موزے پہنے البتہ اگر کسی کو چپل نہ ملیں تو موزوں کو ٹخنوں کے نیچے تک کاٹ دے ( پھر پہنے ) ۔' WHERE id = 5581;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے اسماعیل بن علیہ نے بیان کیا، ان سے ایوب سختیانی نے بیان کیا، ان سے حمید بن ہلال نے اور ان سے ابوبردہ نے بیان کیا کہ عائشہ رضی اللہ عنہا نے ہمیں ایک موٹی کملی ( «كساء» ) اور ایک موٹی ازار نکال کر دکھائی اور کہا کہ رسول اللہ صلی اللہ علیہ وسلم کی روح ان ہی دو کپڑوں میں قبض ہوئی تھی۔' WHERE id = 5592;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے، کہا ہم سے قتادہ نے، کہا کہ میں نے ابوعثمان نہدی سے سنا کہ ہمارے پاس عمر رضی اللہ عنہ کا مکتوب ( خط ) آیا ہم اس وقت عتبہ بن فرقد رضی اللہ عنہ کے ساتھ آذر بائیجان میں تھے ( اس میں لکھا تھا ) کہ رسول اللہ صلی اللہ علیہ وسلم نے ریشم کے استعمال سے ( مردوں کو ) منع کیا ہے سوا اتنے کے اور نبی کریم صلی اللہ علیہ وسلم نے انگوٹھے کے قریب کی اپنی دونوں انگلیوں کے اشارے سے اس کی مقدار بتائی۔ ابوعثمان نہدی نے بیان کیا کہ ہماری سمجھ میں نبی کریم صلی اللہ علیہ وسلم کی مراد اس سے ( کپڑے وغیرہ ریشم کے ) پھول بوٹے بنانے سے تھی۔' WHERE id = 5602;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ نے خبر دی، کہا ہم کو سفیان نے خبر دی، انہیں اشعث بن ابی شعثاء نے، ان سے معاویہ بن سوید بن مقرن نے بیان کیا اور ان سے ابن عازب رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں سرخ «ميثرة» اور «قسي» کے پہننے سے منع فرمایا ہے۔' WHERE id = 5612;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابواسحاق نے اور انہوں نے براء رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم میانہ قد تھے اور میں نے آپ صلی اللہ علیہ وسلم کو سرخ جوڑے میں دیکھا آپ سے زیادہ خوبصورت کوئی چیز میں نے نہیں دیکھی۔' WHERE id = 5622;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مقاتل نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں عیسیٰ بن طہمان نے خبر دی، بیان کیا کہ انس بن مالک رضی اللہ عنہ دو جوتے لے کر ہمارے پاس باہر آئے جس میں دو تسمے لگے ہوئے تھے۔ ثابت بنانی نے کہا کہ یہ نبی کریم صلی اللہ علیہ وسلم کے جوتے ہیں۔' WHERE id = 5632;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا ان سے یونس نے، ان سے ابن شہاب نے انہوں نے کہا کہ مجھ سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم کے ہاتھ میں ایک دن چاندی کی انگوٹھی دیکھی پھر دوسرے لوگوں نے بھی چاندی کی انگوٹھیاں بنوانی شروع کر دیں اور پہننے لگے تو نبی کریم صلی اللہ علیہ وسلم نے اپنی انگوٹھی پھینک دی اور دوسرے لوگوں نے بھی اپنی انگوٹھیاں پھینک دی۔ اس روایت کی متابعت ابراہیم بن سعد، زیاد اور شعیب نے زہری سے کی ہے اور ابن مسافر نے زہری سے بیان کیا کہ میرا خیال ہے کہ «خاتما من ورق‏.» بیان کیا۔' WHERE id = 5642;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ انصاری نے بیان کیا، کہا کہ مجھ سے میرے والد عبداللہ بن مثنیٰ نے بیان کیا، ان سے ثمامہ بن عبداللہ بن انس نے اور ان سے انس رضی اللہ عنہ نے کہ ابوبکر رضی اللہ عنہ جب خلیفہ ہوئے تو انہوں نے مجھ کو زکوٰۃ کے مسائل لکھوا دیئے اور انگوٹھی ( مہر ) کا نقش تین سطروں میں تھا ایک سطر میں ”محمد“ دوسری سطر میں ”رسول“ اور تیسری سطر میں ”اللہ“۔' WHERE id = 5652;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، ان سے حنظلہ بن ابی ہانی نے، ان سے نافع نے بیان کیا، (امام بخاری رحمہ اللہ نے) کہا کہ اس حدیث کو ہمارے اصحاب نے مکی سے روایت کیا، انہوں نے بحوالہ ابن عمر رضی اللہ عنہما کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مونچھ کے بال کتروانا پیدائشی سنت ہے۔“' WHERE id = 5662;
UPDATE hadiths SET urdu = 'اور ہم سے ابونعیم نے بیان کیا، ان سے نصیر بن ابی الاشعث نے بیان کیا، ان سے عبداللہ بن موہب نے کہ ام سلمہ رضی اللہ عنہا نے انہیں نبی کریم صلی اللہ علیہ وسلم کا بال دکھایا جو سرخ تھا۔' WHERE id = 5672;
UPDATE hadiths SET urdu = 'اور ہشام نے بیان کیا، ان سے معمر نے، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم کے قدم اور ہتھیلیاں بھری ہوئی اور گداز تھیں۔' WHERE id = 5683;
UPDATE hadiths SET urdu = 'مجھ سے احمد بن محمد مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو یحییٰ بن سعید انصاری نے خبر دی، انہیں عبدالرحمٰن بن قاسم نے خبر دی، انہیں ان کے والد قاسم بن محمد نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم کو آپ کے احرام میں رہنے کے لیے اپنے ہاتھ سے خوشبو لگائی میں نے اسی طرح ( دسویں تاریخ کو ) منیٰ میں طواف زیارت کرنے سے پہلے اپنے ہاتھ سے آپ کو خوشبو لگائی۔' WHERE id = 5694;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی شیبہ نے بیان کیا، کہا کہ مجھ سے امام مالک نے بیان کیا، ان سے ابن شہاب نے، ان سے حمید بن عبدالرحمٰن بن عوف اور انہوں نے معاویہ بن ابی سفیان رضی اللہ عنہما سے حج کے سال میں سنا وہ مدینہ منورہ میں منبر پر یہ فرما رہے تھے انہوں نے بالوں کی ایک چوٹی جو ان کے چوکیدار کے ہاتھ میں تھی لے کر کہا کہاں ہیں تمہارے علماء میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا ہے آپ اس طرح بال بنانے سے منع فرما رہے تھے اور فرما رہے تھے کہ بنی اسرائیل اس وقت تباہ ہو گئے جب ان کی عورتوں نے اس طرح اپنے بال سنوارنے شروع کر دیئے۔' WHERE id = 5704;
UPDATE hadiths SET urdu = 'مجھ سے یونس بن موسیٰ نے بیان کیا، انہوں نے کہا ہم سے فضل بن دکین نے بیان کیا، انہوں نے کہا ہم سے صخر بن جویریہ نے بیان کیا، ان سے نافع نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، یا ( راوی نے اس طرح بیان کیا کہ ) نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”گودنے والی، گدوانے والی، مصنوعی بال جوڑنے والی اور جڑوانے والی“ یعنی نبی کریم صلی اللہ علیہ وسلم نے ان سب پر لعنت بھیجی ہے۔' WHERE id = 5714;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن فضالہ نے بیان کیا، ان سے ہشام دستوائی نے بیان کیا، ان سے یحییٰ بن ابی کثیر نے، ان سے عمران بن حطان نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم کو اپنے گھر میں جب بھی کوئی چیز ایسی ملتی جس پر صلیب کی مورت بنی ہو ( جیسے نصاریٰ رکھتے ہیں ) تو اس کو توڑ ڈالتے۔' WHERE id = 5725;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا کہ مجھ سے غندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے عون بن ابی جحیفہ نے اور ان سے ان کے والد (وہب بن عبداللہ) نے کہ انہوں نے ایک غلام خریدا جو پچھنا لگاتا تھا پھر فرمایا کہ نبی کریم صلی اللہ علیہ وسلم نے خون نکالنے کی اجرت، کتے کی قیمت اور رنڈی کی کمائی کھانے سے منع فرمایا ہے اور آپ نے سود لینے والے، دینے والے، گودنے والی، گدوانے والی اور مورت بنانے والے پر لعنت بھیجی ہے۔' WHERE id = 5735;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان اور شعبہ نے بیان کیا کہ ہم سے حبیب نے بیان کیا (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، انہیں حبیب نے، انہیں ابوعباس نے اور ان سے عبداللہ بن عمرو نے بیان کیا کہ ایک صحابی نے نبی کریم صلی اللہ علیہ وسلم سے پوچھا کیا میں بھی جہاد میں شریک ہو جاؤں؟ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ تمہارے ماں باپ موجود ہیں انہوں نے کہا کہ جی ہاں موجود ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر انہیں میں جہاد کرو۔' WHERE id = 5745;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا کہ مجھے ابن عثمان نے خبر دی، کہا کہ میں نے موسیٰ بن طلحہ سے سنا اور ان سے ابوایوب رضی اللہ عنہ نے بیان کیا، کہا گیا کہ یا رسول اللہ! کوئی ایسا عمل بتائیں جو مجھے جنت میں لے جائے۔' WHERE id = 5755;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے کہا کہ مجھے عروہ بن زبیر نے خبر دی اور انہیں حکیم بن حزام نے خبر دی، انہوں نے عرض کیا کہ یا رسول اللہ! آپ کا ان کاموں کے بارے میں کیا خیال ہے جنہیں میں عبادت سمجھ کر زمانہ جاہلیت میں کرتا تھا مثلاً صلہ رحمی، غلام کی آزادی، صدقہ، کیا مجھے ان پر ثواب ملے گا؟ حکیم رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ہے تم ان تمام اعمال خیر کے ساتھ اسلام لائے ہو جو پہلے کر چکے ہو۔ اور بعضوں نے ابوالیمان سے بجائے «اتحنث» کے «اتحت» ( تاء کے ساتھ ) روایت کیا ہے اور معمر اور صالح اور ابن مسافر نے بھی «اتحت» روایت کیا ہے۔ ابن اسحاق نے کہا «اتحنث»،‏‏‏‏ «تحت» سے نکلا ہے اس کے معنی مثل اور عبادت کرنا۔ ہشام نے بھی اپنے والد عروہ سے ان لوگوں کی متابعت کی ہے۔' WHERE id = 5765;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے ہشام نے بیان کیا، کہا مجھ کو میرے والد عروہ نے خبر دی اور انہیں عائشہ رضی اللہ عنہا نے کہ نبی کریم صلی اللہ علیہ وسلم نے ایک بچہ ( عبداللہ بن زبیر ) کو اپنی گود میں بٹھلایا اور کھجور چبا کر اس کے منہ میں دی، اس نے آپ پر پیشاب کر دیا آپ نے پانی منگوا کر اس پر بہا دیا۔' WHERE id = 5775;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اگر کوئی مسلمان کسی درخت کا پودا لگاتا ہے اور اس درخت سے کوئی انسان یا جانور کھاتا ہے تو لگانے والے کے لیے وہ صدقہ ہوتا ہے۔“' WHERE id = 5785;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے، ان سے سعید بن ابی بردہ بن ابی موسیٰ اشعری نے بیان کیا، ان سے ان کے والد نے اور ان سے ان کے دادا (ابوموسیٰ اشعری رضی اللہ عنہ) نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ہر مسلمان پر صدقہ کرنا ضروری ہے۔“ صحابہ کرام رضی اللہ عنہم نے عرض کیا اگر کوئی چیز کسی کو ( صدقہ کے لیے ) جو میسر نہ ہو۔ آپ صلی اللہ علیہ وسلم نے فرمایا کہ پھر اپنے ہاتھ سے کام کرے اور اس سے خود کو بھی فائدہ پہنچائے اور صدقہ بھی کرے۔ صحابہ کرام رضی اللہ عنہم نے عرض کی اگر اس میں اس کی طاقت نہ ہو یا کہا کہ نہ کر سکے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر کسی حاجت مند پریشان حال کی مدد کرے۔ صحابہ کرام رضی اللہ عنہم نے عرض کیا اگر وہ یہ بھی نہ کر سکے۔ فرمایا کہ پھر بھلائی کی طرف لوگوں کو رغبت دلائے یا امر بالمعروف کا کرنا عرض کیا اور اگر یہ بھی نہ کر سکے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر برائی سے رکا رہے کہ یہ بھی اس کے لیے صدقہ ہے۔' WHERE id = 5795;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، ان سے ابن منکدر نے بیان کیا، انہوں نے جابر رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ کبھی ایسا نہیں ہوا کہ رسول اللہ صلی اللہ علیہ وسلم سے کسی نے کوئی چیز مانگی ہو اور آپ نے اس کے دینے سے انکار کیا ہو۔' WHERE id = 5806;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے منصور نے بیان کیا، کہا میں نے ابووائل سے سنا اور وہ عبداللہ بن مسعود رضی اللہ عنہ سے بیان کرتے تھے کہ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مسلمان کو گالی دینا گناہ ہے اور اس کو قتل کرنا کفر ہے۔“ غندر نے شعبہ سے روایت کرنے میں سلیمان کی متابعت کی ہے۔' WHERE id = 5816;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہوں نے کہا ہم کو سفیان بن عیینہ نے خبر دی، انہوں نے محمد بن منکدر سے سنا، انہوں نے عروہ بن زبیر سے سنا اور انہیں ام المؤمنین عائشہ رضی اللہ عنہا نے خبر دی، انہوں نے بیان کیا کہ ایک شخص نے رسول اللہ صلی اللہ علیہ وسلم سے اندر آنے کی اجازت چاہی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسے اجازت دے دو، فلاں قبیلہ کا یہ برا آدمی ہے جب وہ شخص اندر آیا تو آپ نے اس کے ساتھ بڑی نرمی سے گفتگو کی۔ میں نے عرض کیا: یا رسول اللہ! آپ کو اس کے متعلق جو کچھ کہنا تھا وہ ارشاد فرمایا اور پھر اس کے ساتھ نرم گفتگو کی۔ آپ صلی اللہ علیہ وسلم نے فرمایا، عائشہ! وہ بدترین آدمی ہے جسے اس کی بدکلامی کے ڈر سے لوگ ( اسے ) چھوڑ دیں۔' WHERE id = 5826;
UPDATE hadiths SET urdu = 'ہم سے بشر بن محمد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو معمر نے خبر دی، انہیں ہمام بن منبہ نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”بدگمانی سے بچتے رہو کیونکہ بدگمانی کی باتیں اکثر جھوٹی ہوتی ہیں، لوگوں کے عیوب تلاش کرنے کے پیچھے نہ پڑو، آپس میں حسد نہ کرو، کسی کی پیٹھ پیچھے برائی نہ کرو، بغض نہ رکھو، بلکہ سب اللہ کے بندے آپس میں بھائی بھائی بن کر رہو۔“' WHERE id = 5836;
UPDATE hadiths SET urdu = 'ہم سے عبدالرحمٰن بن یوسف نے بیان کیا، کہا ہم کو امام مالک رحمہ اللہ نے خبر دی، انہیں ابن شہاب نے، انہیں عطاء بن یزید لیثی نے اور انہیں ابوایوب انصاری رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”کسی شخص کے لیے جائز نہیں کہ اپنے کسی بھائی سے تین دن سے زیادہ کے لیے ملاقات چھوڑے، اس طرح کہ جب دونوں کا سامنا ہو جائے تو یہ بھی منہ پھیر لے اور وہ بھی منہ پھیر لے اور ان دونوں میں بہتر وہ ہے جو سلام میں پہل کرے۔“' WHERE id = 5847;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، کہا ہم کو ابن شہاب نے خبر دی، انہیں حمید بن عبدالرحمٰن نے، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ایک صاحب رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور عرض کیا: میں تو تباہ ہو گیا اپنی بیوی کے ساتھ رمضان میں ( روزہ کی حالت میں ) ہمبستری کر لی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر ایک غلام آزاد کر۔ انہوں نے عرض کیا: میرے پاس کوئی غلام نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر دو مہینے کے روزے رکھ۔ انہوں نے عرض کیا: اس کی مجھ میں طاقت نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا پھر ساٹھ مسکینوں کو کھانا کھلا۔ انہوں نے عرض کیا کہ اتنا بھی میرے پاس نہیں ہے۔ بیان کیا کہ پھر کھجور کا ایک ٹوکرا لایا گیا۔ ابراہیم نے بیان کیا کہ «عرق» ایک طرح کا ( نو کلوگرام کا ) ایک پیمانہ تھا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پوچھنے والا کہاں ہے؟ لو اسے صدقہ کر دینا۔ انہوں نے عرض کیا مجھ سے جو زیادہ محتاج ہو اسے دوں؟ اللہ کی قسم! مدینہ کے دونوں میدانوں کے درمیان کوئی گھرانہ بھی ہم سے زیادہ محتاج نہیں ہے۔ اس پر نبی کریم صلی اللہ علیہ وسلم ہنس دیئے اور آپ کے سامنے کے دندان مبارک کھل گئے، اس کے بعد فرمایا کہ اچھا پھر تو تم میاں بیوی ہی اسے کھا لو۔' WHERE id = 5857;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے مخارق نے، انہوں نے کہا میں نے طارق سے سنا، کہا کہ عبداللہ بن مسعود رضی اللہ عنہ نے کہا بلاشبہ سب سے اچھا کلام اللہ کی کتاب ہے اور سب سے اچھا طریقہ ( چال چلن ) محمد صلی اللہ علیہ وسلم کا طریقہ ہے۔' WHERE id = 5867;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے نافع نے، ان سے ابن عمر رضی اللہ عنہما نے کہ وہ عمر بن خطاب رضی اللہ عنہ کے پاس پہنچے جو چند سواروں کے ساتھ تھے، اس وقت عمر رضی اللہ عنہ اپنے والد کی قسم کھا رہے تھے۔ اس پر رسول اللہ صلی اللہ علیہ وسلم نے انہیں پکار کر کہا، خبردار! یقیناً اللہ پاک تمہیں منع کرتا ہے کہ تم اپنے باپ دادوں کی قسم کھاؤ، پس اگر کسی کو قسم ہی کھانی ہے تو اللہ کی قسم کھائے، ورنہ چپ رہے۔' WHERE id = 5877;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے عبدالعزیز بن ابوسلمہ نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کا گزر ایک شخص پر سے ہوا جو اپنے بھائی پر حیاء کی وجہ سے ناراض ہو رہا تھا اور کہہ رہا تھا کہ تم بہت شرماتے ہو، گویا وہ کہہ رہا تھا کہ تم اس کی وجہ سے اپنا نقصان کر لیتے ہو۔ نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ اسے چھوڑ دو کہ حیاء ایمان میں سے ہے۔' WHERE id = 5887;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے (دوسری سند) اور لیث بن سعد نے بیان کیا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے، انہیں عبیداللہ بن عبداللہ بن عتبہ نے خبر دی اور انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ ایک دیہاتی نے مسجد میں پیشاب کر دیا، لوگ اس کی طرف مارنے کو بڑھے، لیکن رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اسے چھوڑ دو اور جہاں اس نے پیشاب کیا ہے اس جگہ پر پانی کا ایک ڈول بھرا ہوا بہا دو، کیونکہ تم آسانی کرنے والے بنا کر بھیجے گئے ہو تنگی کرنے والے بنا کر نہیں بھیجے گئے۔' WHERE id = 5897;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے ہشام بن یوسف نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں زہری نے انہیں ابوسلمہ نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جو شخص اللہ پر اور آخرت کے دن پر ایمان رکھتا ہو اسے اپنے مہمان کی عزت کرنی چاہیئے اور جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو اسے چاہئے کہ وہ صلہ رحمی کرے، جو شخص اللہ اور آخرت کے دن پر ایمان رکھتا ہو، اسے چاہیئے کہ اچھی بات زبان سے نکالے ورنہ چپ رہے۔“' WHERE id = 5907;
UPDATE hadiths SET urdu = 'ہم سے محمد بن سلام نے بیان کیا، کہا ہم سے عبدہ نے بیان کیا، کہا ہم کو ہشام بن عروہ نے خبر دی، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہا کہ حسان بن ثابت رضی اللہ عنہ نے مشرکین کی ہجو کرنے کی اجازت چاہی تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ان کا اور میرا خاندان تو ایک ہی ہے ( پھر تو میں بھی اس ہجو میں شریک ہو جاؤں گا ) ۔ حسان رضی اللہ عنہ نے کہا کہ میں ہجو سے آپ کو اس طرح صاف نکال دوں گا جس طرح گندھے ہوئے آٹے سے بال نکال لیا جاتا ہے۔ اور ہشام بن عروہ سے روایت ہے، ان سے ان کے والد نے بیان کیا کہ میں حسان بن ثابت رضی اللہ عنہ کو عائشہ رضی اللہ عنہا کی مجلس میں برا کہنے لگا تو انہوں نے کہا کہ حسان کو برا بھلا نہ کہو، وہ نبی کریم صلی اللہ علیہ وسلم کی طرف سے مشرکوں کو جواب دیتا تھا۔' WHERE id = 5918;
UPDATE hadiths SET urdu = 'مجھ سے قتیبہ بن سعید نے بیان کیا، وہ امام مالک سے روایت کرتے ہیں، وہ ابوالزناد سے، وہ اعرج سے، وہ ابوہریرہ رضی اللہ عنہ سے روایت کرتے ہیں کہ رسول اللہ صلی اللہ علیہ وسلم نے ایک شخص کو دیکھا کہ قربانی کا اونٹ ہنکائے جا رہا ہے۔ آپ صلی اللہ علیہ وسلم نے اس سے کہا کہ تو اس پر سوار ہو جا۔ اس نے عرض کیا: یا رسول اللہ! یہ تو قربانی کا اونٹ ہے۔ آپ صلی اللہ علیہ وسلم نے دوسری بار یا تیسری بار فرمایا کہ تیری خرابی ہو، تو سوار ہو جا۔' WHERE id = 5928;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان ثوری نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم سے عرض کیا گیا ایک شخص ایک جماعت سے محبت رکھتا ہے لیکن اس سے مل نہیں سکا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انسان اس کے ساتھ ہے جس سے وہ محبت رکھتا ہے۔ سفیان کے ساتھ اس روایت کی متابعت ابومعاویہ اور محمد بن عبید نے کی ہے۔' WHERE id = 5938;
UPDATE hadiths SET urdu = 'ہم سے عیاش بن ولید نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے بیان کیا، کہا ہم سے معمر نے بیان کیا، ان سے زہری نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”انگور «عنب» کو «كرم» نہ کہو اور یہ نہ کہو کہ ہائے زمانہ کی نامرادی۔ کیونکہ زمانہ تو اللہ ہی کے اختیار میں ہے۔“' WHERE id = 5948;
UPDATE hadiths SET urdu = 'ہم سے صدقہ بن فضل نے بیان کیا، انہوں نے کہا ہم کو محمد بن جعفر نے خبر دی، انہیں شعبہ نے، انہیں عطاء بن ابی میمونہ نے، انہیں ابورافع نے اور انہیں ابوہریرہ رضی اللہ عنہ نے کہ ام المؤمنین زینب رضی اللہ عنہا کا نام برہ تھا، کہا جانے لگا کہ وہ اپنی پاکی ظاہر کرتی ہیں۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے ان کا نام زینب رکھا۔' WHERE id = 5958;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، کہا ہم سے وہیب نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے ابوقلابہ نے اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ ام سلیم رضی اللہ عنہا مسافروں کے سامان کے ساتھ تھیں اور نبی کریم صلی اللہ علیہ وسلم کے غلام انجشہ عورتوں کے اونٹ کو ہانک رہے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”انجش! ذرا اس طرح آہستگی سے لے چل جیسے شیشوں کو لے کر جاتا ہے۔“' WHERE id = 5968;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے شعبہ نے، ان سے قتادہ نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ مدینہ منورہ پر ( ایک رات نامعلوم آواز کی وجہ سے ) ڈر طاری ہو گیا۔ چنانچہ رسول اللہ صلی اللہ علیہ وسلم ابوطلحہ کے ایک گھوڑے پر سوار ہوئے۔ پھر ( واپس آ کر ) فرمایا ”ہمیں تو کوئی ( خوف کی ) چیز نظر نہ آئی، البتہ یہ گھوڑا تو گویا دریا تھا۔“' WHERE id = 5978;
UPDATE hadiths SET urdu = 'ہم سے سلیمان بن حرب نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے اشعث بن سلیم نے کہ میں نے معاویہ بن سوید بن مقرن سے سنا اور ان سے براء رضی اللہ عنہ نے بیان کیا کہ ہمیں نبی کریم صلی اللہ علیہ وسلم نے سات باتوں کا حکم دیا تھا اور سات کاموں سے روکا تھا، ہمیں نبی کریم صلی اللہ علیہ وسلم نے بیمار کی مزاج پرسی کرنے، جنازہ کے پیچھے چلنے، چھینکنے والے کے جواب دینے، دعوت کرنے والے کی دعوت قبول کرنے، سلام کا جواب دینے، مظلوم کی مدد کرنے اور قسم کھا لینے والے کی قسم پوری کرنے میں مدد دینے کا حکم دیا تھا اور نبی کریم صلی اللہ علیہ وسلم نے ہمیں سات کاموں سے روکا تھا، سونے کی انگوٹھی سے، یا بیان کیا کہ سونے کے چھلے سے، ریشم اور دیبا اور سندس ( دیبا سے باریک ریشمی کپڑا ) پہننے سے اور ریشمی زین سے۔' WHERE id = 5988;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا ہم کو مخلد نے خبر دی، انہوں نے کہا ہم کو ابن جریج نے خبر دی، انہوں نے کہا کہ مجھے زیاد نے خبر دی، انہوں نے عبدالرحمٰن بن زید کے غلام ثابت سے سنا، اور انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا۔ انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”سوار پیدل چلنے والے کو سلام کرے، پیدل چلنے والا بیٹھے ہوئے کو اور کم تعداد والے بڑی تعداد والوں کو۔“' WHERE id = 5998;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے عبیداللہ بن ابی بکر نے اور ان سے انس بن مالک رضی اللہ عنہ نے کہ ایک صاحب نبی کریم صلی اللہ علیہ وسلم کے کسی حجرہ میں جھانک کر دیکھنے لگے تو نبی کریم صلی اللہ علیہ وسلم ان کی طرف تیر کا پھل یا بہت سے پھل لے کر بڑھے، گویا میں نبی کریم صلی اللہ علیہ وسلم کو دیکھ رہا ہوں ان صاحب کی طرف اس طرح چپکے چپکے تشریف لائے۔' WHERE id = 6008;
UPDATE hadiths SET urdu = 'ہم سے ابن بشار نے بیان کیا، کہا کہ مجھ سے یحییٰ نے بیان کیا، ان سے عبیداللہ نے، ان سے سعید نے بیان کیا، ان سے ان کے والد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”پھر سر سجدہ سے اٹھا اور اچھی طرح بیٹھ جا۔“' WHERE id = 6018;
UPDATE hadiths SET urdu = 'ہم سے ابوالولید نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا ان سے سعد بن ابراہیم نے ان سے ابوامامہ بن سہل بن حنیف نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے کہ قریظہ کے یہودی سعد بن معاذ رضی اللہ عنہ کو ثالث بنانے پر تیار ہو گئے تو رسول اللہ صلی اللہ علیہ وسلم نے انہیں بلا بھیجا جب وہ آئے تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اپنے سردار کے لینے کو اٹھو یا یوں فرمایا کہ اپنے میں سب سے بہتر کو لینے کے لیے اٹھو۔ پھر وہ نبی کریم صلی اللہ علیہ وسلم کے پاس بیٹھ گئے اور نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بنی قریظہ کے لوگ تمہارے فیصلے پر راضی ہو کر ( قلعہ سے ) اتر آئے ہیں ( اب تم کیا فیصلہ کرتے ہو ) ۔ سعد رضی اللہ عنہ نے کہا کہ پھر میں یہ فیصلہ کرتا ہوں کہ ان میں جو جنگ کے قابل ہیں انہیں قتل کر دیا جائے اور ان کے بچوں اور عورتوں کو قید کر لیا جائے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ آپ نے وہی فیصلہ فرمایا جس فیصلہ کو فرشتہ لے کر آیا تھا۔ ابوعبداللہ ( مصنف ) نے بیان کیا کہ مجھے میرے بعض اصحاب نے ابوالولید کے واسطہ سے ابوسعید رضی اللہ عنہ کا قول ( «على» کے بجائے بصلہ «إلى حكمك‏.‏» نقل کیا ہے۔)' WHERE id = 6028;
UPDATE hadiths SET urdu = 'ہم سے محمد بن ابی غالب نے بیان کیا، کہا ہم کو ابراہیم بن المنذر حزامی نے خبر دی، کہا ہم سے محمد بن فلیح نے بیان کیا، ان سے ان کے باپ نے، ان سے نافع نے اور ان سے ابن عمر رضی اللہ عنہما نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم کو صحن کعبہ میں دیکھا کہ آپ سرین پر بیٹھے ہوئے دونوں رانیں شکم مبارک سے ملائے ہوئے ہاتھوں سے پنڈلی پکڑے ہوئے بیٹھے تھے۔' WHERE id = 6038;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے سفیان ثوری نے بیان کیا، ان سے زہری نے بیان کیا، ان سے عطاء بن یزید لیثی نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے دو طرح کے پہناوے سے اور دو طرح کی خرید و فروخت سے منع فرمایا تھا۔ اشتمال صماء اور ایک کپڑے میں اس طرح احتباء کرنے سے کہ انسان کی شرمگاہ پر کوئی چیز نہ ہو اور ملامست اور منابذت سے۔ اس روایت کی متابعت معمر، محمد بن ابی حفصہ اور عبداللہ بن بدیل نے زہری سے کی ہے۔' WHERE id = 6049;
UPDATE hadiths SET urdu = 'ہم سے حسان بن ابی عباد نے بیان کیا، انہوں نے کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے عطاء بن ابی رباح نے اور ان سے جابر رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب رات میں سونے لگو تو چراغ بجھا دیا کرو اور دروازے بند کر لیا کرو اور مشکیزوں کا منہ باندھ دیا کرو اور کھانے پینے کی چیزیں ڈھک دیا کرو۔“ حماد نے کہا کہ میرا خیال ہے کہ یہ بھی فرمایا کہ ”اگرچہ ایک لکڑی سے ہی ہو۔“' WHERE id = 6060;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث بن سعید نے بیان کیا، کہا ہم سے حسین بن ذکوان معلم نے بیان کیا، کہا ہم سے عبداللہ بن بریدہ نے بیان کیا ان سے بشیر بن کعب عدوی نے کہا کہ مجھ سے شداد بن اوس رضی اللہ عنہ نے بیان کیا اور ان سے رسول اللہ صلی اللہ علیہ وسلم نے کہ سیدالاستغفار ( مغفرت مانگنے کے سب کلمات کا سردار ) یہ ہے یوں کہے «اللهم أنت ربي،‏‏‏‏ لا إله إلا أنت،‏‏‏‏ خلقتني وأنا عبدك،‏‏‏‏ وأنا على عهدك ووعدك ما استطعت،‏‏‏‏ أعوذ بك من شر ما صنعت،‏‏‏‏ أبوء لك بنعمتك على وأبوء بذنبي،‏‏‏‏ اغفر لي،‏‏‏‏ فإنه لا يغفر الذنوب إلا أنت‏ ‏‏.‏» ‏”اے اللہ! تو میرا رب ہے، تیرے سوا کوئی معبود نہیں۔ تو نے ہی مجھے پیدا کیا اور میں تیرا ہی بندہ ہوں میں اپنی طاقت کے مطابق تجھ سے کئے ہوئے عہد اور وعدہ پر قائم ہوں۔ ان بری حرکتوں کے عذاب سے جو میں نے کی ہیں تیری پناہ مانگتا ہوں مجھ پر نعمتیں تیری ہیں اس کا اقرار کرتا ہوں۔ میری مغفرت کر دے کہ تیرے سوا اور کوئی بھی گناہ نہیں معاف کرتا۔“ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جس نے اس دعا کے الفاظ پر یقین رکھتے ہوئے دل سے ان کو کہہ لیا اور اسی دن اس کا انتقال ہو گیا شام ہونے سے پہلے، تو وہ جنتی ہے اور جس نے اس دعا کے الفاظ پر یقین رکھتے ہوئے رات میں ان کو پڑھ لیا اور پھر اس کا صبح ہونے سے پہلے انتقال ہو گیا تو وہ جنتی ہے۔' WHERE id = 6070;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے عبدالرحمٰن ابن مہدی نے، ان سے سفیان ثوری نے، ان سے سلمہ بن کہیل نے، ان سے کریب نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ میں میمونہ ( رضی اللہ عنہا ) کے یہاں ایک رات سویا تو نبی کریم صلی اللہ علیہ وسلم اٹھے اور آپ نے اپنی حوائج ضرورت پوری کرنے کے بعد اپنا چہرہ دھویا، پھر دونوں ہاتھ دھوئے اور پھر سو گئے اس کے بعد آپ کھڑے ہو گئے اور مشکیزہ کے پاس گئے اور آپ نے اس کا منہ کھولا پھر درمیانہ وضو کیا ( نہ مبالغہ کے ساتھ نہ معمولی اور ہلکے قسم کا، تین تین مرتبہ سے ) کم دھویا۔ البتہ پانی ہر جگہ پہنچا دیا۔ پھر آپ نے نماز پڑھی۔ میں بھی کھڑا ہوا اور آپ کے پیچھے ہی رہا کیونکہ میں اسے پسند نہیں کرتا تھا کہ نبی کریم صلی اللہ علیہ وسلم یہ سمجھیں کہ میں آپ کا انتظار کر رہا تھا۔ میں نے بھی وضو کر لیا تھا۔ نبی کریم صلی اللہ علیہ وسلم جب کھڑے ہو کر نماز پڑھنے لگے تو میں بھی آپ کے بائیں طرف کھڑا ہو گیا۔ آپ نے میرا کان پکڑ کر دائیں طرف کر دیا، میں نے نبی کریم صلی اللہ علیہ وسلم ( کی اقتداء میں ) تیرہ رکعت نماز مکمل کی۔ اس کے بعد آپ سو گئے اور آپ کی سانس میں آواز پیدا ہونے لگی۔ نبی کریم صلی اللہ علیہ وسلم جب سوتے تھے تو آپ کی سانس میں آواز پیدا ہونے لگتی تھی۔ اس کے بعد بلال رضی اللہ عنہ نے آپ کو نماز کی اطلاع دی چنانچہ آپ نے ( نیا وضو ) کئے بغیر نماز پڑھی۔ نبی کریم صلی اللہ علیہ وسلم اپنی دعا میں یہ کہتے تھے «اللهم اجعل في قلبي نورا،‏‏‏‏ وفي بصري نورا،‏‏‏‏ وفي سمعي نورا،‏‏‏‏ وعن يميني نورا،‏‏‏‏ وعن يساري نورا،‏‏‏‏ وفوقي نورا،‏‏‏‏ وتحتي نورا،‏‏‏‏ وأمامي نورا،‏‏‏‏ وخلفي نورا،‏‏‏‏ واجعل لي نورا» ”اے اللہ! میرے دل میں نور پیدا کر، میری نظر میں نور پیدا کر، میرے کان میں نور پیدا کر، میرے دائیں طرف نور پیدا کر، میرے بائیں طرف نور پیدا کر، میرے اوپر نور پیدا کر، میرے نیچے نور پیدا کر میرے آگے نور پیدا کر، میرے پیچھے نور پیدا کر اور مجھے نور عطا فرما۔“ کریب ( راوی حدیث ) نے بیان کیا کہ میرے پاس مزید سات لفظ محفوظ ہیں۔ پھر میں نے عباس رضی اللہ عنہما کے ایک صاحب زادے سے ملاقات کی تو انہوں نے مجھ سے ان کے متعلق بیان کیا کہ «عصبي ولحمي ودمي وشعري وبشري،‏‏‏‏ وذكر خصلتين‏.‏» ”میرے پٹھے، میرا گوشت، میرا خون، میرے بال اور میرا چمڑا ان سب میں نور بھر دے۔“ اور دو چیزوں کا اور بھی ذکر کیا۔' WHERE id = 6080;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم کو لیث بن سعد نے خبر دی، کہا کہ مجھ سے یزید بن ابی حبیب نے بیان کیا، ان سے ابوالخیر مرثد بن عبداللہ نے، ان سے عبداللہ بن عمرو بن عاص رضی اللہ عنہما نے اور ان سے ابوبکر صدیق رضی اللہ عنہ نے کہ انہوں نے رسول اللہ صلی اللہ علیہ وسلم سے کہا کہ مجھے ایسی دعا سکھا دیجئیے جسے میں اپنی نماز میں پڑھا کروں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ کہا کر «اللهم إني ظلمت نفسي ظلما كثيرا،‏‏‏‏ ‏‏‏‏ ولا يغفر الذنوب إلا أنت،‏‏‏‏ ‏‏‏‏ فاغفر لي مغفرة من عندك،‏‏‏‏ ‏‏‏‏ وارحمني،‏‏‏‏ ‏‏‏‏ إنك أنت الغفور الرحيم» ”اے اللہ! میں نے اپنی جان پر بہت ظلم کیا ہے اور گناہوں کو تیرے سوا کوئی معاف نہیں کرتا پس میری مغفرت کر، ایسی مغفرت جو تیرے پاس سے ہو اور مجھ پر رحم کر بلاشبہ تو بڑا مغفرت کرنے ولا، بڑا رحم کرنے والا ہے۔“ اور عمرو بن حارث نے بھی اس حدیث کو یزید سے، انہوں نے ابوالخیر سے، انہوں نے عبداللہ بن عمرو رضی اللہ عنہما سے سنا کہ ابوبکر صدیق رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے عرض کیا آخر تک۔' WHERE id = 6090;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ بن حجاج نے، کہا مجھ کو سلیمان بن مہران نے خبر دی، انہیں ابووائل نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے کوئی چیز تقسیم فرمائی تو ایک شخص بولا کہ یہ ایسی تقسیم ہے کہ اس سے اللہ کی رضا مقصود نہیں ہے۔ میں نے نبی کریم صلی اللہ علیہ وسلم کو اس کی خبر دی تو آپ اس پر غصہ ہوئے اور میں نے خفگی کے آثار آپ کے چہرہ مبارک پر دیکھے اور آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ موسیٰ علیہ السلام پر رحم فرمائے، انہیں اس سے بھی زیادہ تکلیف دی گئی لیکن انہوں نے صبر کیا۔' WHERE id = 6100;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ہشام بن ابی عبداللہ نے بیان کیا، ان سے قتادہ نے، ان سے ابوالعالیہ نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم حالت پریشانی میں یہ دعا کیا کرتے تھے «لا إله إلا الله العظيم الحليم،‏‏‏‏ لا إله إلا الله رب العرش العظيم،‏‏‏‏ لا إله إلا الله رب السموات،‏‏‏‏ ورب الأرض،‏‏‏‏ ورب العرش الكريم» ”اللہ صاحب عظمت اور بردبار کے سوا کوئی معبود نہیں، اللہ کے سوا کوئی معبود نہیں جو عرش عظیم کا رب ہے، اللہ کے سوا کوئی معبود نہیں جو آسمانوں اور زمینوں کا رب ہے اور عرش عظیم کا رب ہے۔“ اور وہب نے بیان کیا کہ ہم سے شعبہ نے بیان کیا، ان سے قتادہ نے اس طرح بیان کیا۔' WHERE id = 6110;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، کہا کہ مجھے عبداللہ بن ثعلبہ بن صعیر رضی اللہ عنہ نے خبر دی اور رسول اللہ صلی اللہ علیہ وسلم نے ان کی آنکھ یا منہ پر ہاتھ پھیرا تھا۔ انہوں نے سعد بن ابی وقاص رضی اللہ عنہ کو ایک رکعت وتر نماز پڑھتے دیکھا تھا۔' WHERE id = 6120;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے جریر بن عبدالحمید نے بیان کیا، ان سے ابووائل نے، ان سے مسروق نے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ مدینہ کے یہودیوں کی دو بوڑھی عورتیں میرے پاس آئیں اور انہوں نے مجھ سے کہا کہ قبر والوں کو ان کی قبر میں عذاب ہو گا۔ لیکن میں نے انہیں جھٹلایا اور ان کی ( بات کی ) تصدیق نہیں کر سکی۔ پھر وہ دونوں عورتیں چلی گئیں اور نبی کریم صلی اللہ علیہ وسلم تشریف لائے تو میں نے عرض کیا: یا رسول اللہ! دو بوڑھی عورتیں تھیں، پھر میں آپ سے واقعہ کا ذکر کیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ انہوں نے صحیح کہا، قبر والوں کو عذاب ہو گا اور ان کے عذاب کو تمام چوپائے سنیں گے۔ پھر میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم ہر نماز میں قبر کے عذاب سے اللہ کی پناہ مانگنے لگے تھے۔' WHERE id = 6130;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے سلام بن ابی مطیع نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد عروہ بن زبیر نے اور ان سے ان کی خالہ (ام المؤمنین عائشہ صدیقہ رضی اللہ عنہا) نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم پناہ مانگا کرتے تھے کہا «اللهم إني أعوذ بك من فتنة النار ومن عذاب النار،‏‏‏‏ وأعوذ بك من فتنة القبر،‏‏‏‏ وأعوذ بك من عذاب القبر،‏‏‏‏ وأعوذ بك من فتنة الغنى،‏‏‏‏ وأعوذ بك من فتنة الفقر،‏‏‏‏ وأعوذ بك من فتنة المسيح الدجال» ”اے اللہ! میں تیری پناہ مانگتا ہوں دوزخ کی آزمائش سے، دوزخ کے عذاب سے اور تیری پناہ مانگتا ہوں قبر کی آزمائش سے اور تیری پناہ مانگتا ہوں قبر کے عذاب سے اور تیری پناہ مانگتا ہوں مالداری کی آزمائش سے اور تیری پناہ مانگتا ہوں مسیح دجال کی آزمائش سے۔“' WHERE id = 6140;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، انہوں نے کہا ہم سے عبدالوارث نے بیان کیا، ان سے عبدالعزیز نے بیان کیا اور ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کی اکثر یہ دعا ہوا کرتی تھی «اللهم ربنا آتنا في الدنيا حسنة،‏‏‏‏ ‏‏‏‏ وفي الآخرة حسنة،‏‏‏‏ ‏‏‏‏ وقنا عذاب النار ‏ ‏‏.‏» ”اے اللہ! ہمیں دنیا میں بھلائی ( «حسنة» ) عطا کر اور آخرت میں بھلائی عطا کر اور ہمیں دوزخ سے بچا۔“' WHERE id = 6151;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مثنیٰ نے بیان کیا، کہا ہم سے عبیداللہ بن عبدالمجید نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے ابواسحاق نے بیان کیا، ان سے ابوبکر بن ابی موسیٰ اور ابوبردہ نے میرا خیال ہے کہ ابوموسیٰ اشعری رضی اللہ عنہ کے حوالہ سے کہ نبی کریم صلی اللہ علیہ وسلم یہ دعا کیا کرتے تھے «اللهم اغفرلي خطيئتي وجهلي وإسرافي في أمري،‏‏‏‏ ‏‏‏‏وما أنت أعلم به مني،‏‏‏‏ ‏‏‏‏اللهم اغفر لي هزلي وجدي وخطاى وعمدي،‏‏‏‏ ‏‏‏‏وكل ذلك عندي‏ ‏‏.‏» ”اے اللہ! میری مغفرت فرما میری خطاؤں میں، میری نادانی میں اور میری کسی معاملہ میں زیادتی میں، ان باتوں میں جن کا تو مجھ سے زیادہ جاننے والا ہے۔ اے اللہ! میری مغفرت کر میرے ہنسی مزاح اور سنجیدگی میں اور میرے ارادہ میں اور یہ سب کچھ میری ہی طرف سے ہیں۔“' WHERE id = 6161;
UPDATE hadiths SET urdu = 'ہم سے ابوالحسن محمد بن مقاتل نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہوں نے کہا ہم کو سلیمان بن طرخان تیمی نے خبر دی، انہیں ابوعثمان نہدی نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ایک گھاٹی یا درے پر چڑھنے لگے۔ بیان کیا کہ جب ایک اور صحابی بھی اس پر چڑھ گئے تو انہوں نے بلند آواز سے «لا إله إلا الله والله أكبر‏.‏» کہا۔ راوی نے بیان کیا کہ اس وقت نبی کریم صلی اللہ علیہ وسلم اپنے خچر پر سوار تھے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تم لوگ کسی بہرے یا غائب کو نہیں پکارتے۔ پھر فرمایا، ابوموسیٰ یا تو یوں ( فرمایا ) اے عبداللہ بن قیس! کیا میں تمہیں ایک کلمہ نہ بتا دوں جو جنت کے خزانوں میں سے ہے۔ میں نے عرض کیا، ضرور ارشاد فرمائیں، فرمایا کہ «لا حول ولا قوة إلا بالله» ۔' WHERE id = 6171;
UPDATE hadiths SET urdu = 'ہم سے عبدالسلام بن مطہر نے بیان کیا، انہوں نے کہا ہم سے عمر بن علی بن عطاء نے بیان کیا، ان سے معن بن محمد غفاری نے، ان سے سعید بن ابی سعید مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے اس آدمی کے عذر کے سلسلے میں حجت تمام کر دی جس کی موت کو مؤخر کیا یہاں تک کہ وہ ساٹھ سال کی عمر کو پہنچ گیا۔“ اس روایت کی متابعت ابوحازم اور ابن عجلان نے مقبری سے کی۔' WHERE id = 6181;
UPDATE hadiths SET urdu = 'ہم سے عبدان نے بیان کیا، کہا ہم سے ابوحمزہ نے، ان سے اعمش نے، ان سے ابراہیم نے، ان سے عبیدہ نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے بہتر میرا زمانہ ہے، اس کے بعد ان لوگوں کا جو اس کے بعد ہوں گے پھر جو ان کے بعد ہوں گے اور اس کے بعد ایسے لوگ پیدا ہوں گے جو قسم سے پہلے گواہی دیں گے کبھی گواہی سے پہلے قسم کھائیں گے۔“' WHERE id = 6191;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے صالح نے بیان کیا، ان سے ابن شہاب نے کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی اور ان سے رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اگر انسان کے پاس سونے کی ایک وادی ہو تو وہ چاہے گا کہ دو ہو جائیں اور اس کا منہ قبر کی مٹی کے سوا اور کوئی چیز نہیں بھر سکتی اور اللہ اس کی توبہ قبول کرتا ہے جو توبہ کرے۔“' WHERE id = 6201;
UPDATE hadiths SET urdu = 'ہم سے ابوولید نے بیان کیا، کہا ہم سے سلم بن زریر نے بیان کیا، کہا ہم سے ابورجاء عمران بن تمیم نے بیان کیا، ان سے عمران بن حصین رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میں نے جنت میں جھانکا تو اس میں رہنے والے اکثر غریب لوگ تھے اور میں نے دوزخ میں جھانکا تو اس کی رہنے والیاں اکثر عورتیں تھیں۔“ ابورجاء کے ساتھ اس حدیث کو ایوب سختیانی اور عوف اعرابی نے بھی روایت کیا ہے اور صخر بن جویریہ اور حماد بن نجیح دونوں اس حدیث کو ابورجاء سے، انہوں نے ابن عباس رضی اللہ عنہما سے روایت کیا۔' WHERE id = 6211;
UPDATE hadiths SET urdu = 'ہم سے عبدالعزیز بن عبداللہ اویسی نے بیان کیا، انہوں نے کہا ہم سے ابن ابی حازم نے بیان کیا، ان سے ان کے والد نے بیان کیا، ان سے یزید بن رومان نے بیان کیا، ان سے عروہ بن زبیر نے اور ان سے ام المؤمنین عائشہ رضی اللہ عنہا نے بیان کیا انہوں نے عروہ سے کہا، بیٹے! ہم دو مہینوں میں تین چاند دیکھ لیتے ہیں اور رسول اللہ صلی اللہ علیہ وسلم ( کی بیویوں ) کے گھروں میں چولھا نہیں جلتا تھا۔ میں نے پوچھا پھر آپ لوگ زندہ کس چیز پر رہتی تھیں؟ بتلایا کہ صرف دو کالی چیزوں پر، کھجور اور پانی۔ ہاں، نبی کریم صلی اللہ علیہ وسلم کے کچھ انصاری پڑوسی تھے جن کے یہاں دودہیل اونٹنیاں تھیں وہ اپنے گھروں سے نبی کریم صلی اللہ علیہ وسلم کے لیے دودھ بھیج دیتے اور آپ ہمیں وہی دودھ پلا دیتے تھے۔' WHERE id = 6221;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے یعقوب بن عبدالرحمٰن نے بیان کیا، ان سے عمرو بن ابی عمرو نے بیان کیا، ان سے سعید بن ابی مقبری نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے رحمت کو جس دن بنایا تو اس کے سو حصے کئے اور اپنے پاس ان میں سے نناوے رکھے۔ اس کے بعد تمام مخلوق کے لیے صرف ایک حصہ رحمت کا بھیجا۔ پس اگر کافر کو وہ تمام رحم معلوم ہو جائے جو اللہ کے پاس ہے تو وہ جنت سے ناامید نہ ہو اور اگر مومن کو وہ تمام عذاب معلوم ہو جائیں جو اللہ کے پاس ہیں تو دوزخ سے کبھی بےخوف نہ ہو۔' WHERE id = 6231;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے یحییٰ قطان نے بیان کیا، ان سے عبیداللہ نے بیان کیا، کہا کہ مجھ سے خبیب بن عبدالرحمٰن نے بیان کیا، ان سے حفص بن عاصم نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سات طرح کے لوگ وہ ہیں جنہیں اللہ تعالیٰ اپنے سایہ میں پناہ دے گا۔ ( ان میں ) ایک وہ شخص بھی ہے جس نے تنہائی میں اللہ کو یاد کیا تو اس کی آنکھوں سے آنسو جاری ہو گئے۔“' WHERE id = 6241;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن مثنیٰ نے بیان کیا، انہوں نے کہا ہم سے غندر نے بیان کیا، ان سے شعبہ نے بیان کیا، ان سے عبدالملک بن عمیر نے بیان کیا، ان سے ابوسلمہ نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”سب سے سچا شعر جسے شاعر نے کہا ہے یہ ہے ”ہاں اللہ کے سوا تمام چیزیں بےبنیاد ہیں۔“' WHERE id = 6251;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے، کہا مجھ سے سلمہ بن کہیل نے بیان کیا۔ (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ ہم سے ابونعیم نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے سلمہ نے بیان کیا کہ میں نے جندب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا اور میں نے آپ کے سوا کسی کو یہ کہتے نہیں سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، چنانچہ میں ان کے قریب پہنچا تو میں نے سنا کہ وہ کہہ رہے تھے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ( کسی نیک کام کے نتیجہ میں ) جو شہرت کا طالب ہو اللہ تعالیٰ اس کی بدنیتی قیامت کے دن سب کو سنا دے گا۔ اسی طرح جو کوئی لوگوں کو دکھانے کے لیے نیک کام کرے گا اللہ بھی قیامت کے دن اس کو سب لوگوں کو دکھلا دے گا۔' WHERE id = 6261;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل بن خالد نے، ان سے ابن شہاب نے، کہا مجھ کو سعید بن مسیب اور عروہ بن زبیر نے چند علم والوں کے سامنے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کی زوجہ مطہرہ عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے جب آپ خاصے تندرست تھے فرمایا تھا کسی نبی کی اس وقت تک روح قبض نہیں کی جاتی جب تک جنت میں اس کے رہنے کی جگہ اسے دکھا نہ دی جاتی ہو اور پھر اسے ( دنیا یا آخرت کے لیے ) اختیار دیا جاتا ہے۔ پھر جب نبی کریم صلی اللہ علیہ وسلم بیمار ہوئے اور نبی کریم صلی اللہ علیہ وسلم کا سر مبارک میری ران پر تھا تو آپ پر تھوڑی دیر کے لیے غشی چھا گئی، پھر جب آپ کو ہوش آیا تو آپ چھت کی طرف ٹکٹکی لگا کر دیکھنے لگے۔ پھر فرمایا «اللهم الرفيق الأعلى» میں نے کہا کہ اب نبی کریم صلی اللہ علیہ وسلم ہمیں ترجیح نہیں دے سکتے اور میں سمجھ گئی کہ یہ وہی حدیث ہے جو آپ نے ایک مرتبہ ارشاد فرمائی تھی۔ راوی نے بیان کیا کہ یہ نبی کریم صلی اللہ علیہ وسلم کا آخری کلمہ تھا جو آپ نے اپنی زبان مبارک سے ادا فرمایا یعنی یہ ارشاد کہ «اللهم الرفيق الأعلى» یعنی یا اللہ! مجھ کو بلند رفیقوں کا ساتھ پسند ہے۔' WHERE id = 6271;
UPDATE hadiths SET urdu = 'ہم سے مقاتل مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو یونس بن یزید ایلی نے خبر دی، انہیں زہری نے، کہا مجھ سے سعید بن مسیب نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ زمین کو اپنی مٹھی میں لے لے گا اور آسمانوں کو اپنے دائیں ہاتھ میں لپیٹ لے گا، پھر فرمائے گا کہ اب میں ہوں بادشاہ، آج زمین کے بادشاہ کہاں گئے؟“' WHERE id = 6281;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن اویس نے بیان کیا، کہا مجھ سے میرے بھائی نے بیان کیا، ان سے سلیمان نے، ان سے ثور نے، ان سے ابوالغیث نے، ان سے ابوہریرہ رضی اللہ عنہ نے اور ان سے نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قیامت کے دن سب سے پہلے آدم علیہ السلام کو پکارا جائے گا۔ پھر ان کی نسل ان کو دیکھے گی تو کہا جائے گا کہ یہ تمہارے بزرگ دادا آدم ہیں۔ ( پکارنے پر ) وہ کہیں گے کہ لبیک و سعدیک۔ اللہ تعالیٰ فرمائے گا کہ اپنی نسل میں سے دوزخ کا حصہ نکال لو۔ آدم علیہ السلام عرض کریں گے اے پروردگار! کتنوں کو نکالوں؟ اللہ تعالیٰ فرمائے گا فیصد ( ننانوے فیصد دوزخی ایک جنتی ) ۔ صحابہ رضوان اللہ علیہم نے عرض کیا: یا رسول اللہ! جب ہم میں سو میں ننانوے نکال دئیے جائیں تو پھر باقی کیا رہ جائیں گے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمام امتوں میں میری امت اتنی ہی تعداد میں ہو گی جیسے سیاہ بیل کے جسم پر سفید بال ہوتے ہیں۔' WHERE id = 6291;
UPDATE hadiths SET urdu = 'مجھ سے عمر بن حفص نے بیان کیا، کہا مجھ سے میرے والد نے بیان کیا، کہا کہ مجھ سے اعمش نے بیان کیا، کہا کہ مجھ سے خیثمہ نے بیان کیا، ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”تم میں ہر ہر فرد سے اللہ تعالیٰ قیامت کے دن اس طرح کلام کرے گا کہ اللہ کے اور بندے کے درمیان کوئی ترجمان نہیں ہو گا۔ پھر وہ دیکھے گا تو اس کے آگے کوئی چیز نظر نہیں آئے گی۔ پھر وہ اپنے سامنے دیکھے گا اور اس کے سامنے آگ ہو گی۔ پس تم میں سے جو شخص بھی چاہے کہ وہ آگ سے بچے تو وہ اللہ کی راہ میں خیر خیرات کرتا رہے، خواہ کھجور کے ایک ٹکڑے کے ذریعہ ہی ممکن ہو۔' WHERE id = 6301;
UPDATE hadiths SET urdu = 'ہم سے معاذ بن اسد نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو امام مالک بن انس نے خبر دی، انہیں زید بن اسلم نے، انہیں عطاء بن یسار نے اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ اہل جنت سے فرمائے گا کہ اے جنت والو! جنتی جواب دیں گے ہم حاضر ہیں اے ہمارے پروردگار! تیری سعادت حاصل کرنے کے لیے۔ اللہ تعالیٰ پوچھے گا کیا اب تم لوگ خوش ہوئے؟ وہ کہیں گے اب بھی بھلا ہم راضی نہ ہوں گے کیونکہ اب تو، تو نے ہمیں وہ سب کچھ دے دیا جو اپنی مخلوق کے کسی آدمی کو نہیں دیا۔ اللہ تعالیٰ فرمائے گا کہ میں تمہیں اس سے بھی بہتر چیز دوں گا۔ جنتی کہیں گے اے رب! اس سے بہتر اور کیا چیز ہو گی؟ اللہ تعالیٰ فرمائے گا کہ اب میں تمہارے لیے اپنی رضا مندی کو ہمیشہ کے لیے دائمی کر دوں گا یعنی اس کے بعد کبھی تم پر ناراض نہیں ہوں گا۔' WHERE id = 6311;
UPDATE hadiths SET urdu = 'ہم سے ہدبہ بن خالد نے بیان کیا، کہا ہم سے ہمام بن یحییٰ نے بیان کیا، ان سے قتادہ نے، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”ایک جماعت جہنم سے نکلے گی اس کے بعد کہ جہنم کی آگ نے ان کو جلا ڈالا ہو گا اور پھر وہ جنت میں داخل ہوں گے۔ اہل جنت ان کو «جهنميين» کے نام سے یاد کریں گے۔“' WHERE id = 6321;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے عمرو نے بیان کیا، ان سے سعید بن ابی سعید مقبری نے بیان کیا، ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے عرض کیا: یا رسول اللہ! قیامت کے دن آپ کی شفاعت کی سعادت سب سے زیادہ کون حاصل کرے گا؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے ابوہریرہ! میرا بھی خیال تھا کہ یہ حدیث تم سے پہلے اور کوئی مجھ سے نہیں پوچھے گا، کیونکہ حدیث کے لینے کے لیے میں تمہاری بہت زیادہ حرص دیکھا کرتا ہوں۔ قیامت کے دن میری شفاعت کی سعادت سب سے زیادہ اسے حاصل ہو گی جس نے کلمہ «لا إله إلا الله» خلوص دل سے کہا۔' WHERE id = 6331;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن وہب نے بیان کیا، ان سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، اور ان سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میرے حوض کی لمبائی اتنی ہو گی جتنی ایلہ اور یمن اور شہر صنعاء کے درمیان کی لمبائی ہے۔ اور وہاں اتنی بڑی تعداد میں پیالے ہوں گے جتنی آسمان کے ستاروں کی تعداد ہے۔“' WHERE id = 6341;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن خالد نے بیان کیا، کہا ہم سے لیث نے بیان کیا، ان سے یزید نے، ان سے ابوالخیر مرثد بن عبداللہ نے اور ان سے عقبہ بن عامر رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم باہر تشریف لائے اور شہداء احد کے لیے اس طرح دعا کی جس طرح میت کے لیے جنازہ میں دعا کی جاتی ہے۔ پھر آپ صلی اللہ علیہ وسلم منبر پر تشریف لائے اور فرمایا ”لوگو! میں تم سے آگے جاؤں گا اور تم پر گواہ رہوں گا اور میں واللہ اپنے حوض کی طرف اس وقت بھی دیکھ رہا ہوں اور مجھے زمین کے خزانوں کی کنجیاں دی گئی ہیں یا فرمایا کہ زمین کی کنجیاں دی گئی ہیں۔ اللہ کی قسم! میں تمہارے بارے میں اس بات سے نہیں ڈرتا کہ تم میرے بعد شرک کرو گے، البتہ اس سے ڈرتا ہوں کہ تم دنیا کے لالچ میں پڑ کر ایک دوسرے سے حسد کرنے لگو گے۔' WHERE id = 6351;
UPDATE hadiths SET urdu = 'ہم سے مالک بن اسماعیل نے بیان کیا، کہا ہم سے اسرائیل نے بیان کیا، ان سے عاصم نے، ان سے ابوعثمان نے اور ان سے اسامہ رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں موجود تھا کہ آپ صلی اللہ علیہ وسلم کی صاحبزادیوں میں سے ایک کا بلاوا آیا۔ نبی کریم صلی اللہ علیہ وسلم کی خدمت میں سعد، ابی بن کعب اور معاذ رضی اللہ عنہم موجود تھے۔ بلانے والے نے آ کر کہا کہ ان کا بچہ ( نبی کریم صلی اللہ علیہ وسلم کا نواسہ ) نزع کی حالت میں ہے۔ نبی کریم صلی اللہ علیہ وسلم نے کہلا بھیجا کہ اللہ ہی کا ہے جو وہ لیتا ہے، اس لیے وہ صبر کریں اور اللہ سے اجر کی امید رکھیں۔' WHERE id = 6362;
UPDATE hadiths SET urdu = 'مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم سے عبدالرزاق نے بیان کیا، کہا ہم کو معمر نے خبر دی، انہیں ابن طاؤس نے، انہیں ان کے والد نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ یہ جو «لمم» کا لفظ قرآن میں آیا ہے تو میں «لمم» کے مشابہ اس بات سے زیادہ کوئی بات نہیں جانتا جو ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے بیان کی ہے کہ اللہ تعالیٰ نے انسان کے لیے زنا کا کوئی نہ کوئی حصہ لکھ دیا ہے جس سے اسے لامحالہ گزرنا ہے، پس آنکھ کا زنا ( غیرمحرم کو ) دیکھنا ہے، زبان کا زنا غیرمحرم سے گفتگو کرنا ہے، دل کا زنا خواہش اور شہوت ہے اور شرمگاہ اس کی تصدیق کر دیتی ہے یا اسے جھٹلا دیتی ہے۔ اور شبابہ نے بیان کیا کہ ہم سے ورقاء نے بیان کیا، ان سے ابن طاؤس نے، ان سے ان کے والد نے، ان سے ابوہریرہ رضی اللہ عنہ نے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے پھر اس حدیث کو نقل کیا۔' WHERE id = 6372;
UPDATE hadiths SET urdu = 'ہم سے ابونعمان محمد بن فضل سدوسی نے بیان کیا، کہا ہم سے جریر بن حازم نے بیان کیا، کہا ہم سے امام حسن بصری نے بیان کیا، کہا ہم سے عبدالرحمٰن بن سمرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے عبدالرحمٰن بن سمرہ! کبھی کسی حکومت کے عہدہ کی درخواست نہ کرنا کیونکہ اگر تمہیں یہ مانگنے کے بعد ملے گا تو اللہ پاک اپنی مدد تجھ سے اٹھا لے گا، تو جان، تیرا کام جانے اور اگر وہ عہدہ تمہیں بغیر مانگے مل گیا تو اس میں اللہ کی طرف سے تمہاری اعانت کی جائے گی اور جب تم کوئی قسم کھا لو اور اس کے سوا کسی اور چیز میں بھلائی دیکھو تو اپنی قسم کا کفارہ دے دو اور وہ کام کرو جو بھلائی کا ہو۔' WHERE id = 6382;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن سلیمان نے بیان کیا، انہوں نے کہا کہ مجھ سے ابن وہب نے بیان کیا، انہوں نے کہا کہ مجھے حیوہ نے خبر دی، کہا کہ مجھ سے ابوعقیل زہرہ بن معبد نے بیان کیا، انہوں نے اپنے دادا عبداللہ بن ہشام سے سنا، انہوں نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ تھے اور آپ عمر بن خطاب رضی اللہ عنہ کا ہاتھ پکڑے ہوئے تھے۔ عمر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! آپ مجھے ہر چیز سے زیادہ عزیز ہیں، سوا میری اپنی جان کے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ نہیں، اس ذات کی قسم جس کے ہاتھ میں میری جان ہے۔ ( ایمان اس وقت تک مکمل نہیں ہو سکتا ) جب تک میں تمہیں تمہاری اپنی جان سے بھی زیادہ عزیز نہ ہو جاؤں۔ عمر رضی اللہ عنہ نے عرض کیا: پھر واللہ! اب آپ مجھے میری اپنی جان سے بھی زیادہ عزیز ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں، عمر! اب تیرا ایمان پورا ہوا۔' WHERE id = 6392;
UPDATE hadiths SET urdu = 'مجھ سے اسحاق نے بیان کیا، کہا ہم کو حبان نے خبر دی، کہا ہم سے ہمام نے بیان کیا، کہا ہم سے قتادہ نے بیان کیا، کہا ہم سے انس بن مالک رضی اللہ عنہ نے بیان کیا کہ انہوں نے نبی کریم کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم فرما رہے تھے کہ رکوع اور سجدہ پورے طور پر ادا کیا کرو۔ اللہ کی قسم جس کے ہاتھ میں میری جان ہے میں اپنی کمر کے پیچھے سے تم کو دیکھ لیتا ہوں جب رکوع اور سجدہ کرتے ہو۔' WHERE id = 6403;
UPDATE hadiths SET urdu = 'ہم سے قبیصہ بن عقبہ نے بیان کیا، کہا ہم سے سفیان ثوری نے، انہوں نے اشعث بن ابی الشعثاء سے، انہوں نے معاویہ بن سوید بن مقرن سے، انہوں نے براء بن عازب سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے (دوسری سند) امام بخاری رحمہ اللہ نے کہا اور مجھ سے محمد بن بشار نے بیان کیا، کہا ہم سے غندر محمد بن جعفر نے، کہا ہم سے شعبہ نے، انہوں نے اشعث سے، انہوں نے معاویہ بن سوید بن مقرن سے، انہوں نے براء رضی اللہ عنہ سے، انہوں نے کہا کہ نبی کریم صلی اللہ علیہ وسلم نے قسم کھانے والے کو سچا کرنے کا حکم فرمایا۔' WHERE id = 6413;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابوبکر بن عیاش نے بیان کیا، ان سے عبدالعزیز بن رفیع نے بیان کیا، ان سے عطاء بن ابی رباح نے بیان کیا اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ ایک صحابی نے نبی کریم صلی اللہ علیہ وسلم سے کہا، میں نے رمی کرنے سے پہلے طواف زیارت کر لیا ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ کوئی حرج نہیں۔ تیسرے نے کہا کہ میں نے رمی کرنے سے پہلے ہی ذبح کر لیا۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کوئی حرج نہیں۔' WHERE id = 6424;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے برید نے، ان سے ابوبردہ نے اور ان سے ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ میرے ساتھیوں نے مجھے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں سواری کے جانور مانگنے کے لیے بھیجا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم میں تمہارے لیے کوئی سواری کا جانور نہیں دے سکتا ( کیونکہ موجود نہیں ہیں ) جب میں آپ کے سامنے آیا تو آپ کچھ خفگی میں تھے۔ پھر جب دوبارہ آیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اپنے ساتھیوں کے پاس جا اور کہہ کہ اللہ تعالیٰ نے یا ( یہ کہا کہ ) رسول اللہ صلی اللہ علیہ وسلم نے تمہارے لیے سواری کا انتظام کر دیا۔' WHERE id = 6435;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، ان سے امام مالک نے بیان کیا، ان سے اسحاق بن عبداللہ بن ابی طلحہ نے بیان کیا، انہوں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ابوطلحہ رضی اللہ عنہ نے ( اپنی بیوی ) ام سلیم رضی اللہ عنہا سے کہا کہ میں سن کر آ رہا ہوں نبی کریم صلی اللہ علیہ وسلم کی آواز ( فاقوں کی وجہ سے ) کمزور پڑ گئی ہے اور میں نے آواز سے آپ کے فاقہ کا اندازہ لگایا ہے۔ کیا تمہارے پاس کھانے کی کوئی چیز ہے؟ انہوں نے کہا ہاں۔ چنانچہ انہوں نے جَو کی چند روٹیاں نکالیں اور ایک اوڑھنی لے کر روٹی کو اس کے ایک کونے سے لپیٹ دیا اور اسے نبی کریم صلی اللہ علیہ وسلم کی خدمت میں بھجوایا۔ میں لے کر گیا تو میں نے دیکھا کہ نبی کریم صلی اللہ علیہ وسلم مسجد میں تشریف رکھتے ہیں اور آپ کے ساتھ کچھ لوگ ہیں، میں ان کے پاس جا کے کھڑا ہو گیا تو نبی کریم صلی اللہ علیہ وسلم نے پوچھا، کیا تمہیں ابوطلحہ نے بھیجا ہے، میں نے عرض کیا: جی ہاں۔ پھر نبی کریم صلی اللہ علیہ وسلم نے ان لوگوں سے کہا جو ساتھ تھے کہ اٹھو اور چلو، میں ان کے آگے آگے چل رہا تھا۔ آخر میں ابوطلحہ رضی اللہ عنہ کے یہاں پہنچا اور ان کو اطلاع دی۔ ابوطلحہ نے کہا: ام سلیم! رسول اللہ صلی اللہ علیہ وسلم تشریف لائے ہیں اور ہمارے پاس تو کوئی ایسا کھانا نہیں ہے جو سب کو پیش کیا جا سکے؟ انہوں نے کہا کہ اللہ اور اس کے رسول کو زیادہ علم ہے۔ پھر ابوطلحہ رضی اللہ عنہ باہر نکلے اور نبی کریم صلی اللہ علیہ وسلم سے ملے، اس کے بعد نبی کریم صلی اللہ علیہ وسلم اور ابوطلحہ گھر کی طرف بڑھے اور اندر گئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ام سلیم! جو کچھ تمہارے پاس ہے میرے پاس لاؤ۔ وہ یہی روٹیاں لائیں۔ راوی نے بیان کیا کہ پھر نبی کریم صلی اللہ علیہ وسلم کے حکم سے ان روٹیوں کو چورا کر دیا گیا اور ام سلیم رضی اللہ عنہا نے اپنی ایک ( گھی کی ) کپی کو نچوڑا گیا یہی سالن تھا۔ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے جیسا کہ اللہ نے چاہا دعا پڑھی اور فرمایا کہ دس دس آدمیوں کو اندر بلاؤ انہیں بلایا گیا اور اس طرح سب لوگوں نے کھایا اور خوب سیر ہو گئے، حاضرین کی تعداد ستر یا اسی آدمیوں کی تھی۔' WHERE id = 6445;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، ان سے زہری نے، انہیں عبیداللہ بن عبداللہ نے خبر دی، انہیں ابن عباس رضی اللہ عنہما نے خبر دی، انہیں سعد بن عبادہ رضی اللہ عنہ نے خبر دی کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے ایک نذر کے بارے میں پوچھا جو ان کی والدہ کے ذمہ باقی تھی اور ان کی موت نذر پوری کرنے سے پہلے ہو گئی تھی۔ نبی کریم صلی اللہ علیہ وسلم نے انہیں فتویٰ دیا کہ نذر وہ اپنی ماں کی طرف سے پوری کر دیں۔ چنانچہ بعد میں یہی طریقہ مسنونہ قرار پایا۔' WHERE id = 6455;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، کہا ہم سے ابوشہاب عبداللہ بن نافع نے بیان کیا، ان سے ابن عون نے، ان سے مجاہد نے، ان سے عبدالرحمٰن بن ابی لیلیٰ نے، ان سے کعب بن عجرہ رضی اللہ عنہ نے بیان کیا کہ میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا تو نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قریب ہو جا، میں قریب ہوا تو آپ صلی اللہ علیہ وسلم نے پوچھا کیا تمہارے سر کے کپڑے تکلیف دے رہے ہیں؟ میں نے عرض کیا، جی ہاں، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر روزے صدقہ یا قربانی کا فدیہ دیدے۔ اور مجھے ابن عون نے خبر دی، ان سے ایوب نے بیان کیا کہ روزے تین دن کے ہوں گے اور قربانی ایک بکری کی اور ( کھانے کے لیے ) چھ مسکین ہوں گے۔' WHERE id = 6465;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے حماد بن زید نے بیان کیا، ان سے غیلان بن جریر نے، ان سے ابوبردہ بن ابی موسیٰ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے بیان کیا کہ میں رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں قبیلہ اشعر کے چند لوگوں کے ساتھ حاضر ہوا اور آپ سے سواری کے لیے جانور مانگے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اللہ کی قسم میں تمہیں سواری کے جانور نہیں دے سکتا۔ پھر جب تک اللہ تعالیٰ نے چاہا ہم ٹھہرے رہے اور جب کچھ اونٹ آئے تو تین اونٹ ہمیں دئیے جانے کا حکم فرمایا۔ جب ہم انہیں لے کر چلے تو ہم میں سے بعض نے اپنے ساتھیوں سے کہا کہ ہمیں اللہ اس میں برکت نہیں دے گا۔ ہم نبی کریم صلی اللہ علیہ وسلم کے پاس سواری کے جانور مانگنے آئے تھے تو آپ نے قسم کھا لی تھی کہ ہمیں سواری کے جانور نہیں دے سکتے اور آپ نے عنایت فرمائے ہیں۔ ابوموسیٰ رضی اللہ عنہ نے بیان کیا کہ پھر ہم نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوئے اور آپ سے اس کا ذکر کیا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں نے تمہارے لیے جانور کا انتظام نہیں کیا ہے بلکہ اللہ تعالیٰ نے کیا ہے، اللہ کی قسم! اگر اللہ نے چاہا تو جب بھی میں کوئی قسم کھا لوں گا اور پھر اس کے سوا اور چیز میں اچھائی ہو گی تو میں اپنی قسم کا کفارہ دے دوں گا اور وہی کام کروں گا جس میں اچھائی ہو گی۔' WHERE id = 6475;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن مسلمہ قعبنی نے بیان کیا، ان سے امام مالک نے، ان سے ابن شہاب نے، ان سے عائشہ رضی اللہ عنہا نے کہ جب رسول اللہ صلی اللہ علیہ وسلم کی وفات ہوئی تو آپ کی بیویوں نے چاہا کہ عثمان رضی اللہ عنہ کو ابوبکر رضی اللہ عنہ کے پاس بھیجیں، اپنی میراث طلب کرنے کے لیے۔ پھر عائشہ رضی اللہ عنہا نے یاد دلایا۔ کیا نبی کریم صلی اللہ علیہ وسلم نے نہیں فرمایا تھا کہ ہماری وراثت تقسیم نہیں ہوتی، ہم جو کچھ چھوڑ جائیں وہ سب صدقہ ہے؟' WHERE id = 6486;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے لیث نے، ان سے ابن شہاب نے، ان سے ابن المسیب نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے بنی لحیان کی ایک عورت ملیا بنت عویمر کے بچے کے بارے میں جو ایک عورت کی مار سے مردہ پیدا ہوا تھا کہ مارنے والی عورت کو خون بہا کے طور پر ایک غلام یا لونڈی ادا کرنے کا حکم فرمایا تھا۔ پھر وہ عورت بچہ گرانے والی جس کے متعلق نبی کریم صلی اللہ علیہ وسلم نے فیصلہ دیا تھا مر گئی تو نبی کریم صلی اللہ علیہ وسلم نے فیصلہ کیا کہ اس کی میراث اس کے لڑکوں اور شوہر کو دے دی جائے اور یہ دیت ادا کرنے کا حکم اس کے کنبہ والوں کو دیا تھا۔' WHERE id = 6496;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے یحییٰ نے، ان سے شعبہ نے بیان کیا، ان سے محمد بن زیاد نے بیان کیا، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”لڑکا بستر والے کا حق ہوتا ہے۔“' WHERE id = 6506;
UPDATE hadiths SET urdu = 'ہم سے ابن سلام نے بیان کیا، کہا ہم کو وکیع نے خبر دی، انہیں سفیان نے، انہیں منصور نے، انہیں ابراہیم نے، انہیں اسود نے، اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ ولاء اس کے ساتھ قائم ہو گی جو قیمت دے اور احسان کرے ( آزاد کر کے)' WHERE id = 6516;
UPDATE hadiths SET urdu = 'مجھ سے یحییٰ بن بکیر نے بیان کیا، انہوں نے کہا ہم سے لیث نے بیان کیا، ان سے عقیل نے بیان کیا، ان سے ابن شہاب نے بیان کیا، ان سے ابوبکر بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب بھی زنا کرنے والا زنا کرتا ہے تو وہ مؤمن نہیں رہتا، جب بھی کوئی شراب پینے والا شراب پیتا ہے تو وہ مؤمن نہیں رہتا، جب بھی کوئی چوری کرنے والا چوری کرتا ہے تو وہ مؤمن نہیں رہتا، جب بھی کوئی لوٹنے والا لوٹتا ہے کہ لوگ نظریں اٹھا اٹھا کر اسے دیکھنے لگتے ہیں تو وہ مؤمن نہیں رہتا۔“ اور ابن شہاب سے روایت ہے، ان سے سعید بن مسیب اور ابوسلمہ نے بیان کیا ان سے ابوہریرہ رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے اسی طرح سوا لفظ «نهبة‏.‏» کے۔' WHERE id = 6527;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، انہوں نے کہا ہم سے عبداللہ بن داؤد نے بیان کیا، انہوں نے کہا ہم سے فضیل بن غزوان نے بیان کیا، ان سے عکرمہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”جب زنا کرنے والا زنا کرتا ہے تو وہ مومن نہیں رہتا اور اسی طرح جب چور چوری کرتا ہے تو وہ مومن نہیں رہتا۔“' WHERE id = 6537;
UPDATE hadiths SET urdu = 'ہم سے عثمان بن ابی شیبہ نے بیان کیا، کہا ہم سے عبدہ نے بیان کیا، ان سے ہشام نے، ان سے ان کے والد نے بیان کیا اور انہیں عائشہ رضی اللہ عنہا نے خبر دی کہ نبی کریم صلی اللہ علیہ وسلم کے زمانہ میں چور کا ہاتھ بغیر لکڑی کے چمڑے کی ڈھال یا عام ڈھال کی چوری پر ہی کاٹا جاتا تھا۔ ہم سے عثمان نے بیان کیا، کہا ہم سے حمید بن عبدالرحمٰن نے بیان کیا، ان سے ہشام نے بیان کیا، ان سے ان کے والد نے، ان سے عائشہ رضی اللہ عنہا نے اسی طرح ( بیان کیا ) ۔' WHERE id = 6547;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے ولید بن مسلم نے بیان کیا، کہا کہ مجھ سے ابوقلابہ جرمی نے بیان کیا، ان سے انس رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم کے پاس قبیلہ عکل کے چند لوگ آئے اور اسلام قبول کیا لیکن مدینہ کی آب و ہوا انہیں موافق نہیں آئی ( ان کے پیٹ پھول گئے ) تو نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ صدقہ کے اونٹوں کے ریوڑ میں جائیں اور ان کا پیشاب اور دودھ ملا کر پئیں۔ انہوں نے اس کے مطابق عمل کیا اور تندرست ہو گئے لیکن اس کے بعد وہ مرتد ہو گئے اور ان اونٹوں کے چرواہوں کو قتل کر کے اونٹ ہنکا لے گئے۔ نبی کریم صلی اللہ علیہ وسلم نے ان کی تلاش میں سوار بھیجے اور انہیں پکڑ کے لایا گیا پھر ان کے ہاتھ پاؤں کاٹ دئیے گئے اور ان کی آنکھیں پھوڑ دی گئیں ( کیونکہ انہوں نے اسلامی چرواہے کے ساتھ ایسا ہی برتاؤ کیا تھا ) اور ان کے زخموں پر داغ نہیں لگوایا گیا یہاں تک کہ وہ مر گئے۔' WHERE id = 6557;
UPDATE hadiths SET urdu = 'ہم سے آدم بن ابی ایاس نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے سلمہ بن کہیل نے بیان کیا، کہا کہ میں نے شعبی سے سنا، انہوں نے علی رضی اللہ عنہ سے بیان کیا کہ جب انہوں نے جمعہ کے دن عورت کو رجم کیا تو کہا کہ میں نے اس کا رجم رسول اللہ صلی اللہ علیہ وسلم کی سنت کے مطابق کیا ہے۔' WHERE id = 6567;
UPDATE hadiths SET urdu = 'مجھ سے عبداللہ بن محمد الجعفی نے بیان کیا، کہا ہم سے وہب بن جریر نے بیان کیا، کہا ہم سے ہمارے والد نے کہا کہ میں نے یعلیٰ بن حکیم سے سنا، انہوں نے عکرمہ سے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ جب ماعز بن مالک نبی کریم صلی اللہ علیہ وسلم کے پاس آئے تو نبی کریم صلی اللہ علیہ وسلم نے ان سے فرمایا کہ غالباً تو نے بوسہ دیا ہو گا یا اشارہ کیا ہو گا یا دیکھا ہو گا۔ انہوں نے کہا کہ نہیں یا رسول اللہ! نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کیا پھر تو نے ہمبستری ہی کر لی ہے؟ اس مرتبہ آپ نے کنایہ سے کام نہیں لیا۔ بیان کیا کہ اس کے بعد نبی کریم صلی اللہ علیہ وسلم نے انہیں رجم کا حکم دیا۔' WHERE id = 6578;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ نے بیان کیا، ان سے ابوعوانہ نے بیان کیا، کہا ہم سے عبدالملک نے بیان کیا، ان سے مغیرہ کے کاتب وراد نے، ان سے مغیرہ رضی اللہ عنہ نے بیان کیا کہ سعد بن عبادہ رضی اللہ عنہ نے کہا کہ اگر میں اپنی بیوی کے ساتھ کسی غیر مرد کو دیکھ لوں تو سیدھی تلوار کی دھار سے اسے مار ڈالوں۔ یہ بات نبی کریم صلی اللہ علیہ وسلم تک پہنچی تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ کیا تمہیں سعد کی غیرت پر حیرت ہے۔ میں ان سے بھی بڑھ کر غیرت مند ہوں اور اللہ مجھ سے بھی زیادہ غیرت مند ہے۔' WHERE id = 6594;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، انہوں نے کہا ہم سے یحییٰ بن سعید نے بیان کیا، ان سے عبدالرحمٰن بن قاسم نے بیان کیا، ان سے قاسم بن محمد نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کی مجلس میں لعان کا ذکر آیا تو عاصم بن عدی رضی اللہ عنہ نے اس پر ایک بات کہی پھر وہ واپس آئے۔ اس کے بعد ان کی قوم کے ایک صاحب یہ شکایت لے کر ان کے پاس آئے کہ انہوں نے اپنی بیوی کے ساتھ غیر مرد کو دیکھا ہے۔ عاصم رضی اللہ عنہ نے اس پر کہا کہ میں اپنی اس بات کی وجہ سے آزمائش میں ڈالا گیا ہوں۔ پھر آپ ان صاحب کو لے کر نبی کریم صلی اللہ علیہ وسلم کی مجلس میں تشریف لائے اور نبی کریم صلی اللہ علیہ وسلم کو اس کی اطلاع دی جس حالت میں انہوں نے اپنی بیوی کو پایا۔ وہ صاحب زرد رنگ، کم گوشت، سیدھے بالوں والے تھے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اے اللہ! اس معاملہ کو ظاہر کر دے۔ چنانچہ اس عورت کے یہاں اسی شخص کی شکل کا بچہ پیدا ہوا جس کے متعلق شوہر نے کہا تھا کہ اسے انہوں نے اپنی بیوی کے ساتھ دیکھا ہے پھر نبی کریم صلی اللہ علیہ وسلم نے دونوں کے درمیان لعان کرایا۔ ابن عباس رضی اللہ عنہما سے مجلس میں ایک صاحب نے کہا کہ یہ وہی تھا جس کے متعلق نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ اگر میں کسی کو بلا گواہی کے رجم کر سکتا تو اسے رجم کرتا۔ ابن عباس رضی اللہ عنہما نے کہا کہ نہیں یہ تو وہ عورت تھی جو اسلام لانے کے بعد برائیاں اعلانیہ کرتی تھی۔' WHERE id = 6604;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن بشار نے بیان کیا، انہوں نے کہا، ہم سے محمد بن جعفر نے بیان کیا، انہوں نے کہا ہم سے شعبہ نے بیان کیا، ان سے فراس نے، ان سے شعبی نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کبیرہ گناہ اللہ کے ساتھ کسی کو شریک ٹھہرانا، والدین کی نافرمانی کرنا یا فرمایا کہ ناحق دوسرے کا مال لینے کے لیے جھوٹی قسم کھانا ہیں۔“ شک شعبہ کو تھا اور معاذ نے بیان کیا، ان سے شعبہ نے بیان کیا، کہا کبیرہ گناہ اللہ کے ساتھ کسی کو شریک ٹھہرانا، کسی کا مال ناحق لینے کے لیے جھوٹی قسم کھانا اور والدین کی نافرمانی کرنا یا کہا کہ کسی کی جان لینا۔' WHERE id = 6616;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم نے بیان کیا، کہا ہم سے شیبان نحوی نے، ان سے یحییٰ نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ قبیلہ خزاعہ کے لوگوں نے ایک آدمی کو قتل کر دیا تھا۔ اور عبداللہ بن رجاء نے کہا، ان سے حرب بن شداد نے، ان سے یحییٰ بن ابی کثیر نے، ان سے ابوسلمہ بن عبدالرحمٰن نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ فتح مکہ کے موقع پر قبیلہ خزاعہ نے بنی لیث کے ایک شخص ( ابن اثوع ) کو اپنے جاہلیت کے مقتول کے بدلہ میں قتل کر دیا تھا۔ اس پر رسول اللہ صلی اللہ علیہ وسلم کھڑے ہوئے اور فرمایا ”اللہ تعالیٰ نے مکہ مکرمہ سے ہاتھیوں کے ( شاہ یمن ابرہہ کے ) لشکر کو روک دیا تھا لیکن اس نے اپنے رسول اور مومنوں کو اس پر غلبہ دیا۔ ہاں یہ مجھ سے پہلے کسی کے لیے حلال نہیں ہوا تھا اور نہ میرے بعد کسی کے لیے حلال ہو گا اور میرے لیے بھی دن کو صرف ایک ساعت کے لیے۔ اب اس وقت سے اس کی حرمت پھر قائم ہو گئی۔ ( سن لو ) اس کا کانٹا نہ اکھاڑا جائے، اس کا درخت نہ تراشا جائے اور سوا اس کے جو اعلان کرنے کا ارادہ رکھتا ہے کوئی بھی یہاں کی گری ہوئی چیز نہ اٹھائے اور دیکھو جس کا کوئی عزیز قتل کر دیا جائے تو اسے دو باتوں میں اختیار ہے یا اسے اس کا خون بہا دیا جائے یا قصاص دیا جائے۔ یہ وعظ سن کر اس پر ایک یمنی صاحب ابوشاہ نامی کھڑے ہوئے اور کہا: یا رسول اللہ! اس وعظ کو میرے لیے لکھوا دیجئیے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا یہ وعظ ابوشاہ کے لیے لکھ دو۔ اس کے بعد قریش کے ایک صاحب عباس رضی اللہ عنہ کھڑے ہوئے اور کہا: یا رسول اللہ اذخر گھاس کی اجازت فرما دیجئیے کیونکہ ہم اسے اپنے گھروں میں اور اپنی قبروں میں بچھاتے ہیں۔ چنانچہ نبی کریم صلی اللہ علیہ وسلم نے اذخر گھاس اکھاڑنے کی اجازت دے دی۔ اور اس روایت کی متابعت عبیداللہ نے شیبان کے واسطہ سے ہاتھیوں کے واقعہ کے ذکر کے سلسلہ میں کی۔ بعض نے ابونعیم کے حوالہ سے «القتل‏.‏» کا لفظ روایت کا ہے اور عبیداللہ نے بیان کیا کہ یا مقتول کے گھر والوں کو قصاص دیا جائے۔' WHERE id = 6626;
UPDATE hadiths SET urdu = 'ہم سے مکی بن ابراہیم نے بیان کیا، کہا ہم سے یزید بن ابی عبید نے، اور ان سے سلمہ رضی اللہ عنہ نے بیان کیا کہ ہم نبی کریم صلی اللہ علیہ وسلم کے ساتھ خیبر کی طرف نکلے۔ جماعت کے ایک صاحب نے کہا عامر! ہمیں اپنی حدی سنائیے۔ انہوں نے حدی خوانی شروع کی تو نبی کریم صلی اللہ علیہ وسلم نے پوچھا کہ کون صاحب گا گا کر اونٹوں کو ہانک رہے ہیں؟ لوگوں نے کہا کہ عامر ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، اللہ ان پر رحم کرے۔ صحابہ نے عرض کیا: یا رسول اللہ! آپ نے ہمیں عامر سے فائدہ کیوں نہیں اٹھانے دیا۔ چنانچہ عامر رضی اللہ عنہ اسی رات کو اپنی ہی تلوار سے شہید ہو گئے۔ لوگوں نے کہا کہ ان کے اعمال برباد ہو گئے، انہوں نے خودکشی کر لی ( کیونکہ ایک یہودی پر حملہ کرتے وقت خود اپنی تلوار سے زخمی ہو گئے تھے ) جب میں واپس آیا اور میں نے دیکھا کہ لوگ آپس میں کہہ رہے ہیں کہ عامر کے اعمال برباد ہو گئے تو میں نبی کریم صلی اللہ علیہ وسلم کی خدمت میں حاضر ہوا اور عرض کیا: اے اللہ کے نبی! آپ پر میرے باپ اور ماں فدا ہوں، یہ لوگ کہتے ہیں کہ عامر کے سارے اعمال برباد ہوئے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ جو شخص یہ کہتا ہے غلط کہتا ہے۔ عامر کو دوہرا اجر ملے گا وہ ( اللہ کے راستہ میں ) مشقت اٹھانے والے اور جہاد کرنے والے تھے اور کس قتل کا اجر اس سے بڑھ کر ہو گا؟' WHERE id = 6636;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، انہوں نے کہا ہم سے لیث بن سعد نے بیان کیا، ان سے ابن شہاب نے بیان کیا اور انہیں سہل بن سعد الساعدی رضی اللہ عنہ نے خبر دی کہ ایک آدمی نبی کریم صلی اللہ علیہ وسلم کے دروازہ کے ایک سوراخ سے اندر جھانکنے لگا۔ اس وقت نبی کریم صلی اللہ علیہ وسلم کے پاس لوہے کا کنگھا تھا جس سے آپ سر جھاڑ رہے تھے۔ جب آپ نے اسے دیکھا تو فرمایا کہ اگر مجھے معلوم ہوتا کہ تم میرا انتظار کر رہے ہو تو میں اسے تمہاری آنکھ میں چبھو دیتا۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ ( گھر کے اندر آنے کا ) اذن لینے کا حکم دیا گیا ہے وہ اسی لیے تو ہے کہ نظر نہ پڑے۔' WHERE id = 6647;
UPDATE hadiths SET urdu = 'ہم سے قیس بن حفص نے بیان کیا، کہا ہم سے عبدالواحد بن زیاد نے، کہا ہم سے حسن بن عمرو فقیمی نے، کہا ہم سے مجاہد نے، انہوں نے عبداللہ بن عمرو رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے، آپ صلی اللہ علیہ وسلم نے فرمایا ”جو شخص ایسی جان کو مار ڈاے جس سے عہد کر چکا ہو ( اس کی امان دے چکا ہو ) جیسے ذمی، کافر کو تو وہ جنت کی خوشبو بھی نہ سونگھے گا ( چہ جائے کہ اس میں داخل ہو ) حالانکہ بہشت کی خوشبو چالیس برس کی راہ سے معلوم ہوتی ہے۔“' WHERE id = 6659;
UPDATE hadiths SET urdu = 'ہم سے محمد بن مقاتل ابوالحسن مروزی نے بیان کیا، کہا ہم کو عبداللہ بن مبارک نے خبر دی، کہا ہم کو شعبہ بن حجاج نے، انہوں نے ہشام بن زید بن انس سے، وہ کہتے تھے میں نے اپنے دادا انس بن مالک رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ ایک یہودی نبی کریم صلی اللہ علیہ وسلم کے پاس سے گزرا کہنے لگا «السام عليك‏.‏» یعنی تم مرو۔ نبی کریم صلی اللہ علیہ وسلم نے جواب میں صرف «وعليك‏ ‏‏.‏» کہا ( تو بھی مرے گا ) پھر آپ صلی اللہ علیہ وسلم نے صحابہ رضی اللہ عنہم سے فرمایا کہ تم کو معلوم ہوا، اس نے کیا کہا؟ اس نے «السام عليك‏.‏» کہا۔ صحابہ نے عرض کیا: یا رسول اللہ! ( حکم ہو تو ) اس کو مار ڈالیں۔ آپ صلی اللہ علیہ وسلم نے فرمایا، نہیں۔ جب کتاب والے یہود اور نصاریٰ تم کو سلام کیا کریں تو تم بھی یہی کہا کرو «وعليكم» ۔' WHERE id = 6670;
UPDATE hadiths SET urdu = 'اور ابوعبداللہ امام بخاری رحمہ اللہ نے بیان کیا، ان سے لیث بن سعد نے بیان کیا انہوں نے کہا کہ مجھ سے یونس نے بیان کیا، ان سے ابن شہاب نے بیان کیا، انہوں نے کہا مجھ کو عروہ بن زبیر نے خبر دی، انہیں مسور بن مخرمہ اور عبدالرحمٰن بن عبدالقاری نے خبر دی، ان دونوں نے عمر بن الخطاب رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے ہشام بن حکیم کو نبی اکرم صلی اللہ علیہ وسلم کی زندگی میں سورۃ الفرقان پڑھتے سنا جب غور سے سنا تو وہ بہت سی ایسی قراتوں کے ساتھ پڑھ رہے تھے جن سے نبی کریم صلی اللہ علیہ وسلم نے مجھے نہیں پڑھایا تھا۔ قریب تھا کہ نماز ہی میں، میں ان پر حملہ کر دیتا لیکن میں نے انتظار کیا اور جب انہوں نے سلام پھیرا تو ان کی چادر سے یا ( انہوں نے یہ کہا کہ ) اپنی چادر سے میں نے ان کی گردن میں پھندا ڈال دیا اور ان سے پوچھا کہ اس طرح تمہیں کس نے پڑھایا ہے؟ انہوں نے کہا کہ مجھے اس طرح رسول اللہ صلی اللہ علیہ وسلم نے پڑھایا ہے۔ میں نے ان سے کہا کہ جھوٹ بولتے ہو، واللہ یہ سورت مجھے بھی نبی کریم صلی اللہ علیہ وسلم نے پڑھائی ہے جو میں نے تمہیں ابھی پڑھتے سنا ہے۔ چنانچہ میں انہیں کھینچتا ہوا نبی کریم صلی اللہ علیہ وسلم کے پاس لایا اور عرض کیا: یا رسول اللہ! میں نے اسے سورۃ الفرقان اور طرح پر پڑھتے سنا ہے جس طرح آپ نے مجھے نہیں پڑھائی تھی۔ آپ صلی اللہ علیہ وسلم نے مجھے بھی سورۃ الفرقان پڑھائی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عمر! انہیں چھوڑ دو۔ ہشام سورت پڑھو۔ انہوں نے اسی طرح پڑھ کر سنایا جس طرح میں نے انہیں پڑھتے سنا تھا۔ نبی کریم صلی اللہ علیہ وسلم نے اس پر فرمایا کہ اسی طرح نازل ہوئی تھی پھر نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ عمر! اب تم پڑھو۔ میں نے پڑھا تو آپ صلی اللہ علیہ وسلم نے فرمایا کہ اسی طرح نازل ہوئی تھی پھر فرمایا یہ قرآن سات قراتوں میں نازل ہوا ہے پس تمہیں جس طرح آسانی ہو پڑھو۔' WHERE id = 6680;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، کہا ہم سے سفیان نے بیان کیا، ان سے ابن جریج نے، ان سے ابن ابی ملیکہ نے، ان سے ابوعمرو نے جن کا نام ذکوان ہے اور ان سے عائشہ رضی اللہ عنہا نے بیان کیا کہ میں نے عرض کیا: یا رسول اللہ! کیا عورتوں سے ان کے نکاح کے سلسلہ میں اجازت لی جائے گی؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا، ہاں۔ میں نے عرض کیا لیکن کنواری لڑکی سے اجازت لی جائے گی تو وہ شرم کی وجہ سے چپ سادھ لے گی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی خاموشی ہی اجازت ہے۔' WHERE id = 6690;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے اسماعیل بن جعفر نے بیان کیا، ان سے ابوسہیل نافع نے، ان سے ان کے والد مالک بن ابی عامر نے، اور ان سے طلحہ بن عبیداللہ رضی اللہ عنہ نے کہ ایک دیہاتی ( ضمام بن ثعلبہ ) رسول اللہ صلی اللہ علیہ وسلم کی خدمت میں اس حال میں حاضر ہوا کہ اس کے سر کے بال پراگندہ تھے اور عرض کیا: یا رسول اللہ! مجھے بتائیے کہ اللہ تعالیٰ نے مجھ پر کتنی نمازیں فرض کی ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پانچ وقت کی نمازیں۔ سوا ان نمازوں کے جو تم نفلی پڑھو۔ اس نے کہا مجھے بتائیے کہ اللہ تعالیٰ نے کتنے روزے فرض کئے ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ رمضان کے مہینے کے روزے سوا ان کے جو تم نفلی رکھو۔ اس نے پوچھا مجھے بتائیے کہ اللہ تعالیٰ نے زکوٰۃ کتنی فرض کی ہے؟ بیان کیا کہ اس پر نبی کریم صلی اللہ علیہ وسلم نے زکوٰۃ کے مسائل بیان کئے۔ پھر اس دیہاتی نے کہا اس ذات کی قسم جس نے آپ کو یہ عزت بخشی ہے جو اللہ تعالیٰ نے مجھ پر فرض کیا ہے اس میں نہ میں کسی قسم کی زیادتی کروں گا اور نہ کمی۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اگر اس نے صحیح کہا ہے تو جنت میں جائے گا اور بعض لوگوں نے کہا کہ ایک سو بیس اونٹوں میں دو حصے تین تین برس کی دو اونٹنیاں جو چوتھے برس میں لگی ہوں زکوٰۃ میں لازم آتی ہیں پس مگر کسی نے ان اونٹوں کو عمداً تلف کر ڈالا ( مثلاً ذبح کر دیا ) اور کوئی حیلہ کیا تو اس کے اوپر سے زکوٰۃ ساقط ہو گی۔' WHERE id = 6700;
UPDATE hadiths SET urdu = 'ہم سے مسلم بن ابراہیم نے بیان کیا، کہا ہم سے ہشام نے بیان کیا، کہا ہم سے یحییٰ بن ابی کثیر نے بیان کیا، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کسی کنواری لڑکی کا نکاح اس وقت تک نہ کیا جائے جب تک اس کی اجازت نہ لے لی جائے اور کسی بیوہ کا نکاح اس وقت تک نہ کیا جائے جب تک اس کا حکم نہ معلوم کر لیا جائے۔“ پوچھا گیا: یا رسول اللہ! اس ( کنواری ) کی اجازت کی کیا صورت ہے؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ اس کی خاموشی اجازت ہے۔ اس کے باوجود بعض لوگ کہتے ہیں کہ اگر کنواری لڑکی سے اجازت نہ لی گئی اور نہ اس نے نکاح کیا۔ لیکن کسی شخص نے حیلہ کر کے دو جھوٹے گواہ کھڑے کر دئیے کہ اس نے لڑکی سے نکاح کیا ہے اس کی مرضی سے اور قاضی نے بھی اس کے نکاح کا فیصلہ کر دیا۔ حالانکہ شوہر جانتا ہے کہ وہ جھوٹا ہے کہ گواہی جھوٹی تھی اس کے باوجود اس لڑکی سے صحبت کرنے میں اس کے لیے کوئی حرج نہیں ہے بلکہ یہ نکاح صحیح ہو گا۔' WHERE id = 6711;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یوسف نے بیان کیا، انہوں نے کہا ہم سے سفیان نے بیان کیا، ان سے ابراہیم بن میسرہ نے بیان کیا، ان سے عمرو بن شرید نے، ان سے ابورافع نے کہ سعد رضی اللہ عنہ نے ان کے ایک گھر کی چار سو مثقال قیمت لگائی تو انہوں نے کہا کہ اگر میں نے رسول اللہ صلی اللہ علیہ وسلم کو یہ کہتے نہ سنا ہوتا کہ پڑوسی اپنے پڑوس کا زیادہ مستحق ہے تو میں اسے تمہیں نہ دیتا۔ اور بعض لوگ کہتے ہیں کہ اگر کسی نے کسی گھر کا حصہ خریدا اور چاہا کہ اس کا حق شفہ باطل کر دے تو اسے اس گھر کو اپنے چھوٹے بیٹے کو ہبہ کر دینا چاہیے، اب نابالغ پر قسم بھی نہیں ہو گی۔' WHERE id = 6721;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن قزعہ نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سعید بن المسیب نے بیان کیا، اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”مومن کا خواب نبوت کے چھیالیس حصوں میں سے ایک حصہ ہوتا ہے۔“ اس کی روایت ثابت، حمید، اسحاق بن عبداللہ اور شعیب نے انس رضی اللہ عنہ سے کی انہوں نے نبی کریم صلی اللہ علیہ وسلم سے۔' WHERE id = 6731;
UPDATE hadiths SET urdu = 'ہم سے احمد بن مقدام العجلی نے بیان کیا ‘ کہا ہم سے محمد بن عبدالرحمٰن الطفاوی نے بیان کیا ‘ ان سے ایوب نے بیان کیا ‘ ان سے محمد نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”مجھے «مفاتيح الكلم» دئیے گئے ہیں اور رعب کے ذریعہ میری مدد کی گئی ہے اور گذشتہ رات میں سویا ہوا تھا کہ زمین کے خزانوں کی کنجیاں میرے پاس لائیں گئیں اور میرے سامنے انہیں رکھ دیا گیا۔“ ابوہریرہ رضی اللہ عنہ نے کہا کہ نبی کریم صلی اللہ علیہ وسلم تو اس دنیا سے تشریف لے گئے اور تم ان خزانوں کی کنجیوں کو الٹ پلٹ کر رہے ہو یا نکال رہے ہو یا لوٹ رہے ہو۔' WHERE id = 6741;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا مجھ سے لیث بن سعد نے بیان کیا، کہا مجھ سے عقیل نے بیان کیا، کہا ان سے ابن شہاب نے، کہا مجھ کو ابوامامہ بن سہل نے خبر دی اور ان سے ابو سعید خدری رضی اللہ عنہ نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میں سویا ہوا تھا کہ میں نے لوگوں کو اپنے سامنے پیش ہوتے دیکھا۔ وہ قمیص پہنے ہوئے تھے، ان میں بعض کی قمیص تو سینے تک کی تھی اور بعض کی اس سے بڑی تھی اور میرے سامنے عمر بن خطاب رضی اللہ عنہ پیش کئے گئے تو ان کی قمیص ( زمین سے ) گھسٹ رہی تھی۔ صحابہ نے پوچھا: یا رسول اللہ! آپ نے اس کی تعبیر کیا کی؟ آپ صلی اللہ علیہ وسلم نے فرمایا کہ دین اس کی تعبیر ہے۔' WHERE id = 6751;
UPDATE hadiths SET urdu = 'ہم سے سعید بن عفیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، کہا کہ مجھ سے عقیل نے بیان کیا، ان سے ابن شہاب نے، انہیں سعید نے خبر دی، انہیں ابوہریرہ رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں سویا ہوا تھا کہ میں نے اپنے آپ کو ایک کنویں پر دیکھا۔ اس پر ایک ڈول تھا۔ جتنا اللہ نے چاہا میں نے اس میں سے پانی کھینچا، پھر اس ڈول کو ابن ابی قحافہ نے لے لیا اور انہوں نے بھی ایک یا دو ڈول کھینچنے اور ان کے کھینچنے میں کمزوری تھی، اللہ ان کی مغفرت کرے پھر وہ بڑا ڈول بن گیا اور اسے عمر بن خطاب نے اٹھا لیا۔ میں نے کسی ماہر کو عمر بن خطاب کی طرح کھینچتے نہیں دیکھا یہاں تک کہ انہوں نے لوگوں کے لیے اونٹوں کے حوض بھر دئیے۔ لوگوں نے اپنے اونٹوں کو سیراب کر کے اپنے تھانوں پر لے جا کر بیٹھا دیا۔“' WHERE id = 6762;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن علاء نے بیان کیا، کہا ہم سے ابواسامہ نے بیان کیا، ان سے بریدہ نے، ان سے ان کے دادا ابوبردہ نے، ان سے ابوموسیٰ رضی اللہ عنہ نے میرا خیال ہے کہ نبی کریم صلی اللہ علیہ وسلم سے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا میں نے خواب دیکھا کہ میں مکہ سے ایک ایسی زمین کی طرف ہجرت کر رہا ہوں جہاں کھجوریں ہیں۔ میرا ذہن اس طرف گیا کہ یہ جگہ یمامہ ہے یا ہجر۔ لیکن بعد میں معلوم ہوا کہ مدینہ یعنی یثرب ہے اور میں نے خواب میں گائے دیکھی ( زبح کی ہوئی ) اور یہ آواز سنی کہ کوئی کہہ رہا ہے کہ اور اللہ کے یہاں ہی خیر ہے تو اس کی تعبیر ان مسلمانوں کی صورت میں آئی جو جنگ احد میں شہید ہوئے اور خیر وہ ہے جو اللہ تعالیٰ نے خیر اور سچائی کے ثواب کی صورت میں دیا یعنی وہ جو ہمیں اللہ تعالیٰ نے جنگ بدر کے بعد ( دوسری فتوحات کی صورت میں ) دی۔' WHERE id = 6774;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے یونس نے، ان سے ابن شہاب نے، ان سے عبیداللہ بن عبداللہ بن عتبہ نے، ان سے ابن عباس رضی اللہ عنہما بیان کرتے تھے کہ ایک شخص رسول اللہ صلی اللہ علیہ وسلم کے پاس آیا اور اس نے کہا کہ رات میں نے خواب میں دیکھا کہ ایک ابر کا ٹکڑا ہے جس سے گھی اور شہد ٹپک رہا ہے میں دیکھتا ہوں کہ لوگ انہیں اپنے ہاتھوں میں لے رہے ہیں۔ کوئی زیادہ اور کوئی کم اور ایک رسی ہے جو زمین سے آسمان تک لٹکی ہوئی ہے۔ میں نے دیکھا کہ پہلے آپ صلی اللہ علیہ وسلم نے آ کر اسے پکڑ اور اوپر چڑھ گئے پھر ایک دوسرے صاحب نے بھی اسے پکڑا اور وہ بھی اوپر چڑھ گئے پھر ایک تیسرے صاحب نے پکڑا اور وہ بھی چڑھ گئے پھر چوتھے صاحب نے پکڑا اور وہ بھی اس کے ذریعہ چڑھ گئے۔ پھر وہ رسی ٹوٹ گئی، پھر جڑ گئی۔ ابوبکر رضی اللہ عنہ نے عرض کیا: یا رسول اللہ! میرے ماں باپ آپ پر فدا ہوں۔ مجھے اجازت دیجئیے میں اس کی تعبیر بیان کر دوں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بیان کرو۔ انہوں نے کہا سایہ سے مراد دین اسلام ہے اور شہد اور گھی ٹپک رہا تھا وہ قرآن مجید کی شیرینی ہے اور بعض قرآن کو زیادہ حاصل کرنے والے ہیں، بعض کم اور آسمان سے زمین تک کی رسی سے مراد وہ سچا طریق ہے جس پر آپ صلی اللہ علیہ وسلم قائم ہیں، آپ صلی اللہ علیہ وسلم اسے پکڑے ہوئے ہیں یہاں تک کہ اس کے ذریعہ اللہ آپ کو اٹھا لے گا پھر آپ کے بعد ایک دوسرے صاحب آپ کے خلیفہ اول اسے پکڑیں گے وہ بھی مرتے دم تک اس پر قائم رہیں گے۔ پھر تیسرے صاحب پکڑیں گے ان کا بھی یہی حال ہو گا۔ پھر چوتھے صاحب پکڑیں گے تو ان کا معاملہ خلافت کا کٹ جائے گا وہ بھی اوپر چڑھ جائیں گے۔ یا رسول اللہ! میرے ماں باپ آپ پر قربان ہوں مجھے بتائیے کیا میں نے جو تعبیر دی ہے وہ غلط ہے یا صحیح۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ بعض حصہ کی صحیح تعبیر دی ہے اور بعض کی غلط۔ ابوبکر رضی اللہ عنہ نے عرض کیا: پس واللہ! آپ میری غلطی کو ظاہر فرما دیں نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ قسم نہ کھاؤ۔' WHERE id = 6784;
UPDATE hadiths SET urdu = 'ہم سے ابونعیم فضل بن دکین نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، ان سے زہری نے (دوسری سند) امام بخاری رحمہ اللہ نے کہا کہ اور مجھ سے محمود بن غیلان نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، انہیں معمر نے خبر دی، انہیں زہری نے، انہیں عروہ نے اور ان سے اسامہ بن زید رضی اللہ عنہما نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم مدینہ کے ٹیلوں میں سے ایک ٹیلے پر چڑھے پھر فرمایا کہ میں جو کچھ دیکھتا ہوں تم بھی دیکھتے ہو؟ لوگوں نے کہا کہ نہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ میں فتنوں کو دیکھتا ہوں کہ وہ بارش کے قطروں کی طرح تمہارے گھروں میں داخل ہو رہے ہیں۔' WHERE id = 6797;
UPDATE hadiths SET urdu = 'ہم سے محمد بن یحییٰ ذہلی (یا محمد بن رافع) نے بیان کیا، کہا ہم کو عبدالرزاق نے خبر دی، انہیں معمر نے، انہیں ہمام نے، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کوئی شخص اپنے کسی دینی بھائی کی طرف ہتھیار سے اشارہ نہ کرے کیونکہ وہ نہیں جانتا ممکن ہے شیطان اسے اس کے ہاتھ سے چھڑوا دے اور پھر وہ کسی مسلمان کو مار کر اس کی وجہ سے جہنم کے گڑھے میں گر پڑے۔“' WHERE id = 6808;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، کہا ہم کو شعیب نے خبر دی، انہیں زہری نے، انہیں ابوسلمہ بن عبدالرحمٰن نے خبر دی اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”ایسے فتنے برپا ہوں گے کہ ان میں بیٹھنے والا کھڑے ہونے والے سے بہتر ہو گا اور کھڑا ہونے والا چلنے والے سے بہتر ہو گا اور چلنے والا دوڑنے والے سے بہتر ہو گا۔ اگر کوئی ان کی طرف دور سے بھی جھانک کر دیکھے گا تو وہ اسے بھی سمیٹ لیں گے ایسے وقت جو کوئی اس سے کوئی پناہ کی جگہ پا لے اسے اس کی پناہ لے لینی چاہئیے۔“' WHERE id = 6818;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، انہوں نے کہا ہم سے ہشام بن یوسف نے بیان کیا، انہوں نے کہا ان سے معمر نے بیان کیا، ان سے زہری نے بیان کیا، ان سے سالم نے، ان سے ان کے والد نے کہ نبی کریم صلی اللہ علیہ وسلم منبر کے ایک طرف کھڑے ہوئے اور فرمایا ”فتنہ ادھر ہے، فتنہ ادھر ہے جدھر سے شیطان کا سینگ طلوع ہوتا ہے یا سورج کا سینگ فرمایا۔“' WHERE id = 6828;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن عثمان نے بیان کیا، انہوں نے کہا ہم کو عبداللہ بن مبارک نے خبر دی، انہیں یونس نے خبر دی، انہیں زہری نے، انہیں حمزہ بن عبداللہ بن عمر رضی اللہ عنہما نے خبر دی اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے سنا، انہوں نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”جب اللہ کسی قوم پر عذاب نازل کرتا ہے تو عذاب ان سب لوگوں پر آتا ہے جو اس قوم میں ہوتے ہیں پھر انہیں ان کے اعمال کے مطابق اٹھایا جائے گا۔“' WHERE id = 6840;
UPDATE hadiths SET urdu = 'ہم سے ابوالیمان نے بیان کیا، انہوں نے کہا شعیب نے خبر دی، انہوں نے کہا ہمیں زہری نے خبر دی کہ سعید بن مسیب نے بیان کیا کہ مجھے ابوہریرہ رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”قیامت قائم نہ ہو گی یہاں تک کہ سر زمین حجاز سے ایک آگ نکلے گی اور بصریٰ میں اونٹوں کی گردنوں کو روشن کر دے گی۔“' WHERE id = 6850;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے سالم نے اور ان سے عبداللہ بن عمر رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”میں سویا ہوا ( خواب میں ) کعبہ کا طواف کر رہا تھا کہ ایک صاحب جو گندم گوں تھے اور ان کے سر کے بال سیدھے تھے اور سر سے پانی ٹپک رہا تھا ( ان پر میری نظر پڑی ) میں نے پوچھا یہ کون ہیں؟ میرے ساتھ کے لوگوں نے بتایا کہ یہ عیسیٰ ابن مریم علیہما السلام ہیں پھر میں نے مڑ کر دیکھا تو موٹے شخص پر نظر پڑی جو سرخ تھا اس کے بال گھونگھریالے تھے، ایک آنکھ کا کانا تھا، اس کی ایک آنکھ انگور کی طرح اٹھی ہوئی تھی۔ لوگوں نے بتایا کہ یہ دجال ہے۔ اس کی صورت عبدالعزیٰ بن قطن سے بہت ملتی تھی۔' WHERE id = 6860;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن ابی اویس نے بیان کیا، کہا مجھ کو امام مالک نے خبر دی، انہیں عبداللہ بن دینار نے اور انہیں عبداللہ بن عمر رضی اللہ عنہما نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”آگاہ ہو جاؤ تم میں سے ہر ایک نگہبان ہے اور ہر ایک سے اس کی رعایا کے بارے میں سوال کیا جائے گا۔ پس امام ( امیرالمؤمنین ) لوگوں پر نگہبان ہے اور اس سے اس کی رعایا کے بارے میں سوال ہو گا۔ مرد اپنے گھر والوں کا نگہبان ہے اور اس سے اس کی رعایا کے بارے میں سوال ہو گا اور عورت اپنے شوہر کے گھر والوں اور اس کے بچوں کی نگہبان ہے اور اس سے ان کے بارے میں سوال ہو گا اور کسی شخص کا غلام اپنے سردار کے مال کا نگہبان ہے اور اس سے اس کے بارے میں سوال ہو گا۔ آگاہ ہو جاؤ کہ تم میں سے ہر ایک نگہبان ہے اور ہر ایک سے اس کی رعایا کے بارے میں پرسش ہو گی۔“' WHERE id = 6870;
UPDATE hadiths SET urdu = 'ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید مقبری نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ ہم سے احمد بن یونس نے بیان کیا، انہوں نے کہا ہم سے ابن ابی ذئب نے بیان کیا، ان سے سعید مقبری نے بیان کیا اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ' WHERE id = 6880;
UPDATE hadiths SET urdu = 'ہم سے آدم نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، کہا ہم سے عبدالملک بن عمیر نے کہا کہ میں نے عبدالرحمٰن ابن ابی بکرہ سے سنا کہا کہ ابوبکرہ رضی اللہ عنہ نے اپنے لڑکے ( عبیداللہ ) کو لکھا اور وہ اس وقت سجستان میں تھے کہ دو آدمیوں کے درمیان فیصلہ اس وقت نہ کرنا جب تم غصہ میں ہو کیونکہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا ہے کہ کوئی ثالث دو آدمیوں کے درمیان فیصلہ اس وقت نہ کرے جب وہ غصہ میں ہو۔' WHERE id = 6890;
UPDATE hadiths SET urdu = 'ابن شہاب نے بیان کیا کہ پھر مجھے اس شخص نے خبر دی جس نے جابر بن عبداللہ رضی اللہ عنہما سے سنا تھا، انہوں نے بیان کیا کہ میں بھی ان لوگوں میں تھا جنہوں نے اس شخص کو عیدگاہ پر رجم کیا تھا۔ اس کی روایت یونس، معمر اور ابن جریج نے زہری سے کی، ان سے ابوسلمہ نے، ان سے جابر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے رجم کے سلسلے میں یہی حدیث ذکر کی۔' WHERE id = 6900;
UPDATE hadiths SET urdu = 'ہم سے محمد بن کثیر نے بیان کیا، کہا ہم کو سفیان نے خبر دی، انہیں ہشام نے، انہیں ان کے والد نے اور ان سے عائشہ رضی اللہ عنہا نے کہ ہند نے نبی کریم صلی اللہ علیہ وسلم سے کہا کہ ( ان کے شوہر ) ابوسفیان بخیل ہیں اور مجھے ان کے مال میں سے لینے کی ضرورت ہوتی ہے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ دستور کے مطابق اتنا لے لیا کرو جو تمہارے اور تمہارے بچوں کے لیے کافی ہو۔' WHERE id = 6911;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبداللہ ابوثابت نے بیان کیا، کہا ہم سے ابراہیم بن سعد نے بیان کیا، ان سے ابن شہاب نے، ان سے عبید بن سابق نے اور ان سے زید بن ثابت رضی اللہ عنہ نے کہ جنگ یمامہ میں بکثرت ( قاری صحابہ کی ) شہادت کی وجہ سے ابوبکر رضی اللہ عنہ نے مجھے بلا بھیجا۔ ان کے پاس عمر رضی اللہ عنہ بھی تھے۔ ابوبکر رضی اللہ عنہ نے مجھ سے کہا کہ عمر میرے پاس آئے اور کہا کہ جنگ یمامہ میں قرآن کے قاریوں کا قتل بہت ہوا ہے اور میرا خیال ہے کہ دوسری جنگوں میں بھی اسی طرح وہ شہید کئے جائیں گے اور قرآن اکثر ضائع ہو جائے گا۔ میں سمجھتا ہوں کہ آپ قرآن مجید کو ( کتابی صورت میں ) جمع کرنے کا حکم دیں۔ اس پر میں نے عمر رضی اللہ عنہ سے کہا کہ میں کوئی ایسا کام کیسے کر سکتا ہوں جسے رسول اللہ صلی اللہ علیہ وسلم نے نہیں کیا۔ عمر رضی اللہ عنہ نے کہا واللہ! یہ تو کار خیر ہے۔ عمر رضی اللہ عنہ اس معاملہ میں برابر مجھ سے کہتے رہے یہاں تک کہ اللہ تعالیٰ نے اسی طرح اس معاملے میں میرا بھی سینہ کھول دیا جس طرح عمر رضی اللہ عنہ کا تھا اور میں بھی وہی مناسب سمجھنے لگا جسے عمر رضی اللہ عنہ مناسب سمجھتے تھے۔ زید رضی اللہ عنہ نے بیان کیا کہ مجھ سے ابوبکر رضی اللہ عنہ نے کہا کہ تم جوان ہو، عقلمند ہو اور ہم تمہیں کسی بارے میں متہم بھی نہیں سمجھتے تم نبی کریم صلی اللہ علیہ وسلم کی وحی بھی لکھتے تھے، پس تم اس قرآن مجید ( کی آیات ) کو تلاش کرو اور ایک جگہ جمع کر دو۔ زید رضی اللہ عنہ نے بیان کیا کہ واللہ! اگر ابوبکر رضی اللہ عنہ مجھے کسی پہاڑ کو اٹھا کر دوسری جگہ رکھنے کا مکلف کرتے تو اس کا بوجھ بھی میں اتنا نہ محسوس کرتا جتنا کہ مجھے قرآن مجید کو جمع کرنے کے حکم سے محسوس ہوا۔ میں نے ان لوگوں سے کہا کہ آپ کس طرح ایسا کام کرتے ہیں جو رسول اللہ صلی اللہ علیہ وسلم نے نہیں کیا۔ ابوبکر نے کہا کہ واللہ! یہ خیر ہے۔ چنانچہ مجھے آمادہ کرنے کی کوشش کرتے رہے، یہاں تک کہ اللہ تعالیٰ نے اس کام کے لیے میرا بھی سینہ کھول دیا جس کے لیے ابوبکر و عمر رضی اللہ عنہما کا سینہ کھولا تھا اور میں بھی وہی مناسب خیال کرنے لگا جسے وہ لوگ مناسب خیال کر رہے تھے۔ چنانچہ میں نے قرآن مجید کی تلاش شروع کی۔ اسے میں کھجور کی چھال، چمڑے وغیرہ کے ٹکڑوں، پتلے پتھر کے ٹکڑوں اور لوگوں کے سینوں سے جمع کرنے لگا۔ میں نے سورۃ التوبہ کی آخری آیت «لقد جاءكم رسول من أنفسكم‏» آخر تک خزیمہ یا ابوخزیمہ رضی اللہ عنہ کے پاس پائی اور اس کو سورت میں شامل کر لیا۔ ( قرآن مجید کے یہ مرتب ) صحیفے ابوبکر رضی اللہ عنہ کے پاس رہے جب تک وہ زندہ ہے۔ یہاں تک کہ اللہ تعالیٰ نے انہیں وفات دی پھر وہ عمر رضی اللہ عنہ کے پاس آ گئے اور آخر وقت تک ان کے پاس رہے۔ جب آپ کو بھی اللہ تعالیٰ نے وفات دی تو وہ حفصہ بنت عمر رضی اللہ عنہا کے پاس محفوظ رہے۔ محمد بن عبیداللہ نے کہا کہ «اللخاف» کے لفظ سے ٹھیکری مراد ہے جسے «خزف‏.‏» کہتے ہیں۔' WHERE id = 6921;
UPDATE hadiths SET urdu = 'ہم سے عمرو بن علی نے بیان کیا، انہوں نے کہا ہم سے یحییٰ نے بیان کیا، ان سے سفیان نے بیان کیا، انہوں نے کہا مجھ سے عبداللہ بن دینار نے بیان کیا کہا کہ جب لوگوں نے عبدالملک کی بیعت کی تو عبداللہ بن عمر رضی اللہ عنہما نے اسے لکھا ”اللہ کے بندے عبدالملک امیرالمؤمنین کے نام، میں اقرار کرتا ہوں سننے اور اطاعت کرنے کی۔ اللہ کے بندے عبدالملک امیرالمؤمنین کے لیے اللہ کے دین اور اس کے رسول کی سنت کے مطابق، جتنی مجھ میں طاقت ہو گی اور میرے بیٹوں نے بھی اس کا اقرار کیا۔“' WHERE id = 6933;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن یحییٰ نے بیان کیا، کہا ہم کو سلیمان بن بلال نے خبر دی، انہیں یحییٰ بن سعید نے، کہا میں نے قاسم بن محمد سے سنا کہ عائشہ رضی اللہ عنہا نے کہا ( اپنے سر درد پر ) ہائے سر پھٹا جاتا ہے۔ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا کہ اگر تم مر جاؤ اور میں زندہ رہا تو میں تمہارے لیے مغفرت کروں گا اور تمہارے لیے دعا کروں گا۔ عائشہ رضی اللہ عنہا نے اس پر کہا افسوس میرا خیال ہے کہ آپ میری موت چاہتے ہیں اور اگر ایسا ہو گیا تو آپ دن کے آخری وقت ضرور کسی دوسری عورت سے شادی کر لیں گے۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تو نہیں بلکہ میں اپنا سر دکھنے کا اظہار کرتا ہوں۔ میرا ارادہ ہوا تھا کہ ابوبکر اور ان کے بیٹے کو بلا بھیجوں اور انہیں ( ابوبکر کو ) خلیفہ بنا دوں تاکہ اس پر کسی دعویٰ کرنے والے یا اس کی خواہش رکھنے والے کے لیے کوئی گنجائش نہ رہے لیکن پھر میں نے سوچا کہ اللہ خود ( کسی دوسرے کو خلیفہ ) نہیں ہونے دے گا اور مسلمان بھی اسے دفع کریں گے۔ یا ( آپ نے اس طرح فرمایا کہ ) اللہ دفع کرے گا اور مسلمان کسی اور کو خلیفہ نہ ہونے دیں گے۔' WHERE id = 6945;
UPDATE hadiths SET urdu = 'ہم سے یحییٰ بن بکیر نے بیان کیا، کہا ہم سے لیث بن سعد نے بیان کیا، ان سے عقیل نے، ان سے ابن شہاب نے، ان سے عروہ رضی اللہ عنہ نے کہ عائشہ رضی اللہ عنہا نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے ( حجتہ الوداع کے موقع پر ) فرمایا ”اگر مجھ کو اپنا حال پہلے سے معلوم ہوتا جو بعد کو معلوم ہوا تو میں اپنے ساتھ قربانی کا جانور نہ لاتا اور عمرہ کر کے دوسرے لوگوں کی طرح بھی احرام کھول ڈالتا۔“' WHERE id = 6956;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، انہوں نے کہا ہم سے سفیان بن عیینہ نے کہ عمرو بن دینار نے کہا، ہم سے عطاء بن ابی رباح نے بیان کیا کہ ایک رات ایسا ہوا نبی کریم صلی اللہ علیہ وسلم نے عشاء کی نماز میں دیر کی۔ آخر عمر رضی اللہ عنہ نکلے اور کہنے لگے یا رسول اللہ! نماز پڑھئے عورتیں اور بچے سونے لگے۔ اس وقت آپ صلی اللہ علیہ وسلم ( حجرے سے ) برآمد ہوئے آپ کے سر سے پانی ٹپک رہا تھا ( غسل کر کے باہر تشریف لائے ) فرمانے لگے اگر میری امت پر یا یوں فرمایا کہ لوگوں پر دشوار نہ ہوتا۔ سفیان بن عیینہ نے یوں کہا کہ میری امت پر دشوار نہ ہوتا تو میں اس وقت ( اتنی رات گئے ) ان کو یہ نماز پڑھنے کا حکم دیتا۔ اور ابن جریج نے ( اسی سند سے سفیان سے، انہوں نے ( ابن جریج سے ) انہوں نے عطاء سے روایت کی، انہوں نے ابن عباس رضی اللہ عنہما سے کہ نبی کریم صلی اللہ علیہ وسلم نے اس نماز ( یعنی عشاء کی نماز میں دیر کی۔ عمر رضی اللہ عنہ آئے اور کہنے لگے یا رسول اللہ! عورتیں بچے سو گئے۔ یہ سن کر آپ باہر تشریف لائے، اپنے سر کی ایک جانب سے پانی پونچھ رہے تھے، فرما رہے تھے اس نماز کا ( عمدہ ) وقت یہی ہے اگر میری امت پر شاق نہ ہو۔ عمرو بن دینار نے اس حدیث میں یوں نقل کیا۔ ہم سے عطاء نے بیان کیا اور ابن عباس رضی اللہ عنہما کا ذکر نہیں کیا لیکن عمرو نے یوں کہا آپ کے سر سے پانی ٹپک رہا تھا۔ اور ابن جریج کی روایت میں یوں ہے آپ صلی اللہ علیہ وسلم سر کے ایک جانب سے پانی پونچھ رہے تھے۔ اور عمرو نے کہا آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میری امت پر شاق نہ ہوتا۔ اور ابن جریج نے کہا آپ صلی اللہ علیہ وسلم نے فرمایا کہ اگر میری امت پر شاق نہ ہوتا تو اس نماز کا ( افضل ) وقت تو یہی ہے۔ اور ابراہیم بن المنذر ( امام بخاری رحمہ اللہ کے شیخ ) نے کہا ہم سے معن بن عیسیٰ نے بیان کیا، کہا مجھ سے محمد بن مسلم نے، انہوں نے عمرو بن دینار سے، انہوں نے عطاء بن ابی رباح سے، انہوں نے ابن عباس رضی اللہ عنہما سے، انہوں نے نبی کریم صلی اللہ علیہ وسلم سے پھر یہی حدیث نقل کی۔' WHERE id = 6966;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر نے بیان کیا، کہا ہم سے شعبہ نے، ان سے حکم بن عتبہ نے، ان سے ابراہیم نخعی نے، ان سے علقمہ بن قیس نے اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ہمیں ظہر کی پانچ رکعت نماز پڑھائی تو آپ صلی اللہ علیہ وسلم سے پوچھا گیا: کیا نماز ( کی رکعتوں ) میں کچھ بڑھ گیا ہے؟ نبی کریم صلی اللہ علیہ وسلم نے دریافت فرمایا کہ کیا بات ہے؟ صحابہ نے کہا کہ آپ نے پانچ رکعت نماز پڑھائی ہے۔ پھر نبی کریم صلی اللہ علیہ وسلم نے سلام کے بعد دو سجدے ( سہو کے ) کئے۔' WHERE id = 6976;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے بیان کیا، کہا ہم سے محمد بن المنکدر نے کہا کہ میں نے جابر بن عبداللہ رضی اللہ عنہما سے سنا، بیان کیا کہ غزوہ خندق کے دن نبی کریم صلی اللہ علیہ وسلم نے ( دشمن سے خبر لانے کے لیے ) صحابہ سے کہا تو زبیر رضی اللہ عنہ تیار ہو گئے پھر ان سے کہا تو زبیر رضی اللہ عنہ ہی تیار ہوئے۔ پھر کہا، پھر بھی انہوں نے ہی آمادگی دکھلائی۔ اس کے بعد آپ صلی اللہ علیہ وسلم نے فرمایا کہ ہر نبی کے حواری ( مددگار ) ہوتے ہیں اور میری حواری زبیر ہیں۔ اور سفیان بن عیینہ نے بیان کیا کہ میں نے یہ روایت ابن المنکدر سے یاد کی اور ایوب نے ابن المنکدر سے کہا، اے ابوبکر! ( یہ محمد بن منکدر کی کنیت ہے ) ان سے جابر رضی اللہ عنہ کی حدیث بیان کیجئے کیونکہ لوگ پسند کرتے ہیں کہ آپ جابر رضی اللہ عنہ کی احادیث بیان کریں تو انہوں نے اسی مجلس میں کہا کہ میں نے جابر رضی اللہ عنہ سے سنا اور چار احادیث میں پے در پے یہ کہا کہ میں نے جابر رضی اللہ عنہ سے سنا۔ علی بن عبداللہ مدینی نے کہا کہ میں نے سفیان بن عیینہ سے کہا کہ سفیان ثوری تو غزوہ قریظہ کہتے ہیں ( بجائے غزوہ خندق کے ) انہوں نے کہا کہ میں نے اتنے ہی یقین کے ساتھ یاد کیا ہے جیسا کہ تم اس وقت بیٹھے ہو کہ انہوں نے غزوہ خندق کہا، سفیان نے کہا کہ یہ دونوں ایک ہی غزوہ ہیں ( کیونکہ ) غزوہ خندق کے فوراً بعد اسی دن غزوہ قریظہ پیش آیا اور وہ مسکرائے۔' WHERE id = 6987;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن صباح نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا، کہا کہ میں نے عوف اعرابی سے سنا ‘ ان سے ابوالمنہال نے بیان کیا، انہوں نے ابوبرزہ رضی اللہ عنہ سے سنا، انہوں نے کہا کہ اللہ تعالیٰ نے تمہیں اسلام اور محمد صلی اللہ علیہ وسلم کے ذریعہ غنی کر دیا ہے یا بلند درجہ کر دیا ہے۔' WHERE id = 6997;
UPDATE hadiths SET urdu = 'ہم سے ابوکریب محمد بن علاء نے بیان کیا، کہا ہم سے اسامہ نے بیان کیا، ان سے برید نے، ان سے ان کے دادا ابوبردہ نے اور ان سے ابوموسیٰ اشعری رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”میری اور جس دعوت کے ساتھ مجھے اللہ تعالیٰ نے بھیجا ہے اس کی مثال ایک ایسے شخص جیسی ہے جو کسی قوم کے پاس آئے اور کہے: اے قوم! میں نے ایک لشکر اپنی آنکھوں سے دیکھا ہے اور میں ننگ دھڑنگ تم کو ڈرانے والا ہوں، پس بچاؤ کی صورت کرو تو اس قوم کے ایک گروہ نے بات مان لی اور رات کے شروع ہی میں نکل بھاگے اور حفاظت کی جگہ چلے گئے۔ اس لیے نجات پا گئے لیکن ان کی دوسری جماعت نے جھٹلایا اور اپنی جگہ ہی پر موجود رہے، پھر صبح سویرے ہی دشمن کے لشکر نے انہیں آ لیا اور انہیں مارا اور ان کو برباد کر دیا۔ تو یہ مثال ہے اس کی جو میری اطاعت کریں اور جو دعوت میں لایا ہوں اس کی پیروی کریں اور اس کی مثال ہے جو میری نافرمانی کریں اور جو حق میں لے کر آیا ہوں اسے جھٹلائیں۔' WHERE id = 7008;
UPDATE hadiths SET urdu = 'ہم سے محمد بن عبدالرحیم نے بیان کیا، کہا ہم کو روح بن عبادہ نے خبر دی، کہا ہم سے شعبہ نے بیان کیا، کہا مجھ کو موسیٰ بن انس نے خبر دی کہ میں نے انس بن مالک رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ ایک صاحب نے کہا: یا نبی اللہ! میرے والد کون ہیں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ تمہارے والد فلاں ہیں۔ اور یہ آیت نازل ہوئی «يا أيها الذين آمنوا لا تسألوا عن أشياء‏» ”اے لوگو! ایسی چیزیں نہ پوچھو۔“ الآیہ۔' WHERE id = 7019;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف تنیسی نے بیان کیا، کہا ہم سے لیث بن سعد نے، ان سے عقیل نے، ان سے ابن شہاب نے، انہیں مالک بن اوس نضری نے خبر دی کہ محمد بن جبیر بن مطعم نے مجھ سے اس سلسلہ میں ذکر کیا تھا، پھر میں مالک کے پاس گیا اور ان سے اس حدیث کے متعلق پوچھا۔ انہوں نے بیان کیا کہ میں روانہ ہوا اور عمر رضی اللہ عنہ کی خدمت میں حاضر ہوا۔ اتنے میں ان کے دربان یرفاء آئے اور کہا کہ عثمان، عبدالرحمٰن، زبیر اور سعد رضی اللہ عنہم اندر آنے کی اجازت چاہتے ہیں، کیا انہیں اجازت دی جائے؟ عمر رضی اللہ عنہ نے کہا کہ ہاں۔ چنانچہ سب لوگ اندر آ گئے اور سلام کیا اور بیٹھ گئے، پھر یرفاء نے آ کر پوچھا کہ کیا علی اور عباس کو اجازت دی جائے؟ ان حضرات کو بھی اندر بلایا۔ عباس رضی اللہ عنہ نے کہا کہ امیرالمؤمنین! میرے اور ظالم کے درمیان فیصلہ کر دیجئیے۔ آپس میں دونوں نے سخت کلامی کی۔ اس پر عثمان رضی اللہ عنہ اور ان کے ساتھیوں کی جماعت نے کہا کہ امیرالمؤمنین! ان کے درمیان فیصلہ کر دیجئیے تاکہ دونوں کو آرام حاصل ہو۔ عمر رضی اللہ عنہ نے کہا کہ صبر کرو میں تمہیں اللہ کی قسم دیتا ہوں جس کی اجازت سے آسمان و زمین قائم ہیں۔ کیا آپ لوگوں کو معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا تھا کہ ہماری میراث تقسیم نہیں ہوتی، ہم جو کچھ چھوڑیں وہ صدقہ ہے۔ نبی کریم صلی اللہ علیہ وسلم نے اس سے خود اپنی ذات مراد لی تھی۔ جماعت نے کہا کہ ہاں، نبی کریم صلی اللہ علیہ وسلم نے یہ فرمایا تھا۔ پھر آپ علی اور عباس رضی اللہ عنہم کی طرف متوجہ ہوئے اور کہا کہ میں آپ لوگوں کو اللہ کی قسم دیتا ہوں۔ کیا آپ لوگوں کو معلوم ہے کہ نبی کریم صلی اللہ علیہ وسلم نے یہ فرمایا؟ انہوں نے بھی کہا کہ ہاں۔ عمر رضی اللہ عنہ نے اس کے بعد کہا کہ پھر میں آپ لوگوں سے اس بارے میں گفتگو کرتا ہوں۔ اللہ تعالیٰ نے اپنے رسول کا اس مال میں سے ایک حصہ مخصوص کیا تھا جو اس نے آپ کے سوا کسی کو نہیں دیا۔ اس لیے کہ اللہ تعالیٰ فرماتا ہے «ما أفاء الله على رسوله منهم فما أوجفتم‏» الآیہ۔ تو یہ مال خاص نبی کریم صلی اللہ علیہ وسلم کے لیے تھا، پھر واللہ! نبی کریم صلی اللہ علیہ وسلم نے اسے اپنے لوگوں کو نظر انداز کر کے اپنے لیے جمع نہیں کیا اور نہ اسے اپنی ذاتی جائیداد بنایا۔ نبی کریم صلی اللہ علیہ وسلم نے اسے آپ لوگوں کو بھی دیا اور سب میں تقسیم کیا، یہاں تک اس میں سے یہ مال باقی رہ گیا تو نبی کریم صلی اللہ علیہ وسلم اس میں سے اپنے گھر والوں کا سالانہ خرچ دیتے تھے، پھر باقی اپنے قبضے میں لے لیتے تھے اور اسے بیت المال میں رکھ کر عام مسلمانوں کے ضروریات میں خرچ کرتے تھے۔ نبی کریم صلی اللہ علیہ وسلم نے زندگی بھر اس کے مطابق عمل کیا۔ میں آپ لوگوں کو اللہ کی قسم دیتا ہوں کیا آپ کو اس کا علم ہے؟ صحابہ نے کہا کہ ہاں پھر آپ نے علی اور عباس رضی اللہ عنہما سے کہا، میں آپ دونوں حضرات کو بھی اللہ کی قسم دیتا ہوں کیا آپ لوگوں کو اس کا علم ہے؟ انہوں نے بھی کہا کہ ہاں۔ پھر اللہ تعالیٰ نے اپنے نبی کریم صلی اللہ علیہ وسلم کو وفات دی اور ابوبکر رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم کے ولی ہونے کی حیثیت سے اس پر قبضہ کیا اور اس میں اسی طرح عمل کیا جیسا کہ نبی کریم صلی اللہ علیہ وسلم کرتے تھے۔ آپ دونوں حضرات بھی یہیں موجود تھے۔ آپ نے علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہو کر یہ بات کہی اور آپ لوگوں کا خیال تھا کہ ابوبکر رضی اللہ عنہ اس معاملے میں خطاکار ہیں اور اللہ خوب جانتا ہے کہ وہ اس معاملے میں سچے اور نیک اور سب سے زیادہ حق کی پیروی کرنے والے تھے، پھر اللہ تعالیٰ نے ابوبکر رضی اللہ عنہ کو وفات دی اور میں نے کہا کہ میں رسول اللہ صلی اللہ علیہ وسلم اور ابوبکر صلی اللہ علیہ وسلم کا ولی ہوں اس طرح میں نے بھی اس جائیداد کو اپنے قبضے میں دو سال تک رکھا اور اس میں اسی کے مطابق عمل کرتا رہا جیسا کہ نبی کریم صلی اللہ علیہ وسلم اور ابوبکر صدیق رضی اللہ عنہ نے کیا تھا، پھر آپ دونوں حضرات میرے پاس آئے اور آپ لوگوں کا معاملہ ایک ہی تھا، کوئی اختلاف نہیں تھا۔ آپ ( عباس رضی اللہ عنہ! ) آئے اپنے بھائی کے لڑکے کی طرف سے اپنی میراث لینے اور یہ ( علی رضی اللہ عنہ ) اپنی بیوی کی طرف سے ان کے والد کی میراث کا مطالبہ کرنے آئے۔ میں نے تم سے کہا کہ یہ جائیداد تقسیم تو نہیں ہو سکتی لیکن تم لوگ چاہو تو میں اہتمام کے طور پر آپ کو یہ جائیداد دے دوں لیکن شرط یہ ہے کہ آپ لوگوں پر اللہ کا عہد اور اس کی میثاق ہے کہ اس کو اسی طرح خرچ کرو گے جس طرح رسول اللہ صلی اللہ علیہ وسلم نے کیا تھا اور جس طرح ابوبکر رضی اللہ عنہ نے کیا تھا اور جس طرح میں نے اپنے زمانہ ولایت میں کیا اگر یہ منظور نہ ہو تو پھر مجھ سے اس معاملہ میں بات نہ کریں۔ آپ دونوں حضرات نے کہا کہ اس شرط کے ساتھ ہمارے حوالہ جائیداد کر دیں۔ چنانچہ میں نے اس شرط کے ساتھ آپ کے حوالہ جائیداد کر دی تھی۔ میں آپ لوگوں کو اللہ کی قسم دیتا ہوں۔ کیا میں نے ان لوگوں کو اس شرط کے ساتھ جائیداد دی تھی۔ جماعت نے کہا کہ ہاں، پھر آپ نے علی اور عباس رضی اللہ عنہما کی طرف متوجہ ہوئے اور کہا میں آپ لوگوں کو اللہ کی قسم دیتا ہوں۔ کیا میں نے جائیداد آپ لوگوں کو اس شرط کے ساتھ حوالہ کی تھی؟ انہوں نے کہا کہ ہاں۔ پھر آپ نے کہا، کیا آپ لوگ مجھ سے اس کے سوا کوئی اور فیصلہ چاہتے ہیں۔ پس اس ذات کی قسم جس کے حکم سے آسمان و زمین قائم ہیں، اس میں، اس کے سوا کوئی فیصلہ نہیں کر سکتا یہاں تک کہ قیامت آ جائے۔ اگر آپ لوگ اس کا انتظام نہیں کر سکتے تو پھر میرے حوالہ کر دو میں اس کا بھی انتظام کر لوں گا۔' WHERE id = 7029;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، کہا ہم سے ابوعوانہ نے بیان کیا، ان سے ابوبشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے کہ ایک خاتون رسول اللہ صلی اللہ علیہ وسلم کے پاس آئیں اور عرض کیا کہ میری والدہ نے حج کرنے کی نذر مانی تھی اور وہ ( ادائیگی سے پہلے ہی ) وفات پا گئیں۔ کیا میں ان کی طرف سے حج کر لوں؟ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ ہاں ان کی طرف سے حج کر لو۔ تمہارا کیا خیال ہے، اگر تمہاری والدہ پر قرض ہوتا تو تم اسے پورا کرتیں؟ انہوں نے کہا: جی ہاں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر اس قرض کو بھی پورا کر جو اللہ تعالیٰ کا ہے کیونکہ اس قرض کا پورا کرنا زیادہ ضروری ہے۔' WHERE id = 7039;
UPDATE hadiths SET urdu = 'ہم سے ایوب بن سلمان نے بیان کیا، کہا ہم سے ابوبکر بن اویس نے بیان کیا، ان سے سلیمان بن بلال نے، ان سے صالح بن کیسان نے، ان سے ابن شہاب نے بیان کیا کہ مجھے انس بن مالک رضی اللہ عنہ نے خبر دی کہ رسول اللہ صلی اللہ علیہ وسلم عصر کی نماز پڑھ کر ان گاؤں میں جاتے جو مدینہ کی بلندی پر واقع ہیں وہاں پہنچ جاتے اور سورج بلند رہتا۔ عوالی مدینہ کا بھی یہی حکم ہے اور لیث نے بھی اس حدیث کو یونس سے روایت کیا، اس میں اتنا زیادہ ہے کہ یہ گاؤں مدینہ سے تین چار میل پر واقع ہیں۔' WHERE id = 7051;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے عبدالاعلیٰ نے بیان کیا، کہا ہم سے ہشام بن حسان نے بیان کیا، ان سے ہشام بن عروہ نے بیان کیا، ان سے ان کے والد نے کہ عائشہ رضی اللہ عنہا نے بیان کیا کہ میرے اور رسول اللہ صلی اللہ علیہ وسلم کے لیے یہ لگن رکھی جاتی تھی اور ہم دونوں اس سے ایک ساتھ نہاتے تھے۔' WHERE id = 7061;
UPDATE hadiths SET urdu = 'ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء بن ابی رباح نے، ان سے عبید بن عمیر نے بیان کیا کہ ہم سے مسدد بن مسرہد نے بیان کیا، کہا ہم سے یحییٰ بن سعید قطان نے بیان کیا، ان سے ابن جریج نے، ان سے عطاء بن ابی رباح نے، ان سے عبید بن عمیر نے بیان کیا کہ' WHERE id = 7073;
UPDATE hadiths SET urdu = 'ہم سے موسیٰ بن اسماعیل نے بیان کیا، انہوں نے کہا ہم سے ابراہیم بن سعد نے بیان کیا، انہوں نے کہا ہم کو ابن شہاب نے خبر دی، انہیں عبیداللہ بن عبداللہ بن عتبہ نے اور ان سے عبداللہ بن عباس رضی اللہ عنہما نے بیان کیا کہ تم اہل کتاب سے کسی چیز کے بارے میں کیوں پوچھتے ہو جب کہ تمہاری کتاب جو رسول اللہ صلی اللہ علیہ وسلم پر نازل ہوئی وہ تازہ بھی ہے اور محفوظ بھی اور تمہیں اس نے بتا بھی دیا کہ اہل کتاب نے اپنا دین بدل ڈالا اور اللہ کی کتاب میں تبدیلی کر دی اور اسے اپنے ہاتھ سے از خود بنا کر لکھا اور کہا کہ یہ اللہ کی طرف سے ہے تاکہ اس کے ذریعہ دنیا کا تھوڑا سا مال کما لیں۔ تمہارے پاس ( قرآن و حدیث کا ) جو علم ہے وہ تمہیں ان سے پوچھنے سے منع کرتا ہے۔ واللہ! میں تو نہیں دیکھتا کہ اہل کتاب میں سے کوئی تم سے اس کے بارے میں پوچھتا ہو جو تم پر نازل کیا گیا ہو۔' WHERE id = 7083;
UPDATE hadiths SET urdu = 'ہم سے محمد بن بشار نے بیان کیا، کہا ہم سے عندر نے بیان کیا، کہا ہم سے شعبہ نے بیان کیا، ان سے ابوحصین اور اشعث بن سلیم نے، انہوں نے اسود بن ہلال سے سنا، ان سے معاذ بن جبل رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اے معاذ! کیا تمہیں معلوم ہے کہ اللہ کا اس کے بندوں پر کیا حق ہے؟“ انہوں نے کہا کہ اللہ اور اس کے رسول ہی زیادہ جانتے ہیں۔ نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ یہ ہے کہ وہ صرف اسی کی عبادت کریں اور اس کا کوئی شریک نہ ٹھہرائیں۔ کیا تمہیں معلوم ہے پھر بندوں کا اللہ پر کیا حق ہے؟ عرض کیا کہ اللہ اور اس کے رسول ہی زیادہ جانتے ہیں، فرمایا یہ ہے کہ وہ انہیں عذاب نہ دے۔' WHERE id = 7093;
UPDATE hadiths SET urdu = 'ہم سے ابومعمر نے بیان کیا، کہا ہم سے عبدالوارث نے بیان کیا، کہا ہم سے حسین معلم نے بیان کیا، ان سے عبداللہ بن بریدہ نے، ان سے یحییٰ بن یعمر نے اور انہیں ابن عباس رضی اللہ عنہما نے کہ نبی کریم صلی اللہ علیہ وسلم کہا کرتے تھے ”تیری عزت کی پناہ مانگتا ہوں کہ کوئی معبود تیرے سوا نہیں، تیری ایسی ذات ہے جسے موت نہیں اور جن و انس فنا ہو جائیں گے۔“' WHERE id = 7103;
UPDATE hadiths SET urdu = 'ہم سے سعد بن حفص نے بیان کیا، کہا ہم سے شیبان نے بیان کیا، ان سے منصور نے، ان سے ربعی بن حراش نے، ان سے خرشہ بن الحر نے اور ان سے ابوذر رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم جب رات میں لیٹنے جاتے تو کہتے «باسمك نموت ونحيا» ”ہم تیرے ہی نام سے مریں گے اور اسی سے زندہ ہوں گے۔“ اور جب بیدار ہوتے تو کہتے «الحمد لله الذي أحيانا بعد ما أماتنا وإليه النشور» ”تمام تعریف اس اللہ کے لیے ہے جس نے ہمیں مارنے کے بعد زندہ کیا اور اسی کی طرف جانا ہے۔“' WHERE id = 7114;
UPDATE hadiths SET urdu = 'ہم سے عمر بن حفص نے بیان کیا، کہا ہم سے ہمارے والد نے، کہا ہم سے اعمش نے، کہا میں نے ابوصالح سے سنا اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ فرماتا ہے کہ میں اپنے بندے کے گمان کے ساتھ ہوں اور جب وہ مجھے اپنے دل میں یاد کرتا ہے تو میں بھی اسے اپنے دل میں یاد کرتا ہوں اور جب وہ مجھے مجلس میں یاد کرتا ہے تو میں اسے اس سے بہتر فرشتوں کی مجلس میں اسے یاد کرتا ہوں اور اگر وہ مجھ سے ایک بالشت قریب آتا ہے تو میں اس سے ایک ہاتھ قریب ہو جاتا ہوں اور اگر وہ مجھ سے ایک ہاتھ قریب آتا ہے تو میں اس سے دو ہاتھ قریب ہو جاتا ہوں اور اگر وہ میری طرف چل کر آتا ہے تو میں اس کے پاس دوڑ کر آ جاتا ہوں۔“' WHERE id = 7124;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن یوسف نے بیان کیا، کہا ہم کو مالک نے خبر دی، انہیں ابوحازم نے اور ان سے سہل بن سعد رضی اللہ عنہ نے بیان کیا کہ نبی کریم صلی اللہ علیہ وسلم نے ایک صاحب سے پوچھا کیا آپ کو قرآن میں سے کچھ شے یاد ہے؟ انہوں نے کہا کہ ہاں فلاں فلاں سورتیں انہوں نے ان کے نام بتائے۔' WHERE id = 7135;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل نے بیان کیا، کہا ہم سے امام مالک نے بیان کیا، ان سے ابوالزناد نے، ان سے اعرج نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”یکے بعد دیگرے تمہارے پاس رات اور دن کے فرشتے آتے رہتے ہیں اور یہ عصر اور فجر کی نماز میں جمع ہوتے ہیں، پھر وہ اوپر چڑھتے ہیں، جنہوں نے رات تمہارے ساتھ گزاری ہوتی ہے۔ پھر اللہ تمہارے بارے میں ان سے پوچھتا ہے حالانکہ اسے تمہاری خوب خبر ہے، پوچھتا ہے کہ میرے بندوں کو تم نے کس حال میں چھوڑا؟ وہ کہتے ہیں کہ ہم نے اس حال میں چھوڑا کہ وہ نماز پڑھ رہے تھے۔“' WHERE id = 7146;
UPDATE hadiths SET urdu = 'اور حجاج بن منہال نے بیان کیا، کہا ہم سے حمام بن یحییٰ نے بیان کیا، کہا ہم سے قتادہ بن دعامہ نے بیان کیا اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”قیامت کے دن مومنوں کو ( گرم میدان میں ) روک دیا جائے گا یہاں تک کہ اس کی وجہ سے وہ غمگین ہو جائیں گے اور ( صلاح کر کے ) کہیں گے کہ کاش کوئی ہمارے رب سے ہماری شفاعت کرتا کہ ہمیں اس حالت سے نجات ملتی۔ چنانچہ وہ مل کر آدم علیہ السلام کے پاس آئیں گے اور کہیں گے کہ آپ انسانوں کے باپ ہیں، اللہ نے آپ کو اپنے ہاتھ سے پیدا کیا اور آپ کو جنت میں مقام عطا کیا، آپ کو سجدہ کرنے کا فرشتوں کو حکم دیا اور آپ کو ہر چیز کے نام سکھائے۔ آپ ہماری شفاعت اپنے رب کے حضور میں کریں تاکہ ہمیں اس حالت سے نجات دے۔ بیان کیا کہ آدم علیہ السلام کہیں گے کہ میں اس لائق نہیں وہ اپنی اس غلطی کو یاد کریں گے جو باوجود رکنے کے درخت کھا لینے کی وجہ سے ان سے ہوئی تھی اور کہیں گے کہ نوح علیہ السلام کے پاس جاؤ کیونکہ وہ پہلے نبی ہیں جنہیں اللہ تعالیٰ نے زمین والوں کی طرف رسول بنا کر بھیجا تھا۔ چنانچہ لوگ نوح علیہ السلام کے پاس آئیں گے تو وہ بھی یہ فرمائیں گے کہ میں اس لائق نہیں اور اپنی اس غلطی کو یاد کریں گے جو بغیر علم کے اللہ رب العزت سے سوال کر کے ( اپنے بیٹے کی بخشش کے لیے ) انہوں نے کی تھی اور کہیں گے کہ ابراہیم علیہ السلام کے پاس جاؤ جو اللہ کے خلیل ہیں۔ بیان کیا کہ ہم سب لوگ ابراہیم علیہ السلام کے پاس آئیں گے تو وہ بھی یہی عذر کریں گے کہ میں اس لائق نہیں اور وہ ان تین باتوں کو یاد کریں گے جن میں آپ نے بظاہر غلط بیانی کی تھی اور کہیں گے کہ موسیٰ علیہ السلام کے پاس جاؤ۔ وہ ایسے بندے ہیں جنہیں اللہ تعالیٰ نے توریت دی اور ان سے بات کی اور ان کو نزدیک کر کے ان سے سرگوشی کی۔ بیان کیا کہ پھر لوگ موسیٰ علیہ السلام کے پاس آئیں گے تو وہ بھی کہیں گے کہ میں اس لائق نہیں ہوں اور وہ غلطی یاد کریں گے جو ایک شخص کو قتل کر کے انہوں نے کی تھی۔ ( وہ کہیں گے ) البتہ عیسیٰ علیہ السلام کے پاس جاؤ وہ اللہ کے بندے، اس کے رسول، اللہ کی روح اور اس کا کلمہ ہیں۔ چنانچہ لوگ عیسیٰ علیہ السلام کے پاس آئیں گے۔ وہ فرمائیں گے کہ میں اس لائق نہیں ہوں تم لوگ محمد صلی اللہ علیہ وسلم کے پاس جاؤ۔ وہ ایسے بندے ہیں کہ اللہ نے ان کے اگلے پچھلے تمام گناہ معاف کر دئیے۔ چنانچہ لوگ میرے پاس آئیں گے اور میں اپنے رب سے اس کے در دولت یعنی عرش معلی پر آنے کے لیے اجازت چاہوں گا۔ مجھے اس کی اجازت دی جائے گی پھر میں اللہ تعالیٰ کو دیکھتے ہی سجدہ میں گر پڑوں گا اور اللہ تعالیٰ مجھے جب تک چاہے گا اسی حالت میں رہنے دے گا۔ پھر فرمائے گا کہ اے محمد! سر اٹھاؤ، کہو سنا جائے گا، شفاعت کرو تمہاری شفاعت قبول کی جائے گی، جو مانگو گے دیا جائے گا۔ بیان کیا کہ پھر میں اپنا سر اٹھاؤں گا اور اپنے رب کی حمد و ثنا کروں گا جو وہ مجھے سکھائے گا۔ بیان کیا کہ پھر میں شفاعت کروں گا۔ چنانچہ میرے لیے حد مقرر کی جائے گی اور میں اس کے مطابق لوگوں کو دوزخ سے نکال کر جنت میں داخل کروں گا۔ قتادہ نے بیان کیا کہ میں نے انس رضی اللہ عنہ کو یہ کہتے ہوئے سنا کہ پھر میں نکالوں گا اور جہنم سے نکال کر جنت میں داخل کروں گا۔ پھر تیسری مرتبہ اپنے رب سے اس کے در دولت کے لیے اجازت چاہوں گا اور مجھے اس کی اجازت دی جائے گی۔ پھر میں اللہ رب العزت کو دیکھتے ہی اس کے لیے سجدہ میں گر پڑوں گا اور اللہ تعالیٰ جب تک چاہے گا مجھے یوں ہی چھوڑے رکھے گا۔ پھر فرمائے گا: اے محمد! سر اٹھاؤ، کہو سنا جائے گا شفاعت کرو قبول کی جائے گی، مانگو دیا جائے گا۔ آپ نے بیان کیا کہ میں اپنا سر اٹھاؤں گا اور اپنے رب کی ایسی حمد و ثنا کروں گا جو وہ مجھے سکھائے گا بیان کیا کہ پھر شفاعت کروں گا اور میرے لیے حد مقرر کر دی جائے گا اور میں اس کے مطابق جہنم سے لوگوں کو نکال کر جنت میں داخل کروں گا۔ قتادہ نے بیان کیا کہ میں نے انس رضی اللہ عنہ کو یہ کہتے سنا کہ پھر میں لوگوں کو نکالوں گا اور انہیں جہنم سے نکال کر جنت میں داخل کروں گا، یہاں تک کہ جہنم میں صرف وہی لوگ باقی رہ جائیں گے جنہیں قرآن نے روک رکھا ہو گا یعنی انہیں ہمیشہ ہی اس میں رہنا ہو گا ( یعنی کفار و مشرکین ) پھر آپ نے یہ آیت تلاوت کی «عسى أن يبعثك ربك مقاما محمودا‏» ”قریب ہے کہ آپ کا رب مقام محمود پر آپ کو بھیجے گا“ فرمایا کہ یہی وہ مقام محمود ہے جس کے لیے اللہ تعالیٰ نے اپنے حبیب صلی اللہ علیہ وسلم سے وعدہ کیا ہے۔' WHERE id = 7156;
UPDATE hadiths SET urdu = 'ہم سے حفص بن عمر حوضی نے بیان کیا، کہا ہم سے ہشام دستوائی نے بیان کیا، ان سے قتادہ نے اور ان سے انس رضی اللہ عنہ نے کہ نبی کریم صلی اللہ علیہ وسلم نے فرمایا ”کچھ لوگ ان گناہوں کی وجہ سے جو انہوں نے کئے ہوں گے، آگ سے جھلس جائیں گے یہ ان کی سزا ہو گی۔ پھر اللہ اپنی رحمت سے انہیں جنت میں داخل کرے گا اور انہیں «جهنميون» کہا جائے گا۔ اور ہمام نے بیان کیا، ان سے قتادہ نے، ان سے انس رضی اللہ عنہ نے نبی کریم صلی اللہ علیہ وسلم سے یہی حدیث بیان کی۔' WHERE id = 7166;
UPDATE hadiths SET urdu = 'ہم سے حمیدی نے بیان کیا، کہا ہم سے سے ولید بن مسلم نے بیان کیا، کہا ہم سے ابن جابر نے بیان کیا، کہا مجھ سے عمیر بن ہانی نے بیان کیا، انہوں نے معاویہ رضی اللہ عنہ سے سنا، بیان کیا کہ میں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ میری امت میں سے ایک گروہ ہمیشہ قرآن و حدیث پر قائم رہے گا، اسے جھٹلانے والے اور مخالفین کوئی نقصان نہیں پہنچا سکیں گے، یہاں تک کہ «أمر الله» ( قیامت ) آ جائے گی اور وہ اسی حال میں ہوں گے۔ اس پر مالک بن یخامر نے کہا کہ میں نے معاذ رضی اللہ عنہ سے سنا، وہ کہتے تھے کہ یہ گروہ شام میں ہو گا۔ اس پر معاویہ رضی اللہ عنہ نے کہا کہ یہ مالک رضی اللہ عنہ کہتے ہیں کہ معاذ رضی اللہ عنہ نے کہا تھا کہ یہ گروہ شام میں ہو گا۔' WHERE id = 7176;
UPDATE hadiths SET urdu = 'ہم سے محمد نے بیان کیا، انہوں نے کہا ہم سے عبدالوہاب ثقفی نے بیان کیا، انہوں نے کہا ہم سے خالد حذاء نے بیان کیا، ان سے عکرمہ نے بیان کیا اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم ایک اعرابی کی عیادت کے لیے تشریف لے گئے اور اس سے کہا کہ کوئی مضائقہ نہیں یہ ( بیماری ) تمہارے لیے پاکی کا باعث ہے، اس پر اس نے کہا کہ جناب یہ وہ بخار ہے جو ایک بڈھے پر جوش مار رہا ہے اور اسے قبر تک پہنچا کے رہے گا، نبی کریم صلی اللہ علیہ وسلم نے فرمایا کہ پھر یونہی ہو گا۔' WHERE id = 7186;
UPDATE hadiths SET urdu = 'ہم سے عبداللہ بن محمد مسندی نے بیان کیا، کہا ہم سے سفیان بن عیینہ نے، انہوں نے عمرو بن دینار سے، انہوں نے ابوالعاس (سائب بن فروخ) سے، انہوں نے عبداللہ بن عمر رضی اللہ عنہما سے، انہوں نے کہا نبی کریم صلی اللہ علیہ وسلم نے طائف والوں کو گھیر لیا، اس کو فتح نہیں کیا۔ آخر آپ صلی اللہ علیہ وسلم نے فرمایا کل اللہ نے چاہا تو ہم مدینہ کو لوٹ چلیں گے، اس پر مسلمان بولے واہ ہم فتح کئے بغیر لوٹ جائیں، آپ نے فرمایا کہ ایسا ہے تو پھر کل سویرے لڑائی شروع کرو، صبح کو مسلمان لڑنے لگے لیکن ( قلع فتح نہیں ہوا ) مسلمان زخمی ہوئے۔ پھر آپ صلی اللہ علیہ وسلم نے فرمایا کہ صبح کو اللہ نے چاہا تو ہم مدینہ لوٹ چلیں گے، اس پر مسلمان خوش ہوئے، مسلمانوں کا یہ حال دیکھ کر نبی کریم صلی اللہ علیہ وسلم مسکرائے۔' WHERE id = 7196;
UPDATE hadiths SET urdu = 'ہم سے مسدد نے بیان کیا، ان سے ہشیم بن بشیر نے، ان سے ابی بشر نے، ان سے سعید بن جبیر نے اور ان سے ابن عباس رضی اللہ عنہما نے (سورۃ بنی اسرائیل کی) آیت «ولا تجهر بصلاتك ولا تخافت بها‏» کے بارے میں کہ یہ اس وقت نازل ہوئی جب رسول اللہ صلی اللہ علیہ وسلم مکہ میں چھپ کر عبادت کیا کرتے تھے۔ جب آپ نماز میں آواز بلند کرتے تو مشرکین سنتے اور قرآن مجید اور اس کے نازل کرنے والے اللہ کو اور اس کے لانے والے جبرائیل علیہ السلام کو گالی دیتے ( اور نبی کریم صلی اللہ علیہ وسلم کو بھی ) اسی لیے اللہ تعالیٰ نے فرمایا «ولا تجهر بصلاتك ولا تخافت بها‏» کہ ”اپنی نماز میں نہ آواز بلند کرو اور نہ بالکل آہستہ یعنی آواز اتنی بلند بھی نہ کر کہ مشرکین سن لیں اور اتنی آہستہ بھی نہ کر کہ آپ کے ساتھی بھی نہ سن سکیں بلکہ ان کے درمیان کا راستہ اختیار کر۔“ مطلب یہ ہے کہ اتنی آواز سے پڑھ کہ تیرے اصحاب سن لیں اور قرآن سیکھ لیں، اس سے زیادہ چلا کر نہ پڑھ۔' WHERE id = 7206;
UPDATE hadiths SET urdu = 'ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا مجھ سے سلیمان بن بلال نے بیان کیا، ان سے معاویہ بن ابی مزرد نے بیان کیا اور ان سے سعید بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ ہم سے اسماعیل بن عبداللہ نے بیان کیا، انہوں نے کہا مجھ سے سلیمان بن بلال نے بیان کیا، ان سے معاویہ بن ابی مزرد نے بیان کیا اور ان سے سعید بن یسار نے اور ان سے ابوہریرہ رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”اللہ تعالیٰ نے فرمایا کہ ٹھہر جا۔ اس نے کہا کہ یہ قطع رحم (ناطہٰ توڑنا) سے تیری پناہ مانگنے کا مقام ہے۔ اللہ تعالیٰ نے فرمایا کیا تم اس پر راضی نہیں کہ میں ناطہٰ کو جوڑنے والے سے اپنے رحم کا ناطہٰ جوڑوں اور ناطہٰ کو کاٹنے والوں سے جدا ہو جاؤں۔ اس نے کہا کہ ضرور، میرے رب! اللہ تعالیٰ نے فرمایا کہ پھر یہی تیرا مقام ہے۔ پھر ابوہریرہ رضی اللہ عنہ نے (سورۃ محمد کی) یہ آیت پڑھی «فهل عسيتم إن توليتم أن تفسدوا في الأرض وتقطعوا أرحامكم‏» ”ممکن ہے کہ اگر تم حاکم بن جاؤ تو زمین میں فساد کرو اور قطع رحم کرو۔“' WHERE id = 7217;
UPDATE hadiths SET urdu = 'ہم سے علی بن حجر نے بیان کیا، کہا ہم کو عیسیٰ بن یونس نے خبر دی، انہیں اعمش نے، انہیں خیثمہ نے اور ان سے عدی بن حاتم رضی اللہ عنہ نے بیان کیا کہ رسول اللہ صلی اللہ علیہ وسلم نے فرمایا ”تم میں سے ہر شخص سے تمہارا رب اس طرح بات کرے گا کہ تمہارے اور اس کے درمیان کوئی ترجمان نہیں ہو گا وہ اپنے دائیں طرف دیکھے گا اور اسے اپنے اعمال کے سوا اور کچھ نظر نہیں آئے گا اور وہ اپنے بائیں طرف دیکھے گا اور اسے اپنے اعمال کے سوا کچھ نظر نہیں آئے گا۔ پھر اپنے سامنے دیکھے گا تو اپنے سامنے جہنم کے سوا اور کوئی چیز نہ دیکھے گا۔ پس جہنم سے بچو خواہ کھجور کے ایک ٹکڑے ہی کے ذریعہ ہو سکے۔“ اعمش نے بیان کیا کہ مجھ سے عمرو بن مرہ نے بیان کیا، ان سے خیشمہ نے اسی طرح اور اس میں یہ لفظ زیادہ کئے کہ ( جہنم سے بچو ) خواہ ایک اچھی بات ہی کے ذریعہ ہو۔' WHERE id = 7227;
UPDATE hadiths SET urdu = 'ہم سے علی بن عبداللہ مدینی نے بیان کیا، کہا ہم سے حاتم بن وردان نے بیان کیا، کہا ہم سے ایوب نے بیان کیا، ان سے عکرمہ نے اور ان سے ابن عباس رضی اللہ عنہما نے بیان کیا کہ تم اہل کتاب سے ان کی کتابوں کے مسائل کے بارے میں کیونکر سوال کرتے ہو، تمہارے پاس خود اللہ کی کتاب موجود ہے جو زمانہ کے اعتبار سے بھی تم سے سب سے زیادہ قریب ہے، تم اسے پڑھتے ہو، وہ خالص ہے اس میں کوئی ملاوٹ نہیں۔' WHERE id = 7237;
UPDATE hadiths SET urdu = 'ہم سے قتیبہ بن سعید نے بیان کیا، کہا ہم سے جریر نے بیان کیا، ان سے اعمش نے، ان سے ابووائل نے، ان سے عمرو بن شرجیل نے بیان کیا اور ان سے عبداللہ بن مسعود رضی اللہ عنہ نے بیان کیا کہ ایک صاحب نے عرض کیا: یا رسول اللہ! کون سا گناہ اللہ کے نزدیک سب سے بڑا ہے؟ فرمایا کہ تم اللہ کی عبادت میں کسی کو بھی ساجھی بناؤ حالانکہ تمہیں اللہ نے پیدا کیا ہے۔ پوچھا پھر کون سا؟ فرمایا یہ کہ تم اپنے بچے کو اس خوف سے مار ڈالو کہ وہ تمہارے ساتھ کھائے گا۔ پوچھا پھر کون سا؟ فرمایا یہ کہ تم اپنے پڑوسی کی بیوی سے زنا کرو۔ چنانچہ اللہ تعالیٰ نے ( سورۃ الفرقان میں ) اس کی تصدیق میں قرآن نازل فرمایا «والذين لا يدعون مع الله إلها آخر ولا يقتلون النفس التي حرم الله إلا بالحق ولا يزنون ومن يفعل ذلك‏» ”اور وہ لوگ جو اللہ کے ساتھ کسی دوسرے معبود باطل کو نہیں پکارتے اور جو کسی ایسے کی جان نہیں لیتے جسے اللہ نے حرام کیا ہے سوا حق کے اور جو زنا نہیں کرتے اور جو کوئی ایسا کرے گا وہ گناہ سے بھڑ جائے گا۔“' WHERE id = 7247;
UPDATE hadiths SET urdu = 'ہم سے ابراہیم بن حمزہ نے بیان کیا، انہوں نے کہا ہم سے ابن ابی حازم نے بیان کیا، ان سے یزید نے بیان کیا ان سے محمد بن ابراہیم نے، ان سے ابوسلمہ نے اور ان سے ابوہریرہ رضی اللہ عنہ نے کہ انہوں نے نبی کریم صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ کسی چیز کو اتنی توجہ سے نہیں سنتا جتنی توجہ سے اچھی آواز سے پڑھنے پر نبی کے قرآن مجید کو سنتا ہے۔' WHERE id = 7259;
UPDATE hadiths SET urdu = 'مجھ سے محمد بن غالب نے بیان کیا، ان سے محمد بن اسماعیل بصریٰ نے بیان کیا، کہا ہم سے معتمر بن سلیمان نے بیان کیا، انہوں نے اپنے والد سے سنا، انہوں نے کہا کہ ہم سے قتادہ نے بیان کیا، ان سے ابورافع نے حدیث بیان کی، انہوں نے ابوہریرہ رضی اللہ عنہ سے سنا، انہوں نے بیان کیا کہ میں نے رسول اللہ صلی اللہ علیہ وسلم سے سنا، آپ صلی اللہ علیہ وسلم نے فرمایا کہ اللہ تعالیٰ نے مخلوق کو پیدا کرنے سے پہلے ایک تحریر لکھی کہ میری رحمت میرے غضب سے بڑھ کر ہے، چنانچہ یہ اس کے پاس عرش کے اوپر لکھا ہوا ہے۔' WHERE id = 7269;
